globalThis.__BQ = {"apolarKovalent":{"ilkokul":{"kolay":[{"q":"İki aynı atom birleştiğinde elektronlarını nasıl paylaşır?","steps":[{"t":"Aynı güç","a":"eşit çeker","d":"Aynı çeşit iki atomun çekme gücü eşittir, hiçbiri öbüründen daha güçlü değildir."},{"t":"Eşit paylaşım","a":"ortada durur","d":"Bu yüzden ortak elektronlar tam ortada, eşit şekilde paylaşılır."}],"ans":"Aynı iki atom birleştiğinde çekme güçleri eşit olduğu için elektronları tam eşit paylaşır."},{"q":"Soluduğumuz havadaki oksijen gazı (O₂) nasıl oluşur?","fig":"<svg viewBox='0 0 320 160'><circle cx='120' cy='80' r='28' fill='#e0552b' stroke='#1a2b45'/><text x='120' y='85' font-size='13' text-anchor='middle' fill='#fff'>O</text><circle cx='200' cy='80' r='28' fill='#e0552b' stroke='#1a2b45'/><text x='200' y='85' font-size='13' text-anchor='middle' fill='#fff'>O</text><line x1='148' y1='80' x2='172' y2='80' stroke='#1a2b45' stroke-width='3'/><text x='160' y='140' font-size='11' text-anchor='middle' fill='#1a2b45'>O₂</text></svg>","steps":[{"t":"İki oksijen","a":"aynı atom","d":"İki tane oksijen (O) atomu bir araya gelir."},{"t":"Paylaşım","a":"elektron ortak","d":"Elektronlarını eşit paylaşarak oksijen gazı molekülünü (O₂) oluşturur."}],"ans":"İki oksijen atomu elektronlarını eşit paylaşarak oksijen gazını (O₂) oluşturur."},{"q":"İki hidrojen atomu birleşince hangi atom elektronu daha çok çeker?","steps":[{"t":"İki H","a":"aynı atom","d":"İki hidrojen atomu tamamen aynı çeşittir."},{"t":"Eşitlik","a":"hiçbiri","d":"İkisi de aynı güçte çektiği için hiçbiri elektronu daha çok kendine çekemez."}],"ans":"İki hidrojen aynı olduğundan hiçbiri elektronu daha çok çekmez, eşit paylaşırlar."},{"q":"Aynı atomlardan oluşan bir molekülde elektronlar nereye daha yakın durur?","steps":[{"t":"Eşit çekim","a":"iki taraf da aynı","d":"İki taraftaki atom eşit güçte çektiği için elektronlar bir tarafa kaymaz."},{"t":"Orta","a":"tam ortada","d":"Bu yüzden ortak elektronlar tam ortada, dengede durur."}],"ans":"Aynı atomlu molekülde elektronlar bir tarafa kaymaz, tam ortada eşit dururlar."},{"q":"Doğal gazın içindeki metan (CH₄) hangi atomlardan oluşur?","steps":[{"t":"Karbon","a":"bir tane C","d":"Metanın ortasında bir karbon (C) atomu bulunur."},{"t":"Hidrojen","a":"dört tane H","d":"Bu karbona dört hidrojen (H) bağlanır; metan CH₄ olarak yazılır."}],"ans":"Metan, bir karbon ve dört hidrojen atomundan (CH₄) oluşur."}],"zor":[{"q":"Klor gazı (Cl₂) molekülünde elektronlar neden hiçbir atoma kaymaz?","fig":"<svg viewBox='0 0 320 160'><circle cx='120' cy='80' r='28' fill='#9ed9a8' stroke='#1a2b45'/><text x='120' y='85' font-size='12' text-anchor='middle' fill='#1a2b45'>Cl</text><circle cx='200' cy='80' r='28' fill='#9ed9a8' stroke='#1a2b45'/><text x='200' y='85' font-size='12' text-anchor='middle' fill='#1a2b45'>Cl</text><line x1='148' y1='80' x2='172' y2='80' stroke='#1a2b45' stroke-width='3'/><text x='160' y='140' font-size='11' text-anchor='middle' fill='#1a2b45'>Cl₂</text></svg>","steps":[{"t":"İki Cl aynı","a":"eşit güç","d":"İki klor atomu aynı çeşittir, ortak elektronları eşit güçte çekerler."},{"t":"Denge","a":"kaymaz","d":"Çekim güçleri eşit olduğundan elektronlar bir atoma yaklaşmaz, ortada kalır."}],"ans":"Cl₂'de iki klor aynı çeşit olup eşit güçle çektiğinden elektronlar hiçbir atoma kaymaz."},{"q":"Bir molekülde elektronlar eşit paylaşılırsa molekülün yük dengesi nasıl olur?","steps":[{"t":"Eşit dağılım","a":"ortada yük","d":"Elektronlar ortada eşit durunca yük de iki tarafa eşit dağılır."},{"t":"Kutup yok","a":"dengeli","d":"Bir uç eksi, diğer uç artı olmaz; molekülün uçları arasında yük farkı oluşmaz."}],"ans":"Elektronlar eşit paylaşılınca yük dengeli dağılır; molekülün uçları arasında artı-eksi farkı oluşmaz."},{"q":"İki farklı kişi eşit güçle bir ipi çekerse ip nereye gider, bu hangi bağa benzer?","steps":[{"t":"Eşit çekiş","a":"ip ortada","d":"İki kişi aynı güçle çekerse ip hiçbir tarafa kaymaz, ortada kalır."},{"t":"Benzetme","a":"apolar bağ","d":"Aynı güçle paylaşılan elektronlar da ortada kalır; bu, eşit paylaşımlı (apolar) bağa benzer."}],"ans":"Eşit güçle çekilen ip ortada kalır; bu, elektronların eşit paylaşıldığı apolar bağa benzer."},{"q":"Azot gazı (N₂) molekülünde iki azot arasındaki paylaşım eşit midir?","steps":[{"t":"İki N aynı","a":"aynı atom","d":"Molekülde iki azot atomu vardır ve ikisi de aynı çeşittir."},{"t":"Eşit paylaşım","a":"eşit","d":"Aynı atomlar eşit güçle çektiği için elektron paylaşımı tam eşittir."}],"ans":"Evet; N₂'de iki azot aynı olduğundan elektron paylaşımı eşittir."},{"q":"Hidrojen gazı (H₂) ile su (H₂O) arasında elektron paylaşımı açısından ne fark vardır?","steps":[{"t":"H₂ eşit","a":"aynı atomlar","d":"H₂'de iki hidrojen aynı olduğundan elektronlar eşit paylaşılır."},{"t":"Suda eşitsiz","a":"farklı atomlar","d":"Suda hidrojen ile oksijen farklı olduğundan oksijen elektronu daha çok çeker, paylaşım eşit değildir."}],"ans":"H₂'de paylaşım eşittir; suda ise oksijen daha güçlü çektiğinden paylaşım eşit değildir."}]},"ortaokul":{"kolay":[{"q":"Apolar kovalent bağ nedir?","steps":[{"t":"Eşit paylaşım","a":"elektron ortak","d":"Apolar kovalent bağda iki atom ortak elektronları eşit olarak paylaşır."},{"t":"Yük dengesi","a":"kutup yok","d":"Paylaşım eşit olduğundan bağda kalıcı artı-eksi uçlar (kutup) oluşmaz."}],"ans":"Apolar kovalent bağ, atomların ortak elektronları eşit paylaştığı ve kutup oluşmayan bağdır."},{"q":"Hangi durumda kovalent bağ apolar olur?","steps":[{"t":"Aynı atomlar","a":"H₂, O₂, N₂","d":"Aynı çeşit atomlar arasında (H₂, O₂, Cl₂, N₂) çekim eşit olduğundan bağ apolardır."},{"t":"Eşit çekim","a":"elektronegatiflik farkı yok","d":"İki atomun elektron çekme gücü (elektronegatifliği) aynı/çok yakın olduğunda bağ apolar olur."}],"ans":"Aynı veya elektron çekme gücü eşit atomlar arasında oluşan kovalent bağ apolardır (H₂, O₂, N₂ gibi)."},{"q":"H₂ molekülündeki bağ neden apolardır?","fig":"<svg viewBox='0 0 320 160'><circle cx='120' cy='80' r='26' fill='#cfd8e8' stroke='#1a2b45'/><text x='120' y='85' font-size='13' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='200' cy='80' r='26' fill='#cfd8e8' stroke='#1a2b45'/><text x='200' y='85' font-size='13' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='152' cy='80' r='5' fill='#2b6be0'/><circle cx='168' cy='80' r='5' fill='#2b6be0'/><text x='160' y='140' font-size='10' text-anchor='middle' fill='#1a2b45'>ortak çift tam ortada</text></svg>","steps":[{"t":"İki H aynı","a":"eşit çekim","d":"İki hidrojen atomunun elektron çekme gücü eşittir."},{"t":"Ortak çift ortada","a":"kayma yok","d":"Ortak elektron çifti tam ortada kalır, bir atoma kaymaz; bu yüzden bağ apolardır."}],"ans":"H₂'de iki aynı atom eşit çektiğinden ortak çift ortada kalır ve bağ apolar olur."},{"q":"Apolar bir molekülün dipol momenti neden sıfırdır?","steps":[{"t":"Kutup yok","a":"yük dengeli","d":"Apolar molekülde artı ve eksi yük merkezleri çakışır, kalıcı kutup yoktur."},{"t":"Dipol sıfır","a":"net yön yok","d":"Bir uçtan diğerine yük ayrılması olmadığından dipol momenti sıfırdır."}],"ans":"Apolar molekülde artı-eksi yük merkezleri çakıştığından kutup oluşmaz; bu yüzden dipol momenti sıfırdır."},{"q":"Metan (CH₄) bütünüyle neden apolar kabul edilir?","steps":[{"t":"Bağlar","a":"dört C–H","d":"Metanda dört C–H bağı vardır; bu bağlar çok az kutupludur."},{"t":"Simetri","a":"dengeli yapı","d":"Dört bağ uzayda simetrik (dengeli) dağıldığından etkileri birbirini götürür ve molekül apolar olur."}],"ans":"Metanda dört C–H bağı simetrik dağıldığından etkileri birbirini götürür; bu nedenle CH₄ apolardır."}],"zor":[{"q":"Aynı atomlar arasındaki bağda elektronegatiflik farkı nedir ve bağı nasıl etkiler?","steps":[{"t":"Fark sıfır","a":"aynı çekim","d":"Aynı çeşit atomların elektronegatifliği eşit olduğundan aralarındaki fark sıfırdır."},{"t":"Eşit paylaşım","a":"tam apolar","d":"Fark sıfır olunca elektronlar tam eşit paylaşılır ve bağ tamamen apolar olur."}],"ans":"Aynı atomlar arasında elektronegatiflik farkı sıfırdır; bu da elektronların tam eşit paylaşılarak bağın apolar olmasını sağlar."},{"q":"N₂ molekülündeki bağ türünü ve apolarlığını açıklayınız.","fig":"<svg viewBox='0 0 320 160'><circle cx='120' cy='80' r='28' fill='#5b6b85' stroke='#1a2b45'/><text x='120' y='85' font-size='13' text-anchor='middle' fill='#fff'>N</text><circle cx='200' cy='80' r='28' fill='#5b6b85' stroke='#1a2b45'/><text x='200' y='85' font-size='13' text-anchor='middle' fill='#fff'>N</text><line x1='148' y1='70' x2='172' y2='70' stroke='#1a2b45' stroke-width='3'/><line x1='148' y1='80' x2='172' y2='80' stroke='#1a2b45' stroke-width='3'/><line x1='148' y1='90' x2='172' y2='90' stroke='#1a2b45' stroke-width='3'/><text x='160' y='140' font-size='11' text-anchor='middle' fill='#1a2b45'>N≡N üçlü bağ</text></svg>","steps":[{"t":"Üçlü bağ","a":"3 ortak çift","d":"Her azotun oktete ulaşması için 3 elektron çifti paylaşması gerekir; aralarında üçlü bağ (N≡N) oluşur."},{"t":"Apolar","a":"eşit paylaşım","d":"İki azot aynı atom olduğundan bu üç çift de eşit paylaşılır; molekül apolardır."}],"ans":"N₂'de iki azot üç elektron çifti paylaşarak üçlü bağ (N≡N) kurar; aynı atomlar olduğundan paylaşım eşittir ve molekül apolardır."},{"q":"CO₂ molekülünde C=O bağları polar olduğu halde molekül neden apolardır?","steps":[{"t":"Bağ polaritesi","a":"C=O polar","d":"Oksijen karbondan daha elektronegatif olduğundan her C=O bağı polardır ve bir bağ dipolü taşır."},{"t":"Doğrusal simetri","a":"dipoller götürür","d":"CO₂ doğrusal (O=C=O) olduğundan iki bağ dipolü zıt yönlüdür ve birbirini götürür; net dipol sıfır olur."}],"ans":"CO₂'de polar C=O bağları doğrusal geometride zıt yönlü olup birbirini götürdüğünden net dipol sıfırdır; molekül apolardır."},{"q":"Apolar moleküller arasında etkili olan çekim kuvveti hangisidir?","steps":[{"t":"Kalıcı kutup yok","a":"hidrojen bağı yok","d":"Apolar moleküllerde kalıcı kutup olmadığından hidrojen bağı veya dipol-dipol çekimi bulunmaz."},{"t":"London kuvvetleri","a":"anlık dipol","d":"Elektronların anlık dağılımıyla oluşan zayıf London (dağılma) kuvvetleri apolar molekülleri bir arada tutar."}],"ans":"Apolar moleküller arasında, anlık dipollerden doğan zayıf London (van der Waals dağılma) kuvvetleri etkilidir."},{"q":"Apolar maddeler neden suda zor çözünüp yağda kolay çözünür?","steps":[{"t":"Benzer benzeri çözer","a":"polariteye göre","d":"Bir madde, kendine benzer polariteye sahip çözücüde iyi çözünür."},{"t":"Apolar tercihi","a":"yağda çözünür","d":"Apolar madde, kutuplu su yerine apolar yağ ile uyumludur; bu yüzden yağda çözünür, suda çözünmez."}],"ans":"\"Benzer benzeri çözer\" ilkesince apolar maddeler kutuplu suya değil, apolar çözücülere (yağa) benzer; bu yüzden yağda çözünür, suda zor çözünür."}]},"lise":{"kolay":[{"q":"Apolar kovalent bağ hangi koşulda oluşur?","steps":[{"t":"Elektronegatiflik farkı","a":"≈ 0","d":"İki atomun elektronegatiflik farkı yaklaşık sıfır (genelde 0,4'ten küçük) olduğunda bağ apolar kabul edilir."},{"t":"Eşit paylaşım","a":"ortak çift dengede","d":"Bu durumda ortak elektron çifti atomlar arasında eşit (simetrik) dağılır."}],"ans":"İki atomun elektronegatiflik farkı sıfıra yakın olduğunda ortak elektronlar eşit paylaşılır ve apolar kovalent bağ oluşur."},{"q":"H₂, O₂ ve N₂ moleküllerindeki bağları apolarlık açısından karşılaştırınız.","fig":"<svg viewBox='0 0 320 170'><circle cx='70' cy='60' r='18' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='120' cy='60' r='18' fill='#cfd8e8' stroke='#1a2b45'/><line x1='88' y1='60' x2='102' y2='60' stroke='#1a2b45' stroke-width='2'/><text x='95' y='95' font-size='10' text-anchor='middle' fill='#1a2b45'>H–H</text><circle cx='180' cy='60' r='18' fill='#e0552b' stroke='#1a2b45'/><circle cx='230' cy='60' r='18' fill='#e0552b' stroke='#1a2b45'/><line x1='198' y1='55' x2='212' y2='55' stroke='#1a2b45' stroke-width='2'/><line x1='198' y1='65' x2='212' y2='65' stroke='#1a2b45' stroke-width='2'/><text x='205' y='95' font-size='10' text-anchor='middle' fill='#1a2b45'>O=O</text><circle cx='150' cy='130' r='18' fill='#5b6b85' stroke='#1a2b45'/><circle cx='200' cy='130' r='18' fill='#5b6b85' stroke='#1a2b45'/><line x1='168' y1='124' x2='182' y2='124' stroke='#1a2b45' stroke-width='2'/><line x1='168' y1='130' x2='182' y2='130' stroke='#1a2b45' stroke-width='2'/><line x1='168' y1='136' x2='182' y2='136' stroke='#1a2b45' stroke-width='2'/><text x='175' y='162' font-size='10' text-anchor='middle' fill='#1a2b45'>N≡N</text></svg>","steps":[{"t":"Bağ sayısı","a":"tekli, çift, üçlü","d":"H₂'de tek bağ (H–H), O₂'de çift bağ (O=O), N₂'de üçlü bağ (N≡N) bulunur."},{"t":"Hepsi apolar","a":"aynı atomlar","d":"Üçünde de bağ aynı tür atomlar arasında olduğundan elektronlar eşit paylaşılır; tümü apolardır."}],"ans":"H₂ tek, O₂ çift, N₂ üçlü bağ içerir; üçünde de bağ aynı atomlar arasında olduğundan elektron paylaşımı eşittir ve hepsi apolardır."},{"q":"Bir molekülün dipol momentinin sıfır olması ne anlama gelir?","steps":[{"t":"Yük merkezleri","a":"çakışık","d":"Dipol momenti sıfırsa molekülde artı ve eksi yük merkezleri çakışıktır."},{"t":"Apolar molekül","a":"net kutup yok","d":"Bu durumda molekülün net bir kutbu yoktur, yani molekül apolardır."}],"ans":"Dipol momentinin sıfır olması, artı-eksi yük merkezlerinin çakıştığını ve molekülün net kutbunun olmadığını (apolar olduğunu) gösterir."},{"q":"CH₄ molekülü neden apolardır?","fig":"<svg viewBox='0 0 320 180'><circle cx='160' cy='90' r='24' fill='#33415588' stroke='#1a2b45'/><text x='160' y='95' font-size='13' text-anchor='middle' fill='#fff'>C</text><circle cx='160' cy='35' r='14' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='110' cy='130' r='14' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='210' cy='130' r='14' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='160' cy='150' r='14' fill='#cfd8e8' stroke='#1a2b45'/><line x1='160' y1='66' x2='160' y2='49' stroke='#1a2b45' stroke-width='2'/><line x1='143' y1='105' x2='120' y2='122' stroke='#1a2b45' stroke-width='2'/><line x1='177' y1='105' x2='200' y2='122' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='114' x2='160' y2='136' stroke='#1a2b45' stroke-width='2'/><text x='160' y='172' font-size='10' text-anchor='middle' fill='#1a2b45'>dörtyüzlü simetri</text></svg>","steps":[{"t":"Bağ dipolleri","a":"hafif polar C–H","d":"Dört C–H bağı az da olsa polardır, her biri küçük bir dipol taşır."},{"t":"Dörtyüzlü simetri","a":"toplam sıfır","d":"Bağlar 109,5° açıyla düzgün dörtyüzlü simetride dağıldığından dipoller vektörel olarak birbirini götürür; net dipol sıfır olur."}],"ans":"CH₄'te dört C–H bağı dipolü düzgün dörtyüzlü simetride birbirini götürdüğünden net dipol sıfırdır; molekül apolardır."},{"q":"Apolar moleküllerin kaynama noktaları neden genelde düşüktür?","steps":[{"t":"Zayıf etkileşim","a":"London kuvvetleri","d":"Apolar moleküller arasında yalnızca zayıf London (dağılma) kuvvetleri vardır."},{"t":"Kolay ayrılma","a":"düşük kaynama","d":"Bu zayıf kuvvetleri yenmek az enerji gerektirdiğinden moleküller kolay ayrılır ve kaynama noktası düşük olur."}],"ans":"Apolar moleküller arasında yalnızca zayıf London kuvvetleri bulunduğundan, az enerjiyle ayrılırlar ve kaynama noktaları genelde düşüktür."}],"zor":[{"q":"Bağ polar olduğu halde molekülün apolar olabilmesini geometri ile açıklayınız (CO₂, BF₃, CCl₄).","fig":"<svg viewBox='0 0 320 170'><circle cx='100' cy='60' r='16' fill='#e0552b' stroke='#1a2b45'/><circle cx='160' cy='60' r='18' fill='#33415588' stroke='#1a2b45'/><circle cx='220' cy='60' r='16' fill='#e0552b' stroke='#1a2b45'/><line x1='116' y1='60' x2='142' y2='60' stroke='#1a2b45' stroke-width='2'/><line x1='178' y1='60' x2='204' y2='60' stroke='#1a2b45' stroke-width='2'/><text x='112' y='40' font-size='10' fill='#1a2b45'>←</text><text x='205' y='40' font-size='10' fill='#1a2b45'>→</text><text x='160' y='110' font-size='10' text-anchor='middle' fill='#1a2b45'>O=C=O doğrusal</text><text x='160' y='140' font-size='10' text-anchor='middle' fill='#1a2b45'>zıt dipoller toplamı = 0</text></svg>","steps":[{"t":"Bağ dipolleri","a":"her bağ polar","d":"CO₂, BF₃ ve CCl₄'te merkez atomla çevre atomlar arasında elektronegatiflik farkı olduğundan her bağ polardır."},{"t":"Simetri iptali","a":"vektörel sıfır","d":"Doğrusal (CO₂), düzlem üçgen (BF₃) ve düzgün dörtyüzlü (CCl₄) simetrilerde bağ dipolleri vektörel olarak toplanıp sıfır verir; molekül apolar olur."}],"ans":"CO₂, BF₃ ve CCl₄'te polar bağların dipolleri simetrik geometride vektörel olarak birbirini götürür; net dipol sıfır olduğundan moleküller apolardır."},{"q":"Aynı atomlar arasındaki üçlü bağın (N₂) hem apolar hem de çok kararlı olmasını açıklayınız.","steps":[{"t":"Apolarlık","a":"aynı atom","d":"İki azot aynı atom olduğundan elektronegatiflik farkı sıfırdır; üç çift de eşit paylaşılır ve bağ apolardır."},{"t":"Kararlılık","a":"üçlü bağ enerjisi","d":"N≡N üçlü bağı çok yüksek bağ enerjisine (≈ 945 kJ/mol) sahiptir; bu yüzden N₂ tepkimeye girmesi zor, çok kararlı bir moleküldür."}],"ans":"N₂'de aynı atomlar elektronları eşit paylaştığından bağ apolardır; üçlü bağın çok yüksek bağ enerjisi de molekülü olağanüstü kararlı yapar."},{"q":"Apolar bir bağda elektron yoğunluğunun dağılımını ve dipol momentin sıfır oluşunu ilişkilendiriniz.","steps":[{"t":"Elektron bulutu","a":"simetrik dağılım","d":"Apolar bağda ortak elektron bulutu iki çekirdek arasında simetrik dağılır, hiçbir uca yoğunlaşmaz."},{"t":"Dipol vektörü","a":"büyüklük sıfır","d":"Yük ayrılması olmadığından bağ dipol momenti vektörünün büyüklüğü sıfırdır; kısmi yük (δ⁺/δ⁻) oluşmaz."}],"ans":"Apolar bağda elektron bulutu simetrik dağıldığından kısmi yük ayrılması olmaz; bu nedenle bağ dipol momentinin büyüklüğü sıfırdır."},{"q":"İndüklenmiş dipol-indüklenmiş dipol (London) kuvvetlerinin apolar moleküllerde büyüklüğünü ne belirler?","steps":[{"t":"Polarlanabilirlik","a":"elektron sayısı","d":"Molekülün elektron sayısı (ve büyüklüğü) arttıkça elektron bulutu daha kolay anlık dipol oluşturur (polarlanabilirlik artar)."},{"t":"Etki","a":"büyük molekül = güçlü","d":"Polarlanabilirlik arttıkça London kuvvetleri güçlenir; bu yüzden büyük apolar moleküller daha yüksek kaynama noktasına sahiptir."}],"ans":"London kuvvetlerinin büyüklüğünü molekülün polarlanabilirliği (elektron sayısı/büyüklüğü) belirler; daha büyük apolar moleküllerde bu kuvvetler güçlenir ve kaynama noktası yükselir."},{"q":"Cl₂ ve F₂ aynı grupta olduğu halde Cl₂'nin oda koşulunda gaz, ama daha kolay sıvılaşmasının apolar yapısıyla ilişkisi nedir?","steps":[{"t":"İkisi de apolar","a":"aynı atomlu","d":"Hem F₂ hem Cl₂ aynı tür atomlardan oluştuğundan apolardır; aralarında yalnızca London kuvvetleri vardır."},{"t":"Polarlanabilirlik farkı","a":"Cl daha büyük","d":"Klor atomu flordan daha çok elektrona ve daha büyük elektron bulutuna sahiptir; polarlanabilirliği yüksek olduğundan London kuvvetleri güçlüdür ve Cl₂ daha kolay sıvılaşır."}],"ans":"İkisi de apolar olup yalnızca London kuvveti içerir; Cl₂'nin daha büyük ve polarlanabilir elektron bulutu nedeniyle London kuvvetleri daha güçlüdür, bu yüzden F₂'ye göre daha kolay sıvılaşır."}]}},"atomBirlesir":{"ilkokul":{"kolay":[{"q":"Atomlar neden çoğu zaman tek başına durmaz, birbirine tutunur?","steps":[{"t":"Yalnız atom","a":"kararsız","d":"Çoğu atom tek başınayken rahat değildir, daha sağlam bir yapıya geçmek ister."},{"t":"Tutunma","a":"birleşir","d":"Atomlar birbirine tutunarak daha sağlam ve dengeli bir yapı oluşturur."}],"ans":"Atomlar daha kararlı (sağlam) bir yapıya ulaşmak için birbirine tutunur."},{"q":"İki ya da daha çok atom birleşip oluşturduğu küçük yapıya ne denir?","steps":[{"t":"Birleşme","a":"atomlar yan yana","d":"Birkaç atom bir araya gelip birbirine tutunur."},{"t":"Yeni yapı","a":"molekül","d":"Birbirine bağlı bu atom topluluğuna molekül denir."}],"ans":"Birbirine bağlanan atomların oluşturduğu küçük yapıya molekül denir."},{"q":"Atomlar birbirine tutunurken hangi küçük tanecikleri kullanır?","steps":[{"t":"Dış tanecik","a":"elektron","d":"Atomun en dışındaki elektronlar tutunmada görev alır."},{"t":"Verme-alma-paylaşma","a":"elektronlarla","d":"Atomlar bu dış elektronları vererek, alarak ya da paylaşarak birbirine bağlanır."}],"ans":"Atomlar birbirine tutunurken en dıştaki elektronlarını kullanır."},{"q":"Su molekülünde hangi atomlar birleşmiştir?","fig":"<svg viewBox='0 0 320 170'><circle cx='160' cy='90' r='26' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='95' font-size='14' text-anchor='middle' fill='#fff'>O</text><circle cx='110' cy='60' r='16' fill='#cfd8e8' stroke='#1a2b45'/><text x='110' y='65' font-size='11' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='210' cy='60' r='16' fill='#cfd8e8' stroke='#1a2b45'/><text x='210' y='65' font-size='11' text-anchor='middle' fill='#1a2b45'>H</text><line x1='138' y1='76' x2='122' y2='66' stroke='#1a2b45' stroke-width='2'/><line x1='182' y1='76' x2='198' y2='66' stroke='#1a2b45' stroke-width='2'/><text x='160' y='150' font-size='11' text-anchor='middle' fill='#1a2b45'>su (H₂O)</text></svg>","steps":[{"t":"Atomlar","a":"hidrojen ve oksijen","d":"Su molekülünde hidrojen (H) ve oksijen (O) atomları birleşmiştir."},{"t":"Birleşme","a":"tutunma","d":"Bu atomlar birbirine tutunarak su molekülünü (H₂O) oluşturur."}],"ans":"Su molekülünde hidrojen (H) ve oksijen (O) atomları birleşmiştir."},{"q":"Atomların birbirine tutunmasını sağlayan bağa kısaca ne diyebiliriz?","steps":[{"t":"Tutunma","a":"köprü gibi","d":"Atomlar arasındaki tutunmayı, onları bir arada tutan bir köprü gibi düşünebiliriz."},{"t":"Bağ","a":"kimyasal bağ","d":"Atomları bir arada tutan bu çekime <b>bağ</b> denir."}],"ans":"Atomları bir arada tutan çekime bağ denir."}],"zor":[{"q":"Bir atom en dış elektron katmanını tamamladığında ne kazanır?","steps":[{"t":"Dolu dış katman","a":"kararlı","d":"En dış katmanı dolduğunda atom daha sağlam, kararlı bir yapıya ulaşır."},{"t":"Nasıl olur","a":"birleşerek","d":"Bunu çoğu zaman başka atomlarla birleşip elektron paylaşarak ya da alıp vererek başarır."}],"ans":"Dış katmanını tamamlayan atom daha kararlı (sağlam) bir yapı kazanır."},{"q":"Neden iki hidrojen atomu birleşip H₂ oluşturmak ister?","fig":"<svg viewBox='0 0 320 160'><circle cx='120' cy='80' r='24' fill='#cfd8e8' stroke='#1a2b45'/><text x='120' y='85' font-size='13' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='200' cy='80' r='24' fill='#cfd8e8' stroke='#1a2b45'/><text x='200' y='85' font-size='13' text-anchor='middle' fill='#1a2b45'>H</text><line x1='144' y1='80' x2='176' y2='80' stroke='#1a2b45' stroke-width='3'/><text x='160' y='140' font-size='11' text-anchor='middle' fill='#1a2b45'>H₂</text></svg>","steps":[{"t":"Tek H zayıf","a":"yalnız kalmaz","d":"Tek bir hidrojen atomu kararlı değildir, bir eşle birleşmek ister."},{"t":"Paylaşım","a":"elektron ortak","d":"İki hidrojen elektronlarını paylaşıp birlikte daha kararlı bir yapı (H₂) kurar."}],"ans":"İki hidrojen birleşince daha kararlı olduğu için H₂ oluşturmak ister."},{"q":"Soy gazlar (helyum, neon gibi) neden başka atomlarla kolayca birleşmez?","steps":[{"t":"Dış katman","a":"zaten dolu","d":"Soy gazların en dış katmanı zaten tam doludur."},{"t":"İhtiyaç yok","a":"kararlı","d":"Dış katmanları dolu olduğu için kararlıdırlar, birleşmeye ihtiyaçları olmaz."}],"ans":"Soy gazların dış katmanı zaten dolu ve kararlı olduğundan başka atomlarla kolayca birleşmez."},{"q":"Aynı çeşit atomlar da birleşebilir mi, bir örnek verir misiniz?","steps":[{"t":"Aynı atomlar","a":"birleşebilir","d":"Aynı çeşit atomlar da birbirine tutunabilir."},{"t":"Örnek","a":"O₂","d":"İki oksijen atomu birleşip soluduğumuz oksijen gazını (O₂) oluşturur."}],"ans":"Evet, aynı çeşit atomlar da birleşir; örneğin iki oksijen birleşip O₂ olur."},{"q":"Yemek tuzu (NaCl) hangi iki atomun birleşmesiyle oluşur?","steps":[{"t":"Birinci atom","a":"sodyum","d":"Yemek tuzunda sodyum (Na) atomu bulunur."},{"t":"İkinci atom","a":"klor","d":"Sodyum, klor (Cl) atomu ile birleşerek tuzu (NaCl) oluşturur."}],"ans":"Yemek tuzu, sodyum (Na) ve klor (Cl) atomlarının birleşmesiyle oluşur."}]},"ortaokul":{"kolay":[{"q":"Atomların bağ kurmasının temel amacı nedir?","steps":[{"t":"Kararsızlık","a":"dış katman eksik","d":"Çoğu atomun en dış (değerlik) katmanı tam dolu değildir; bu durum kararsızdır."},{"t":"Kararlı yapı","a":"katmanı tamamlamak","d":"Atom elektron alıp vererek veya paylaşarak dış katmanını tamamlar ve kararlı hale gelir."}],"ans":"Atomlar, en dış katmanını tamamlayıp kararlı hale gelmek için bağ kurar."},{"q":"Kararlı (soy gaz) elektron düzeni ne demektir?","fig":"<svg viewBox='0 0 320 175'><circle cx='160' cy='90' r='10' fill='#e0552b' stroke='#1a2b45'/><circle cx='160' cy='90' r='34' fill='none' stroke='#1a2b45'/><circle cx='160' cy='56' r='5' fill='#2b6be0'/><circle cx='194' cy='90' r='5' fill='#2b6be0'/><circle cx='160' cy='124' r='5' fill='#2b6be0'/><circle cx='126' cy='90' r='5' fill='#2b6be0'/><text x='160' y='162' font-size='10' text-anchor='middle' fill='#1a2b45'>dolu son katman</text></svg>","steps":[{"t":"Dolu katman","a":"8 (veya 2) elektron","d":"Son katmanında 8 elektron (ilk katmanda 2) bulunan düzen kararlıdır."},{"t":"Hedef yapı","a":"soy gaz benzeri","d":"Atomlar bağ kurarken en yakın soy gazın bu dolu düzenine ulaşmaya çalışır."}],"ans":"Kararlı düzen, son katmanın 8 (ilk katmanda 2) elektronla tam dolu olduğu soy gaz benzeri elektron dizilimidir."},{"q":"Atomlar bağ kurarken en çok hangi elektronlarını kullanır?","steps":[{"t":"Değerlik elektronu","a":"son katman","d":"Atomun en dış katmanındaki elektronlara değerlik elektronu denir."},{"t":"Bağda rol","a":"bunlar kullanılır","d":"Bağlar bu değerlik elektronlarının alınması, verilmesi ya da paylaşılmasıyla kurulur."}],"ans":"Atomlar bağ kurarken en dış katmandaki değerlik elektronlarını kullanır."},{"q":"Bir atom elektron verirse, diğeri alırsa nasıl bir bağ oluşur?","steps":[{"t":"Aktarım","a":"ver-al","d":"Bir atom elektronunu verir, diğeri bu elektronu alır."},{"t":"Zıt yük çekimi","a":"bağ","d":"Veren atom artı, alan atom eksi yüklenir; zıt yükler çekilerek bağ kurar."}],"ans":"Bir atomun elektron verip diğerinin alması, zıt yüklerin çektiği bir bağ oluşturur."},{"q":"Atomlar bağ kurmadan önce hangi tabloya bakarak benzerliklerini anlarız?","steps":[{"t":"Tablo","a":"periyodik tablo","d":"Atomların özellikleri periyodik tabloda düzenli gösterilir."},{"t":"Değerlik","a":"grup numarası","d":"Bir atomun grubu, değerlik elektron sayısını ve nasıl bağ kuracağını ipuçlarıyla verir."}],"ans":"Periyodik tablo, atomların değerlik elektronlarını ve nasıl bağ kuracaklarını anlamaya yardımcı olur."}],"zor":[{"q":"Bir atomun kaç elektron alıp vereceğini ya da paylaşacağını ne belirler?","steps":[{"t":"Değerlik elektronu","a":"son katman sayısı","d":"En dış katmandaki değerlik elektron sayısı atomun davranışını belirler."},{"t":"Hedef düzen","a":"oktete ulaşmak","d":"Atom son katmanı 8'e (oktet) tamamlamak için kaç elektrona ihtiyacı varsa o kadar alır, verir veya paylaşır."}],"ans":"Atomun son katmanındaki değerlik elektron sayısı, oktete ulaşmak için kaç elektron alıp vereceğini belirler."},{"q":"Sodyum neden 1 elektron vermeyi, klor ise 1 elektron almayı tercih eder?","fig":"<svg viewBox='0 0 320 175'><circle cx='95' cy='85' r='28' fill='#cfd8e8' stroke='#1a2b45'/><text x='95' y='90' font-size='13' text-anchor='middle' fill='#1a2b45'>Na</text><circle cx='225' cy='85' r='28' fill='#9ed9a8' stroke='#1a2b45'/><text x='225' y='90' font-size='13' text-anchor='middle' fill='#1a2b45'>Cl</text><line x1='124' y1='85' x2='194' y2='85' stroke='#2b6be0' stroke-width='2'/><polygon points='194,85 184,80 184,90' fill='#2b6be0'/><text x='159' y='72' font-size='10' text-anchor='middle' fill='#1a2b45'>e⁻ aktarımı</text></svg>","steps":[{"t":"Sodyum","a":"son katmanda 1 e⁻","d":"Sodyumun son katmanında tek elektron vardır; onu vermek dolu bir alt katman bırakır ve daha kolaydır."},{"t":"Klor","a":"son katmanda 7 e⁻","d":"Klorun son katmanında 7 elektron vardır; 1 elektron alarak oktete (8'e) tamamlamak ona daha yakındır."}],"ans":"Sodyum tek değerlik elektronunu vermek, klor ise 7'yi 8'e tamamlamak için 1 elektron almak en kolay yolu olduğundan böyle davranır."},{"q":"Atomlar elektron paylaşmak yerine neden bazen elektron aktarır?","steps":[{"t":"Elektron çekim farkı","a":"metal-ametal","d":"Bir atom (metal) elektronu zayıf tutar, diğeri (ametal) güçlü çeker; bu büyük fark aktarımı kolaylaştırır."},{"t":"Sonuç","a":"iyonlar oluşur","d":"Aktarım sonucu artı ve eksi iyonlar oluşur, zıt yükler çekilerek iyonik bağ kurulur."}],"ans":"Atomların elektron çekim güçleri çok farklıysa (metal-ametal) elektron paylaşmak yerine aktarılır ve iyonik bağ oluşur."},{"q":"Bir atomun 'kararlı' olması ne demektir, neden bu hale ulaşmak ister?","steps":[{"t":"Kararlı atom","a":"düşük enerji","d":"Kararlı yapı, atomun enerjisinin düşük ve dengede olduğu durumdur; daha az tepkir."},{"t":"Eğilim","a":"düşük enerjiye gitmek","d":"Doğada her sistem mümkünse düşük enerjili (kararlı) hale gitme eğilimindedir; atom da bağ kurarak bunu sağlar."}],"ans":"Kararlı olmak, atomun düşük enerjili ve dengeli hale gelmesidir; doğada her şey düşük enerjiyi tercih ettiği için atom bağ kurarak buna ulaşmak ister."},{"q":"Hidrojen ve oksijenin birleşip su oluşturmasını adım adım nasıl açıklarsınız?","fig":"<svg viewBox='0 0 320 170'><circle cx='160' cy='85' r='24' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='90' font-size='13' text-anchor='middle' fill='#fff'>O</text><circle cx='110' cy='55' r='14' fill='#cfd8e8' stroke='#1a2b45'/><text x='110' y='60' font-size='10' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='210' cy='55' r='14' fill='#cfd8e8' stroke='#1a2b45'/><text x='210' y='60' font-size='10' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='139' cy='72' r='4' fill='#2b6be0'/><circle cx='181' cy='72' r='4' fill='#2b6be0'/><text x='160' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>ortak elektron çiftleri</text></svg>","steps":[{"t":"İhtiyaç","a":"O 2, H 1 eksik","d":"Oksijenin son katmanı 2, her hidrojenin 1 elektrona ihtiyacı vardır."},{"t":"Paylaşım","a":"iki ortak çift","d":"Oksijen iki hidrojenle birer elektron çifti paylaşır; üçü de oktet/dublete ulaşıp kararlı su molekülü (H₂O) oluşur."}],"ans":"Oksijen iki hidrojenle birer ortak elektron çifti paylaşır; böylece hepsi kararlı hale gelir ve su (H₂O) molekülü oluşur."}]},"lise":{"kolay":[{"q":"Atomların bağ kurmasının temelindeki itici güç enerji açısından nasıl açıklanır?","steps":[{"t":"Enerji düşüşü","a":"daha düşük enerji","d":"Atomlar bir araya geldiğinde sistemin potansiyel enerjisi azalırsa bağ oluşur; düşük enerjili hal daha kararlıdır."},{"t":"Kararlılık","a":"soy gaz düzeni","d":"Atom genellikle en yakın soy gazın elektron düzenine ulaşarak bu düşük enerjili, kararlı duruma erişir."}],"ans":"Atomlar, bir araya gelince sistemin enerjisi düştüğü (daha kararlı hale geldikleri) için bağ kurar; çoğunlukla soy gaz elektron düzenine ulaşmayı hedeflerler."},{"q":"Oktet kuralı nedir ve bağ oluşumuyla ilişkisi nedir?","steps":[{"t":"Kural","a":"son katman 8","d":"Atomlar son katmanlarında 8 elektron (soy gaz düzeni) bulundurmaya eğilimlidir; hidrojen için hedef 2'dir (dublet)."},{"t":"Bağla ulaşma","a":"al-ver-paylaş","d":"Atom oktete ulaşmak için elektron alır, verir veya paylaşır; bu da bağ oluşumunu doğurur."}],"ans":"Oktet kuralı, atomların son katmanını 8 elektrona tamamlama eğilimidir; atomlar bunu elektron alıp vererek ya da paylaşarak, yani bağ kurarak gerçekleştirir."},{"q":"Bir atomun değerlik elektron sayısı, kuracağı bağ türü hakkında neyi belirler?","steps":[{"t":"Değerlik elektronu","a":"son katman e⁻","d":"Değerlik elektron sayısı, atomun oktete ne kadar uzak olduğunu gösterir."},{"t":"Eğilim","a":"verme-alma-paylaşma","d":"Az değerlik elektronlu (metal) atomlar vermeye, çok elektronlu (ametal) atomlar almaya ya da paylaşmaya eğilimlidir."}],"ans":"Değerlik elektron sayısı atomun oktete uzaklığını gösterir; buna göre atom elektron vermeye (metal), almaya ya da paylaşmaya (ametal) eğilim duyar ve bağ türü belirlenir."},{"q":"Elektronegatiflik farkı, oluşacak bağın türünü nasıl etkiler?","steps":[{"t":"Çok büyük fark","a":"iyonik","d":"İki atom arası elektronegatiflik farkı çok büyükse (metal-ametal) elektron aktarılır ve iyonik bağ oluşur."},{"t":"Küçük/orta fark","a":"kovalent","d":"Fark küçük veya orta düzeyde (ametal-ametal) ise elektronlar paylaşılır ve kovalent bağ oluşur."}],"ans":"Elektronegatiflik farkı çok büyükse bağ iyonik (aktarım), küçük/orta ise kovalent (paylaşım) olur."},{"q":"Bağ oluşumu sırasında neden enerji açığa çıkar?","steps":[{"t":"Çekim baskın","a":"kararlı uzaklık","d":"Atomlar yaklaşırken belli bir uzaklıkta çekim itmeden baskın gelir ve potansiyel enerji en düşük (en kararlı) değere iner."},{"t":"Enerji salımı","a":"ekzotermik","d":"Sistem daha düşük enerjili hale geçtiği için aradaki enerji farkı dışarı (genelde ısı olarak) salınır."}],"ans":"Bağ kurulurken sistem daha düşük enerjili kararlı hale geçtiğinden, aradaki enerji farkı dışarıya salınır; bu yüzden bağ oluşumu genellikle enerji açığa çıkarır (ekzotermiktir)."}],"zor":[{"q":"Hidrojen bağ enerjisi-uzaklık eğrisinde minimum noktanın anlamı nedir?","fig":"<svg viewBox='0 0 320 190'><line x1='40' y1='160' x2='300' y2='160' stroke='#1a2b45' stroke-width='1'/><line x1='40' y1='20' x2='40' y2='160' stroke='#1a2b45' stroke-width='1'/><path d='M60 30 C 90 120, 110 150, 150 150 C 220 150, 250 145, 295 142' fill='none' stroke='#2b6be0' stroke-width='2'/><circle cx='150' cy='150' r='4' fill='#e0552b'/><text x='150' y='178' font-size='9' text-anchor='middle' fill='#1a2b45'>bağ uzunluğu</text><text x='205' y='140' font-size='9' fill='#1a2b45'>minimum enerji</text><text x='20' y='90' font-size='9' fill='#1a2b45'>E</text></svg>","steps":[{"t":"Çekim ve itme","a":"denge","d":"Atomlar yaklaşırken çekim enerjiyi düşürür; çok yaklaşınca çekirdek-çekirdek itmesi enerjiyi yükseltir."},{"t":"Minimum nokta","a":"kararlı bağ","d":"Eğrinin en düşük noktası, çekim ile itmenin dengelendiği uzaklıktır; burası bağ uzunluğu ve en kararlı (en düşük enerjili) durumdur."}],"ans":"Eğrinin minimumu çekim ile itmenin dengelendiği noktadır; bu uzaklık bağ uzunluğunu verir ve sistemin en kararlı (en düşük enerjili) hâlini gösterir."},{"q":"Atomlar neden 'soy gaz düzenine ulaşma' eğilimi gösterir; bunun temel nedeni nedir?","steps":[{"t":"Dolu kabuk kararlılığı","a":"düşük enerji","d":"Tam dolu (soy gaz) elektron kabukları küresel simetrik ve enerji bakımından çok kararlıdır."},{"t":"Eğilimin kaynağı","a":"enerji minimizasyonu","d":"Atomlar tepkimede bu düşük enerjili dolu kabuk düzenine yakınsayarak sistemin toplam enerjisini en aza indirir; oktet bu eğilimin pratik bir ifadesidir."}],"ans":"Soy gazların tam dolu elektron kabukları çok düşük enerjili ve kararlı olduğundan, atomlar enerjilerini en aza indirmek için bu düzene ulaşmaya yönelir; oktet kuralı bu eğilimin özetidir."},{"q":"Oktet kuralının istisnaları nelerdir, birer örnekle açıklayınız?","steps":[{"t":"Eksik oktet","a":"BeCl₂, BF₃","d":"Bazı atomlar oktetten az elektronla kararlı olur; berilyum (4 e⁻) ve bor (6 e⁻) buna örnektir."},{"t":"Genişlemiş oktet","a":"PCl₅, SF₆","d":"3. periyot ve sonrası bazı atomlar d orbitalleri sayesinde 8'den çok elektron bulundurabilir (fosfor 10, kükürt 12 e⁻)."}],"ans":"Oktetin istisnaları vardır: bazı atomlar eksik oktetle (BeCl₂, BF₃) ya da genişlemiş oktetle (PCl₅, SF₆) kararlı olabilir; ayrıca tek elektronlu (radikal) yapılar da kurala uymaz."},{"q":"İyonik ve kovalent bağ oluşumunu enerji ve elektron davranışı açısından karşılaştırınız.","steps":[{"t":"İyonik oluşum","a":"aktarım + örgü enerjisi","d":"Metal elektron verir, ametal alır; oluşan zıt iyonlar düzenli bir kristal örgüde toplanır ve salınan örgü enerjisi yapıyı kararlı kılar."},{"t":"Kovalent oluşum","a":"paylaşım + örtüşme","d":"Ametaller değerlik orbitallerini örtüştürerek elektron çifti paylaşır; örtüşmeyle azalan potansiyel enerji bağı kararlı kılar."}],"ans":"İyonik bağda elektron aktarılır ve iyonlar örgü enerjisiyle kararlı kristal kurar; kovalent bağda orbital örtüşmesiyle elektron paylaşılır ve azalan enerji bağı kararlı yapar. İkisinde de itici güç, sistemin enerjisini düşürmektir."},{"q":"Bir tepkimede atomların yeniden düzenlenmesi sırasında bağların rolünü açıklayınız.","steps":[{"t":"Bağ kırılması","a":"enerji gerekir","d":"Mevcut bağları koparmak için dışarıdan enerji verilmesi gerekir (endotermik adım)."},{"t":"Bağ oluşması","a":"enerji salınır","d":"Yeni, daha kararlı bağlar oluşurken enerji açığa çıkar; net enerji değişimi kırılan ve oluşan bağların enerji farkına bağlıdır."}],"ans":"Kimyasal tepkimede önce var olan bağlar kırılır (enerji alır), sonra yeni daha kararlı bağlar oluşur (enerji verir); tepkimenin net enerjisi bu iki adımın farkına eşittir ve atomlar bu yolla daha kararlı düzene geçer."}]}},"bagEnerjisi":{"ilkokul":{"kolay":[{"q":"İki topu bir yaya bağlasak, onları ayırmak için ne yapmamız gerekir?","steps":[{"t":"Bağ vardır","a":"yay tutar","d":"Yay iki topu birbirine bağlı tutar, kolayca ayrılmazlar."},{"t":"Enerji gerekir","a":"çekip ayırırız","d":"Topları ayırmak için kuvvet uygular, yani enerji harcarız."}],"ans":"Bağlı iki şeyi ayırmak için enerji (kuvvet) harcamamız gerekir."},{"q":"Atomları birbirine bağlayan şeye ne diyoruz?","steps":[{"t":"Birleşme","a":"bağ","d":"Atomlar birbirine bir bağ ile tutunur."},{"t":"Kopma","a":"enerji ister","d":"Bu bağı koparmak için enerji vermek gerekir."}],"ans":"Atomları birbirine tutan şeye bağ denir; onu koparmak enerji ister."},{"q":"Bir bağ kurulurken mi yoksa kopuyorken mi enerji açığa çıkar?","steps":[{"t":"Kurulurken","a":"enerji çıkar","d":"İki atom birleşip bağ kurarken enerji açığa çıkar."},{"t":"Kopuyorken","a":"enerji ister","d":"Bağ kırılırken ise enerji vermemiz gerekir."}],"ans":"Bağ kurulurken enerji açığa çıkar; bağ kopuyorken enerji harcanır."},{"q":"Tahta parçalarını çiviyle birleştirmek neye benzer?","fig":"<svg viewBox='0 0 320 160'><circle cx='110' cy='80' r='26' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='210' cy='80' r='26' fill='#cfd8e8' stroke='#1a2b45'/><line x1='136' y1='80' x2='184' y2='80' stroke='#1a2b45' stroke-width='4'/><text x='160' y='140' font-size='12' text-anchor='middle' fill='#1a2b45'>atomlar arası bağ</text></svg>","steps":[{"t":"Bağlama","a":"birleşir","d":"Çivi iki tahtayı birleştirir, tıpkı bağ iki atomu birleştirdiği gibi."},{"t":"Ayırma","a":"güç gerekir","d":"Onları ayırmak için çiviyi çekmek, yani güç (enerji) gerekir."}],"ans":"Çiviyle birleştirmek bağ kurmaya benzer; ayırmak için güç (enerji) gerekir."},{"q":"Sağlam (güçlü) bir bağ ile gevşek bir bağdan hangisini koparmak daha zordur?","steps":[{"t":"Güçlü bağ","a":"sıkı tutar","d":"Güçlü bağ atomları sıkıca tutar."},{"t":"Zor kopar","a":"çok enerji","d":"Bu yüzden güçlü bağı koparmak için daha çok enerji gerekir."}],"ans":"Güçlü bağı koparmak daha zordur, daha çok enerji gerektirir."}],"zor":[{"q":"Bir oyuncak iki mıknatısla birbirine yapışıyor. Daha güçlü mıknatısları ayırmak neden daha zordur?","steps":[{"t":"Güçlü çekim","a":"sıkı yapışır","d":"Güçlü mıknatıslar birbirini daha kuvvetle çeker, sıkıca yapışır."},{"t":"Ayırma","a":"çok enerji","d":"Daha kuvvetli çekimi yenmek için daha çok enerji harcamak gerekir."}],"ans":"Güçlü çekim sıkı tuttuğu için onları ayırmak daha çok enerji ister."},{"q":"Buz erirken ve su kaynarken neden enerji (ısı) vermemiz gerekir?","steps":[{"t":"Tanecikler bağlı","a":"çekim var","d":"Sudaki tanecikler birbirini çeker, bir arada durur."},{"t":"Ayırmak için","a":"ısı veririz","d":"Onları birbirinden uzaklaştırmak için ısı (enerji) vermemiz gerekir."}],"ans":"Tanecikleri ayırmak için ısı vermemiz gerekir; ayırmak enerji ister."},{"q":"Bir maket iki parçayı tutkalla birleştirip sonra ayırıyoruz. Hangi adımda enerji harcanır?","steps":[{"t":"Birleştirme","a":"enerji çıkar","d":"Parçalar birleşip bağ kurarken durum daha kararlı olur, enerji açığa çıkar."},{"t":"Ayırma","a":"enerji harcanır","d":"Bağı koparıp parçaları ayırmak için enerji vermek gerekir."}],"ans":"Parçaları ayırırken (bağı koparırken) enerji harcanır."},{"q":"İki atom birbirine yaklaşıp bağ kurunca neden daha kararlı (rahat) olurlar?","steps":[{"t":"Bağ kurma","a":"enerji salınır","d":"Atomlar bağ kurarken fazla enerjilerini dışarı salar."},{"t":"Düşük enerji","a":"kararlı","d":"Enerjisi azalan sistem daha kararlı ve dengelidir."}],"ans":"Bağ kurarken enerji saldıkları için atomlar daha düşük enerjili ve kararlı olur."},{"q":"Çok güçlü bir ipi koparmak ile ince bir ipi koparmak arasındaki fark, bağ enerjisine nasıl benzer?","steps":[{"t":"Kalın ip","a":"çok güç","d":"Kalın, güçlü ip için daha çok kuvvet (enerji) gerekir."},{"t":"Benzetme","a":"güçlü bağ","d":"Aynı şekilde güçlü kimyasal bağı koparmak da daha çok enerji ister."}],"ans":"Kalın ip gibi güçlü bağı koparmak da daha çok enerji gerektirir."}]},"ortaokul":{"kolay":[{"q":"Bağ enerjisi nedir?","steps":[{"t":"Tanım","a":"koparma enerjisi","d":"Bağ enerjisi, bir kimyasal bağı koparmak için gereken enerjidir."},{"t":"Birim","a":"kJ/mol","d":"Genellikle 1 mol bağ için kJ/mol cinsinden verilir."}],"ans":"Bağ enerjisi, bir bağı koparmak için gereken enerjidir; birimi kJ/mol'dür."},{"q":"Bir bağ koparken enerji girer mi çıkar mı?","steps":[{"t":"Kopma","a":"enerji emer","d":"Bağ kırılması enerji gerektirir, dışarıdan enerji emilir (endotermik)."},{"t":"Oluşma","a":"enerji verir","d":"Bağ oluşunca enerji açığa çıkar (ekzotermik)."}],"ans":"Bağ koparken enerji emilir; bağ oluşurken enerji açığa çıkar."},{"q":"Tek, çift ve üçlü bağdan hangisi en güçlüdür?","fig":"<svg viewBox='0 0 320 170'><circle cx='70' cy='60' r='16' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='130' cy='60' r='16' fill='#cfd8e8' stroke='#1a2b45'/><line x1='86' y1='60' x2='114' y2='60' stroke='#1a2b45' stroke-width='2'/><text x='100' y='95' font-size='10' text-anchor='middle' fill='#1a2b45'>tek</text><circle cx='200' cy='60' r='16' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='260' cy='60' r='16' fill='#cfd8e8' stroke='#1a2b45'/><line x1='216' y1='54' x2='244' y2='54' stroke='#1a2b45' stroke-width='2'/><line x1='216' y1='66' x2='244' y2='66' stroke='#1a2b45' stroke-width='2'/><text x='230' y='95' font-size='10' text-anchor='middle' fill='#1a2b45'>çift</text></svg>","steps":[{"t":"Bağ sayısı","a":"artar güç artar","d":"Bağ sayısı arttıkça atomlar arası çekim güçlenir."},{"t":"Sıralama","a":"tek < çift < üçlü","d":"Bu yüzden en güçlü ve en yüksek enerjili bağ üçlü bağdır."}],"ans":"En güçlü bağ üçlü bağdır: tek < çift < üçlü sırasıyla güçlenir."},{"q":"Hangi tepkimeye ekzotermik (ısı veren) denir?","steps":[{"t":"Tanım","a":"ısı verir","d":"Çevreye ısı veren tepkimeye ekzotermik denir."},{"t":"Bağ enerjisi","a":"oluşan > kırılan","d":"Oluşan bağların enerjisi kırılanlardan fazlaysa fazla enerji ısı olarak çıkar."}],"ans":"Ekzotermik tepkime çevreye ısı verir; oluşan bağ enerjisi kırılandan fazladır."},{"q":"Yanma (örneğin odunun yanması) neden enerji açığa çıkarır?","steps":[{"t":"Bağlar kırılır","a":"enerji emilir","d":"Önce yakıttaki ve oksijendeki bağlar kırılır, bu enerji ister."},{"t":"Yeni bağlar","a":"çok enerji çıkar","d":"Oluşan yeni bağlar (CO₂, H₂O) daha çok enerji saldığından net enerji açığa çıkar."}],"ans":"Yanmada oluşan bağlar kırılanlardan çok enerji saldığı için ısı açığa çıkar."}],"zor":[{"q":"N₂ molekülünün çok kararlı olması bağ enerjisiyle nasıl açıklanır?","steps":[{"t":"Üçlü bağ","a":"N≡N","d":"Azot molekülünde iki atom arasında üçlü bağ vardır."},{"t":"Yüksek enerji","a":"~945 kJ/mol","d":"Üçlü bağ çok güçlü ve yüksek enerjili olduğundan kırmak çok zordur."},{"t":"Sonuç","a":"kararlı","d":"Kırılması zor olduğu için N₂ kimyasal olarak çok kararlıdır."}],"ans":"N₂'deki güçlü üçlü bağı (~945 kJ/mol) kırmak zor olduğundan molekül çok kararlıdır."},{"q":"Bir tepkimede 600 kJ bağ kırılıp 800 kJ bağ oluşuyorsa tepkime ekzotermik mi endotermik mi olur?","steps":[{"t":"Kural","a":"karşılaştır","d":"Oluşan bağ enerjisi kırılandan büyükse tepkime ekzotermiktir."},{"t":"Karşılaştırma","a":"800 > 600","d":"Oluşan 800 kJ, kırılan 600 kJ'den büyük olduğundan fazla enerji açığa çıkar."},{"t":"Sonuç","a":"ekzotermik","d":"Net 200 kJ enerji çevreye verilir, tepkime ekzotermiktir."}],"ans":"Oluşan (800 kJ) kırılandan (600 kJ) büyük olduğundan tepkime ekzotermiktir, 200 kJ açığa çıkar."},{"q":"Bağ enerjisi neden 'bir bağı koparma enerjisi' ile 'bağ oluşurken çıkan enerji' için aynı sayıdır?","steps":[{"t":"Aynı bağ","a":"aynı kuvvet","d":"Bir bağı kırmak ve oluşturmak aynı atomlar arası çekimi içerir."},{"t":"Enerji korunumu","a":"zıt işaret","d":"Kırarken emilen enerji ile oluşurken salınan enerji eşit büyüklükte, ters işaretlidir."}],"ans":"Aynı bağ olduğundan kırma ve oluşma enerjileri eşit büyüklüktedir, yalnızca işaretleri terstir."},{"q":"H₂ + Cl₂ → 2HCl tepkimesinde toplam kaç mol bağ kırılır, kaç mol bağ oluşur?","steps":[{"t":"Kırılan","a":"1 H–H + 1 Cl–Cl","d":"1 mol H–H ve 1 mol Cl–Cl bağı kırılır, toplam 2 mol bağ."},{"t":"Oluşan","a":"2 H–Cl","d":"2 mol HCl oluştuğundan 2 mol H–Cl bağı kurulur."},{"t":"Karşılaştırma","a":"net enerji","d":"Oluşan H–Cl bağları daha güçlü olduğundan tepkime ekzotermiktir."}],"ans":"2 mol bağ (H–H ve Cl–Cl) kırılır, 2 mol H–Cl bağı oluşur; tepkime ekzotermiktir."},{"q":"Soğuk paketlerde (instant cold pack) çözünme endotermik olur; bağ/etkileşim enerjisiyle ilişkilendirin.","steps":[{"t":"Bağ kopması","a":"enerji emer","d":"Tuz çözünürken iyonlar arası çekimleri kırmak enerji gerektirir."},{"t":"Yeni etkileşim","a":"daha az enerji","d":"Oluşan iyon-su etkileşimleri daha az enerji saldığında net enerji emilir."},{"t":"Sonuç","a":"endotermik","d":"Sistem ortamdan ısı çektiği için paket soğur."}],"ans":"Kırılan etkileşimler oluşandan fazla enerji gerektirdiğinden çözünme endotermiktir ve ortam soğur."}]},"lise":{"kolay":[{"q":"Bağ enerjisinin (bağ ayrışma enerjisi) tanımı nedir?","steps":[{"t":"Tanım","a":"homolitik koparma","d":"Gaz fazında 1 mol bağı atomlarına ayırmak için gereken enerjidir."},{"t":"İşaret","a":"pozitif","d":"Bağ kırma endotermik olduğundan bu enerji pozitif değerlidir (kJ/mol)."}],"ans":"Bağ enerjisi, gaz fazında 1 mol bağı koparmak için gereken (pozitif) enerjidir."},{"q":"ΔH'ı bağ enerjilerinden hesaplayan formül nedir?","steps":[{"t":"Formül","a":"ΔH = Σkırılan − Σoluşan","d":"Tepkime ısısı, kırılan bağların enerjileri toplamından oluşan bağların enerjileri toplamı çıkarılarak bulunur."},{"t":"Yorum","a":"işaret","d":"Sonuç negatifse ekzotermik, pozitifse endotermiktir."}],"ans":"ΔH = Σ(kırılan bağ enerjileri) − Σ(oluşan bağ enerjileri)."},{"q":"C–C, C=C ve C≡C bağlarının enerjileri nasıl sıralanır?","steps":[{"t":"Bağ derecesi","a":"artar güç artar","d":"Bağ derecesi (sayısı) arttıkça bağ enerjisi büyür."},{"t":"Sıralama","a":"tek<çift<üçlü","d":"C–C ≈ 348, C=C ≈ 614, C≡C ≈ 839 kJ/mol şeklinde artar."}],"ans":"C–C < C=C < C≡C; bağ derecesi arttıkça bağ enerjisi büyür."},{"q":"Bağ enerjileri tablo değerleri neden 'ortalama' olarak verilir?","steps":[{"t":"Ortam etkisi","a":"komşu atomlar","d":"Aynı bağ türü farklı moleküllerde komşu gruplara göre biraz değişir."},{"t":"Ortalama","a":"yaklaşık","d":"Bu yüzden tablolar çok molekülün ortalamasını verir; hesaplar yaklaşık olur."}],"ans":"Aynı bağ molekülden moleküle biraz değiştiği için tablo değerleri ortalamadır, sonuçlar yaklaşıktır."},{"q":"Bağ uzunluğu ile bağ enerjisi arasındaki genel ilişki nedir?","steps":[{"t":"Kısa bağ","a":"güçlü","d":"Genelde bağ kısaldıkça atomlar daha sıkı çekilir."},{"t":"İlişki","a":"ters orantı","d":"Bu yüzden kısa bağlar genellikle yüksek bağ enerjili (güçlü) olur."}],"ans":"Genellikle bağ kısaldıkça bağ enerjisi artar; bağ uzunluğu ile enerji ters yönlüdür."},{"q":"Bir tepkimede ΔH = −200 kJ/mol bulunduysa bu ne anlama gelir?","steps":[{"t":"İşaret","a":"negatif","d":"ΔH negatif olduğundan sistem enerji kaybeder."},{"t":"Yorum","a":"ekzotermik","d":"Oluşan bağlar kırılanlardan güçlüdür; çevreye 200 kJ ısı verilir."}],"ans":"ΔH = −200 kJ/mol, tepkimenin ekzotermik olduğunu ve 200 kJ ısı verdiğini gösterir."},{"q":"Bağ enerjisi ile bağ oluşum entalpisinin işareti nasıl ilişkilidir?","steps":[{"t":"Kırma","a":"+ değer","d":"Bağ kırmak endotermiktir, enerji girer (+)."},{"t":"Oluşma","a":"− değer","d":"Aynı bağın oluşması ekzotermiktir; eşit büyüklükte ama negatif (−) işaretlidir."}],"ans":"Bağ kırma enerjisi pozitif, aynı bağın oluşumu eşit büyüklükte negatiftir."},{"q":"Neden çok bağın kırıldığı tepkimeler ilk anda enerji girişi (aktivasyon) gerektirir?","steps":[{"t":"Önce kırılma","a":"enerji emilir","d":"Tepkime başlarken mevcut bağların kırılması için enerji gerekir."},{"t":"Aktivasyon","a":"eşik enerji","d":"Bu başlangıç enerjisi aktivasyon enerjisidir; ekzotermik tepkime bile bunu aşmalıdır."}],"ans":"Bağ kırma enerji gerektirdiği için tepkimeler önce aktivasyon enerjisi eşiğini aşmalıdır."},{"q":"Bağ enerjilerinden hesaplanan ΔH ile gerçek (deneysel) ΔH arasında neden küçük fark olabilir?","steps":[{"t":"Ortalama değer","a":"yaklaşık","d":"Bağ enerjileri ortalama değerler olduğundan hesap yaklaşıktır."},{"t":"Hal etkisi","a":"gaz varsayımı","d":"Bağ enerjisi yöntemi gaz fazını varsayar; hal değişimi enerjileri ihmal edilir."}],"ans":"Ortalama bağ değerleri ve gaz fazı varsayımı nedeniyle hesaplanan ΔH gerçeğinden biraz sapabilir."},{"q":"Bir bağın daha güçlü olması, içerdiği moleküllerin tepkimeye girme isteğini nasıl etkiler?","steps":[{"t":"Güçlü bağ","a":"kırması zor","d":"Güçlü bağ yüksek enerji gerektirdiğinden kolay kırılmaz."},{"t":"Sonuç","a":"daha kararlı","d":"Bu molekül kimyasal olarak daha kararlı ve daha az reaktiftir."}],"ans":"Güçlü bağlı moleküller daha kararlı ve genelde daha az reaktiftir."}],"zor":[{"q":"CH₄ + 2O₂ → CO₂ + 2H₂O tepkimesinin ΔH'ını bağ enerjileriyle hesaplayın (C–H=413, O=O=498, C=O=799, O–H=463 kJ/mol).","fig":"<svg viewBox='0 0 320 150'><text x='20' y='60' font-size='13' fill='#1a2b45'>CH₄ + 2O₂</text><line x1='130' y1='55' x2='180' y2='55' stroke='#1a2b45' stroke-width='2'/><polygon points='180,55 172,51 172,59' fill='#1a2b45'/><text x='195' y='60' font-size='13' fill='#1a2b45'>CO₂ + 2H₂O</text><text x='160' y='120' font-size='11' text-anchor='middle' fill='#1a2b45'>ekzotermik yanma</text></svg>","steps":[{"t":"Kırılan","a":"4 C–H + 2 O=O","d":"4×413 + 2×498 = 1652 + 996 = 2648 kJ kırılan bağ enerjisi."},{"t":"Oluşan","a":"2 C=O + 4 O–H","d":"CO₂'de 2 C=O ve 2 H₂O'da 4 O–H: 2×799 + 4×463 = 1598 + 1852 = 3450 kJ."},{"t":"ΔH","a":"2648 − 3450 = −802","d":"ΔH = Σkırılan − Σoluşan = 2648 − 3450 = −802 kJ/mol."}],"ans":"ΔH = −802 kJ/mol; tepkime ekzotermiktir (oluşan bağlar daha güçlü)."},{"q":"H₂ + Cl₂ → 2HCl için ΔH'ı hesaplayın (H–H=436, Cl–Cl=242, H–Cl=431 kJ/mol).","steps":[{"t":"Kırılan","a":"H–H + Cl–Cl","d":"1×436 + 1×242 = 678 kJ kırılan bağ enerjisi."},{"t":"Oluşan","a":"2 H–Cl","d":"2 mol H–Cl oluşur: 2×431 = 862 kJ açığa çıkar."},{"t":"ΔH","a":"678 − 862 = −184","d":"ΔH = 678 − 862 = −184 kJ/mol, ekzotermik."}],"ans":"ΔH = −184 kJ/mol; tepkime ekzotermiktir."},{"q":"N₂ + 3H₂ ⇌ 2NH₃ tepkimesinin ΔH'ını bulun (N≡N=945, H–H=436, N–H=391 kJ/mol).","steps":[{"t":"Kırılan","a":"N≡N + 3 H–H","d":"1×945 + 3×436 = 945 + 1308 = 2253 kJ kırılan."},{"t":"Oluşan","a":"6 N–H","d":"2 NH₃'te toplam 6 N–H bağı: 6×391 = 2346 kJ oluşan."},{"t":"ΔH","a":"2253 − 2346 = −93","d":"ΔH = 2253 − 2346 = −93 kJ/mol; ekzotermik (ısı verir)."}],"ans":"ΔH = −93 kJ/mol; amonyak sentezi ekzotermiktir."},{"q":"2H₂ + O₂ → 2H₂O tepkimesinin ΔH'ını hesaplayın (H–H=436, O=O=498, O–H=463 kJ/mol).","steps":[{"t":"Kırılan","a":"2 H–H + O=O","d":"2×436 + 1×498 = 872 + 498 = 1370 kJ kırılan bağ enerjisi."},{"t":"Oluşan","a":"4 O–H","d":"2 H₂O'da toplam 4 O–H bağı: 4×463 = 1852 kJ oluşan."},{"t":"ΔH","a":"1370 − 1852 = −482","d":"ΔH = 1370 − 1852 = −482 kJ/mol; güçlü ekzotermik tepkime."}],"ans":"ΔH = −482 kJ/mol; su oluşumu güçlü ekzotermik bir tepkimedir."},{"q":"Bir tepkimede Σkırılan = 1500 kJ, Σoluşan = 1500 kJ ise ΔH kaçtır ve bu enerji açısından ne anlama gelir?","steps":[{"t":"ΔH","a":"1500 − 1500 = 0","d":"ΔH = Σkırılan − Σoluşan = 0 kJ/mol bulunur."},{"t":"Yorum","a":"ısı alışverişi ~yok","d":"Net bağ enerjisi değişmediğinden tepkime termonötrale yakındır."},{"t":"Not","a":"yön entropiyle","d":"Bu durumda tepkimenin yönü daha çok entropi (ΔS) tarafından belirlenir."}],"ans":"ΔH = 0 kJ/mol; bağ enerjisi açısından net ısı alışverişi yoktur (termonötrale yakın)."},{"q":"C₂H₄ + H₂ → C₂H₆ (eten hidrojenasyonu) için ΔH'ı hesaplayın (C=C=614, C–C=348, H–H=436, C–H=413 kJ/mol).","steps":[{"t":"Kırılan","a":"C=C + H–H","d":"Etende 1 C=C kısmen kırılıp tek bağa iner ve H–H kırılır: değişen bağlar 1 C=C(614) ve 1 H–H(436) = 1050 kJ; ayrıca yeni 2 C–H için H atomları kullanılır."},{"t":"Oluşan","a":"C–C + 2 C–H","d":"C=C tek bağa dönüşür (1 C–C=348) ve 2 yeni C–H bağı oluşur (2×413=826): toplam 1174 kJ."},{"t":"ΔH","a":"1050 − 1174 = −124","d":"ΔH = 1050 − 1174 = −124 kJ/mol; ekzotermik."}],"ans":"ΔH = −124 kJ/mol; eten hidrojenasyonu ekzotermiktir."},{"q":"Bağ enerjisi yöntemiyle hesaplanan ΔH neden yalnızca gaz fazı tepkimeleri için doğrudan geçerlidir?","steps":[{"t":"Yöntemin temeli","a":"gaz molekülleri","d":"Bağ enerjileri, gaz fazında bağ koparma için tanımlanır."},{"t":"Hal değişimi","a":"ek enerji","d":"Sıvı/katı haller, hal değişimi (buharlaşma, erime) entalpilerini içerir; bu yöntem onları kapsamaz."},{"t":"Düzeltme","a":"hal terimleri","d":"Doğru sonuç için hal değişimi entalpileri ayrıca eklenmelidir."}],"ans":"Bağ enerjileri gaz fazı için tanımlandığından, sıvı/katı haller için hal değişimi entalpileri ayrıca hesaba katılmalıdır."},{"q":"Hess yasası ile bağ enerjisi yöntemi aynı ΔH'ı vermelidir; aralarındaki kavramsal fark nedir?","steps":[{"t":"Bağ enerjisi","a":"ortalama bağ","d":"Bağ enerjisi yöntemi ortalama bağ değerleriyle yaklaşık ΔH verir."},{"t":"Hess yasası","a":"oluşum entalpileri","d":"Hess yasası, ölçülmüş oluşum/tepkime entalpilerini toplayarak kesin sonuç verir."},{"t":"Sonuç","a":"yaklaşık ≈ kesin","d":"Her ikisi de entalpinin yol bağımsızlığına dayanır; bağ enerjisi yaklaşık, Hess daha kesindir."}],"ans":"İkisi de entalpinin yola bağlı olmamasına dayanır; bağ enerjisi ortalamalarla yaklaşık, Hess ölçülmüş değerlerle kesin sonuç verir."},{"q":"Bir tepkime hem çok güçlü bağlar kırıp hem çok güçlü bağlar oluşturuyorsa ΔH'ın büyüklüğü neye bağlıdır?","steps":[{"t":"Tek başına güç","a":"belirleyici değil","d":"Mutlak bağ güçleri değil, kırılan ile oluşan toplamlar arasındaki FARK önemlidir."},{"t":"Fark","a":"ΔH = fark","d":"ΔH yalnızca Σkırılan − Σoluşan farkına eşittir."},{"t":"Sonuç","a":"küçük fark→küçük ΔH","d":"İki toplam birbirine yakınsa güçlü bağlar olsa bile ΔH küçük olur."}],"ans":"ΔH'ın büyüklüğü tek bağların gücüne değil, kırılan ve oluşan bağ enerjisi toplamları arasındaki farka bağlıdır."},{"q":"Patlayıcıların çok hızlı ve yüksek enerji açığa çıkarmasını bağ enerjisi ve gaz oluşumu ile açıklayın.","steps":[{"t":"Zayıf bağlar kırılır","a":"az enerji","d":"Patlayıcılarda zayıf/kararsız bağlar kolayca kırılır, az enerji ister."},{"t":"Çok güçlü bağ oluşur","a":"N₂, CO₂","d":"Ürünlerde çok güçlü N≡N ve C=O bağları oluşur, büyük enerji açığa çıkar."},{"t":"Gaz genleşmesi","a":"hızlı hacim","d":"Aniden çok mol gaz oluşması büyük hacim artışıyla patlamayı yaratır."}],"ans":"Zayıf bağların kırılıp çok güçlü N₂/CO₂ bağlarının oluşması büyük negatif ΔH verir; ani gaz genleşmesi patlamayı doğurur."}]}},"buzGenlesme":{"ilkokul":{"kolay":[{"q":"Suyu buzluğa koyup dondurduğumuzda kabın içinde ne olur?","steps":[{"t":"Su donar","a":"buz olur","d":"Buzluktaki soğuk, sıvı suyu katı buza çevirir."},{"t":"Yer kaplar","a":"şişer","d":"Buz, sudan biraz daha fazla yer kapladığı için kabın içinde kabarır."}],"ans":"Su donunca buza döner ve eskisinden biraz daha fazla yer kaplar (şişer)."},{"q":"Bir bardak suyu ağzına kadar doldurup dondurursak ne görürüz?","steps":[{"t":"Su donar","a":"buz olur","d":"Bardaktaki su soğuyunca katı buz hâline gelir."},{"t":"Taşar/kabarır","a":"yukarı çıkar","d":"Buz daha çok yer kapladığı için bardağın üstünden taşıp kabarır."}],"ans":"Donan su şiştiği için bardağın ağzından yukarı doğru kabarır."},{"q":"Buz parçası bir bardak suya atıldığında ne yapar?","fig":"<svg viewBox='0 0 320 180'><rect x='90' y='40' width='140' height='110' fill='none' stroke='#1a2b45'/><rect x='92' y='80' width='136' height='68' fill='#cfe3f5'/><rect x='130' y='62' width='40' height='30' fill='#eaf4fc' stroke='#2b6be0'/><text x='160' y='168' font-size='12' text-anchor='middle' fill='#1a2b45'>buz suda yüzer</text></svg>","steps":[{"t":"Suya atılır","a":"batmaz","d":"Buz parçası suyun dibine inmez, üstte kalır."},{"t":"Yüzer","a":"hafif olduğu için","d":"Buz, sudan daha hafif olduğu için suyun üstünde yüzer."}],"ans":"Buz, sudan hafif olduğu için suya atınca batmaz, üstte yüzer."},{"q":"Kışın çok soğukta su borusu neden patlayabilir?","steps":[{"t":"Su donar","a":"buz olur","d":"Borunun içindeki su soğukta donar."},{"t":"Şişer","a":"boruyu zorlar","d":"Donan su şişip yer kaplayınca boruyu içeriden zorlar ve patlatabilir."}],"ans":"Borudaki su donunca şişer ve boruyu zorlayarak patlatabilir."},{"q":"Buzdolabında dondurduğumuz su şişesini neden ağzına kadar doldurmamalıyız?","steps":[{"t":"Su donar","a":"buz olur","d":"Şişedeki su donunca buza döner."},{"t":"Yer kaplar","a":"şişeyi şişirir","d":"Buz daha çok yer kapladığı için tam dolu şişeyi şişirip patlatabilir."}],"ans":"Donan su şiştiği için tam dolu şişe çatlayabilir; bu yüzden biraz boşluk bırakırız."}],"zor":[{"q":"Kışın göl yüzeyi buz tutarken altındaki su neden hâlâ sıvı kalır?","steps":[{"t":"Buz hafiftir","a":"üstte kalır","d":"Donan su hafiflediği için buz gölün üstünde yüzer."},{"t":"Alt korunur","a":"su sıvı kalır","d":"Üstteki buz tabakası örtü gibi davranıp alttaki suyun daha fazla soğumasını yavaşlatır."}],"ans":"Buz üstte yüzüp örtü oluşturduğu için göl dibindeki su sıvı kalabilir."},{"q":"Balıklar kışın buz tutan gölde nasıl yaşamaya devam edebilir?","steps":[{"t":"Buz üstte","a":"yüzer","d":"Buz sudan hafif olduğu için gölün üst kısmını kaplar."},{"t":"Alt su sıvı","a":"yaşam sürer","d":"Buzun altındaki su donmadan sıvı kalır, balıklar burada yaşayabilir."}],"ans":"Buz üstte kaldığı için altındaki su donmaz; balıklar bu sıvı suda yaşar."},{"q":"Aynı miktar su ile aynı miktar buzdan hangisi daha çok yer kaplar?","fig":"<svg viewBox='0 0 320 180'><rect x='60' y='70' width='70' height='80' fill='#cfe3f5' stroke='#1a2b45'/><text x='95' y='168' font-size='12' text-anchor='middle' fill='#1a2b45'>su</text><rect x='200' y='50' width='70' height='100' fill='#eaf4fc' stroke='#2b6be0'/><text x='235' y='168' font-size='12' text-anchor='middle' fill='#1a2b45'>buz</text></svg>","steps":[{"t":"Su donar","a":"buz olur","d":"Su donduğunda buza dönüşür."},{"t":"Hacim artar","a":"buz büyür","d":"Aynı kütledeki buz, sudan daha fazla yer kapladığı için daha büyüktür."}],"ans":"Aynı kütlede buz, sudan daha çok yer kaplar."},{"q":"Bir göl, dipten yukarı doğru değil de üstten aşağı doğru donsaydı canlılar için ne olurdu?","steps":[{"t":"Normal durum","a":"üstten donar","d":"Gerçekte buz üstte yüzer, alt su sıvı kalır ve canlılar korunur."},{"t":"Tersi olsaydı","a":"dip donardı","d":"Buz dibe çökseydi göl tabandan tepeye kadar tamamen donardı."}],"ans":"Göl tümüyle donar, dipteki canlılar yaşayacak sıvı su bulamazdı."},{"q":"Kayalardaki çatlaklara dolan su kışın kayayı nasıl parçalar?","steps":[{"t":"Su dolar","a":"çatlağa girer","d":"Yağmur veya kar suyu kayanın çatlaklarına dolar."},{"t":"Donup şişer","a":"kayayı çatlatır","d":"Donan su şişip çatlağı içeriden zorlar ve kayayı zamanla parçalar."}],"ans":"Çatlağa dolan su donup şişerek kayayı içeriden zorlar ve parçalar."}]},"ortaokul":{"kolay":[{"q":"Su donduğunda yoğunluğu neden azalır?","steps":[{"t":"Hacim artar","a":"buz şişer","d":"Su donunca molekülleri daha geniş yerleşir, hacmi artar."},{"t":"Yoğunluk düşer","a":"d = kütle/hacim","d":"Kütle aynı kalıp hacim arttığı için yoğunluk (kütle/hacim) azalır."}],"ans":"Su donunca hacmi arttığı için yoğunluğu azalır."},{"q":"Buzun suda yüzmesinin temel nedeni nedir?","fig":"<svg viewBox='0 0 320 180'><rect x='80' y='50' width='160' height='110' fill='none' stroke='#1a2b45'/><rect x='82' y='90' width='156' height='68' fill='#cfe3f5'/><rect x='130' y='70' width='44' height='32' fill='#eaf4fc' stroke='#2b6be0'/><text x='160' y='175' font-size='11' text-anchor='middle' fill='#1a2b45'>buz: daha az yoğun</text></svg>","steps":[{"t":"Yoğunluk farkı","a":"buz < su","d":"Buzun yoğunluğu sıvı sudan daha düşüktür."},{"t":"Yüzme","a":"hafif üstte kalır","d":"Daha az yoğun cisim daha yoğun sıvının üstünde yüzer."}],"ans":"Buz sudan daha az yoğun olduğu için suyun üstünde yüzer."},{"q":"Suyun en yoğun olduğu sıcaklık kaç derecedir?","steps":[{"t":"Anomali","a":"+4 °C","d":"Su 4 °C'de en küçük hacme, dolayısıyla en yüksek yoğunluğa ulaşır."},{"t":"Daha soğuk","a":"genleşir","d":"4 °C'den daha soğutulunca su yeniden genleşir, donunca iyice şişer."}],"ans":"Su, +4 °C'de en yoğundur; bundan daha soğukta genleşmeye başlar."},{"q":"Buzun yapısında moleküller suya göre nasıl dizilir?","steps":[{"t":"Buz örgüsü","a":"düzenli açık","d":"Buzda su molekülleri düzenli, boşluklu bir kafes (örgü) oluşturur."},{"t":"Sonuç","a":"hacim artar","d":"Bu açık örgü, sıvı sudan daha fazla yer kapladığı için hacim artar."}],"ans":"Buzda moleküller düzenli ve boşluklu dizilir, bu yüzden hacim artar."},{"q":"Göllerin üstten donması canlılar için neden önemlidir?","steps":[{"t":"Buz yüzer","a":"üstte tabaka","d":"Buz sudan hafif olduğu için göl yüzeyinde tabaka oluşturur."},{"t":"Yalıtım","a":"alt sıvı kalır","d":"Bu buz tabakası ısı yalıtımı yapar, alttaki suyun donmasını yavaşlatır."}],"ans":"Üstte yüzen buz yalıtım yapar, alttaki su sıvı kalır ve canlılar korunur."}],"zor":[{"q":"Suyun yoğunluk anomalisi hidrojen bağlarıyla nasıl açıklanır?","steps":[{"t":"Hidrojen bağı","a":"molekülleri bağlar","d":"Su molekülleri arasında çekici hidrojen bağları kurulur."},{"t":"Donunca","a":"açık örgü","d":"Donarken her molekül 4 komşusuyla bağ kurup düzenli, boşluklu bir örgü oluşturur."},{"t":"Sonuç","a":"hacim artar","d":"Bu boşluklu yerleşim hacmi büyütür, yoğunluğu düşürür."}],"ans":"Donunca hidrojen bağları boşluklu açık örgü kurar; hacim artar, yoğunluk azalır."},{"q":"Su 4 °C'den 0 °C'ye soğutulurken hacmi nasıl değişir, neden?","steps":[{"t":"4 °C","a":"en küçük hacim","d":"Su 4 °C'de en yoğundur, yani hacmi en küçüktür."},{"t":"Soğutma","a":"hacim büyür","d":"4 °C'nin altında hidrojen bağları açık örgü kurmaya başlar, hacim genişler."},{"t":"Donma","a":"ani sıçrama","d":"0 °C'de tam buz örgüsü kurulunca hacim daha da artar."}],"ans":"4 °C'den 0 °C'ye soğurken su genleşir; açık örgü kurulduğu için hacmi büyür."},{"q":"Eşit kütledeki su 0 °C'de donunca hacmi yaklaşık nasıl değişir, yoğunluğa etkisi nedir?","steps":[{"t":"Su yoğunluğu","a":"~1 g/cm³","d":"Sıvı suyun yoğunluğu yaklaşık 1 g/cm³'tür."},{"t":"Buz yoğunluğu","a":"~0,92 g/cm³","d":"Buzun yoğunluğu yaklaşık 0,92 g/cm³'e düşer, hacim yaklaşık %9 artar."},{"t":"Sonuç","a":"buz yüzer","d":"Yoğunluk azaldığı için buz suyun üstünde yüzer."}],"ans":"Donunca hacim yaklaşık %9 artar, yoğunluk ~1'den ~0,92 g/cm³'e düşer; buz yüzer."},{"q":"Bir buz dağının (aysberg) yalnızca küçük bir kısmının su üstünde görünmesini açıklayın.","fig":"<svg viewBox='0 0 320 180'><line x1='20' y1='95' x2='300' y2='95' stroke='#2b6be0'/><rect x='20' y='95' width='280' height='75' fill='#cfe3f5'/><polygon points='130,55 175,95 100,95' fill='#eaf4fc' stroke='#1a2b45'/><polygon points='100,95 175,95 195,150 90,150' fill='#dcebf7' stroke='#1a2b45'/><text x='160' y='168' font-size='10' text-anchor='middle' fill='#1a2b45'>büyük kısım su altında</text></svg>","steps":[{"t":"Yoğunluk oranı","a":"0,92/1,00","d":"Buzun yoğunluğu suyun yaklaşık %92'sidir."},{"t":"Yüzme dengesi","a":"batan = ~%92","d":"Cismin ağırlığını taşıyacak kadarı suya batar, bu da hacmin yaklaşık %92'sidir."},{"t":"Görünen","a":"~%8","d":"Geriye yalnızca yaklaşık %8'lik bir tepe kısmı su üstünde kalır."}],"ans":"Buz suyun ~%92'si kadar yoğun olduğundan hacminin ~%92'si batar, yalnızca ~%8'i görünür."},{"q":"Suyun yoğunluk anomalisi olmasaydı kutup denizleri ve yaşam nasıl etkilenirdi?","steps":[{"t":"Buz batardı","a":"dipten donma","d":"Buz sudan yoğun olsaydı oluştuğu anda dibe çökerdi."},{"t":"Tüm su donardı","a":"kalıcı buz","d":"Üstte yalıtım tabakası olmayınca deniz tabandan yukarı tamamen donabilirdi."},{"t":"Yaşam zorlanır","a":"sıvı su yok","d":"Sıvı su kalmayınca su canlıları yaşam ortamı bulamazdı."}],"ans":"Anomali olmasa buz dibe çöker, sular tümüyle donar ve su yaşamı büyük zarar görürdü."}]},"lise":{"kolay":[{"q":"Suyun yoğunluk anomalisinde anahtar moleküller arası kuvvet nedir?","steps":[{"t":"Polar molekül","a":"O kısmen eksi","d":"Su polar bir moleküldür; O ucu kısmen (−), H uçları kısmen (+) yüklüdür."},{"t":"Hidrojen bağı","a":"O···H","d":"Bir molekülün O'su, komşunun H'siyle hidrojen bağı kurar; anomalinin nedeni budur."}],"ans":"Anomalinin nedeni su molekülleri arasındaki hidrojen bağlarıdır."},{"q":"Buz örgüsünde her su molekülü kaç hidrojen bağıyla çevrelenir?","steps":[{"t":"Tetrahedral","a":"4 komşu","d":"Buzda her su molekülü dört komşu molekülle hidrojen bağı kurar."},{"t":"Açık yapı","a":"boşluklu örgü","d":"Bu dörtyüzlü düzen boşluklu, açık bir kristal örgü oluşturur."}],"ans":"Buzda her su molekülü 4 hidrojen bağıyla dörtyüzlü, açık bir örgü kurar."},{"q":"Buzun yoğunluğunun sudan düşük olması niceliksel olarak ne kadardır?","steps":[{"t":"Su","a":"1,00 g/cm³","d":"Sıvı suyun yoğunluğu 4 °C'de yaklaşık 1,00 g/cm³'tür."},{"t":"Buz","a":"0,917 g/cm³","d":"0 °C buzunun yoğunluğu yaklaşık 0,917 g/cm³'tür."}],"ans":"Buzun yoğunluğu (~0,917 g/cm³) suyunkinden (~1,00 g/cm³) düşüktür."},{"q":"Sıvı suda hidrojen bağları buzdakine göre nasıl bir düzendedir?","steps":[{"t":"Sıvı su","a":"düzensiz","d":"Sıvı suda hidrojen bağları sürekli kurulup kopar, düzensizdir."},{"t":"Daha sıkı","a":"boşluk az","d":"Düzensiz yerleşim molekülleri daha sıkı paketler, hacim küçük olur."}],"ans":"Sıvı suda hidrojen bağları düzensizdir ve moleküller daha sıkı paketlendiğinden hacim küçüktür."},{"q":"Suyun en yüksek yoğunluğa ulaştığı +4 °C neyi temsil eder?","steps":[{"t":"İki etki","a":"yarışır","d":"Soğuma molekülleri yaklaştırır; ancak açık örgü eğilimi onları uzaklaştırır."},{"t":"Denge","a":"+4 °C","d":"Bu iki etkinin dengelendiği noktada hacim en küçük, yoğunluk en yüksektir."}],"ans":"+4 °C, büzülme ile açık örgü oluşumunun dengelendiği en yoğun noktadır."},{"q":"Göllerde +4 °C'lik su neden dibe çöker?","steps":[{"t":"En yoğun","a":"+4 °C suyu","d":"Su +4 °C'de en yüksek yoğunluğa sahiptir."},{"t":"Çökme","a":"dibe iner","d":"En yoğun su olduğu için göl tabanına yerleşir; daha soğuk su üstte kalır."}],"ans":"+4 °C'deki su en yoğun olduğundan göl dibine çöker, daha soğuk su üstte kalır."},{"q":"Buzun erime sırasında hacmi nasıl değişir?","steps":[{"t":"Örgü çöker","a":"bağlar kısmen kopar","d":"Buz erirken açık hidrojen bağı örgüsünün bir kısmı bozulur."},{"t":"Hacim azalır","a":"su sıkışır","d":"Moleküller boşlukları doldurarak daha sıkı yerleşir, hacim küçülür."}],"ans":"Buz erirken açık örgü çöker, moleküller sıkışır ve hacim azalır."},{"q":"Yoğunluk anomalisi 'kolligatif' bir özellik midir, yoksa yapısal mı?","steps":[{"t":"Yapısal neden","a":"hidrojen bağı","d":"Anomali, su molekülünün geometrisi ve hidrojen bağı örgüsünden kaynaklanır."},{"t":"Sonuç","a":"yapısal","d":"Tanecik sayısına değil, yapıya bağlı olduğu için yapısal bir özelliktir."}],"ans":"Yoğunluk anomalisi, hidrojen bağı örgüsünden gelen yapısal bir özelliktir."},{"q":"Buzun su üstünde yüzmesini Arşimet ilkesiyle nasıl ifade ederiz?","steps":[{"t":"Kaldırma kuvveti","a":"taşan suyun ağırlığı","d":"Buza etkiyen kaldırma kuvveti, taşırdığı suyun ağırlığına eşittir."},{"t":"Denge","a":"buz < su yoğunluğu","d":"Buzun yoğunluğu düşük olduğundan, ağırlığını taşıyacak kaldırma kuvvetine hacmin bir kısmı batınca ulaşılır ve buz yüzer."}],"ans":"Buz daha az yoğun olduğu için hacminin bir kısmı battığında kaldırma kuvveti ağırlığını dengeler ve yüzer."},{"q":"Suyun anomalisi, gezegende sıcaklık dengelemesine nasıl katkı yapar?","steps":[{"t":"Buz yalıtımı","a":"üstte tabaka","d":"Yüzeyde oluşan buz, alttaki suyu soğuktan yalıtır."},{"t":"Sıvı su korunur","a":"ısı deposu","d":"Korunan büyük su kütlesi ısıyı depolayıp salarak iklimi dengeler."}],"ans":"Yüzen buz suyu yalıtır, korunan büyük su kütlesi ısı deposu olarak iklimi dengeler."}],"zor":[{"q":"Buzdaki tetrahedral hidrojen bağı örgüsü, sıvı sudan daha düşük yoğunluğu moleküler düzeyde nasıl doğurur?","steps":[{"t":"Geometri","a":"104,5° açı","d":"Su molekülü açısaldır; O üzerinde iki ortaklanmamış çift, iki O–H bağı vardır."},{"t":"Buz örgüsü","a":"4 yönlü bağ","d":"Her molekül 4 komşuyla dörtyüzlü hidrojen bağı kurarak büyük boşluklu bir kristal oluşturur."},{"t":"Sonuç","a":"hacim ↑, d ↓","d":"Boşluklu örgü birim hücrede daha az molekül barındırır; yoğunluk düşer."}],"ans":"Açısal molekülün 4 yönlü tetrahedral hidrojen bağı örgüsü boşluklu olduğundan buzun yoğunluğu düşer."},{"q":"Bir göl yüzeyi −10 °C havada donarken su sütununda sıcaklık ve yoğunluk dağılımı nasıl oluşur?","steps":[{"t":"Üst tabaka","a":"0 °C buz","d":"Yüzeyde 0 °C'de buz oluşur ve hafif olduğundan üstte kalır."},{"t":"Orta tabaka","a":"0–4 °C","d":"Buzun hemen altında 0 ile 4 °C arası soğuk su bulunur."},{"t":"Dip","a":"+4 °C en yoğun","d":"En yoğun +4 °C suyu dibe çökerek tabanda toplanır; canlılar burada yaşar."}],"ans":"Üstte buz, altında 0–4 °C su, dipte +4 °C en yoğun su; bu katmanlaşma dipteki yaşamı korur."},{"q":"100 g su 0 °C'de tamamen donduğunda hacim değişimini hesaplayın (ρ_su=1,00 g/cm³, ρ_buz=0,92 g/cm³).","steps":[{"t":"Su hacmi","a":"V = m/ρ = 100 cm³","d":"100 g ÷ 1,00 g/cm³ = 100 cm³ sıvı su hacmi bulunur."},{"t":"Buz hacmi","a":"100/0,92 ≈ 108,7 cm³","d":"Kütle korunur; 100 g ÷ 0,92 g/cm³ ≈ 108,7 cm³ buz hacmi olur."},{"t":"Değişim","a":"ΔV ≈ +8,7 cm³","d":"Hacim 100'den 108,7 cm³'e çıkar, yaklaşık %8,7 artar."}],"ans":"Hacim ~100 cm³'ten ~108,7 cm³'e çıkar; yaklaşık %8,7 artış olur."},{"q":"Yoğunluğu 0,917 g/cm³ olan buzun, yoğunluğu 1,00 g/cm³ olan tatlı suda hacminin yüzde kaçı su üstünde kalır?","steps":[{"t":"Yüzme dengesi","a":"batan kısım = ρ_buz/ρ_su","d":"Yüzen cisimde batan hacim oranı, cismin yoğunluğunun sıvı yoğunluğuna oranına eşittir."},{"t":"Batan oran","a":"0,917/1,00 = %91,7","d":"Hacmin yaklaşık %91,7'si suya batar."},{"t":"Üstte kalan","a":"%8,3","d":"100 − 91,7 = yaklaşık %8,3'lük kısım su üstünde görünür."}],"ans":"Hacmin yaklaşık %91,7'si batar, yaklaşık %8,3'ü su üstünde kalır."},{"q":"Aynı buz tatlı su yerine yoğunluğu 1,025 g/cm³ olan deniz suyunda yüzdürülürse görünen kısım nasıl değişir?","steps":[{"t":"Deniz suyu yoğun","a":"1,025 g/cm³","d":"Tuz nedeniyle deniz suyu tatlı sudan daha yoğundur."},{"t":"Batan oran","a":"0,917/1,025 ≈ %89,5","d":"Batan hacim oranı 0,917 ÷ 1,025 ≈ %89,5'e düşer."},{"t":"Üstte kalan","a":"≈ %10,5","d":"Daha yoğun sıvıda buz biraz daha yüzer; görünen kısım ~%8,3'ten ~%10,5'e çıkar."}],"ans":"Deniz suyu daha yoğun olduğundan buz biraz daha yüzer; görünen kısım ~%10,5'e çıkar."},{"q":"Suyun yoğunluk anomalisi göl ekosisteminde 'sonbahar/ilkbahar dönüşümü' (turnover) olayını nasıl yönetir?","steps":[{"t":"Yaz katmanı","a":"sıcak üstte","d":"Yazın ılık, az yoğun su üstte; soğuk su dipte katmanlaşır."},{"t":"Soğuma","a":"+4 °C çöker","d":"Sonbaharda yüzey suyu +4 °C'ye soğuyunca en yoğun olur ve dibe çöker."},{"t":"Karışım","a":"besin/oksijen dağılır","d":"Bu çökme su sütununu karıştırır; oksijen dibe, besin yüzeye taşınır."}],"ans":"+4 °C suyunun en yoğun olması mevsimsel çökme-karışmayı (turnover) tetikleyerek oksijen ve besini dağıtır."},{"q":"Buz erirken hacmin azalması, çoğu maddenin tersi davranışıdır; bunun termodinamik/yapısal nedeni nedir?","steps":[{"t":"Genel kural","a":"katı yoğun","d":"Çoğu maddede katı hâl sıvıdan daha sıkı paketlenir, bu yüzden daha yoğundur."},{"t":"Suda istisna","a":"açık örgü","d":"Buz hidrojen bağı örgüsü nedeniyle boşluklu olduğundan sıvıdan az yoğundur."},{"t":"Erime","a":"hacim azalır","d":"Eriyince örgü kısmen çöker, moleküller sıkışır ve hacim küçülür."}],"ans":"Buzun açık hidrojen bağı örgüsü sıvıdan boşluklu olduğundan, erirken örgü çöker ve hacim azalır."},{"q":"Clausius–Clapeyron/erime eğrisi bağlamında suyun katı-sıvı denge eğrisinin negatif eğimli olması neyi gösterir?","steps":[{"t":"Hacim ilişkisi","a":"V_buz > V_su","d":"Erimede sıvı, katıdan küçük hacim kaplar (ΔV erime < 0)."},{"t":"Eğim","a":"negatif","d":"P–T grafiğinde erime eğrisinin eğimi ΔV ile aynı işaretli olduğundan negatif olur."},{"t":"Sonuç","a":"basınç eritir","d":"Basınç artışı buzun erime sıcaklığını düşürür; basınç buzu eritebilir."}],"ans":"Negatif eğim, buzun sıvıdan daha hacimli olduğunu ve artan basıncın erime sıcaklığını düşürdüğünü gösterir."},{"q":"Bir su deposu kışın kısmen donduğunda, donmuş ve sıvı kısımların yoğunluk farkı depo içi tabakalaşmayı nasıl belirler?","steps":[{"t":"Buz üstte","a":"ρ düşük","d":"Yoğunluğu düşük buz daima yüzeyde toplanır."},{"t":"+4 °C dipte","a":"ρ yüksek","d":"En yoğun +4 °C suyu tabanda yer alır."},{"t":"Ara katman","a":"0–4 °C","d":"Arada sıcaklığı 0 ile 4 °C arasında değişen, yoğunluğu kademeli su bulunur."}],"ans":"Düşük yoğunluklu buz üstte, en yoğun +4 °C su dipte, arada kademeli soğuk su olacak şekilde tabakalaşır."},{"q":"Suyun yoğunluk anomalisi olmasaydı Dünya'da hayatın ortaya çıkışı neden büyük ölçüde engellenirdi?","steps":[{"t":"Buz dibe çökerdi","a":"yalıtım yok","d":"Buz sudan yoğun olsaydı oluştuğu anda dibe iner, yüzeyde yalıtıcı örtü olmazdı."},{"t":"Kütlesel donma","a":"sular tümüyle donar","d":"Yalıtım olmadan denizler ve göller tabandan yüzeye kademeli donardı."},{"t":"Yaşam ortamı yok","a":"sıvı su kalmaz","d":"Kalıcı sıvı su olmayınca ilk hücresel yaşamın gelişeceği kararlı su ortamı oluşamazdı."}],"ans":"Anomali olmasa buz dibe çöküp sular tümüyle donar, kararlı sıvı su kalmaz ve yaşamın gelişimi engellenirdi."}]}},"dipolDipol":{"ilkokul":{"kolay":[{"q":"Bazı küçük topların bir ucu hafif artı, diğer ucu hafif eksi olsa, yan yana gelince nasıl dururlar?","steps":[{"t":"Uçların yükü","a":"bir uç +, bir uç −","d":"Bu toplarda bir taraf hafif artı, öbür taraf hafif eksi gibidir."},{"t":"Yan yana duruş","a":"zıt uçlar buluşur","d":"Bir topun artı ucu, komşu topun eksi ucuna döner ve birbirlerini çeker."}],"ans":"Artı uç ile eksi uç birbirini çeker, böylece toplar zıt uçları yan yana gelecek şekilde dizilir."},{"q":"Bir tarafı hafif artı, bir tarafı hafif eksi olan parçacıklara bir benzetme yapsak neye benzer?","steps":[{"t":"İki uçlu","a":"küçük mıknatıs","d":"Bir ucu artı bir ucu eksi olan parçacık, küçük bir mıknatıs gibidir."},{"t":"Çekim","a":"zıt uçlar","d":"Mıknatısta da zıt uçlar birbirini çeker, aynı uçlar iter."}],"ans":"İki ucu farklı yüklü olan bu parçacıklar küçük birer mıknatısa benzetilebilir."},{"q":"İki ucu farklı yüklü olan tanecikler birbirine yapışmaya benzer şekilde tutunur mu?","steps":[{"t":"Hafif çekim","a":"evet, yapışır gibi","d":"Artı ve eksi uçlar birbirini çektiği için tanecikler hafifçe tutunur."},{"t":"Sonuç","a":"bir arada kalır","d":"Bu hafif yapışma sayesinde tanecikler bir arada durur."}],"ans":"Evet, zıt uçlar birbirini çektiği için tanecikler hafifçe yapışır gibi tutunur."},{"q":"Bir ucu artı bir ucu eksi olan iki tanecik, aynı uçları karşı karşıya gelirse ne olur?","fig":"<svg viewBox='0 0 320 130'><rect x='40' y='50' width='90' height='30' rx='12' fill='#cfd8e8' stroke='#1a2b45'/><text x='52' y='70' font-size='12' fill='#1a2b45'>+</text><text x='112' y='70' font-size='12' fill='#1a2b45'>−</text><rect x='190' y='50' width='90' height='30' rx='12' fill='#cfd8e8' stroke='#1a2b45'/><text x='200' y='70' font-size='12' fill='#1a2b45'>+</text><text x='262' y='70' font-size='12' fill='#1a2b45'>−</text><text x='160' y='110' font-size='10' text-anchor='middle' fill='#1a2b45'>zıt uçlar çeker, aynı uçlar iter</text></svg>","steps":[{"t":"Aynı uç","a":"iter","d":"İki artı uç ya da iki eksi uç karşılaşırsa birbirini iter."},{"t":"Dönme","a":"yön değiştirir","d":"Tanecikler döner ve zıt uçları karşı karşıya gelecek şekilde yerleşmeye çalışır."}],"ans":"Aynı uçlar birbirini iter, bu yüzden tanecikler dönüp zıt uçlarını karşı karşıya getirir."},{"q":"İki uçlu (artı-eksi) taneciklerden oluşan bir sıvıyı ısıtmak neden biraz zordur?","steps":[{"t":"Tutunma","a":"birbirini çeker","d":"Tanecikler zıt uçlarından birbirine tutunduğu için bir arada dururlar."},{"t":"Ayırmak için","a":"ısı gerekir","d":"Onları ayırıp buhar yapmak için biraz fazladan ısı vermek gerekir."}],"ans":"Tanecikler birbirine tutunduğu için onları ayırıp buharlaştırmak biraz fazladan ısı ister."}],"zor":[{"q":"İki ucu farklı yüklü tanecikler ile hiç yükü olmayan tanecikler arasında hangisi daha çok tutunur?","steps":[{"t":"Yüklü uçlar","a":"çekim var","d":"Artı-eksi uçları olan tanecikler birbirini çeker, daha sıkı tutunur."},{"t":"Yüksüz","a":"zayıf tutunma","d":"Hiç kalıcı yükü olmayanlar çok daha zayıf tutunur."}],"ans":"İki ucu farklı yüklü olan tanecikler birbirine daha çok tutunur."},{"q":"Bir sıvının tanecikleri birbirini güçlü çekerse o sıvı kolay mı zor mu buharlaşır?","steps":[{"t":"Güçlü çekim","a":"sıkı tutunma","d":"Tanecikler birbirine güçlü tutunursa kolay kolay ayrılmazlar."},{"t":"Buharlaşma","a":"zorlaşır","d":"Ayrılmaları zor olduğu için buharlaşmak için daha çok ısı ister, geç buharlaşır."}],"ans":"Tanecikleri güçlü çeken sıvı daha zor (geç) buharlaşır."},{"q":"İki uçlu taneciklerin neden zıt uçlarını karşı karşıya getirdiğini açıklar mısın?","fig":"<svg viewBox='0 0 320 140'><rect x='110' y='30' width='100' height='28' rx='12' fill='#cfd8e8' stroke='#1a2b45'/><text x='122' y='49' font-size='12' fill='#1a2b45'>+</text><text x='192' y='49' font-size='12' fill='#1a2b45'>−</text><rect x='110' y='85' width='100' height='28' rx='12' fill='#cfd8e8' stroke='#1a2b45'/><text x='122' y='104' font-size='12' fill='#1a2b45'>−</text><text x='192' y='104' font-size='12' fill='#1a2b45'>+</text><line x1='130' y1='58' x2='200' y2='85' stroke='#2b6be0' stroke-width='1.5' stroke-dasharray='4 3'/><text x='250' y='75' font-size='9' text-anchor='middle' fill='#1a2b45'>+ ile − çeker</text></svg>","steps":[{"t":"Çekim kuralı","a":"zıt çeker","d":"Artı yük ile eksi yük birbirini çeker; aynı yükler iter."},{"t":"En rahat duruş","a":"zıt uçlar yan yana","d":"Tanecikler en az itme, en çok çekim olacak şekilde, yani zıt uçları yan yana gelecek biçimde dizilir."}],"ans":"Zıt uçlar (+ ve −) birbirini çektiği için tanecikler zıt uçlarını karşı karşıya getirerek dizilir."},{"q":"Yapışkan band gibi düşün: tanecikler birbirine ne kadar yapışırsa sıvının kaynaması nasıl değişir?","steps":[{"t":"Çok yapışma","a":"sıkı bağ","d":"Tanecikler birbirine çok yapışırsa onları ayırmak için çok enerji gerekir."},{"t":"Kaynama","a":"daha yüksek","d":"Bu yüzden böyle bir sıvının kaynama sıcaklığı daha yüksek olur."}],"ans":"Tanecikler birbirine ne kadar çok yapışırsa sıvının kaynama sıcaklığı o kadar yüksek olur."},{"q":"Aynı büyüklükte iki sıvıdan biri yapışkan uçlu taneciklerden, diğeri yapışmayan taneciklerden olsa hangisi daha geç kurur?","steps":[{"t":"Yapışkan uçlu","a":"zor ayrılır","d":"Artı-eksi uçları olan tanecikler birbirine tutunduğu için zor uçar."},{"t":"Karşılaştırma","a":"yapışkan geç kurur","d":"Yapışmayan tanecikli sıvı daha kolay uçar, yapışkan olan daha geç kurur."}],"ans":"Artı-eksi uçları olan (yapışkan) taneciklerden oluşan sıvı daha geç kurur (buharlaşır)."}]},"ortaokul":{"kolay":[{"q":"Polar bir molekül ne demektir?","steps":[{"t":"Yük dağılımı","a":"eşit değil","d":"Polar molekülde elektronlar eşit paylaşılmadığı için bir uç hafif eksi, diğer uç hafif artı olur."},{"t":"İki kutuplu","a":"kalıcı dipol","d":"Bu kalıcı artı-eksi uç ayrımına dipol denir; molekül kalıcı olarak iki kutupludur."}],"ans":"Polar molekül, bir ucu kısmi artı (δ⁺) diğer ucu kısmi eksi (δ⁻) olan, kalıcı dipole sahip moleküldür."},{"q":"Dipol-dipol etkileşimi hangi moleküller arasında görülür?","fig":"<svg viewBox='0 0 320 130'><rect x='40' y='50' width='90' height='30' rx='12' fill='#cfd8e8' stroke='#1a2b45'/><text x='52' y='70' font-size='12' fill='#1a2b45'>δ⁺</text><text x='106' y='70' font-size='12' fill='#1a2b45'>δ⁻</text><rect x='190' y='50' width='90' height='30' rx='12' fill='#cfd8e8' stroke='#1a2b45'/><text x='200' y='70' font-size='12' fill='#1a2b45'>δ⁺</text><text x='254' y='70' font-size='12' fill='#1a2b45'>δ⁻</text><text x='160' y='110' font-size='10' text-anchor='middle' fill='#1a2b45'>δ⁺ ... δ⁻ çekim</text></svg>","steps":[{"t":"Taraflar","a":"polar moleküller","d":"Dipol-dipol etkileşimi, kalıcı dipole sahip polar moleküller arasında oluşur."},{"t":"Çekim","a":"δ⁺ ... δ⁻","d":"Bir molekülün kısmi artı ucu, komşu molekülün kısmi eksi ucunu çeker."}],"ans":"Dipol-dipol etkileşimi, kalıcı dipole sahip polar moleküller arasında δ⁺ ile δ⁻ çekimi şeklinde görülür."},{"q":"Polar moleküller birbirine nasıl yönelir?","steps":[{"t":"Zıt uçlar","a":"karşı karşıya","d":"Bir molekülün δ⁺ ucu, komşu molekülün δ⁻ ucuna dönerek karşı karşıya gelir."},{"t":"Dizilim","a":"düzenli yerleşim","d":"Böylece moleküller birbirini çekecek şekilde düzenli yönelir."}],"ans":"Polar moleküller, bir molekülün δ⁺ ucu komşunun δ⁻ ucuna bakacak şekilde yönelir."},{"q":"Dipol-dipol etkileşimi London (dağılma) kuvvetlerinden genelde güçlü müdür yoksa zayıf mı?","steps":[{"t":"Kalıcı dipol","a":"güçlü","d":"Dipol-dipol etkileşiminde kalıcı yük ayrımı vardır, bu çekimi güçlendirir."},{"t":"Karşılaştırma","a":"London'dan güçlü","d":"Bu yüzden benzer büyüklükteki moleküllerde dipol-dipol, London kuvvetlerinden daha güçlüdür."}],"ans":"Dipol-dipol etkileşimi, benzer büyüklükteki moleküllerde London kuvvetlerinden daha güçlüdür."},{"q":"Polar maddelerin kaynama noktası, benzer büyüklükteki apolar maddelere göre nasıldır?","steps":[{"t":"Ek çekim","a":"dipol-dipol","d":"Polar moleküller arasında ek olarak dipol-dipol çekimi bulunur."},{"t":"Kaynama","a":"daha yüksek","d":"Bu ek çekimi koparmak fazladan enerji istediğinden kaynama noktası daha yüksektir."}],"ans":"Polar maddelerin kaynama noktası, benzer büyüklükteki apolar maddelere göre daha yüksektir."}],"zor":[{"q":"İki molekülün dipol-dipol etkileşim kurabilmesi için temel koşul nedir?","steps":[{"t":"Polarlık şartı","a":"kalıcı dipol","d":"Her iki molekülün de kalıcı dipole, yani kalıcı bir δ⁺/δ⁻ ayrımına sahip olması gerekir."},{"t":"Apolar dışlanır","a":"polar olmalı","d":"Apolar moleküllerde kalıcı dipol olmadığından bunlar dipol-dipol etkileşimi yapamaz."}],"ans":"Dipol-dipol etkileşimi için her iki molekülün de kalıcı dipole sahip (polar) olması gerekir."},{"q":"HCl molekülleri sıvı halde neden dipol-dipol etkileşimiyle tutunur?","fig":"<svg viewBox='0 0 320 135'><circle cx='80' cy='55' r='16' fill='#cfd8e8' stroke='#1a2b45'/><text x='80' y='60' font-size='10' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='130' cy='55' r='22' fill='#9ed9a8' stroke='#1a2b45'/><text x='130' y='60' font-size='11' text-anchor='middle' fill='#1a2b45'>Cl</text><text x='72' y='40' font-size='10' fill='#1a2b45'>δ⁺</text><text x='150' y='40' font-size='10' fill='#1a2b45'>δ⁻</text><circle cx='215' cy='95' r='16' fill='#cfd8e8' stroke='#1a2b45'/><text x='215' y='100' font-size='10' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='265' cy='95' r='22' fill='#9ed9a8' stroke='#1a2b45'/><text x='265' y='100' font-size='11' text-anchor='middle' fill='#1a2b45'>Cl</text><line x1='148' y1='62' x2='205' y2='90' stroke='#2b6be0' stroke-width='1.5' stroke-dasharray='4 3'/></svg>","steps":[{"t":"Polar bağ","a":"H–Cl","d":"Klor hidrojenden daha elektronegatif olduğundan H–Cl bağı polardır; Cl ucu δ⁻, H ucu δ⁺ olur."},{"t":"Moleküller arası","a":"δ⁺ ... δ⁻","d":"Bir HCl'nin δ⁺ (H) ucu, komşu HCl'nin δ⁻ (Cl) ucunu çeker; bu dipol-dipol etkileşimidir."}],"ans":"HCl polar olduğundan bir molekülün δ⁺ (H) ucu komşunun δ⁻ (Cl) ucunu çeker; bu dipol-dipol etkileşimiyle moleküller tutunur."},{"q":"Molekül kütleleri yakın olan iki maddeden polar olanın kaynama noktası neden daha yüksektir?","steps":[{"t":"Ortak kuvvet","a":"London ikisinde de var","d":"Yakın kütleli iki maddede London (dağılma) kuvvetleri benzer düzeydedir."},{"t":"Ek dipol-dipol","a":"polarda fazladan çekim","d":"Polar maddede buna ek olarak dipol-dipol çekimi de bulunur; toplam çekim arttığı için kaynama noktası yükselir."}],"ans":"Polar maddede London kuvvetlerine ek olarak dipol-dipol çekimi bulunduğundan toplam çekim artar ve kaynama noktası daha yüksek olur."},{"q":"Dipol-dipol etkileşiminin gücü moleküller arası uzaklıkla nasıl değişir?","steps":[{"t":"Uzaklık etkisi","a":"azalır","d":"Moleküller birbirinden uzaklaştıkça dipoller arası çekim hızla zayıflar."},{"t":"Yakınlık etkisi","a":"artar","d":"Moleküller yaklaştıkça δ⁺ ve δ⁻ uçların çekimi güçlenir."}],"ans":"Dipol-dipol etkileşimi moleküller yaklaştıkça güçlenir, uzaklaştıkça hızla zayıflar."},{"q":"Aynı maddenin sıvı ve gaz halini düşünürsek dipol-dipol etkileşimi hangisinde daha etkilidir?","steps":[{"t":"Sıvı hal","a":"moleküller yakın","d":"Sıvıda moleküller birbirine yakındır, dipol uçlar etkili biçimde çekim kurar."},{"t":"Gaz hal","a":"moleküller uzak","d":"Gazda moleküller çok uzak ve hızlı hareket ettiğinden dipol-dipol çekimi neredeyse etkisizdir."}],"ans":"Dipol-dipol etkileşimi, moleküllerin birbirine yakın olduğu sıvı halde gaz haline göre çok daha etkilidir."}]},"lise":{"kolay":[{"q":"Dipol-dipol etkileşimini tanımlayınız ve hangi tür moleküller arasında oluştuğunu belirtiniz.","steps":[{"t":"Tanım","a":"kalıcı dipoller arası çekim","d":"Dipol-dipol etkileşimi, kalıcı dipole sahip polar moleküllerin δ⁺ ve δ⁻ uçları arasındaki elektrostatik çekimdir."},{"t":"Koşul","a":"polar moleküller","d":"Yalnızca kalıcı dipol momentine sahip polar moleküller arasında görülür; apolar moleküllerde gözlenmez."}],"ans":"Dipol-dipol etkileşimi, polar moleküllerin kalıcı δ⁺ ve δ⁻ uçları arasındaki elektrostatik çekimdir ve yalnızca polar moleküller arasında oluşur."},{"q":"Dipol-dipol etkileşiminin London (dağılma) kuvvetlerinden genellikle daha güçlü olmasının nedeni nedir?","steps":[{"t":"London kuvveti","a":"anlık dipol","d":"London kuvvetleri, elektron hareketinden doğan anlık (geçici) dipollerden kaynaklanır."},{"t":"Dipol-dipol","a":"kalıcı dipol","d":"Dipol-dipolde ise kalıcı yük ayrımı vardır; sürekli ve daha düzenli bir çekim sağladığından benzer kütlede London'dan güçlüdür."}],"ans":"Dipol-dipol etkileşimi kalıcı yük ayrımına dayandığından, anlık dipollere dayanan London kuvvetlerine göre benzer kütlede daha güçlüdür."},{"q":"Benzer molekül kütlesine sahip polar ve apolar iki maddenin kaynama noktalarını karşılaştırınız.","fig":"<svg viewBox='0 0 320 150'><rect x='40' y='40' width='80' height='28' rx='10' fill='#cfd8e8' stroke='#1a2b45'/><text x='52' y='59' font-size='11' fill='#1a2b45'>δ⁺</text><text x='96' y='59' font-size='11' fill='#1a2b45'>δ⁻</text><rect x='40' y='80' width='80' height='28' rx='10' fill='#cfd8e8' stroke='#1a2b45'/><text x='52' y='99' font-size='11' fill='#1a2b45'>δ⁺</text><text x='96' y='99' font-size='11' fill='#1a2b45'>δ⁻</text><text x='80' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>polar: dipol-dipol</text><rect x='205' y='40' width='80' height='28' rx='10' fill='#e6e9ef' stroke='#1a2b45'/><rect x='205' y='80' width='80' height='28' rx='10' fill='#e6e9ef' stroke='#1a2b45'/><text x='245' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>apolar: sadece London</text></svg>","steps":[{"t":"Etkileşim farkı","a":"polarda ek çekim","d":"İkisinde de London kuvvetleri benzerken, polar maddede ek olarak dipol-dipol çekimi vardır."},{"t":"Sonuç","a":"polar daha yüksek","d":"Toplam moleküller arası çekim polar maddede daha büyük olduğundan kaynama noktası daha yüksektir."}],"ans":"Benzer kütlede polar madde, dipol-dipol çekiminin eklenmesiyle apolar maddeye göre daha yüksek kaynama noktasına sahiptir."},{"q":"Bir molekülün kalıcı dipol momentine sahip olması için hangi iki koşul gereklidir?","steps":[{"t":"Polar bağ","a":"elektronegatiflik farkı","d":"Molekülde elektronegatiflik farkından doğan polar bağ(lar) bulunmalıdır."},{"t":"Asimetrik geometri","a":"dipoller götürmemeli","d":"Bağ dipolleri molekül geometrisinde birbirini sıfırlamamalı; net bir dipol momenti kalmalıdır."}],"ans":"Kalıcı dipol için molekülde polar bağ bulunmalı ve geometri, bağ dipollerinin birbirini götürmediği asimetrik bir yapı olmalıdır."},{"q":"Dipol-dipol etkileşimleri maddenin hangi fiziksel özelliklerini etkiler?","steps":[{"t":"Faz değişimi","a":"kaynama/erime noktası","d":"Moleküller arası çekimi artırdığından erime ve kaynama noktalarını yükseltir."},{"t":"Diğer özellikler","a":"buhar basıncı, çözünürlük","d":"Buhar basıncını düşürür ve 'benzer benzeri çözer' kuralı gereği polar çözücülerde çözünürlüğü etkiler."}],"ans":"Dipol-dipol etkileşimleri erime/kaynama noktasını yükseltir, buhar basıncını düşürür ve polar maddelerin çözünürlüğünü etkiler."}],"zor":[{"q":"Molekül kütleleri çok yakın olan dimetil eter ve etanolden etanolün kaynama noktasının belirgin yüksek olmasını yalnızca dipol-dipol ile açıklamak yeterli midir?","steps":[{"t":"Her ikisi polar","a":"dipol-dipol var","d":"Hem dimetil eter hem etanol polardır; ikisinde de dipol-dipol etkileşimi bulunur."},{"t":"Hidrojen bağı","a":"etanolde ek","d":"Etanolde −OH grubu olduğundan ek olarak güçlü hidrojen bağı yapar; bu, dipol-dipolden çok daha güçlüdür."},{"t":"Sonuç","a":"yetersiz","d":"Bu yüzden büyük farkı sadece dipol-dipol ile açıklamak yetersizdir; hidrojen bağı (özel bir güçlü dipol-dipol türü) belirleyicidir."}],"ans":"Hayır; her ikisi de dipol-dipol yapar ama etanolün belirgin yüksek kaynama noktasının asıl nedeni −OH ile yaptığı güçlü hidrojen bağıdır."},{"q":"Dipol momenti büyüyen polar moleküllerde kaynama noktasının nasıl değiştiğini ve nedenini açıklayınız.","steps":[{"t":"Dipol momenti","a":"yük ayrımı ölçüsü","d":"Dipol momenti, molekülün δ⁺ ve δ⁻ uçları arasındaki yük ayrımının büyüklüğünü gösterir."},{"t":"Çekim gücü","a":"momentle artar","d":"Dipol momenti büyüdükçe moleküller arası dipol-dipol çekimi güçlenir."},{"t":"Sonuç","a":"kaynama yükselir","d":"Daha güçlü çekimi koparmak için daha çok enerji gerektiğinden kaynama noktası genelde yükselir."}],"ans":"Dipol momenti büyüdükçe dipol-dipol çekimi güçlenir; bu çekimi yenmek daha çok enerji istediğinden kaynama noktası genellikle yükselir."},{"q":"Sıvı bir polar maddeyi gaz fazına geçirirken dipol-dipol etkileşimleri açısından ne olur?","fig":"<svg viewBox='0 0 320 150'><rect x='35' y='40' width='60' height='22' rx='8' fill='#cfd8e8' stroke='#1a2b45'/><rect x='35' y='70' width='60' height='22' rx='8' fill='#cfd8e8' stroke='#1a2b45'/><rect x='35' y='100' width='60' height='22' rx='8' fill='#cfd8e8' stroke='#1a2b45'/><text x='65' y='140' font-size='10' text-anchor='middle' fill='#1a2b45'>sıvı: yakın, çekim güçlü</text><line x1='110' y1='80' x2='160' y2='80' stroke='#1a2b45' stroke-width='2'/><polygon points='160,80 150,75 150,85' fill='#1a2b45'/><text x='135' y='70' font-size='9' text-anchor='middle' fill='#1a2b45'>ısı</text><rect x='185' y='45' width='50' height='18' rx='7' fill='#cfd8e8' stroke='#1a2b45'/><rect x='250' y='95' width='50' height='18' rx='7' fill='#cfd8e8' stroke='#1a2b45'/><text x='245' y='140' font-size='10' text-anchor='middle' fill='#1a2b45'>gaz: uzak, çekim koptu</text></svg>","steps":[{"t":"Sıvıda durum","a":"çekim güçlü","d":"Sıvı fazda moleküller yakındır ve dipol-dipol çekimi onları bir arada tutar."},{"t":"Buharlaşma","a":"çekimi yenmek","d":"Gaz fazına geçişte bu çekimleri yenmek için enerji (buharlaşma ısısı) verilmelidir."},{"t":"Gaz fazı","a":"çekim ihmal edilir","d":"Gazda moleküller çok uzaklaştığından dipol-dipol etkileşimi pratikte ortadan kalkar."}],"ans":"Sıvıdan gaza geçişte moleküller arası dipol-dipol çekimlerini yenmek için enerji harcanır; gaz fazında moleküller uzaklaştığı için bu etkileşim ihmal edilir hale gelir."},{"q":"Polar bir maddenin buhar basıncının, benzer kütleli apolar maddeye göre neden daha düşük olduğunu açıklayınız.","steps":[{"t":"Buhar basıncı","a":"kaçma eğilimi","d":"Buhar basıncı, moleküllerin sıvıdan gaz fazına kaçma eğiliminin bir ölçüsüdür."},{"t":"Dipol-dipol engeli","a":"çekim tutuyor","d":"Polar maddede dipol-dipol çekimi molekülleri daha sıkı tuttuğundan daha az molekül buharlaşabilir."},{"t":"Sonuç","a":"daha düşük basınç","d":"Bu nedenle aynı sıcaklıkta polar maddenin buhar basıncı, apolar maddeye göre daha düşüktür."}],"ans":"Polar maddede dipol-dipol çekimi molekülleri sıkıca tuttuğundan buharlaşma azalır; bu yüzden benzer kütleli apolar maddeye göre buhar basıncı daha düşüktür."},{"q":"Dipol-dipol etkileşimi ile iyon-dipol etkileşimi arasındaki temel fark ve göreli güç sıralaması nedir?","steps":[{"t":"Taraflar","a":"molekül-molekül vs iyon-molekül","d":"Dipol-dipol iki polar molekül arasında; iyon-dipol ise bir iyon ile bir polar molekül arasında oluşur."},{"t":"Yük büyüklüğü","a":"tam yük vs kısmi yük","d":"İyonda tam (±1, ±2 ...) yük varken, dipolde yalnızca kısmi (δ) yük bulunur."},{"t":"Güç sıralaması","a":"iyon-dipol daha güçlü","d":"Tam yük kısmi yükten daha güçlü çekim yaptığından iyon-dipol etkileşimi dipol-dipolden belirgin biçimde güçlüdür."}],"ans":"Dipol-dipol iki polar molekül (kısmi yükler) arasında; iyon-dipol ise tam yüklü iyon ile polar molekül arasındadır ve tam yük nedeniyle iyon-dipol etkileşimi dipol-dipolden daha güçlüdür."}]}},"dipolIndukDipol":{"ilkokul":{"kolay":[{"q":"İki ucu farklı yüklü bir tanecik, hiç yükü olmayan bir taneciğin yanına gelince ne olabilir?","steps":[{"t":"Yaklaşma","a":"yüklü uç yaklaşır","d":"Artı-eksi uçlu tanecik, yüksüz taneciğe yaklaşır."},{"t":"Etkileme","a":"yük dağılımı bozulur","d":"Yüklü uç, yüksüz taneciğin içindeki küçük yükleri biraz iter ya da çeker; böylece o tanecikte de geçici bir artı-eksi uç oluşur."}],"ans":"Yüklü uçlu tanecik, yüksüz taneciğin içinde geçici bir artı-eksi uç (geçici yük ayrımı) oluşturabilir."},{"q":"Yüksüz bir taneciğe geçici olarak iki uçlu hale geldiğinde ne diyebiliriz?","steps":[{"t":"Önce yüksüz","a":"dengeli","d":"Tanecik normalde dengelidir, belirgin bir artı ya da eksi ucu yoktur."},{"t":"Sonra geçici uç","a":"oluşturulmuş dipol","d":"Komşu yüklü tanecik onu etkileyip geçici bir artı-eksi uç oluşturursa, ona 'oluşturulmuş (indüklenmiş) iki uçlu' denir."}],"ans":"Yüksüz tanecikte komşusunun oluşturduğu geçici artı-eksi uca 'oluşturulmuş (indüklenmiş) dipol' denir."},{"q":"Bu geçici çekim, kalıcı artı-eksi uçların çekiminden güçlü müdür yoksa zayıf mı?","steps":[{"t":"Geçici","a":"kısa süreli","d":"Oluşturulan uç geçicidir ve zayıftır."},{"t":"Karşılaştırma","a":"daha zayıf","d":"Kalıcı uçların çekimine göre bu geçici çekim daha zayıftır."}],"ans":"Bu geçici çekim, kalıcı artı-eksi uçların çekiminden daha zayıftır."},{"q":"Oksijen gazı suda neden çok az çözünür?","fig":"<svg viewBox='0 0 320 130'><circle cx='90' cy='65' r='18' fill='#e0552b' stroke='#1a2b45'/><text x='75' y='50' font-size='9' fill='#1a2b45'>δ⁻</text><text x='105' y='50' font-size='9' fill='#1a2b45'>δ⁺</text><circle cx='200' cy='65' r='20' fill='#dfe7f0' stroke='#1a2b45'/><text x='200' y='70' font-size='10' text-anchor='middle' fill='#1a2b45'>O₂</text><line x1='108' y1='65' x2='180' y2='65' stroke='#2b6be0' stroke-width='1.5' stroke-dasharray='4 3'/><text x='160' y='115' font-size='10' text-anchor='middle' fill='#1a2b45'>zayıf çekim</text></svg>","steps":[{"t":"Su iki uçlu","a":"yüklü","d":"Su taneciğinin artı-eksi uçları vardır."},{"t":"O₂ yüksüz","a":"zayıf çekim","d":"Oksijen taneciğinin kalıcı uçları olmadığından su onu ancak zayıfça çekebilir, bu yüzden çok az çözünür."}],"ans":"Oksijen taneciğinin kalıcı artı-eksi uçları olmadığından su onu sadece zayıfça çeker; bu yüzden suda çok az çözünür."},{"q":"Yüksüz taneciği iki uçlu hale getiren komşu uzaklaşırsa ne olur?","steps":[{"t":"Komşu uzaklaşır","a":"etki biter","d":"Geçici ucu oluşturan yüklü komşu uzaklaşınca etkisi kalkar."},{"t":"Geri dönüş","a":"yine yüksüz","d":"Tanecik eski dengeli (yüksüz) haline geri döner; geçici uç kaybolur."}],"ans":"Komşu uzaklaşınca geçici uç kaybolur ve tanecik yeniden dengeli (yüksüz) haline döner."}],"zor":[{"q":"İki uçlu su taneciği, yüksüz bir taneciği nasıl 'iki uçlu' yapabilir?","steps":[{"t":"Yaklaşma","a":"artı uç yaklaşır","d":"Suyun bir ucu (örneğin artı) yüksüz taneciğe yaklaşır."},{"t":"İtme-çekme","a":"yükler kayar","d":"Bu uç, yüksüz taneciğin içindeki küçük eksi yükleri kendine çeker; tanecikte bir tarafta eksi, öbür tarafta artı oluşur, yani geçici iki uçlu olur."}],"ans":"Su, bir ucuyla yüksüz taneciğin içindeki yükleri kaydırarak onda geçici bir artı-eksi uç (iki uçluluk) oluşturur."},{"q":"Apolar (yüksüz) gazların suda az çözünmesinin nedeni nedir?","steps":[{"t":"Su güçlü çeker","a":"kendi türünü","d":"Su molekülleri birbirini güçlü çeker (kalıcı uçlar ve hidrojen bağı)."},{"t":"Yüksüz gaz zayıf","a":"sadece geçici","d":"Yüksüz gaz ile su arasında sadece zayıf geçici çekim olduğundan gaz suya pek karışamaz, az çözünür."}],"ans":"Su kendi taneciklerini güçlü çekerken yüksüz gazla sadece zayıf geçici çekim kurabildiğinden, apolar gazlar suda az çözünür."},{"q":"Geçici (oluşturulmuş) çekim, balonu duvara yapıştıran statik elektriğe benzetilebilir mi?","fig":"<svg viewBox='0 0 320 130'><circle cx='110' cy='65' r='26' fill='#dfe7f0' stroke='#1a2b45'/><text x='110' y='70' font-size='10' text-anchor='middle' fill='#1a2b45'>balon</text><rect x='200' y='25' width='30' height='80' fill='#e6e9ef' stroke='#1a2b45'/><text x='215' y='118' font-size='9' text-anchor='middle' fill='#1a2b45'>duvar</text><line x1='136' y1='65' x2='198' y2='65' stroke='#2b6be0' stroke-width='1.5' stroke-dasharray='4 3'/></svg>","steps":[{"t":"Statik balon","a":"yük oluşturur","d":"Yüklü balon duvara yaklaşınca duvarda geçici zıt yük oluşturup yapışır."},{"t":"Benzerlik","a":"oluşturulmuş yük","d":"Aynı şekilde yüklü bir tanecik de komşusunda geçici zıt yük oluşturup onu çeker; ikisi de oluşturulmuş (indüklenmiş) çekimdir."}],"ans":"Evet; balonun duvarda geçici zıt yük oluşturup yapışması gibi, yüklü bir tanecik de komşusunda geçici yük oluşturarak çeker."},{"q":"Kalıcı uçlu su ile yüksüz gaz arasındaki çekim neden zayıftır?","steps":[{"t":"Tek taraf kalıcı","a":"diğeri geçici","d":"Sadece suyun kalıcı ucu vardır; gazın ucu ise ancak geçici olarak oluşturulur."},{"t":"Zayıf ve kısa","a":"az çekim","d":"Geçici uç küçük ve kısa süreli olduğundan oluşan çekim zayıftır."}],"ans":"Yüksüz gazda yalnızca geçici (küçük, kısa süreli) bir uç oluştuğundan, kalıcı uçlu su ile arasındaki çekim zayıftır."},{"q":"Soda (gazlı içecek) açık bırakılınca gazın kaçması bu zayıf çekimle ilgili olabilir mi?","steps":[{"t":"Zayıf tutma","a":"gaz az bağlı","d":"Gaz tanecikleri suya sadece zayıf geçici çekimle tutunur."},{"t":"Kaçma","a":"kolay ayrılır","d":"Bu çekim zayıf olduğundan gaz tanecikleri kolayca sıvıdan ayrılıp havaya kaçar."}],"ans":"Evet; gaz suya sadece zayıf geçici çekimle tutunduğundan kolayca ayrılıp havaya kaçar, içecek gazını kaybeder."}]},"ortaokul":{"kolay":[{"q":"Dipol-indüklenmiş dipol etkileşimi hangi iki tür molekül arasında oluşur?","steps":[{"t":"Birinci taraf","a":"polar molekül","d":"Bir tarafta kalıcı dipole sahip polar bir molekül bulunur."},{"t":"İkinci taraf","a":"apolar molekül","d":"Diğer tarafta normalde dipolü olmayan apolar bir molekül bulunur."}],"ans":"Dipol-indüklenmiş dipol etkileşimi, bir polar molekül ile bir apolar molekül arasında oluşur."},{"q":"Polar bir molekül, apolar molekülde nasıl bir dipol oluşturur?","fig":"<svg viewBox='0 0 320 130'><rect x='40' y='50' width='80' height='28' rx='10' fill='#cfd8e8' stroke='#1a2b45'/><text x='52' y='69' font-size='11' fill='#1a2b45'>δ⁺</text><text x='98' y='69' font-size='11' fill='#1a2b45'>δ⁻</text><circle cx='220' cy='64' r='24' fill='#dfe7f0' stroke='#1a2b45'/><text x='205' y='52' font-size='9' fill='#1a2b45'>δ⁺</text><text x='232' y='80' font-size='9' fill='#1a2b45'>δ⁻</text><line x1='122' y1='64' x2='196' y2='64' stroke='#2b6be0' stroke-width='1.5' stroke-dasharray='4 3'/></svg>","steps":[{"t":"Elektron itmesi","a":"yük kayar","d":"Polar molekülün yüklü ucu, apolar molekülün elektron bulutunu iter ya da çeker."},{"t":"İndüklenmiş dipol","a":"geçici dipol","d":"Bu etkiyle apolar molekülde geçici (indüklenmiş) bir dipol oluşur."}],"ans":"Polar molekül, apolar molekülün elektron bulutunu kaydırarak onda geçici (indüklenmiş) bir dipol oluşturur."},{"q":"İndüklenmiş dipol 'geçici' midir yoksa 'kalıcı' mı?","steps":[{"t":"Bağımlılık","a":"polar moleküle bağlı","d":"İndüklenmiş dipol, yalnızca polar molekül yakındayken vardır."},{"t":"Geçici","a":"uzaklaşınca kaybolur","d":"Polar molekül uzaklaşınca apolar molekül eski haline döner; dipol kaybolur."}],"ans":"İndüklenmiş dipol geçicidir; yalnızca polar molekül yakınken oluşur, uzaklaşınca kaybolur."},{"q":"O₂ gazının suda az çözünmesini bu etkileşimle açıklayınız.","steps":[{"t":"Su polar, O₂ apolar","a":"farklı","d":"Su polardır, O₂ ise apolardır."},{"t":"Zayıf çekim","a":"dipol-indüklenmiş dipol","d":"Su O₂'de ancak zayıf bir indüklenmiş dipol oluşturabildiğinden çekim zayıftır; bu yüzden O₂ suda az çözünür."}],"ans":"Su, apolar O₂'de yalnızca zayıf bir indüklenmiş dipol oluşturabildiği için çekim zayıftır; bu nedenle O₂ suda az çözünür."},{"q":"Dipol-indüklenmiş dipol etkileşimi dipol-dipolden güçlü müdür?","steps":[{"t":"Dipol-dipol","a":"iki kalıcı dipol","d":"Dipol-dipolde her iki tarafta da kalıcı dipol vardır."},{"t":"Karşılaştırma","a":"daha zayıf","d":"Dipol-indüklenmiş dipolde bir taraf yalnızca geçici dipol oluşturduğundan etkileşim daha zayıftır."}],"ans":"Hayır; bir taraf sadece geçici dipol oluşturduğundan dipol-indüklenmiş dipol, dipol-dipolden daha zayıftır."}],"zor":[{"q":"Bir apolar molekülün ne kadar kolay indüklenebileceğini ne belirler?","steps":[{"t":"Kutuplanabilirlik","a":"elektron bulutu","d":"Apolar molekülün elektron bulutunun ne kadar kolay kayabildiğine kutuplanabilirlik denir."},{"t":"Boyut etkisi","a":"büyük daha kolay","d":"Büyük, çok elektronlu moleküllerin elektron bulutu daha gevşek olduğundan daha kolay indüklenir."}],"ans":"Bir apolar molekülün kutuplanabilirliği (elektron bulutunun kolay kayabilmesi) belirler; büyük, çok elektronlu moleküller daha kolay indüklenir."},{"q":"Polar molekül uzaklaştığında apolar moleküldeki dipole ne olur, neden?","steps":[{"t":"Neden var","a":"dış etki","d":"İndüklenmiş dipol, polar molekülün dış etkisiyle (elektron bulutunu kaydırmasıyla) oluşur."},{"t":"Etki kalkar","a":"dipol kaybolur","d":"Polar molekül uzaklaşınca bu dış etki kalkar ve elektron bulutu eski dengeli dağılımına döner; dipol kaybolur."}],"ans":"Polar molekül uzaklaşınca onu oluşturan dış etki kalkar; apolar molekülün elektron bulutu eski haline döner ve indüklenmiş dipol kaybolur."},{"q":"Sıcaklık artınca gazların sudaki çözünürlüğü neden azalır?","steps":[{"t":"Zayıf çekim","a":"dipol-indüklenmiş dipol","d":"Gaz molekülleri suya zaten zayıf dipol-indüklenmiş dipol çekimiyle tutunur."},{"t":"Isı etkisi","a":"hareket artar","d":"Sıcaklık artınca gaz molekülleri daha çok hareket eder, bu zayıf çekimi kolayca yenip sıvıdan kaçar; çözünürlük azalır."}],"ans":"Gaz suya yalnızca zayıf dipol-indüklenmiş dipol çekimiyle tutunur; sıcaklık artınca artan hareketle bu zayıf çekim yenilir ve gazların çözünürlüğü azalır."},{"q":"Neden CO₂ ve O₂ gibi apolar gazlar suda az çözünürken NH₃ gibi polar gaz çok çözünür?","fig":"<svg viewBox='0 0 320 135'><circle cx='80' cy='60' r='20' fill='#dfe7f0' stroke='#1a2b45'/><text x='80' y='65' font-size='10' text-anchor='middle' fill='#1a2b45'>O₂</text><text x='80' y='100' font-size='9' text-anchor='middle' fill='#1a2b45'>apolar: az</text><circle cx='235' cy='60' r='20' fill='#cfd8e8' stroke='#1a2b45'/><text x='235' y='65' font-size='9' text-anchor='middle' fill='#1a2b45'>NH₃</text><text x='235' y='100' font-size='9' text-anchor='middle' fill='#1a2b45'>polar: çok</text></svg>","steps":[{"t":"Apolar gaz","a":"zayıf çekim","d":"O₂, CO₂ apolardır; su onlarla yalnızca zayıf dipol-indüklenmiş dipol çekimi kurar, az çözünürler."},{"t":"Polar gaz","a":"güçlü çekim","d":"NH₃ polardır; su ile güçlü dipol-dipol ve hidrojen bağı kurabildiğinden çok daha fazla çözünür."}],"ans":"Apolar O₂/CO₂ su ile yalnızca zayıf dipol-indüklenmiş dipol kurarken, polar NH₃ su ile güçlü dipol-dipol ve hidrojen bağı kurar; bu yüzden NH₃ suda çok çözünür."},{"q":"Dipol-indüklenmiş dipol etkileşimi günlük hayatta nerede önemlidir, bir örnek veriniz?","steps":[{"t":"Gaz çözünürlüğü","a":"sudaki oksijen","d":"Sudaki çözünmüş oksijen, su (polar) ile O₂ (apolar) arasındaki bu etkileşim sayesinde bir miktar bulunur."},{"t":"Önemi","a":"canlılar için","d":"Bu az miktardaki çözünmüş oksijen, balık ve su canlılarının solunumu için yaşamsaldır."}],"ans":"Dipol-indüklenmiş dipol etkileşimi sayesinde suda az da olsa oksijen çözünür; bu çözünmüş oksijen balık gibi su canlılarının solunumu için yaşamsaldır."}]},"lise":{"kolay":[{"q":"Dipol-indüklenmiş dipol etkileşimini tanımlayınız.","steps":[{"t":"Taraflar","a":"polar + apolar","d":"Bu etkileşim bir polar molekül ile bir apolar molekül arasında oluşur."},{"t":"Mekanizma","a":"dipol indükler","d":"Polar molekülün kalıcı dipolü, apolar molekülün elektron bulutunu kutuplaştırarak geçici (indüklenmiş) bir dipol oluşturur; bu iki dipol arasındaki çekim etkileşimi sağlar."}],"ans":"Dipol-indüklenmiş dipol etkileşimi, bir polar molekülün kalıcı dipolünün apolar molekülde geçici dipol oluşturmasıyla ortaya çıkan zayıf çekimdir."},{"q":"O₂'nin suda az çözünmesini dipol-indüklenmiş dipol etkileşimiyle açıklayınız.","fig":"<svg viewBox='0 0 320 140'><circle cx='90' cy='65' r='18' fill='#e0552b' stroke='#1a2b45'/><text x='72' y='50' font-size='9' fill='#1a2b45'>δ⁻</text><text x='102' y='50' font-size='9' fill='#1a2b45'>δ⁺</text><text x='90' y='100' font-size='9' text-anchor='middle' fill='#1a2b45'>H₂O (polar)</text><circle cx='215' cy='65' r='22' fill='#dfe7f0' stroke='#1a2b45'/><text x='198' y='52' font-size='9' fill='#1a2b45'>δ⁺</text><text x='228' y='82' font-size='9' fill='#1a2b45'>δ⁻</text><text x='215' y='105' font-size='9' text-anchor='middle' fill='#1a2b45'>O₂ (indüklenmiş)</text><line x1='110' y1='65' x2='192' y2='65' stroke='#2b6be0' stroke-width='1.5' stroke-dasharray='4 3'/></svg>","steps":[{"t":"Etkileşim türü","a":"dipol-indüklenmiş dipol","d":"Polar su molekülü apolar O₂'de geçici bir dipol indükler; aralarında yalnızca bu zayıf etkileşim kurulur."},{"t":"Zayıf çekim","a":"az çözünür","d":"Bu etkileşim, su molekülleri arası güçlü hidrojen bağlarından çok zayıf olduğundan O₂ suda yalnızca az miktarda çözünür."}],"ans":"Su, apolar O₂'de yalnızca zayıf bir indüklenmiş dipol oluşturur; bu çekim suyun kendi içindeki hidrojen bağlarından çok zayıf olduğundan O₂ suda az çözünür."},{"q":"Bir apolar molekülün kutuplanabilirliği (polarizebilite) hangi etmenlere bağlıdır?","steps":[{"t":"Elektron sayısı","a":"çok elektron","d":"Molekül ne kadar çok elektrona ve büyük elektron bulutuna sahipse o kadar kolay kutuplanır."},{"t":"Bağ gevşekliği","a":"gevşek bulut","d":"Dış elektronları çekirdeğe gevşek bağlı, büyük moleküller daha kolay indüklenir, yani kutuplanabilirliği yüksektir."}],"ans":"Kutuplanabilirlik, molekülün elektron sayısı ve boyutu arttıkça (elektron bulutu büyük ve gevşek oldukça) artar."},{"q":"Dipol-indüklenmiş dipol etkileşimini dipol-dipol ve London kuvvetleriyle güç açısından sıralayınız.","steps":[{"t":"Dipol türleri","a":"kalıcı vs geçici","d":"Dipol-dipol iki kalıcı dipol; dipol-indüklenmiş dipol bir kalıcı bir geçici dipol; London iki anlık dipol içerir."},{"t":"Sıralama","a":"dipol-dipol > dipol-indük > London","d":"Genellikle dipol-dipol en güçlü, ardından dipol-indüklenmiş dipol, en zayıf ise London dağılma kuvvetleridir."}],"ans":"Genel güç sırası dipol-dipol > dipol-indüklenmiş dipol > London (dağılma) kuvvetleri biçimindedir."},{"q":"Bir maddenin polar bir çözücüde az çözünmesi her zaman dipol-indüklenmiş dipol ile mi ilgilidir?","steps":[{"t":"Apolar çözünen","a":"dipol-indüklenmiş dipol","d":"Çözünen apolar ise polar çözücü ile yalnızca zayıf dipol-indüklenmiş dipol kurar, bu da az çözünürlüğü açıklar."},{"t":"Genelleme uyarısı","a":"her zaman değil","d":"Ancak az çözünürlüğün başka nedenleri (güçlü örgü enerjisi, geometri vb.) de olabilir; bu yüzden tek başına genellenemez."}],"ans":"Apolar çözünenin polar çözücüde az çözünmesi tipik olarak dipol-indüklenmiş dipol ile açıklanır, ancak az çözünürlüğün tek nedeni bu olmayabilir."}],"zor":[{"q":"Henry yasasına göre gaz çözünürlüğü basınçla artar; bu olayı dipol-indüklenmiş dipol etkileşimiyle ilişkilendirerek açıklayınız.","steps":[{"t":"Zayıf etkileşim","a":"gaz az tutulur","d":"Apolar gaz molekülleri suya yalnızca zayıf dipol-indüklenmiş dipol çekimiyle tutulur, bu yüzden çözünürlükleri düşüktür."},{"t":"Basınç etkisi","a":"daha çok molekül","d":"Basınç artınca sıvı yüzeyine çarpan gaz molekülü sayısı artar; daha çok molekül su ile bu zayıf etkileşimi kurabilir."},{"t":"Sonuç","a":"çözünürlük artar","d":"Bu nedenle Henry yasası gereği gaz çözünürlüğü basınçla doğru orantılı olarak artar."}],"ans":"Apolar gaz suya zayıf dipol-indüklenmiş dipol ile tutulur; basınç arttıkça yüzeye çarpan ve bu etkileşimi kuran molekül sayısı arttığından, Henry yasasına uygun biçimde çözünürlük artar."},{"q":"Aynı grup apolar gazlardan (örneğin He, Ne, Ar) ağır olanların suda biraz daha fazla çözünmesini nasıl açıklarsınız?","steps":[{"t":"Kutuplanabilirlik","a":"boyutla artar","d":"Ar, He'ye göre daha büyük ve daha çok elektronludur, bu yüzden kutuplanabilirliği daha yüksektir."},{"t":"İndüklenmiş dipol","a":"daha güçlü","d":"Su, kutuplanabilirliği yüksek Ar'da daha büyük bir indüklenmiş dipol oluşturur, dolayısıyla çekim daha güçlüdür."},{"t":"Sonuç","a":"daha fazla çözünür","d":"Daha güçlü dipol-indüklenmiş dipol çekimi nedeniyle ağır (büyük) apolar gazlar suda biraz daha fazla çözünür."}],"ans":"Ağır apolar gazlar daha yüksek kutuplanabilirliğe sahip olduğundan su onlarda daha güçlü indüklenmiş dipol oluşturur; bu daha güçlü çekim nedeniyle suda biraz daha fazla çözünürler."},{"q":"Polar bir çözücüde apolar bir madde çözündüğünde sistemin enerjisi açısından dipol-indüklenmiş dipol etkileşiminin rolünü değerlendiriniz.","steps":[{"t":"Çözücü-çözücü kopuşu","a":"enerji gerekir","d":"Apolar maddeyi yerleştirmek için güçlü çözücü-çözücü etkileşimlerinin (örneğin hidrojen bağları) bir kısmı kırılır; bu enerji gerektirir."},{"t":"Yeni etkileşim","a":"zayıf indüklenmiş dipol","d":"Buna karşılık oluşan çözücü-çözünen etkileşimi yalnızca zayıf dipol-indüklenmiş dipoldür; az enerji açığa çıkarır."},{"t":"Net değerlendirme","a":"az çözünürlük","d":"Kırılan güçlü etkileşimler, oluşan zayıf etkileşimlerle yeterince karşılanmadığından çözünme sınırlı kalır."}],"ans":"Apolar maddeyi çözmek için kırılan güçlü çözücü-çözücü etkileşimlerinin enerjisi, oluşan zayıf dipol-indüklenmiş dipol etkileşimleriyle yeterince karşılanamaz; bu enerji dezavantajı apolar maddenin polar çözücüde az çözünmesine yol açar."},{"q":"Dipol-indüklenmiş dipol etkileşiminin gücünü belirleyen iki temel faktörü, ilgili moleküllerin özellikleriyle birlikte açıklayınız.","steps":[{"t":"Polar molekülün dipol momenti","a":"büyük moment güçlü","d":"İndükleyen polar molekülün dipol momenti ne kadar büyükse, apolar molekülde o kadar büyük bir dipol indükler."},{"t":"Apolar molekülün kutuplanabilirliği","a":"yüksek polarizebilite","d":"İndüklenen apolar molekülün elektron bulutu ne kadar büyük ve gevşekse (kutuplanabilirlik yüksekse) o kadar kolay ve büyük dipol oluşur."},{"t":"Birleşik etki","a":"ikisi de artırır","d":"Her iki faktör de büyüdükçe oluşan indüklenmiş dipol ve dolayısıyla çekim kuvveti artar."}],"ans":"Dipol-indüklenmiş dipol etkileşiminin gücü, indükleyen polar molekülün dipol momenti ile indüklenen apolar molekülün kutuplanabilirliği arttıkça büyür."},{"q":"London (dağılma) kuvvetleri ile dipol-indüklenmiş dipol etkileşimi arasındaki temel fark nedir?","steps":[{"t":"İndükleyen kaynak","a":"kalıcı vs anlık","d":"Dipol-indüklenmiş dipolde indüklemeyi yapan kalıcı bir dipoldür; London'da ise indüklemeyi anlık (geçici) bir dipol yapar."},{"t":"Moleküller","a":"polar-apolar vs apolar-apolar","d":"Dipol-indüklenmiş dipol polar-apolar çiftinde; London ise apolar moleküller dahil tüm moleküller arasında görülür."},{"t":"Ortaklık","a":"ikisi de indükleme","d":"Her ikisinde de bir molekülde dipol 'indüklenir'; fark, indüklemeyi başlatan dipolün kalıcı mı anlık mı olduğudur."}],"ans":"Her ikisi de indüklenmiş dipole dayanır; fark, dipol-indüklenmiş dipolde indükleyenin kalıcı bir dipol, London kuvvetlerinde ise anlık (geçici) bir dipol olmasıdır."}]}},"elementBilesik":{"ilkokul":{"kolay":[{"q":"Sadece tek çeşit atomdan oluşan saf maddeye ne denir?","steps":[{"t":"Tek çeşit atom","a":"aynı atomlar","d":"Bir maddenin içinde sadece aynı çeşit atomlar varsa, o madde tek tür atomdan oluşur."},{"t":"Adı","a":"element","d":"Yalnız tek çeşit atom içeren saf maddeye element denir."}],"ans":"Sadece tek çeşit atomdan oluşan saf maddeye element denir."},{"q":"Farklı çeşit atomların belirli oranda kimyasal birleşmesiyle oluşan saf maddeye ne denir?","steps":[{"t":"Farklı atomlar","a":"birleşir","d":"İki ya da daha çok farklı atom belirli bir oranda kimyasal olarak birleşir."},{"t":"Adı","a":"bileşik","d":"Bu yeni saf maddeye bileşik denir; örneğin su (H₂O)."}],"ans":"Farklı atomların belirli oranda kimyasal birleşmesiyle oluşan saf maddeye bileşik denir."},{"q":"Demir (Fe) bir element midir, bir bileşik midir?","steps":[{"t":"İçeriği","a":"tek çeşit atom","d":"Demir yalnızca demir (Fe) atomlarından oluşur."},{"t":"Sonuç","a":"element","d":"Tek çeşit atomdan oluştuğu için demir bir elementtir."}],"ans":"Demir tek çeşit atomdan oluştuğu için bir elementtir."},{"q":"Su (H₂O) bir element midir, bir bileşik midir?","fig":"<svg viewBox='0 0 320 170'><circle cx='160' cy='90' r='26' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='95' font-size='14' text-anchor='middle' fill='#fff'>O</text><circle cx='110' cy='60' r='16' fill='#cfd8e8' stroke='#1a2b45'/><text x='110' y='65' font-size='11' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='210' cy='60' r='16' fill='#cfd8e8' stroke='#1a2b45'/><text x='210' y='65' font-size='11' text-anchor='middle' fill='#1a2b45'>H</text><line x1='138' y1='76' x2='122' y2='66' stroke='#1a2b45' stroke-width='2'/><line x1='182' y1='76' x2='198' y2='66' stroke='#1a2b45' stroke-width='2'/><text x='160' y='150' font-size='11' text-anchor='middle' fill='#1a2b45'>2 H + 1 O</text></svg>","steps":[{"t":"İçeriği","a":"iki çeşit atom","d":"Suda hidrojen (H) ve oksijen (O) olmak üzere iki çeşit atom vardır."},{"t":"Sonuç","a":"bileşik","d":"Farklı atomlar birleştiği için su bir bileşiktir."}],"ans":"Su, hidrojen ve oksijen birleştiği için bir bileşiktir."},{"q":"Tuzlu su bir bileşik midir yoksa karışım mıdır?","steps":[{"t":"Birleşme yok","a":"sadece karışmış","d":"Tuzlu suda tuz ve su birbirine kimyasal olarak bağlanmaz, sadece içinde dağılır."},{"t":"Sonuç","a":"karışım","d":"İstenirse suyu buharlaştırıp tuzu geri alabiliriz; bu yüzden tuzlu su bir karışımdır."}],"ans":"Tuzlu su, tuz ve suyun kimyasal birleşmeden bir arada bulunduğu bir karışımdır."}],"zor":[{"q":"Element ile bileşik arasındaki en temel fark nedir?","steps":[{"t":"Element","a":"tek çeşit atom","d":"Element yalnızca tek çeşit atomdan oluşur (örneğin altın, oksijen gazı)."},{"t":"Bileşik","a":"farklı atomlar birleşir","d":"Bileşikte farklı çeşit atomlar belirli oranda kimyasal olarak birleşir (örneğin su)."}],"ans":"Element tek çeşit atomdan oluşur; bileşikte ise farklı atomlar kimyasal olarak birleşmiştir."},{"q":"Bir bileşik ile bir karışım arasındaki fark nedir?","fig":"<svg viewBox='0 0 320 170'><rect x='40' y='40' width='90' height='90' rx='8' fill='none' stroke='#1a2b45'/><circle cx='70' cy='70' r='9' fill='#e0552b' stroke='#1a2b45'/><circle cx='100' cy='70' r='9' fill='#e0552b' stroke='#1a2b45'/><circle cx='70' cy='100' r='9' fill='#e0552b' stroke='#1a2b45'/><circle cx='100' cy='100' r='9' fill='#e0552b' stroke='#1a2b45'/><text x='85' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>bileşik (bağlı)</text><rect x='190' y='40' width='90' height='90' rx='8' fill='none' stroke='#1a2b45'/><circle cx='215' cy='65' r='8' fill='#e0552b' stroke='#1a2b45'/><circle cx='255' cy='80' r='8' fill='#2b6be0' stroke='#1a2b45'/><circle cx='220' cy='110' r='8' fill='#2b6be0' stroke='#1a2b45'/><circle cx='258' cy='112' r='8' fill='#e0552b' stroke='#1a2b45'/><text x='235' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>karışım (serbest)</text></svg>","steps":[{"t":"Bileşik","a":"kimyasal birleşme","d":"Bileşikte atomlar belirli oranda kimyasal olarak bağlıdır; yeni bir madde oluşur."},{"t":"Karışım","a":"sadece bir arada","d":"Karışımda maddeler kimyasal birleşmeden bir aradadır ve fiziksel yollarla ayrılabilir."}],"ans":"Bileşikte atomlar belirli oranda kimyasal birleşir ve yeni madde olur; karışımda maddeler birleşmeden bir aradadır, ayrılabilir."},{"q":"Hava bir bileşik midir yoksa karışım mıdır, neden?","steps":[{"t":"İçeriği","a":"birçok gaz","d":"Hava azot, oksijen, karbondioksit gibi farklı gazların bir aradalığıdır."},{"t":"Birleşme yok","a":"karışım","d":"Bu gazlar kimyasal olarak birleşmemiştir; oranları değişebilir, bu yüzden hava bir karışımdır."}],"ans":"Hava, farklı gazların kimyasal birleşmeden bir arada bulunduğu bir karışımdır."},{"q":"Saf madde ne demektir, bir örnek verir misiniz?","steps":[{"t":"Tek tür yapı","a":"hep aynı","d":"Saf madde, her yeri aynı yapıda olan ve tek tür tanecikten oluşan maddedir."},{"t":"Örnek","a":"saf su, altın","d":"Saf su (bileşik) ve altın (element) saf maddelere örnektir."}],"ans":"Saf madde, tek tür tanecikten oluşan ve her yeri aynı olan maddedir; örneğin saf su ve altın."},{"q":"Bir bileşikteki atomların oranı neden hep aynıdır?","fig":"<svg viewBox='0 0 320 150'><circle cx='120' cy='75' r='22' fill='#e0552b' stroke='#1a2b45'/><text x='120' y='80' font-size='12' text-anchor='middle' fill='#fff'>O</text><circle cx='75' cy='50' r='13' fill='#cfd8e8' stroke='#1a2b45'/><text x='75' y='54' font-size='9' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='75' cy='100' r='13' fill='#cfd8e8' stroke='#1a2b45'/><text x='75' y='104' font-size='9' text-anchor='middle' fill='#1a2b45'>H</text><text x='200' y='80' font-size='12' fill='#1a2b45'>her zaman 2 H : 1 O</text></svg>","steps":[{"t":"Belirli oran","a":"sabit sayı","d":"Bir bileşiği oluşturan atomlar her zaman belirli, sabit bir sayıda birleşir."},{"t":"Örnek su","a":"2 H : 1 O","d":"Su her zaman 2 hidrojen ve 1 oksijen oranındadır; bu oran değişirse madde su olmaktan çıkar."}],"ans":"Bileşikte atomlar belirli ve sabit bir oranda birleştiği için (örneğin suda 2 H : 1 O) oran her zaman aynıdır."}]},"ortaokul":{"kolay":[{"q":"Element nedir, bir bileşikten temel farkı nedir?","steps":[{"t":"Element","a":"tek tür atom","d":"Element, aynı tür atomlardan oluşan ve kimyasal yolla daha basit maddelere ayrılamayan saf maddedir."},{"t":"Fark","a":"bileşik = farklı atomlar","d":"Bileşik ise farklı atomların belirli oranda kimyasal birleşmesiyle oluşur."}],"ans":"Element tek tür atomdan oluşan saf maddedir; bileşikten farkı, bileşikte farklı atomların kimyasal olarak birleşmesidir."},{"q":"Bileşiğin bir karışımdan farkını iki maddeyle açıklayınız (su ve şekerli su).","steps":[{"t":"Su (bileşik)","a":"belirli oran","d":"Su, hidrojen ve oksijenin 2:1 oranında kimyasal birleşmesiyle oluşur ve fiziksel yolla ayrılamaz."},{"t":"Şekerli su (karışım)","a":"değişken oran","d":"Şekerli suda şeker ve su birleşmez; oran değişebilir ve buharlaştırma ile ayrılabilir."}],"ans":"Bileşikte (su) atomlar belirli oranda kimyasal birleşir ve fiziksel yolla ayrılmaz; karışımda (şekerli su) maddeler birleşmeden bir aradadır ve ayrılabilir."},{"q":"Saf madde kaça ayrılır, nelerdir?","steps":[{"t":"İki grup","a":"element ve bileşik","d":"Saf maddeler element ve bileşik olmak üzere iki gruba ayrılır."},{"t":"Tanımlar","a":"tek/farklı atom","d":"Element tek tür atom, bileşik ise belirli oranda birleşmiş farklı atomlar içerir."}],"ans":"Saf maddeler element (tek tür atom) ve bileşik (belirli oranda birleşmiş farklı atomlar) olmak üzere ikiye ayrılır."},{"q":"Bir bileşiğin özellikleri, onu oluşturan elementlerin özelliklerine benzer mi?","fig":"<svg viewBox='0 0 320 150'><circle cx='70' cy='75' r='20' fill='#cfd8e8' stroke='#1a2b45'/><text x='70' y='80' font-size='10' text-anchor='middle' fill='#1a2b45'>Na</text><text x='105' y='80' font-size='16' fill='#1a2b45'>+</text><circle cx='150' cy='75' r='20' fill='#9ed9a8' stroke='#1a2b45'/><text x='150' y='80' font-size='10' text-anchor='middle' fill='#1a2b45'>Cl</text><text x='185' y='80' font-size='16' fill='#1a2b45'>→</text><rect x='225' y='55' width='60' height='40' rx='6' fill='#f0f0f0' stroke='#1a2b45'/><text x='255' y='80' font-size='11' text-anchor='middle' fill='#1a2b45'>NaCl</text></svg>","steps":[{"t":"Element özellikleri","a":"farklı","d":"Sodyum patlayıcı bir metal, klor zehirli bir gazdır."},{"t":"Bileşik özelliği","a":"yepyeni","d":"Birleşince oluşan tuz (NaCl) yenilebilir, zararsız bir katıdır; yani bileşiğin özellikleri tamamen yeni olur."}],"ans":"Hayır; bileşiğin özellikleri onu oluşturan elementlerden tamamen farklı, yepyeni özelliklerdir (örneğin Na + Cl → yemek tuzu)."},{"q":"O₂ bir element molekülü müdür yoksa bileşik midir?","steps":[{"t":"İçeriği","a":"iki oksijen","d":"O₂ molekülünde sadece oksijen atomları vardır."},{"t":"Sonuç","a":"element","d":"Tek tür atom içerdiği için O₂ bir element (element molekülü) sayılır, bileşik değildir."}],"ans":"O₂ yalnızca oksijen atomlarından oluştuğu için bir elementtir (element molekülü), bileşik değildir."}],"zor":[{"q":"Bir bileşik fiziksel yollarla bileşenlerine ayrılabilir mi, neden?","steps":[{"t":"Kimyasal bağ","a":"güçlü birleşme","d":"Bileşikte atomlar kimyasal bağlarla belirli oranda bağlıdır."},{"t":"Ayırma yolu","a":"kimyasal tepkime","d":"Bu bağları kırmak fiziksel yollarla (süzme, buharlaştırma) olmaz; ancak kimyasal tepkime (örneğin elektroliz) ile ayrılabilir."}],"ans":"Hayır; bileşikteki atomlar kimyasal bağlarla bağlı olduğundan fiziksel yolla ayrılamaz, ancak kimyasal yolla (örneğin elektroliz) ayrılabilir."},{"q":"Sabit oranlar kanununu suyu örnek alarak açıklayınız.","fig":"<svg viewBox='0 0 320 150'><circle cx='130' cy='70' r='22' fill='#e0552b' stroke='#1a2b45'/><text x='130' y='75' font-size='12' text-anchor='middle' fill='#fff'>O</text><circle cx='85' cy='45' r='13' fill='#cfd8e8' stroke='#1a2b45'/><text x='85' y='49' font-size='9' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='85' cy='95' r='13' fill='#cfd8e8' stroke='#1a2b45'/><text x='85' y='99' font-size='9' text-anchor='middle' fill='#1a2b45'>H</text><text x='215' y='66' font-size='11' fill='#1a2b45'>kütlece</text><text x='215' y='84' font-size='11' fill='#1a2b45'>1 H : 8 O</text></svg>","steps":[{"t":"Sabit sayı oranı","a":"2 H : 1 O","d":"Su her zaman 2 hidrojen ve 1 oksijen atomu içerir; bu oran değişmez."},{"t":"Kütle oranı","a":"1 g H : 8 g O","d":"Kütlece bakıldığında suda hidrojen ile oksijen her zaman 1:8 oranındadır; bu sabit oranlar kanunudur."}],"ans":"Sabit oranlar kanununa göre bir bileşiği oluşturan elementlerin kütle oranı sabittir; suda bu oran her zaman 1 g hidrojen : 8 g oksijendir."},{"q":"Aynı elementlerden iki farklı bileşik oluşabilir mi, örnek veriniz?","steps":[{"t":"Farklı oran","a":"katlı oran","d":"Aynı elementler farklı sayısal oranlarda birleşerek farklı bileşikler verebilir."},{"t":"Örnek","a":"CO ve CO₂","d":"Karbon ve oksijen, 1 oksijenle karbonmonoksit (CO), 2 oksijenle karbondioksit (CO₂) oluşturur; bunlar farklı maddelerdir."}],"ans":"Evet; aynı elementler farklı oranlarda birleşerek farklı bileşikler verebilir, örneğin karbon ve oksijenden CO ve CO₂ oluşur (katlı oranlar)."},{"q":"Bir maddenin element mi, bileşik mi yoksa karışım mı olduğunu nasıl ayırt ederiz?","steps":[{"t":"Tane çeşidi","a":"tek/farklı","d":"Tek tür atom varsa element; farklı atomlar belirli oranda kimyasal bağlıysa bileşiktir."},{"t":"Ayrışma yolu","a":"fiziksel/kimyasal","d":"Fiziksel yolla bileşenlerine ayrılabiliyorsa karışım; ancak kimyasal yolla ayrılabiliyorsa bileşiktir; hiç ayrılamıyorsa elementtir."}],"ans":"Tane çeşidine ve ayrışma yoluna bakarız: tek tür atom = element, kimyasal birleşmiş farklı atom = bileşik, kimyasal birleşmeden bir arada ve fiziksel yolla ayrılabilen = karışım."},{"q":"Homojen ve heterojen karışım arasındaki fark nedir, birer örnekle açıklayınız.","steps":[{"t":"Homojen","a":"her yeri aynı","d":"Homojen karışımda bileşenler tek tip görünür ve her yeri aynıdır; örneğin tuzlu su, kolonya."},{"t":"Heterojen","a":"farklı bölgeler","d":"Heterojen karışımda bileşenler gözle ayırt edilebilir, her yeri farklıdır; örneğin kum-su, ayran."}],"ans":"Homojen karışımda bileşenler tek tip görünür ve her yeri aynıdır (tuzlu su); heterojen karışımda bileşenler ayırt edilebilir ve farklı bölgeler vardır (kum-su)."}]},"lise":{"kolay":[{"q":"Element ve bileşik kavramlarını saf madde sınıflandırması içinde tanımlayınız.","steps":[{"t":"Element","a":"tek tür atom","d":"Element, aynı cins atomlardan oluşan ve kimyasal yöntemlerle daha basit maddelere ayrıştırılamayan saf maddedir."},{"t":"Bileşik","a":"belirli oran + kimyasal bağ","d":"Bileşik, en az iki farklı elementin belirli kütle oranında kimyasal bağlarla birleşmesiyle oluşan saf maddedir."}],"ans":"Saf maddeler element ve bileşik diye ikiye ayrılır: element tek tür atomdan oluşur ve kimyasal yolla ayrışmaz; bileşik farklı elementlerin belirli oranda kimyasal bağlarla birleşmesiyle oluşur."},{"q":"Bir bileşiğin saf madde, su-tuz çözeltisinin ise karışım sayılmasının nedeni nedir?","steps":[{"t":"Bileşik","a":"sabit bileşim","d":"Bileşiğin bileşimi (atom türü ve oranı) her örnekte aynıdır ve belirli kimyasal formülle gösterilir."},{"t":"Karışım","a":"değişken bileşim","d":"Çözeltide bileşenlerin oranı değişebilir, kimyasal bağ yoktur ve fiziksel yolla ayrılabilir."}],"ans":"Bileşik sabit bileşimli ve kimyasal bağlı olduğundan saf maddedir; çözelti ise değişken oranlı, kimyasal bağsız ve fiziksel yolla ayrılabilir olduğundan karışımdır."},{"q":"Sabit oranlar kanunu (Proust) nedir, neyi ifade eder?","steps":[{"t":"İlke","a":"sabit kütle oranı","d":"Bir bileşiği oluşturan elementlerin kütleleri arasında daima sabit ve basit bir oran vardır."},{"t":"Anlamı","a":"bileşik sabit bileşimli","d":"Bu nedenle saf bir bileşiğin bileşimi nereden alınırsa alınsın aynıdır; bu, bileşiği karışımdan ayıran temel özelliktir."}],"ans":"Sabit oranlar kanunu, bir bileşiği oluşturan elementlerin kütlelerinin daima sabit bir oranda olduğunu ifade eder; bu yüzden bir bileşik her zaman aynı bileşimdedir."},{"q":"Element molekülü ile bileşik molekülünü örneklerle ayırınız.","fig":"<svg viewBox='0 0 320 150'><circle cx='70' cy='75' r='20' fill='#e0552b' stroke='#1a2b45'/><text x='70' y='80' font-size='10' text-anchor='middle' fill='#fff'>O</text><circle cx='115' cy='75' r='20' fill='#e0552b' stroke='#1a2b45'/><text x='115' y='80' font-size='10' text-anchor='middle' fill='#fff'>O</text><line x1='90' y1='75' x2='95' y2='75' stroke='#1a2b45' stroke-width='3'/><text x='92' y='115' font-size='10' text-anchor='middle' fill='#1a2b45'>O₂ element molekülü</text><circle cx='225' cy='75' r='18' fill='#33415588' stroke='#1a2b45'/><text x='225' y='80' font-size='10' text-anchor='middle' fill='#fff'>C</text><circle cx='190' cy='75' r='15' fill='#e0552b' stroke='#1a2b45'/><text x='190' y='80' font-size='9' text-anchor='middle' fill='#fff'>O</text><circle cx='260' cy='75' r='15' fill='#e0552b' stroke='#1a2b45'/><text x='260' y='80' font-size='9' text-anchor='middle' fill='#fff'>O</text><text x='225' y='115' font-size='10' text-anchor='middle' fill='#1a2b45'>CO₂ bileşik molekülü</text></svg>","steps":[{"t":"Element molekülü","a":"aynı atomlar","d":"Aynı tür atomlardan oluşan moleküllerdir; örneğin O₂, N₂, H₂, Cl₂."},{"t":"Bileşik molekülü","a":"farklı atomlar","d":"Farklı tür atomların belirli oranda bağlanmasıyla oluşur; örneğin H₂O, CO₂, NH₃."}],"ans":"Element molekülü aynı tür atomlardan (O₂, N₂) oluşur ve element sayılır; bileşik molekülü ise farklı atomlardan (H₂O, CO₂) oluşur ve bileşiktir."},{"q":"Bir bileşiğin fiziksel değişimle değil de kimyasal değişimle bileşenlerine ayrılmasının nedeni nedir?","steps":[{"t":"Kimyasal bağ","a":"yüksek enerji","d":"Bileşikte atomlar kimyasal bağlarla tutulur; bu bağları koparmak yüksek enerji gerektirir."},{"t":"Kimyasal yöntem","a":"elektroliz, ısı","d":"Fiziksel yöntemler bağı koparmaya yetmez; bağı koparmak için kimyasal yöntem (elektroliz, ısıl ayrışma) gerekir."}],"ans":"Bileşikteki atomlar yüksek enerjili kimyasal bağlarla bağlı olduğundan, bu bağları ancak kimyasal değişim (örneğin elektroliz ya da ısıl ayrışma) koparabilir; fiziksel değişim yetmez."}],"zor":[{"q":"Katlı oranlar kanununu (Dalton) CO ve CO₂ üzerinden açıklayınız.","steps":[{"t":"Sabit karbon","a":"12 g C","d":"Aynı kütlede (12 g) karbon ele alalım; CO'da bu karbonla 16 g oksijen, CO₂'de 32 g oksijen birleşir."},{"t":"Basit tam sayı oranı","a":"16 : 32 = 1 : 2","d":"Sabit karbon başına oksijen kütleleri 16 : 32, yani 1 : 2 gibi basit bir tam sayı oranındadır; bu katlı oranlar kanunudur."}],"ans":"Katlı oranlar kanununa göre aynı elementler birden çok bileşik oluşturduğunda, birinin sabit kütlesiyle birleşen diğerinin kütleleri basit tam sayı oranındadır; CO ve CO₂'de sabit karbon başına oksijen oranı 1 : 2'dir."},{"q":"Suyun kütlece bileşimini hesaplayarak sabit oranlar kanununu doğrulayınız (H=1, O=16).","steps":[{"t":"Formül kütlesi","a":"H₂O = 18","d":"H₂O'da 2 hidrojen (2·1 = 2 g) ve 1 oksijen (16 g) vardır; toplam 18 g/mol."},{"t":"Kütle yüzdeleri","a":"%11,1 H, %88,9 O","d":"Hidrojen yüzdesi 2/18·100 = %11,1; oksijen yüzdesi 16/18·100 = %88,9; bu oran her su örneğinde aynıdır."}],"ans":"H₂O'nun formül kütlesi 18 g/mol'dür; kütlece %11,1 hidrojen ve %88,9 oksijen içerir. Bu sabit yüzdeler suyun her örneğinde aynı olduğundan sabit oranlar kanununu doğrular."},{"q":"Bir maddenin element, bileşik ya da karışım olduğuna deneysel olarak nasıl karar verilir?","steps":[{"t":"Ayrıştırma denemesi","a":"fiziksel/kimyasal","d":"Madde fiziksel yolla (damıtma, süzme) ayrılıyorsa karışımdır; ayrılmıyor ama kimyasal yolla (elektroliz) ayrılıyorsa bileşiktir."},{"t":"Sabit özellik","a":"erime/kaynama","d":"Saf madde (element/bileşik) keskin ve sabit erime-kaynama noktasına sahiptir; karışımda bu değerler aralık gösterir, böylece ayrım netleşir."}],"ans":"Madde fiziksel yolla ayrılabiliyorsa karışım; sadece kimyasal yolla ayrılabiliyorsa bileşik; hiç ayrışmayan tek tür atom ise elementtir. Saf maddenin sabit erime-kaynama noktası bu kararı destekler."},{"q":"Homojen karışım (çözelti) ile bileşik, makro ve mikro düzeyde nasıl ayrılır?","steps":[{"t":"Mikro düzey","a":"bağ var/yok","d":"Bileşikte tanecikler belirli oranda kimyasal bağlıdır; çözeltide çözünen tanecikler çözücü içinde serbestçe dağılmıştır, kimyasal bağ kurmaz."},{"t":"Makro düzey","a":"sabit/değişken bileşim","d":"Bileşiğin bileşimi sabit ve formülle gösterilir; çözeltinin derişimi (oranı) belli sınırlarda istenildiği gibi değiştirilebilir ve fiziksel yolla ayrılır."}],"ans":"Mikro düzeyde bileşikte kimyasal bağ varken çözeltide yoktur; makro düzeyde bileşik sabit bileşimli ve formülle gösterilirken çözeltinin derişimi değiştirilebilir ve fiziksel yolla ayrılabilir."},{"q":"Allotropi kavramı, 'tek tür atom = element' tanımıyla nasıl bağdaşır (örneğin oksijen)?","steps":[{"t":"Allotrop tanımı","a":"aynı element, farklı yapı","d":"Bir elementin atomlarının farklı biçimde dizilmesiyle oluşan farklı maddelere allotrop denir; örneğin oksijen O₂ ve ozon O₃."},{"t":"Element tanımıyla uyum","a":"hâlâ tek tür atom","d":"Hem O₂ hem O₃ yalnızca oksijen atomu içerir; tek tür atomdan oluştukları için ikisi de elementtir, yalnızca yapıları farklıdır."}],"ans":"Allotroplar (O₂ ve O₃ gibi) aynı elementin farklı yapılı biçimleridir; ikisi de tek tür atomdan oluştuğundan element tanımıyla çelişmez, sadece atomların diziliş ve sayısı farklıdır."}]}},"etkilesimSinif":{"ilkokul":{"kolay":[{"q":"Atomları sımsıkı tutan kuvvet mi, yoksa molekülleri uzaktan çeken kuvvet mi daha güçlüdür?","steps":[{"t":"İki tür kuvvet","a":"güçlü ve zayıf","d":"Atomları birbirine bağlayan güçlü kuvvetler ve molekülleri uzaktan tutan zayıf kuvvetler vardır."},{"t":"Karşılaştırma","a":"bağ daha güçlü","d":"Atomları sımsıkı tutan bağ kuvveti, molekülleri uzaktan çeken kuvvetten daha güçlüdür."}],"ans":"Atomları sımsıkı tutan bağ kuvveti, molekülleri uzaktan çeken kuvvetten daha güçlüdür."},{"q":"Mıknatısların birbirini uzaktan hafifçe çekmesi, hangi tür kuvvete benzer?","steps":[{"t":"Hafif çekim","a":"uzaktan","d":"Moleküller de birbirini uzaktan hafifçe çeker, tıpkı mıknatısların hafif çekimi gibi."},{"t":"Zayıf kuvvet","a":"kolay ayrılır","d":"Bu çekim zayıftır, moleküller kolayca ayrılabilir."}],"ans":"Mıknatısların uzaktan hafif çekimi, moleküller arasındaki zayıf çekim kuvvetine benzer."},{"q":"Buz eridiğinde su moleküllerinin atomları parçalanır mı?","steps":[{"t":"Erime","a":"moleküller ayrılır","d":"Buz eriyince su molekülleri birbirinden ayrılır ama parçalanmaz."},{"t":"Atomlar","a":"sağlam kalır","d":"Her su molekülünün içindeki atomlar güçlü bağlarla bağlı kaldığı için parçalanmaz."}],"ans":"Hayır; buz eridiğinde moleküller ayrılır ama içlerindeki atomlar güçlü bağlarla bağlı kaldığı için parçalanmaz."},{"q":"Su damlalarının yüzeyde toparlanıp damla halinde durmasını ne sağlar?","fig":"<svg viewBox='0 0 320 150'><path d='M160 40 C120 90 120 120 160 120 C200 120 200 90 160 40 Z' fill='#2b6be0' stroke='#1a2b45'/><text x='160' y='140' font-size='11' text-anchor='middle' fill='#1a2b45'>su damlası</text></svg>","steps":[{"t":"Moleküller birbirini çeker","a":"hafif çekim","d":"Su molekülleri birbirini hafifçe çeker."},{"t":"Toparlanma","a":"damla olur","d":"Bu çekim molekülleri bir arada tutar, su damla halinde toparlanır."}],"ans":"Su moleküllerinin birbirini hafifçe çekmesi, suyun damla halinde toparlanmasını sağlar."},{"q":"Metaller neden hem sağlam hem de elektriği iyi iletir?","steps":[{"t":"Sıkı bağlı","a":"güçlü tutunma","d":"Metal atomları birbirine güçlü bir şekilde tutunduğu için metal sağlamdır."},{"t":"Gezen elektronlar","a":"akım taşır","d":"Metalde serbest gezen elektronlar olduğu için elektrik kolayca iletilir."}],"ans":"Metal atomları güçlü tutunduğundan sağlamdır; içindeki serbest gezen elektronlar da elektriği iyi iletir."}],"zor":[{"q":"Şekeri suda eritince şeker molekülleri parçalanır mı, yoksa sadece birbirinden mi ayrılır?","steps":[{"t":"Çözünme","a":"moleküller dağılır","d":"Şeker suda çözünürken molekülleri su içinde dağılır."},{"t":"İç bağlar","a":"sağlam","d":"Her şeker molekülünün içindeki güçlü bağlar kırılmaz, sadece moleküller birbirinden ayrılır."}],"ans":"Şeker suda eridiğinde molekülleri birbirinden ayrılır ama her molekülün içindeki güçlü bağlar kırılmaz."},{"q":"Neden suyu kaynatıp buhar yapmak, suyu hidrojen ve oksijene ayırmaktan daha kolaydır?","steps":[{"t":"Kaynatma","a":"zayıf kuvvet kırılır","d":"Kaynatınca sadece moleküller arası zayıf çekim kırılır, bu kolaydır."},{"t":"Ayırma","a":"güçlü bağ kırılır","d":"Hidrojen ve oksijene ayırmak için molekül içindeki güçlü bağları kırmak gerekir, bu çok zordur."}],"ans":"Kaynatmak yalnızca zayıf molekül arası kuvvetleri kırar; suyu elementlerine ayırmak ise güçlü bağları kırmak gerektirir, bu yüzden çok daha zordur."},{"q":"Bazı maddeler neden çok düşük sıcaklıkta erirken (mum gibi) bazıları çok yüksek sıcaklıkta erir (tuz gibi)?","steps":[{"t":"Zayıf çekimli","a":"kolay erir","d":"Mum gibi maddelerde moleküller arası çekim zayıftır, az ısıyla kolayca erir."},{"t":"Güçlü bağlı","a":"zor erir","d":"Tuz gibi maddelerde tanecikler güçlü bağlarla tutulur, eritmek için çok yüksek sıcaklık gerekir."}],"ans":"Mum zayıf molekül arası çekimle tutulduğu için kolay; tuz ise güçlü bağlarla tutulduğu için ancak çok yüksek sıcaklıkta erir."},{"q":"Tutkal iki kâğıdı birbirine yapıştırır; bu, moleküller arası çekime mi benzer?","steps":[{"t":"Yapışma","a":"çekim","d":"Tutkalın molekülleri kâğıt yüzeyini çeker ve tutar."},{"t":"Benzetme","a":"zayıf kuvvetler gibi","d":"Bu yapışma, moleküllerin birbirini çeken zayıf kuvvetlerine benzetilebilir."}],"ans":"Evet; tutkalın yapıştırması, moleküllerin birbirini çeken zayıf çekim kuvvetlerine benzetilebilir."},{"q":"Su molekülleri neden birbirini diğer sıvıların moleküllerinden daha güçlü tutar?","fig":"<svg viewBox='0 0 320 150'><circle cx='90' cy='60' r='16' fill='#e0552b' stroke='#1a2b45'/><text x='90' y='65' font-size='9' text-anchor='middle' fill='#fff'>O</text><circle cx='200' cy='90' r='16' fill='#e0552b' stroke='#1a2b45'/><text x='200' y='95' font-size='9' text-anchor='middle' fill='#fff'>O</text><circle cx='125' cy='80' r='9' fill='#cfd8e8' stroke='#1a2b45'/><line x1='133' y1='84' x2='186' y2='90' stroke='#2b6be0' stroke-width='2' stroke-dasharray='4 3'/><text x='160' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>özel çekim</text></svg>","steps":[{"t":"Özel çekim","a":"güçlü tutunma","d":"Su moleküllerinde özel bir çekim vardır, birbirlerine daha sıkı tutunurlar."},{"t":"Sonuç","a":"yüzey gerilimi","d":"Bu yüzden su damla olur ve küçük böcekler suyun üzerinde durabilir."}],"ans":"Su moleküllerinde özel bir güçlü çekim olduğundan birbirlerine daha sıkı tutunur; bu yüzden su damla yapar ve yüzeyinde böcek durabilir."}]},"ortaokul":{"kolay":[{"q":"Kimyasal etkileşimler kaç ana gruba ayrılır?","steps":[{"t":"İki ana grup","a":"güçlü ve zayıf","d":"Kimyasal etkileşimler güçlü etkileşimler ve zayıf etkileşimler olarak iki gruba ayrılır."},{"t":"Yer","a":"bağ ve molekül arası","d":"Güçlü olanlar atomlar arası bağlar, zayıf olanlar moleküller arası çekimlerdir."}],"ans":"Kimyasal etkileşimler güçlü (atomlar arası bağ) ve zayıf (moleküller arası çekim) olarak iki ana gruba ayrılır."},{"q":"Güçlü etkileşimler (kimyasal bağlar) hangileridir?","steps":[{"t":"Üç tür","a":"iyonik, kovalent, metalik","d":"Güçlü etkileşimler iyonik bağ, kovalent bağ ve metalik bağdır."},{"t":"Konum","a":"atomlar arası","d":"Bu bağlar atomları birbirine bağlayan güçlü kuvvetlerdir."}],"ans":"Güçlü etkileşimler (kimyasal bağlar) iyonik, kovalent ve metalik bağlardır."},{"q":"Zayıf etkileşimler nerede görülür?","steps":[{"t":"Konum","a":"moleküller arasında","d":"Zayıf etkileşimler atomlar arasında değil, moleküller arasında görülür."},{"t":"Örnek","a":"van der Waals, hidrojen bağı","d":"Van der Waals kuvvetleri ve hidrojen bağı zayıf etkileşimlere örnektir."}],"ans":"Zayıf etkileşimler moleküller arasında görülür; van der Waals kuvvetleri ve hidrojen bağı bunlara örnektir."},{"q":"Hidrojen bağı bir kimyasal bağ mıdır, yoksa moleküller arası bir çekim midir?","fig":"<svg viewBox='0 0 320 160'><circle cx='90' cy='70' r='20' fill='#e0552b' stroke='#1a2b45'/><text x='90' y='75' font-size='11' text-anchor='middle' fill='#fff'>O</text><circle cx='128' cy='98' r='12' fill='#cfd8e8' stroke='#1a2b45'/><text x='128' y='102' font-size='9' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='225' cy='115' r='20' fill='#e0552b' stroke='#1a2b45'/><text x='225' y='120' font-size='11' text-anchor='middle' fill='#fff'>O</text><line x1='138' y1='103' x2='208' y2='113' stroke='#2b6be0' stroke-width='2' stroke-dasharray='4 3'/><text x='178' y='98' font-size='9' text-anchor='middle' fill='#1a2b45'>hidrojen bağı</text></svg>","steps":[{"t":"Konum","a":"moleküller arası","d":"Hidrojen bağı atomları birbirine bağlamaz; moleküller arasında oluşur."},{"t":"Sınıf","a":"zayıf etkileşim","d":"Bu yüzden bir kimyasal bağ değil, moleküller arası zayıf bir çekimdir (ama van der Waals'tan güçlüdür)."}],"ans":"Hidrojen bağı bir kimyasal bağ değildir; moleküller arasında oluşan zayıf bir çekimdir (van der Waals'tan güçlüdür)."},{"q":"Van der Waals kuvvetleri nelerdir?","steps":[{"t":"Tür","a":"London ve dipol","d":"Van der Waals kuvvetleri London (dağılma) kuvvetleri ve dipol-dipol çekimlerini kapsar."},{"t":"Güç","a":"en zayıf","d":"Bunlar moleküller arası çekimlerin en zayıf olanlarıdır."}],"ans":"Van der Waals kuvvetleri, moleküller arası en zayıf çekimlerdir; London (dağılma) ve dipol-dipol çekimlerini kapsar."},{"q":"Güçlü ve zayıf etkileşimler arasında genel güç sıralaması nasıldır?","steps":[{"t":"Güçlüler önde","a":"bağlar","d":"Kimyasal bağlar (iyonik, kovalent, metalik) çok güçlüdür."},{"t":"Zayıflar arkada","a":"hidrojen > van der Waals","d":"Moleküller arası çekimler daha zayıftır; hidrojen bağı van der Waals'tan güçlüdür."}],"ans":"Güç sırası genelde: kimyasal bağlar (güçlü) > hidrojen bağı > van der Waals kuvvetleri (en zayıf) şeklindedir."}],"zor":[{"q":"İyonik, kovalent ve metalik bağların ortak özelliği nedir, neden hepsine 'güçlü etkileşim' denir?","steps":[{"t":"Konum","a":"atomlar/iyonlar arası","d":"Üçü de tanecikleri (atom ya da iyon) bir arada tutan, madde içindeki temel bağlardır."},{"t":"Güç","a":"çok enerji ister","d":"Bu bağları kırmak çok enerji gerektirir; bu yüzden hepsi güçlü etkileşim sayılır."}],"ans":"İyonik, kovalent ve metalik bağ tanecikleri madde içinde bir arada tutar ve kırılması yüksek enerji ister; bu yüzden hepsi güçlü etkileşimdir."},{"q":"Neden bir maddeyi eritmek, onun kovalent bağlarını kırmaktan genelde daha kolaydır?","steps":[{"t":"Erimede","a":"molekül arası kuvvet","d":"Moleküler bir madde eridiğinde yalnızca zayıf moleküller arası kuvvetler kırılır."},{"t":"Bağ kırma","a":"çok daha zor","d":"Kovalent bağları kırmak molekülü parçalar ve çok daha fazla enerji ister."}],"ans":"Erimede yalnızca zayıf molekül arası kuvvetler kırıldığından, güçlü kovalent bağları kırmaya göre çok daha az enerji gerekir."},{"q":"London kuvvetleri ile dipol-dipol kuvvetleri arasındaki fark nedir?","steps":[{"t":"London","a":"anlık dipol","d":"London kuvvetleri, elektronların anlık dengesizliğiyle oluşan geçici dipoller arası çekimdir; tüm moleküllerde bulunur."},{"t":"Dipol-dipol","a":"kalıcı dipol","d":"Dipol-dipol kuvvetleri, polar moleküllerin kalıcı kısmi yükleri (δ⁺/δ⁻) arasındaki çekimdir."}],"ans":"London kuvvetleri anlık (geçici) dipoller arası çekim olup tüm moleküllerde bulunur; dipol-dipol ise polar moleküllerin kalıcı dipolleri arasındaki çekimdir."},{"q":"Su molekülleri arasındaki hidrojen bağı, suyun hangi özelliğini açıklar?","fig":"<svg viewBox='0 0 320 160'><circle cx='80' cy='60' r='18' fill='#e0552b' stroke='#1a2b45'/><text x='80' y='65' font-size='10' text-anchor='middle' fill='#fff'>O</text><circle cx='115' cy='85' r='10' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='210' cy='100' r='18' fill='#e0552b' stroke='#1a2b45'/><text x='210' y='105' font-size='10' text-anchor='middle' fill='#fff'>O</text><line x1='123' y1='89' x2='194' y2='98' stroke='#2b6be0' stroke-width='2' stroke-dasharray='4 3'/><text x='160' y='140' font-size='9' text-anchor='middle' fill='#1a2b45'>hidrojen bağı</text></svg>","steps":[{"t":"Çekim","a":"güçlü tutunma","d":"Hidrojen bağı su moleküllerini birbirine alışılmadık ölçüde sıkı tutar."},{"t":"Sonuç","a":"yüksek kaynama","d":"Bu çekimi kırmak için fazla enerji gerektiğinden suyun kaynama noktası beklenenden yüksektir."}],"ans":"Su molekülleri arasındaki hidrojen bağı onları sıkı tuttuğundan suyun kaynama noktası, yüksek yüzey gerilimi gibi özellikleri olağandışı derecede yüksektir."},{"q":"İki maddeden hangisinin erime noktası daha yüksektir: iyonik bağlı tuz mu, yoksa van der Waals'la tutulan parafin mi? Neden?","steps":[{"t":"Tuz","a":"güçlü iyonik bağ","d":"Tuzda iyonlar güçlü iyonik bağlarla tutulur, eritmek çok enerji ister."},{"t":"Parafin","a":"zayıf van der Waals","d":"Parafinde moleküller zayıf van der Waals kuvvetleriyle tutulur, kolayca erir."}],"ans":"Tuzun erime noktası daha yüksektir; çünkü güçlü iyonik bağlar, parafini tutan zayıf van der Waals kuvvetlerinden çok daha fazla enerji ister."}]},"lise":{"kolay":[{"q":"Kimyasal etkileşimleri güçlü ve zayıf olarak sınıflandırınız.","steps":[{"t":"Güçlü","a":"kimyasal bağlar","d":"Güçlü etkileşimler atomlar/iyonlar arası kimyasal bağlardır: iyonik, kovalent ve metalik bağ."},{"t":"Zayıf","a":"moleküller arası","d":"Zayıf etkileşimler moleküller arasında olur: van der Waals (London, dipol-dipol) ve hidrojen bağı."}],"ans":"Güçlü etkileşimler kimyasal bağlardır (iyonik, kovalent, metalik); zayıf etkileşimler moleküller arası kuvvetlerdir (van der Waals ve hidrojen bağı)."},{"q":"Van der Waals kuvvetlerini alt türleriyle açıklayınız.","steps":[{"t":"London","a":"dağılma kuvveti","d":"London (dağılma) kuvvetleri anlık dipollerden doğar, tüm moleküllerde (apolar dahil) bulunur."},{"t":"Dipol-dipol","a":"kalıcı dipol","d":"Dipol-dipol kuvvetleri polar moleküllerin kalıcı dipolleri arasındaki çekimdir."}],"ans":"Van der Waals kuvvetleri; tüm moleküllerde görülen London (dağılma) kuvvetleri ile polar moleküllerdeki dipol-dipol çekimlerini kapsar."},{"q":"Hidrojen bağının oluşma koşulu nedir ve neden van der Waals'tan güçlüdür?","fig":"<svg viewBox='0 0 320 165'><circle cx='80' cy='60' r='20' fill='#e0552b' stroke='#1a2b45'/><text x='80' y='65' font-size='11' text-anchor='middle' fill='#fff'>O</text><circle cx='118' cy='88' r='11' fill='#cfd8e8' stroke='#1a2b45'/><text x='118' y='92' font-size='8' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='220' cy='110' r='20' fill='#5b6b85' stroke='#1a2b45'/><text x='220' y='115' font-size='11' text-anchor='middle' fill='#fff'>N</text><line x1='127' y1='92' x2='203' y2='108' stroke='#2b6be0' stroke-width='2' stroke-dasharray='4 3'/><text x='170' y='100' font-size='9' text-anchor='middle' fill='#1a2b45'>hidrojen bağı</text></svg>","steps":[{"t":"Koşul","a":"H–F/O/N","d":"Hidrojen bağı, H atomunun F, O ya da N gibi çok elektronegatif bir atoma bağlı olmasıyla, komşu molekülün F/O/N'una doğru oluşur."},{"t":"Güç","a":"belirgin kısmi yük","d":"Bu atomlar arasındaki büyük elektronegatiflik farkı belirgin kısmi yükler oluşturur; bu yüzden hidrojen bağı van der Waals'tan güçlüdür."}],"ans":"Hidrojen bağı, F/O/N'a bağlı H ile komşu molekülün F/O/N'u arasında oluşur; oluşan büyük kısmi yükler nedeniyle van der Waals kuvvetlerinden güçlüdür."},{"q":"Genel olarak kimyasal etkileşimlerin güç (kuvvet) sıralamasını yazınız.","steps":[{"t":"Güçlü grup","a":"iyonik/kovalent/metalik","d":"Kimyasal bağlar en güçlüdür ve birbirine yakın büyüklüktedir."},{"t":"Zayıf grup","a":"H bağı > dipol > London","d":"Moleküller arası kuvvetlerde sıralama: hidrojen bağı > dipol-dipol > London kuvvetleri."}],"ans":"Güç sırası genel olarak: kimyasal bağlar (iyonik, kovalent, metalik) ≫ hidrojen bağı > dipol-dipol > London (van der Waals) kuvvetleri şeklindedir."},{"q":"Bir maddenin kaynama noktası ile sahip olduğu etkileşim türü arasındaki ilişki nedir?","steps":[{"t":"Güçlü etkileşim","a":"yüksek kaynama","d":"Madde ne kadar güçlü etkileşimle tutuluyorsa hal değiştirmek için o kadar çok enerji gerekir."},{"t":"Karşılaştırma","a":"H bağlı > apolar","d":"Hidrojen bağı içeren maddelerin kaynama noktası, yalnız London kuvveti taşıyan benzer kütleli apolar maddelerden yüksektir."}],"ans":"Bir maddedeki etkileşim ne kadar güçlüyse kaynama noktası o kadar yüksektir; örneğin hidrojen bağlı maddeler, benzer kütleli apolar (yalnız London) maddelerden daha yüksek sıcaklıkta kaynar."}],"zor":[{"q":"H₂O, H₂S, H₂Se moleküllerinde kaynama noktası beklenenin tersine H₂O'da neden en yüksektir?","steps":[{"t":"Beklenti","a":"kütle artarsa kaynama artar","d":"Molekül kütlesi büyüdükçe London kuvvetleri artar; bu yüzden H₂Se'nin en yüksek beklenir."},{"t":"İstisna","a":"H₂O'da hidrojen bağı","d":"H₂O'da oksijenin yüksek elektronegatifliği güçlü hidrojen bağları oluşturur, diğer ikisinde bu bağ neredeyse yoktur."},{"t":"Sonuç","a":"H₂O en yüksek","d":"Hidrojen bağı London etkisini geride bıraktığından H₂O en yüksek kaynama noktasına sahiptir."}],"ans":"Beklenenin aksine H₂O'nun kaynama noktası en yüksektir; çünkü su molekülleri arasındaki güçlü hidrojen bağları, kütle artışına bağlı London kuvvetlerinin etkisini bastırır."},{"q":"İyonik bağ ile hidrojen bağını güç, konum ve kopma enerjisi açısından karşılaştırınız.","steps":[{"t":"Konum","a":"bağ vs molekül arası","d":"İyonik bağ tanecikler (iyonlar) arası bir kimyasal bağdır; hidrojen bağı ise moleküller arası bir çekimdir."},{"t":"Güç","a":"iyonik ≫ hidrojen","d":"İyonik bağ tipik olarak yüzlerce kJ/mol enerji isterken hidrojen bağı çok daha düşük enerjiyle (onlu kJ/mol) kırılır."},{"t":"Sonuç","a":"farklı olaylar","d":"İyonik bağı kırmak maddeyi parçalar (kimyasal); hidrojen bağını kırmak çoğunlukla hal değiştirir (fiziksel)."}],"ans":"İyonik bağ iyonlar arası güçlü bir kimyasal bağdır ve kırılması yüksek enerji ister; hidrojen bağı ise moleküller arası daha zayıf bir çekim olup düşük enerjiyle (genelde hal değişiminde) kırılır."},{"q":"Apolar bir molekül olan O₂ sıvılaşabilir mi; hangi kuvvet bunu sağlar?","fig":"<svg viewBox='0 0 320 150'><circle cx='90' cy='70' r='20' fill='#e0552b' stroke='#1a2b45'/><circle cx='135' cy='70' r='20' fill='#e0552b' stroke='#1a2b45'/><circle cx='200' cy='95' r='20' fill='#e0552b' stroke='#1a2b45'/><circle cx='245' cy='95' r='20' fill='#e0552b' stroke='#1a2b45'/><line x1='150' y1='75' x2='185' y2='88' stroke='#5b6b85' stroke-width='2' stroke-dasharray='3 3'/><text x='168' y='130' font-size='9' text-anchor='middle' fill='#1a2b45'>London çekimi</text></svg>","steps":[{"t":"Apolar","a":"kalıcı dipol yok","d":"O₂ apolardır; dipol-dipol ya da hidrojen bağı oluşturamaz."},{"t":"London","a":"anlık dipol","d":"Yine de elektronların anlık dengesizliğiyle oluşan London kuvvetleri vardır."},{"t":"Sonuç","a":"çok düşük sıcaklıkta sıvılaşır","d":"Bu zayıf kuvvetler ancak çok düşük sıcaklıkta molekülleri bir arada tutmaya yeter, böylece O₂ sıvılaşabilir."}],"ans":"Evet; O₂ apolar olsa da moleküller arası London (dağılma) kuvvetleri vardır, bu zayıf çekimler çok düşük sıcaklıkta O₂'nin sıvılaşmasını sağlar."},{"q":"Grafit ve elmas yalnızca karbon atomlarından oluştuğu halde özellikleri neden çok farklıdır; bu hangi etkileşimle ilgilidir?","steps":[{"t":"Elmas","a":"3 boyutlu kovalent ağ","d":"Elmasta her karbon dört komşusuyla güçlü kovalent bağ yapar, devasa bir ağ örgüsü oluşur; çok serttir."},{"t":"Grafit","a":"katmanlar arası zayıf kuvvet","d":"Grafitte karbonlar katmanlar halinde kovalent bağlıdır, ama katmanlar arasında yalnızca zayıf van der Waals kuvvetleri vardır."},{"t":"Sonuç","a":"kayganlık","d":"Bu zayıf kuvvetler katmanların birbiri üzerinde kaymasına izin verir; grafit yumuşak ve kaygandır."}],"ans":"Elmasta karbonlar üç boyutlu güçlü kovalent ağ kurduğu için serttir; grafitte ise katmanlar arası yalnızca zayıf van der Waals kuvvetleri olduğundan katmanlar kayar ve grafit yumuşak/kaygandır."},{"q":"Bir maddenin suda iyi çözünmesi ile içerdiği etkileşim türü arasında nasıl bir ilişki vardır?","steps":[{"t":"Kural","a":"benzer benzeri çözer","d":"Çözünme, çözünen ve çözücünün etkileşim türlerinin benzer olmasıyla kolaylaşır."},{"t":"Polar/iyonik","a":"suda çözünür","d":"Su polar ve hidrojen bağı yapan bir çözücüdür; iyonik bileşikler ve polar (hidrojen bağı yapan) moleküller suda iyi çözünür."},{"t":"Apolar","a":"suda çözünmez","d":"Yalnız London kuvveti taşıyan apolar maddeler (yağ gibi) su ile uyumlu etkileşim kuramadığından suda çözünmez."}],"ans":"Su polar ve hidrojen bağı yapan bir çözücü olduğundan, iyonik ve polar maddeler ('benzer benzeri çözer') suda iyi çözünür; apolar (yalnız London kuvvetli) maddeler ise çözünmez."}]}},"hidrojenBagi":{"ilkokul":{"kolay":[{"q":"Su molekülleri birbirine tutunup damla oluşturabilir mi?","steps":[{"t":"Su molekülleri","a":"birbirini çeker","d":"Su molekülleri birbirine doğru hafifçe çekilir, el ele tutuşur gibi."},{"t":"Damla","a":"bir arada durur","d":"Bu çekim sayesinde su molekülleri bir arada kalır ve yuvarlak damlalar oluşur."}],"ans":"Evet; su molekülleri birbirine tutunduğu için bir araya gelip damla oluşturur."},{"q":"Yağmur damlası neden havada dağılmadan yuvarlak kalır?","fig":"<svg viewBox='0 0 320 160'><path d='M160 35 C120 95 120 130 160 130 C200 130 200 95 160 35 Z' fill='#9ccaff' stroke='#1a2b45'/><text x='160' y='105' font-size='12' text-anchor='middle' fill='#1a2b45'>su damlası</text></svg>","steps":[{"t":"Tutunma","a":"birbirine çeker","d":"Damladaki su molekülleri birbirine tutunarak bir arada durur."},{"t":"Yuvarlak biçim","a":"toparlanır","d":"Bu çekim molekülleri içe doğru toplar, böylece damla yuvarlak kalır."}],"ans":"Su molekülleri birbirine güçlü tutunduğundan, damla dağılmaz ve yuvarlak kalır."},{"q":"Buz ısıtılınca neden hemen değil, biraz zaman geçince kaynayıp buhar olur?","steps":[{"t":"Tutunma var","a":"birbirine yapışık","d":"Su molekülleri birbirine sıkıca tutunmuştur, ayrılmak istemez."},{"t":"Isı gerek","a":"ayrılması zaman alır","d":"Molekülleri birbirinden ayırıp buhar yapmak için epeyce ısı ve zaman gerekir."}],"ans":"Su molekülleri birbirine güçlü tutunduğundan, onları ayırıp kaynatmak çok ısı ister; bu yüzden hemen buhar olmaz."},{"q":"Bir bardak suyu ağzına kadar dikkatle doldurduğunda su kenardan biraz taşkın (kabarık) durabilir mi?","fig":"<svg viewBox='0 0 320 165'><rect x='95' y='45' width='130' height='100' fill='none' stroke='#1a2b45' stroke-width='2'/><path d='M97 60 Q160 42 223 60 L223 143 L97 143 Z' fill='#9ccaff' stroke='#1a2b45'/><text x='160' y='160' font-size='10' text-anchor='middle' fill='#1a2b45'>su yüzeyi kabarık durur</text></svg>","steps":[{"t":"Yüzey çekimi","a":"birbirini tutar","d":"Yüzeydeki su molekülleri birbirine tutunarak ince bir 'zar' gibi davranır."},{"t":"Kabarık durur","a":"taşmaz","d":"Bu tutunma sayesinde su, bardağın kenarından biraz yüksekte kabarık durabilir."}],"ans":"Evet; su molekülleri birbirine tutunduğundan, su bardağın ağzından biraz kabarık (taşmadan) durabilir."},{"q":"Su, neden birçok şeyi (şeker, tuz) içinde eritebilir?","steps":[{"t":"Su çekici","a":"tutunmayı sever","d":"Su molekülleri yüklü uçlara sahiptir ve başka taneciklere de tutunmayı sever."},{"t":"Eritme","a":"sarıp dağıtır","d":"Su, şeker ya da tuz taneciklerini sarıp birbirinden ayırarak içinde eritir."}],"ans":"Su molekülleri yüklü uçlarıyla taneciklere tutunup onları sarıp dağıttığı için birçok şeyi eritebilir."}],"zor":[{"q":"Su molekülünün bir tarafı hafif eksi, diğer tarafı hafif artı gibi davranır; bu neden tutunmaya yardım eder?","fig":"<svg viewBox='0 0 320 165'><circle cx='160' cy='70' r='24' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='75' font-size='12' text-anchor='middle' fill='#fff'>O</text><circle cx='118' cy='112' r='14' fill='#cfd8e8' stroke='#1a2b45'/><text x='118' y='116' font-size='9' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='202' cy='112' r='14' fill='#cfd8e8' stroke='#1a2b45'/><text x='202' y='116' font-size='9' text-anchor='middle' fill='#1a2b45'>H</text><text x='160' y='38' font-size='11' text-anchor='middle' fill='#1a2b45'>− uç</text><text x='105' y='148' font-size='10' fill='#1a2b45'>+ uç</text><text x='205' y='148' font-size='10' fill='#1a2b45'>+ uç</text></svg>","steps":[{"t":"İki farklı uç","a":"artı ve eksi","d":"Su molekülünün bir ucu hafif eksi, diğer ucu hafif artıdır."},{"t":"Zıt uçlar çeker","a":"tutunma","d":"Bir molekülün artı ucu, komşu molekülün eksi ucunu çeker; böylece moleküller birbirine tutunur."}],"ans":"Su molekülünün artı ve eksi uçları olduğundan, bir molekülün artı ucu komşunun eksi ucunu çeker ve moleküller birbirine tutunur."},{"q":"Küçük bir böcek (su sineği) neden su yüzeyinde batmadan durabilir?","steps":[{"t":"Yüzey zarı","a":"tutunan moleküller","d":"Yüzeydeki su molekülleri birbirine güçlü tutunarak gergin bir zar gibi davranır."},{"t":"Hafif yük","a":"batmaz","d":"Böcek çok hafif olduğundan bu gergin yüzeyi yırtamaz ve üstünde durabilir."}],"ans":"Su yüzeyindeki moleküller birbirine güçlü tutunup gergin bir zar oluşturur; hafif böcek bu zarı yırtamadığı için batmadan durur."},{"q":"Buz neden suyun üstünde yüzer, dibe batmaz?","steps":[{"t":"Donunca dizilir","a":"aralıklı yapı","d":"Su donunca molekülleri belirli aralıklarla diziler, aralarında boşluk kalır."},{"t":"Daha hafif","a":"yüzer","d":"Boşluklu yapı buzu aynı hacimde sudan daha hafif yapar, bu yüzden buz suyun üstünde yüzer."}],"ans":"Su donarken molekülleri boşluklu (aralıklı) dizildiğinden buz, aynı hacimdeki sudan daha hafif olur ve suyun üstünde yüzer."},{"q":"Islak iki kâğıt birbirine neden yapışır?","steps":[{"t":"Aradaki su","a":"köprü kurar","d":"İki kâğıt arasındaki su molekülleri hem kâğıtlara hem birbirine tutunur."},{"t":"Çekim","a":"yapışma","d":"Bu çekim kâğıtları birbirine doğru çeker, böylece ıslak kâğıtlar yapışır."}],"ans":"Aradaki su molekülleri hem kâğıtlara hem birbirine tutunup köprü kurduğundan, ıslak kâğıtlar birbirine yapışır."},{"q":"Aynı büyüklükte iki gazdan biri kokusuz (apolar), diğeri su gibi tutunan uçlara sahip; hangisi daha zor buhar olur?","steps":[{"t":"Tutunan uçlar","a":"güçlü çekim","d":"Su gibi artı/eksi uçları olan moleküller birbirine güçlü tutunur."},{"t":"Buharlaşma","a":"zor ayrılır","d":"Güçlü tutunan moleküller daha zor ayrılır, bu yüzden daha geç buhar olur (daha yüksek sıcaklıkta kaynar)."}],"ans":"Artı/eksi uçlarıyla birbirine güçlü tutunan (su benzeri) molekül, apolar olandan daha zor buhar olur; çünkü onları ayırmak daha çok ısı ister."}]},"ortaokul":{"kolay":[{"q":"Hidrojen bağı nedir?","steps":[{"t":"H'nin durumu","a":"F/O/N'ye bağlı","d":"Bir molekülde hidrojen (H), çok elektronegatif olan flor (F), oksijen (O) ya da azot (N) atomuna bağlıyken kısmi artı yüklenir."},{"t":"Komşuyu çekme","a":"güçlü çekim","d":"Bu kısmi artı H, komşu molekülün F/O/N atomunun ortaklanmamış elektron çiftini güçlü çeker; bu çekime hidrojen bağı denir."}],"ans":"Hidrojen bağı, F/O/N'ye bağlı kısmi artı H ile komşu moleküldeki F/O/N atomu arasındaki güçlü çekimdir."},{"q":"Hidrojen bağı hangi atomlarla oluşur?","steps":[{"t":"H gerekli","a":"F/O/N'ye bağlı","d":"Hidrojen bağı için H'nin flor, oksijen ya da azota (F, O, N) bağlı olması gerekir."},{"t":"Karşıda da F/O/N","a":"elektronegatif","d":"Karşıdaki molekülde de yine F, O veya N gibi çok elektronegatif bir atom bulunmalıdır."}],"ans":"Hidrojen bağı, H'nin F/O/N'ye bağlı olduğu durumda komşu moleküldeki F, O veya N atomuyla oluşur."},{"q":"Su moleküllerinin yüksek kaynama noktasının nedeni nedir?","fig":"<svg viewBox='0 0 320 165'><circle cx='90' cy='65' r='18' fill='#e0552b' stroke='#1a2b45'/><text x='90' y='70' font-size='10' text-anchor='middle' fill='#fff'>O</text><circle cx='128' cy='92' r='11' fill='#cfd8e8' stroke='#1a2b45'/><text x='128' y='96' font-size='8' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='220' cy='112' r='18' fill='#e0552b' stroke='#1a2b45'/><text x='220' y='117' font-size='10' text-anchor='middle' fill='#fff'>O</text><line x1='138' y1='96' x2='205' y2='110' stroke='#2b6be0' stroke-width='2' stroke-dasharray='4 3'/><text x='175' y='90' font-size='9' text-anchor='middle' fill='#1a2b45'>hidrojen bağı</text></svg>","steps":[{"t":"H bağları","a":"moleküller arası","d":"Su molekülleri arasında çok sayıda hidrojen bağı bulunur, bunlar molekülleri sıkıca bir arada tutar."},{"t":"Kaynama","a":"çok ısı gerekir","d":"Kaynamak için bu hidrojen bağlarının kopması gerekir; bu da fazladan enerji ister, kaynama noktası yükselir."}],"ans":"Su moleküllerini bir arada tutan hidrojen bağlarını koparmak fazladan enerji gerektirdiğinden suyun kaynama noktası yüksektir."},{"q":"Hidrojen bağının bulunduğu üç madde örneği nedir?","steps":[{"t":"Yaygın örnekler","a":"su, HF, NH₃","d":"Su (H₂O), hidrojen florür (HF) ve amonyak (NH₃) molekülleri arasında hidrojen bağı bulunur."},{"t":"Ortak özellik","a":"H + F/O/N","d":"Üçünde de H, çok elektronegatif F, O ya da N atomuna bağlıdır."}],"ans":"Su (H₂O), hidrojen florür (HF) ve amonyak (NH₃) hidrojen bağı içeren madde örnekleridir."},{"q":"Hidrojen bağı, diğer moleküller arası çekimlere göre güçlü müdür zayıf mıdır?","steps":[{"t":"Karşılaştırma","a":"en güçlü zayıf etkileşim","d":"Hidrojen bağı, moleküller arası zayıf çekimlerin en güçlüsüdür."},{"t":"Bağlardan zayıf","a":"kovalentten zayıf","d":"Yine de molekül içindeki kovalent ya da iyonik bağlardan daha zayıftır."}],"ans":"Hidrojen bağı, moleküller arası etkileşimlerin en güçlüsüdür; ama kovalent ve iyonik bağlardan zayıftır."}],"zor":[{"q":"Neden H₂O'nun kaynama noktası H₂S'ten yüksektir?","steps":[{"t":"H₂O'da H bağı","a":"O elektronegatif","d":"Oksijen çok elektronegatif olduğundan su molekülleri arasında güçlü hidrojen bağı oluşur."},{"t":"H₂S'te yok","a":"S zayıf çeker","d":"Kükürt yeterince elektronegatif olmadığından H₂S'te hidrojen bağı oluşmaz, moleküller daha zayıf tutunur."}],"ans":"Su molekülleri arasında güçlü hidrojen bağı varken H₂S'te yoktur; bu yüzden H₂O'nun kaynama noktası H₂S'ten yüksektir."},{"q":"DNA'nın iki ipliğini bir arada hangi etkileşim tutar?","steps":[{"t":"Bazlar arası","a":"hidrojen bağı","d":"DNA'nın iki ipliğindeki bazlar birbirine hidrojen bağlarıyla tutunur."},{"t":"Çok ama zayıf","a":"açılabilir","d":"Tek tek zayıf olan bu bağlar sayıca çok olduğundan ipliği bir arada tutar; gerektiğinde kolayca açılabilir."}],"ans":"DNA'nın iki ipliğini, bazlar arasındaki hidrojen bağları bir arada tutar; bu bağlar gerektiğinde açılabilecek kadar uygundur."},{"q":"Buzun sudan daha az yoğun olması (yüzmesi) hidrojen bağıyla nasıl açıklanır?","fig":"<svg viewBox='0 0 320 160'><circle cx='100' cy='60' r='13' fill='#9ccaff' stroke='#1a2b45'/><circle cx='160' cy='50' r='13' fill='#9ccaff' stroke='#1a2b45'/><circle cx='220' cy='60' r='13' fill='#9ccaff' stroke='#1a2b45'/><circle cx='130' cy='105' r='13' fill='#9ccaff' stroke='#1a2b45'/><circle cx='190' cy='105' r='13' fill='#9ccaff' stroke='#1a2b45'/><line x1='112' y1='62' x2='148' y2='53' stroke='#2b6be0' stroke-dasharray='3 3'/><line x1='172' y1='53' x2='208' y2='61' stroke='#2b6be0' stroke-dasharray='3 3'/><line x1='105' y1='71' x2='123' y2='94' stroke='#2b6be0' stroke-dasharray='3 3'/><text x='160' y='145' font-size='10' text-anchor='middle' fill='#1a2b45'>açık altıgen örgü</text></svg>","steps":[{"t":"Donunca dizilim","a":"açık örgü","d":"Su donarken hidrojen bağları molekülleri düzenli, boşluklu bir altıgen örgüye yerleştirir."},{"t":"Daha az yoğun","a":"yüzer","d":"Bu açık örgü, buzun hacmini büyütüp yoğunluğunu düşürür; bu yüzden buz su üzerinde yüzer."}],"ans":"Hidrojen bağları su donarken molekülleri açık (boşluklu) bir örgüye dizer; buz daha az yoğun olduğundan suyun üstünde yüzer."},{"q":"Hidrojen bağının normal bir dipol-dipol etkileşiminden farkı nedir?","steps":[{"t":"Özel koşul","a":"H + F/O/N","d":"Hidrojen bağında H'nin F, O ya da N gibi çok elektronegatif bir atoma bağlı olması şarttır; sıradan dipol-dipolde bu özel koşul yoktur."},{"t":"Çok güçlü","a":"küçük H + yüksek yük","d":"Çok küçük ve neredeyse çıplak kısmi artı H, komşu atomun elektron çiftine çok yaklaşabildiğinden hidrojen bağı diğer dipol-dipol çekimlerden belirgin güçlüdür."}],"ans":"Hidrojen bağı, H'nin F/O/N'ye bağlı olduğu özel ve çok güçlü bir dipol-dipol etkileşimidir; sıradan dipol-dipolden bu özel koşulu ve daha yüksek gücüyle ayrılır."},{"q":"Proteinlerin belirli bir şekle katlanmasında hidrojen bağının rolü nedir?","steps":[{"t":"Zincir içi çekim","a":"H bağları kurar","d":"Protein zincirindeki uygun gruplar (örneğin C=O ve N–H) arasında hidrojen bağları oluşur."},{"t":"Şekli sabitler","a":"katlanma","d":"Bu çok sayıda hidrojen bağı zinciri belirli sarmal/katlı şekillerde tutarak proteinin işlevsel yapısını sabitler."}],"ans":"Protein zincirindeki gruplar arasında oluşan çok sayıda hidrojen bağı, zinciri belirli bir şekilde katlayıp tutarak proteinin işlevsel yapısını sabitler."}]},"lise":{"kolay":[{"q":"Hidrojen bağının oluşum koşullarını açıklayınız.","steps":[{"t":"Bağlı H","a":"F/O/N'ye bağlı","d":"Hidrojen, kendinden çok daha elektronegatif olan F, O ya da N atomuna kovalent bağlı olmalı ve böylece yüksek kısmi artı (δ⁺) yük taşımalıdır."},{"t":"Alıcı atom","a":"ortaklanmamış çift","d":"Karşıda ortaklanmamış elektron çifti bulunan bir F, O veya N atomu bulunmalıdır; δ⁺ H ile bu çift arasındaki güçlü çekim hidrojen bağını oluşturur."}],"ans":"Hidrojen bağı, F/O/N'ye bağlı δ⁺ yüklü H ile ortaklanmamış elektron çifti taşıyan bir F/O/N atomu arasında oluşur."},{"q":"Neden H₂O'nun kaynama noktası, H₂S'ten beklenenin aksine daha yüksektir?","fig":"<svg viewBox='0 0 320 165'><circle cx='90' cy='62' r='18' fill='#e0552b' stroke='#1a2b45'/><text x='90' y='67' font-size='10' text-anchor='middle' fill='#fff'>O</text><circle cx='128' cy='90' r='11' fill='#cfd8e8' stroke='#1a2b45'/><text x='128' y='94' font-size='8' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='220' cy='110' r='18' fill='#e0552b' stroke='#1a2b45'/><text x='220' y='115' font-size='10' text-anchor='middle' fill='#fff'>O</text><line x1='138' y1='94' x2='205' y2='108' stroke='#2b6be0' stroke-width='2' stroke-dasharray='4 3'/><text x='175' y='88' font-size='9' text-anchor='middle' fill='#1a2b45'>H bağı</text></svg>","steps":[{"t":"O elektronegatif","a":"güçlü H bağı","d":"Oksijen çok elektronegatif olduğundan su molekülleri arasında güçlü hidrojen bağları oluşur."},{"t":"S'te H bağı yok","a":"yalnız zayıf kuvvet","d":"Kükürt daha az elektronegatif olduğundan H₂S'te hidrojen bağı oluşmaz, sadece zayıf van der Waals kuvvetleri vardır; bu yüzden H₂S daha düşük sıcaklıkta kaynar."}],"ans":"Su molekülleri arasında güçlü hidrojen bağı varken H₂S'te yalnızca zayıf van der Waals kuvvetleri bulunur; bu nedenle H₂O'nun kaynama noktası H₂S'ten yüksektir."},{"q":"Hidrojen bağının canlılar için önemine iki örnek veriniz.","steps":[{"t":"DNA","a":"baz çiftleri","d":"DNA'nın iki ipliğindeki tamamlayıcı bazları hidrojen bağları bir arada tutar; bu bağlar replikasyonda kolay açılabilir."},{"t":"Proteinler","a":"katlanma","d":"Proteinlerin sarmal/katlı yapılarını (ikincil yapı) hidrojen bağları kararlı tutar; bu da işlevleri için gereklidir."}],"ans":"Hidrojen bağları DNA'nın baz çiftlerini bir arada tutar ve proteinlerin katlanmış yapısını kararlı kılar; her ikisi de yaşam için temeldir."},{"q":"Suyun yüksek özısısı (çok ısı depolayabilmesi) hidrojen bağıyla nasıl ilişkilidir?","steps":[{"t":"Verilen ısı","a":"H bağına gider","d":"Suya verilen ısı enerjisinin önemli kısmı, sıcaklığı yükseltmeden önce hidrojen bağlarını zorlamak/koparmak için harcanır."},{"t":"Yavaş ısınma","a":"yüksek özısı","d":"Bu nedenle suyun sıcaklığı yavaş yükselir; yani su yüksek özısıya sahiptir ve çok ısı depolayabilir."}],"ans":"Suya verilen ısının çoğu önce hidrojen bağlarını zorladığından su yavaş ısınır; bu da suyun yüksek özısıya sahip olmasını sağlar."},{"q":"HF'nin, kendinden daha ağır HCl'ye göre beklenmedik biçimde yüksek kaynama noktasına sahip olmasının nedeni nedir?","steps":[{"t":"HF'de H bağı","a":"F çok elektronegatif","d":"Flor en elektronegatif element olduğundan HF molekülleri arasında güçlü hidrojen bağları oluşur."},{"t":"HCl'de yok","a":"yalnız dipol-dipol","d":"Klor F kadar elektronegatif olmadığından HCl'de hidrojen bağı oluşmaz; daha ağır olmasına rağmen sadece zayıf dipol-dipol çekimleri vardır, bu yüzden daha düşük sıcaklıkta kaynar."}],"ans":"HF molekülleri arasında güçlü hidrojen bağı bulunurken HCl'de yalnızca zayıf dipol-dipol çekimleri vardır; bu yüzden daha hafif olan HF, HCl'den daha yüksek sıcaklıkta kaynar."}],"zor":[{"q":"Hidrojen bağının neden olağan dipol-dipol etkileşimlerinden belirgin biçimde güçlü olduğunu mekanizmasıyla açıklayınız.","fig":"<svg viewBox='0 0 320 170'><circle cx='80' cy='70' r='20' fill='#e0552b' stroke='#1a2b45'/><text x='80' y='75' font-size='10' text-anchor='middle' fill='#fff'>O</text><circle cx='124' cy='95' r='10' fill='#cfd8e8' stroke='#1a2b45'/><text x='124' y='99' font-size='8' text-anchor='middle' fill='#1a2b45'>H</text><text x='124' y='118' font-size='9' text-anchor='middle' fill='#1a2b45'>δ⁺</text><circle cx='225' cy='100' r='20' fill='#5b6b85' stroke='#1a2b45'/><text x='225' y='105' font-size='10' text-anchor='middle' fill='#fff'>N</text><text x='225' y='135' font-size='9' text-anchor='middle' fill='#1a2b45'>δ⁻ (yalın çift)</text><line x1='134' y1='97' x2='208' y2='100' stroke='#2b6be0' stroke-width='2' stroke-dasharray='4 3'/></svg>","steps":[{"t":"Çıplak proton etkisi","a":"küçük, yüksek yük yoğunluğu","d":"H'nin tek elektronu güçlü bir şekilde F/O/N'ye çekildiğinden, neredeyse çıplak ve çok küçük bir δ⁺ çekirdek kalır; yük yoğunluğu çok yüksektir."},{"t":"Yakın temas","a":"yalın çifte yaklaşma","d":"Bu küçük δ⁺ H, alıcı atomun ortaklanmamış elektron çiftine çok yakın yaklaşabilir; mesafe küçüldükçe elektrostatik çekim güçlenir, bu da hidrojen bağını sıradan dipol-dipolden güçlü kılar."}],"ans":"H'nin elektronu F/O/N'ye güçlü çekilince geriye küçük, yüksek yük yoğunluklu neredeyse çıplak bir δ⁺ proton kalır; bu, alıcının yalın çiftine çok yaklaşabildiğinden hidrojen bağı olağan dipol-dipolden belirgin güçlüdür."},{"q":"Suyun yüksek yüzey gerilimi ve kohezyonu hidrojen bağı ağıyla nasıl açıklanır?","steps":[{"t":"Hacim içi denge","a":"her yöne H bağı","d":"Sıvının iç kısmındaki bir su molekülü çevresindeki moleküllerle her yönde hidrojen bağı yapar, net kuvvet dengelidir."},{"t":"Yüzeyde içe çekme","a":"yüzey gerilimi","d":"Yüzeydeki moleküllerin üstünde komşu olmadığından sadece içe ve yana çekilirler; bu içe çekim yüzeyi gergin (yüzey gerilimi) yapar ve molekülleri bir arada tutar (kohezyon)."}],"ans":"Su molekülleri arasındaki yoğun hidrojen bağı ağı, yüzeydeki molekülleri içe doğru çekerek yüzey gerilimini ve molekülleri bir arada tutan kohezyonu oluşturur."},{"q":"Etanol (C₂H₅OH) ile dimetil eter (CH₃OCH₃) aynı molekül formülüne sahip olduğu halde etanolün kaynama noktası neden çok daha yüksektir?","steps":[{"t":"Etanolde O–H","a":"H bağı kurar","d":"Etanolde −OH grubundaki H, oksijene bağlı olduğundan molekülleri arasında hidrojen bağı oluşur."},{"t":"Eterde O–H yok","a":"H bağı yok","d":"Dimetil eterde H'ler yalnızca karbona bağlıdır; O–H bulunmadığından moleküller arası hidrojen bağı oluşmaz, yalnızca daha zayıf dipol-dipol/London kuvvetleri vardır, bu yüzden çok daha düşük sıcaklıkta kaynar."}],"ans":"Etanol −OH grubuyla moleküller arası hidrojen bağı kurar; dimetil eterde O–H bulunmadığından bu bağ oluşmaz, yalnızca zayıf kuvvetler vardır, bu yüzden etanolün kaynama noktası belirgin yüksektir."},{"q":"Molekül içi (intramoleküler) hidrojen bağı ile moleküller arası (intermoleküler) hidrojen bağının madde özelliklerine etkisi nasıl farklılaşır?","steps":[{"t":"Molekül içi","a":"aynı molekülde","d":"Molekül içi hidrojen bağı, aynı molekülün iki grubu arasında oluşur; molekülü kendine kapatır ve komşu moleküllerle bağlanmayı azaltabilir."},{"t":"Moleküller arası","a":"komşu moleküller","d":"Moleküller arası hidrojen bağı farklı molekülleri birbirine bağlar; bu, kaynama noktasını ve viskoziteyi belirgin biçimde yükseltir. Molekül içi bağ ise genelde kaynama noktasını düşürür."}],"ans":"Moleküller arası hidrojen bağı molekülleri birbirine bağlayarak kaynama noktası ve viskoziteyi yükseltir; molekül içi hidrojen bağı ise molekülü kendine kapatıp komşularla bağlanmayı azalttığından bu özellikleri genelde düşürür."},{"q":"Hidrojen bağının kovalent bağa kısmen benzediği yönündeki modern yorum nasıl açıklanır?","steps":[{"t":"Yön bağımlılığı","a":"doğrusala yatkın","d":"Sıradan elektrostatik çekimlerden farklı olarak hidrojen bağı belirli bir yön (genelde D–H···A doğrusala yakın) tercih eder; bu yönelim kovalent bağ benzeri bir özelliktir."},{"t":"Kısmi örtüşme","a":"yalın çift–σ* örtüşmesi","d":"Modern model, alıcının yalın çiftinin, D–H bağının boş σ* orbitaliyle kısmen örtüşerek az miktarda elektron yoğunluğu paylaştığını söyler; bu kısmi kovalent katkı, hidrojen bağının yönlü ve güçlü olmasını açıklar."}],"ans":"Hidrojen bağı yalnız elektrostatik değildir; alıcının yalın çifti, D–H bağının σ* orbitaliyle kısmen örtüşüp az elektron paylaşır. Bu kısmi kovalent katkı, hidrojen bağının belirli yönde (doğrusala yakın) ve görece güçlü olmasını açıklar."}]}},"iyonDipol":{"ilkokul":{"kolay":[{"q":"Tuzu suya atınca tuz tanesi neden gözden kaybolur (çözünür)?","steps":[{"t":"Su yardımı","a":"su tanecikleri sarar","d":"Su tanecikleri tuzun küçük parçacıklarını her yandan sarar."},{"t":"Dağılma","a":"suya karışır","d":"Sarılan parçacıklar suyun içine dağılır ve gözle görünmez olur, yani çözünür."}],"ans":"Su tanecikleri tuzun parçacıklarını sarıp suya dağıttığı için tuz görünmez olur, yani çözünür."},{"q":"Su taneciğinin bir ucu hafif artı, bir ucu hafif eksi olması neye yarar?","steps":[{"t":"İki uçlu","a":"+ ve − uç","d":"Su taneciğinin bir tarafı hafif artı, diğer tarafı hafif eksidir."},{"t":"Tutunma","a":"yüklü taneye yapışır","d":"Bu sayede su, artı ya da eksi yüklü tanecikleri uygun ucuyla çekip tutabilir."}],"ans":"Suyun bir ucu artı bir ucu eksi olduğu için yüklü tanecikleri çekip tutmasına yarar."},{"q":"Yemek tuzu suda mı yoksa zeytinyağında mı daha kolay çözünür?","steps":[{"t":"Su","a":"yüklü uçları var","d":"Su tanecikleri yüklü olduğundan tuzun parçacıklarını çeker ve çözer."},{"t":"Yağ","a":"yüklü uç yok","d":"Yağ taneciklerinde böyle güçlü artı-eksi uçlar yoktur, tuzu çözemez."}],"ans":"Yemek tuzu suda kolay çözünür, zeytinyağında çözünmez."},{"q":"Bir su taneciği, eksi yüklü bir taneciğe hangi ucuyla döner?","fig":"<svg viewBox='0 0 320 130'><circle cx='90' cy='65' r='24' fill='#9ed9a8' stroke='#1a2b45'/><text x='90' y='70' font-size='11' text-anchor='middle' fill='#1a2b45'>−</text><circle cx='200' cy='65' r='18' fill='#e0552b' stroke='#1a2b45'/><text x='200' y='70' font-size='10' text-anchor='middle' fill='#fff'>O</text><circle cx='235' cy='45' r='9' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='235' cy='85' r='9' fill='#cfd8e8' stroke='#1a2b45'/><text x='168' y='40' font-size='9' fill='#1a2b45'>su + ucu</text><line x1='114' y1='65' x2='182' y2='65' stroke='#2b6be0' stroke-width='1.5' stroke-dasharray='4 3'/></svg>","steps":[{"t":"Çekim","a":"zıt çeker","d":"Eksi yüklü tanecik, suyun artı ucunu çeker."},{"t":"Yönelme","a":"artı uç döner","d":"Su, hidrojenlerin bulunduğu artı ucuyla eksi taneciğe döner."}],"ans":"Su taneciği, eksi yüklü taneciğe artı ucuyla (hidrojen tarafıyla) döner."},{"q":"Şekeri ya da tuzu suda karıştırınca daha çabuk çözünür mü?","steps":[{"t":"Karıştırma","a":"su yeniler","d":"Karıştırınca tanecik çevresine sürekli yeni su tanecikleri gelir."},{"t":"Sonuç","a":"daha hızlı","d":"Böylece su parçacıkları daha çabuk sarar ve çözünme hızlanır."}],"ans":"Evet, karıştırınca su tanecikleri taneyi daha hızlı sardığı için daha çabuk çözünür."}],"zor":[{"q":"Su, neden tuzdaki artı taneciği de eksi taneciği de çekebilir?","steps":[{"t":"İki uçlu su","a":"+ ve − uç","d":"Suyun hem artı ucu hem eksi ucu vardır."},{"t":"Uygun ucu seçer","a":"zıt yükü çeker","d":"Artı taneye eksi ucuyla, eksi taneye artı ucuyla döner; böylece her iki yüklü taneyi de çeker."}],"ans":"Suyun hem artı hem eksi ucu olduğu için, uygun ucunu kullanarak hem artı hem eksi tanecikleri çekebilir."},{"q":"Su tanecikleri tuzun parçacığını sardığında o parçacık ne olur?","steps":[{"t":"Sarma","a":"her yandan su","d":"Su tanecikleri yüklü parçacığı her taraftan sarar."},{"t":"Kopma","a":"katıdan ayrılır","d":"Bu sayede parçacık katı tuzdan kopar ve suyun içinde serbestçe dolaşır."}],"ans":"Su tanecikleri parçacığı sarınca onu katı tuzdan koparır ve suda serbestçe dağılmasını sağlar."},{"q":"Su taneciği bir artı yüklü taneciğe hangi ucuyla yönelir, neden?","fig":"<svg viewBox='0 0 320 130'><circle cx='95' cy='65' r='24' fill='#cfd8e8' stroke='#1a2b45'/><text x='95' y='70' font-size='11' text-anchor='middle' fill='#1a2b45'>+</text><circle cx='205' cy='65' r='18' fill='#e0552b' stroke='#1a2b45'/><text x='205' y='70' font-size='10' text-anchor='middle' fill='#fff'>O</text><text x='168' y='40' font-size='9' fill='#1a2b45'>su − ucu</text><line x1='119' y1='65' x2='187' y2='65' stroke='#2b6be0' stroke-width='1.5' stroke-dasharray='4 3'/></svg>","steps":[{"t":"Eksi uç","a":"oksijen tarafı","d":"Suyun eksi ucu, oksijenin bulunduğu taraftır."},{"t":"Çekim","a":"artıya döner","d":"Artı yüklü tanecik, suyun bu eksi ucunu çeker; zıt yükler birbirini çektiği için su eksi ucuyla döner."}],"ans":"Su, artı yüklü taneciğe eksi ucuyla (oksijen tarafıyla) döner, çünkü zıt yükler birbirini çeker."},{"q":"Aynı tuz, soğuk suya göre sıcak suda neden daha kolay çözünür?","steps":[{"t":"Sıcak su","a":"tanecikler hızlı","d":"Sıcak suda tanecikler daha hızlı hareket eder."},{"t":"Daha çok çarpışma","a":"hızlı sarma","d":"Hızlı tanecikler tuz parçacıklarını daha sık çarpıp daha çabuk sarar, çözünme hızlanır."}],"ans":"Sıcak suda tanecikler hızlı hareket edip tuzu daha çabuk sardığından çözünme daha kolay olur."},{"q":"Suyu yüklü tanecikleri çeken küçük mıknatıslara benzetebilir miyiz?","steps":[{"t":"Benzetme","a":"iki uçlu","d":"Su, bir ucu artı bir ucu eksi olduğu için küçük bir mıknatıs gibidir."},{"t":"Çekim","a":"zıt ucu çeker","d":"Mıknatıs gibi, suyun her ucu kendine zıt yüklü taneciği çeker."}],"ans":"Evet; su, iki uçlu küçük bir mıknatıs gibi davranıp zıt yüklü tanecikleri çeker."}]},"ortaokul":{"kolay":[{"q":"İyon-dipol etkileşimi hangi iki tanecik türü arasında oluşur?","steps":[{"t":"Birinci taraf","a":"iyon","d":"Bir tarafta yüklü bir tanecik, yani iyon (örneğin Na⁺ veya Cl⁻) bulunur."},{"t":"İkinci taraf","a":"polar molekül","d":"Diğer tarafta kalıcı dipole sahip polar bir molekül (örneğin H₂O) bulunur."}],"ans":"İyon-dipol etkileşimi, bir iyon ile bir polar molekül arasında oluşur."},{"q":"NaCl suda çözünürken Na⁺ iyonunu su molekülünün hangi ucu çeker?","fig":"<svg viewBox='0 0 320 145'><circle cx='160' cy='70' r='20' fill='#cfd8e8' stroke='#1a2b45'/><text x='160' y='75' font-size='11' text-anchor='middle' fill='#1a2b45'>Na⁺</text><circle cx='250' cy='70' r='16' fill='#e0552b' stroke='#1a2b45'/><text x='250' y='75' font-size='9' text-anchor='middle' fill='#fff'>O</text><text x='235' y='52' font-size='9' fill='#1a2b45'>δ⁻</text><circle cx='70' cy='70' r='16' fill='#e0552b' stroke='#1a2b45'/><text x='70' y='75' font-size='9' text-anchor='middle' fill='#fff'>O</text><text x='55' y='52' font-size='9' fill='#1a2b45'>δ⁻</text><line x1='86' y1='70' x2='140' y2='70' stroke='#2b6be0' stroke-width='1.5' stroke-dasharray='4 3'/><line x1='180' y1='70' x2='234' y2='70' stroke='#2b6be0' stroke-width='1.5' stroke-dasharray='4 3'/></svg>","steps":[{"t":"Na⁺ yükü","a":"artı","d":"Sodyum iyonu Na⁺ artı yüklüdür."},{"t":"Su ucu","a":"oksijen (δ⁻)","d":"Suyun oksijen ucu kısmi eksi (δ⁻) olduğundan artı Na⁺ iyonunu çeker; su oksijen ucuyla iyona döner."}],"ans":"Na⁺ iyonunu su molekülünün kısmi eksi (δ⁻) oksijen ucu çeker."},{"q":"İyonik bir katı (tuz) suda nasıl çözünür?","steps":[{"t":"Su yönelir","a":"uygun uç döner","d":"Su molekülleri katının iyonlarına zıt uçlarıyla döner: artı iyona oksijen (δ⁻) ucu, eksi iyona hidrojen (δ⁺) ucu."},{"t":"İyon ayrılır","a":"örgüden kopar","d":"Yeterince su molekülü bir iyonu çevreleyince iyon kristal örgüden kopar ve suya geçer."}],"ans":"Su molekülleri iyonları zıt uçlarıyla çekip çevreler, böylece iyonlar kristal örgüden kopar ve tuz suda çözünür."},{"q":"Su molekülünün bir iyonu çevrelemesine ne ad verilir?","steps":[{"t":"Çevreleme","a":"su kabuğu","d":"Çözünen iyonun etrafını su molekülleri bir kabuk gibi sarar."},{"t":"Adı","a":"hidratasyon","d":"Su molekülleri ile iyonun bu şekilde sarılmasına hidratasyon (suyla çevrelenme) denir."}],"ans":"İyonun su molekülleriyle çevrelenmesine hidratasyon denir."},{"q":"İyon-dipol etkileşimi neden dipol-dipol etkileşiminden daha güçlüdür?","steps":[{"t":"İyon yükü","a":"tam yük","d":"İyonda tam (büyük) bir yük vardır."},{"t":"Dipol yükü","a":"kısmi yük","d":"Polar molekülde ise sadece kısmi (küçük) δ yükü vardır; tam yük daha güçlü çektiğinden iyon-dipol daha güçlüdür."}],"ans":"İyonda tam yük, dipolde ise yalnızca kısmi yük olduğundan iyon-dipol etkileşimi dipol-dipolden daha güçlüdür."}],"zor":[{"q":"NaCl'nin suda çözünmesini iyon-dipol etkileşimiyle adım adım açıklayınız.","fig":"<svg viewBox='0 0 320 155'><rect x='30' y='40' width='70' height='70' fill='none' stroke='#1a2b45'/><text x='48' y='65' font-size='10' fill='#1a2b45'>Na⁺</text><text x='70' y='90' font-size='10' fill='#1a2b45'>Cl⁻</text><text x='65' y='128' font-size='9' text-anchor='middle' fill='#1a2b45'>kristal NaCl</text><line x1='105' y1='75' x2='150' y2='75' stroke='#1a2b45' stroke-width='2'/><polygon points='150,75 140,70 140,80' fill='#1a2b45'/><circle cx='210' cy='60' r='16' fill='#cfd8e8' stroke='#1a2b45'/><text x='210' y='65' font-size='9' text-anchor='middle' fill='#1a2b45'>Na⁺</text><circle cx='265' cy='60' r='12' fill='#e0552b' stroke='#1a2b45'/><circle cx='180' cy='60' r='12' fill='#e0552b' stroke='#1a2b45'/><circle cx='265' cy='105' r='16' fill='#9ed9a8' stroke='#1a2b45'/><text x='265' y='110' font-size='9' text-anchor='middle' fill='#1a2b45'>Cl⁻</text><text x='220' y='140' font-size='9' text-anchor='middle' fill='#1a2b45'>su ile sarılmış iyonlar</text></svg>","steps":[{"t":"Su yönelimi","a":"zıt uçlar","d":"Su molekülleri NaCl yüzeyindeki iyonlara döner: oksijen (δ⁻) ucu Na⁺'ya, hidrojen (δ⁺) ucu Cl⁻'ye yönelir."},{"t":"İyon-dipol çekimi","a":"örgü zayıflar","d":"Bu iyon-dipol çekimleri, iyonları kristal örgüde tutan iyonik bağdan gelen çekimi yener."},{"t":"Hidratasyon","a":"iyon suya geçer","d":"İyonlar örgüden koparak su molekülleriyle çevrelenir (hidrate olur) ve çözeltiye dağılır."}],"ans":"Su molekülleri iyonlara zıt uçlarıyla yönelir, iyon-dipol çekimleri örgü çekimini yener ve hidratlanan Na⁺ ile Cl⁻ iyonları suya geçerek NaCl çözünür."},{"q":"Bir iyonun yükü arttıkça iyon-dipol etkileşiminin gücü nasıl değişir?","steps":[{"t":"Yük etkisi","a":"çekim artar","d":"İyonun yükü büyüdükçe (örneğin +1 yerine +2) su moleküllerini çekme gücü artar."},{"t":"Karşılaştırma","a":"Mg²⁺ > Na⁺","d":"Bu nedenle Mg²⁺ gibi iki değerli bir iyon, Na⁺ gibi tek değerli iyona göre suyu daha güçlü çeker, daha güçlü hidratlanır."}],"ans":"İyonun yükü arttıkça iyon-dipol etkileşimi güçlenir; bu yüzden Mg²⁺, Na⁺'dan daha güçlü iyon-dipol çekimi yapar."},{"q":"İyonik bir katının suda çözünebilmesi için iyon-dipol çekimlerinin neyi yenmesi gerekir?","steps":[{"t":"Örgü çekimi","a":"iyonik bağ","d":"Kristalde iyonlar, zıt yüklü komşularıyla güçlü iyonik (örgü) çekimle tutulur."},{"t":"Koşul","a":"iyon-dipol > örgü","d":"İyonun çözünmesi için su moleküllerinin sağladığı iyon-dipol çekiminin, örgüyü ayakta tutan çekimi yenebilmesi gerekir."}],"ans":"Çözünme için su moleküllerinin sağladığı iyon-dipol çekimlerinin, iyonları örgüde tutan iyonik (örgü) çekimini yenmesi gerekir."},{"q":"İyon-dipol etkileşimi neden iyonik bağdan zayıf, dipol-dipolden güçlüdür?","steps":[{"t":"İyonik bağa göre","a":"daha zayıf","d":"İyonik bağ iki tam yüklü iyon (± ile ±) arasındadır; iyon-dipol ise tam yük ile kısmi yük (± ile δ) arasındadır, bu yüzden daha zayıftır."},{"t":"Dipol-dipole göre","a":"daha güçlü","d":"Dipol-dipol iki kısmi yük (δ ile δ) arasındadır; iyon-dipolde bir tarafta tam yük olduğundan dipol-dipolden güçlüdür."}],"ans":"İyon-dipol, tam yük ile kısmi yük arasındadır; iki tam yükün olduğu iyonik bağdan zayıf, iki kısmi yükün olduğu dipol-dipolden ise güçlüdür."},{"q":"Apolar bir çözücüde (örneğin hekzan) tuz neden çözünmez, iyon-dipol açısından açıklayınız.","steps":[{"t":"Apolar çözücü","a":"dipol yok","d":"Hekzan gibi apolar moleküllerde kalıcı dipol (δ⁺/δ⁻ uçlar) bulunmaz."},{"t":"İyon-dipol kurulamaz","a":"çekim zayıf","d":"Dipol olmadığından çözücü, iyonları çekecek güçlü iyon-dipol etkileşimi oluşturamaz; örgüyü yenecek çekim sağlanamaz."}],"ans":"Apolar çözücüde kalıcı dipol bulunmadığından güçlü iyon-dipol çekimi oluşamaz; iyonik örgü yenilemez ve tuz çözünmez."}]},"lise":{"kolay":[{"q":"İyon-dipol etkileşimini tanımlayınız ve tipik bir örnek veriniz.","steps":[{"t":"Tanım","a":"iyon + polar molekül","d":"İyon-dipol etkileşimi, yüklü bir iyon ile kalıcı dipole sahip polar bir molekül arasındaki elektrostatik çekimdir."},{"t":"Örnek","a":"Na⁺ ve H₂O","d":"Sulu çözeltide Na⁺ iyonu ile su molekülünün δ⁻ oksijen ucu arasındaki çekim tipik bir örnektir."}],"ans":"İyon-dipol etkileşimi, bir iyon ile polar bir molekül arasındaki elektrostatik çekimdir; Na⁺ ile H₂O arasındaki etkileşim tipik bir örnektir."},{"q":"İyonik bir bileşiğin suda çözünmesi sürecini hidratasyon kavramıyla açıklayınız.","fig":"<svg viewBox='0 0 320 150'><circle cx='160' cy='75' r='22' fill='#cfd8e8' stroke='#1a2b45'/><text x='160' y='80' font-size='11' text-anchor='middle' fill='#1a2b45'>Na⁺</text><circle cx='160' cy='25' r='12' fill='#e0552b' stroke='#1a2b45'/><circle cx='160' cy='125' r='12' fill='#e0552b' stroke='#1a2b45'/><circle cx='110' cy='75' r='12' fill='#e0552b' stroke='#1a2b45'/><circle cx='210' cy='75' r='12' fill='#e0552b' stroke='#1a2b45'/><line x1='160' y1='53' x2='160' y2='37' stroke='#2b6be0' stroke-dasharray='3 2'/><line x1='160' y1='97' x2='160' y2='113' stroke='#2b6be0' stroke-dasharray='3 2'/><line x1='138' y1='75' x2='122' y2='75' stroke='#2b6be0' stroke-dasharray='3 2'/><line x1='182' y1='75' x2='198' y2='75' stroke='#2b6be0' stroke-dasharray='3 2'/><text x='160' y='148' font-size='9' text-anchor='middle' fill='#1a2b45'>hidratlanmış iyon</text></svg>","steps":[{"t":"İyon-dipol oluşumu","a":"su yönelir","d":"Polar su molekülleri, katının iyonlarına zıt uçlarıyla yönelerek iyon-dipol çekimleri kurar."},{"t":"Hidratasyon","a":"iyon çevrelenir","d":"İyonun çevresi su moleküllerince sarılır (hidratasyon); açığa çıkan hidratasyon enerjisi örgü enerjisini karşılarsa iyonlar çözeltiye geçer."}],"ans":"Su molekülleri iyonlarla iyon-dipol çekimi kurup onları çevreler (hidratasyon); hidratasyon enerjisi örgü enerjisini karşıladığında iyonlar çözünerek suya geçer."},{"q":"İyon-dipol, dipol-dipol ve London kuvvetlerini göreli güçlerine göre sıralayınız.","steps":[{"t":"Yük büyüklüğü","a":"tam > kısmi > anlık","d":"İyon-dipolde tam yük, dipol-dipolde kalıcı kısmi yük, London'da ise anlık (geçici) dipol vardır."},{"t":"Sıralama","a":"iyon-dipol > dipol-dipol > London","d":"Genel olarak güç sırası iyon-dipol > dipol-dipol > London dağılma kuvvetleri biçimindedir."}],"ans":"Göreli güç sırası genellikle iyon-dipol > dipol-dipol > London (dağılma) kuvvetleri şeklindedir."},{"q":"İyon-dipol etkileşiminin gücü iyonun yükü ve yarıçapına nasıl bağlıdır?","steps":[{"t":"Yük etkisi","a":"yük arttıkça güçlü","d":"İyonun yükü büyüdükçe oluşan iyon-dipol çekimi güçlenir."},{"t":"Yarıçap etkisi","a":"küçük iyon daha güçlü","d":"İyon yarıçapı küçüldükçe yük daha yoğun olur ve su moleküllerini daha yakından, daha güçlü çeker."}],"ans":"İyon-dipol etkileşimi, iyonun yükü arttıkça ve yarıçapı küçüldükçe (yük yoğunluğu arttıkça) güçlenir."},{"q":"Suyun iyi bir iyonik çözücü olmasını molekül yapısı üzerinden açıklayınız.","steps":[{"t":"Polarlık","a":"yüksek dipol momenti","d":"Su açısal geometrisi nedeniyle yüksek dipol momentine sahip, belirgin δ⁺/δ⁻ uçları olan polar bir moleküldür."},{"t":"İyon-dipol kabiliyeti","a":"hem + hem − iyonu sarar","d":"Su, oksijen (δ⁻) ucuyla katyonları, hidrojen (δ⁺) uçlarıyla anyonları güçlü iyon-dipol çekimiyle çevreleyip çözebilir."}],"ans":"Su, yüksek dipol momentli polar bir molekül olduğundan δ⁻ ucuyla katyonları, δ⁺ uçlarıyla anyonları güçlü iyon-dipol çekimiyle çevreler; bu da onu iyi bir iyonik çözücü yapar."}],"zor":[{"q":"NaCl'nin suda çözünme sürecini örgü enerjisi ve hidratasyon enerjisi dengesiyle açıklayınız.","steps":[{"t":"Örgü enerjisi","a":"ayırmak için gerekli","d":"İyonik örgüyü gaz fazı iyonlarına ayırmak örgü enerjisi kadar enerji gerektirir (endotermik)."},{"t":"Hidratasyon enerjisi","a":"açığa çıkar","d":"Su molekülleri iyon-dipol etkileşimleriyle iyonları hidratladığında hidratasyon enerjisi açığa çıkar (ekzotermik)."},{"t":"Net denge","a":"karşılaştırma","d":"Hidratasyon enerjisi örgü enerjisini büyük ölçüde karşılarsa çözünme gerçekleşir; net etki çözünme ısısını belirler."}],"ans":"Çözünmede örgü enerjisi iyonları ayırmak için harcanır, iyon-dipol kaynaklı hidratasyon enerjisi açığa çıkar; hidratasyon enerjisi örgü enerjisini karşılayabildiğinde NaCl çözünür."},{"q":"Aynı yükte fakat farklı yarıçaplı iki katyonun (örneğin Li⁺ ve K⁺) hidratasyon enerjilerini iyon-dipol gücüyle karşılaştırınız.","steps":[{"t":"Yük yoğunluğu","a":"küçük iyon yüksek","d":"Li⁺ daha küçük olduğundan yük yoğunluğu (yük/yarıçap) K⁺'ya göre daha yüksektir."},{"t":"İyon-dipol gücü","a":"Li⁺ daha güçlü","d":"Yüksek yük yoğunluğu su moleküllerini daha yakından ve güçlü çeker, iyon-dipol etkileşimi daha güçlü olur."},{"t":"Sonuç","a":"Li⁺ daha büyük hidratasyon","d":"Bu nedenle Li⁺'nin hidratasyon enerjisi (mutlak değerce) K⁺'dan daha büyüktür."}],"ans":"Daha küçük yarıçaplı Li⁺ daha yüksek yük yoğunluğuna sahip olduğundan güçlü iyon-dipol etkileşimi yapar; bu yüzden hidratasyon enerjisi K⁺'dan daha büyüktür."},{"q":"İyon-dipol etkileşimi, iyonik bağ ile dipol-dipol etkileşimi arasında nasıl bir 'köprü' oluşturur, açıklayınız.","steps":[{"t":"İki uç","a":"tam yük ve kısmi yük","d":"İyonik bağ iki tam yük (±/±) arasında; dipol-dipol iki kısmi yük (δ/δ) arasında oluşur."},{"t":"İyon-dipolün konumu","a":"tam yük + kısmi yük","d":"İyon-dipolde bir tarafta tam yük, diğer tarafta kısmi yük bulunur; bu yüzden gücü bu ikisinin arasındadır."},{"t":"Sonuç","a":"köprü rolü","d":"Böylece iyonik bağ ile dipol-dipol arasında geçişi sağlayan, ikisinden ara güçte bir etkileşimdir."}],"ans":"İyon-dipol, bir tarafta tam yük diğer tarafta kısmi yük taşıdığından; tam yüklerin iyonik bağı ile kısmi yüklerin dipol-dipol etkileşimi arasında ara güçte bir köprü oluşturur."},{"q":"Çözünme bir denge süreciyse, doymuş tuz çözeltisinde iyon-dipol etkileşimleri açısından moleküler düzeyde ne olur?","fig":"<svg viewBox='0 0 320 150'><rect x='40' y='95' width='90' height='35' fill='none' stroke='#1a2b45'/><text x='85' y='118' font-size='9' text-anchor='middle' fill='#1a2b45'>katı NaCl</text><circle cx='200' cy='50' r='14' fill='#cfd8e8' stroke='#1a2b45'/><text x='200' y='55' font-size='8' text-anchor='middle' fill='#1a2b45'>Na⁺</text><circle cx='250' cy='70' r='14' fill='#9ed9a8' stroke='#1a2b45'/><text x='250' y='75' font-size='8' text-anchor='middle' fill='#1a2b45'>Cl⁻</text><line x1='110' y1='95' x2='180' y2='62' stroke='#2b6be0' stroke-width='1.2' stroke-dasharray='3 2'/><polygon points='180,62 178,72 187,69' fill='#2b6be0'/><line x1='185' y1='75' x2='120' y2='100' stroke='#5b6b85' stroke-width='1.2' stroke-dasharray='3 2'/><polygon points='120,100 130,98 124,107' fill='#5b6b85'/><text x='215' y='140' font-size='9' text-anchor='middle' fill='#1a2b45'>çözünme ⇌ çökelme</text></svg>","steps":[{"t":"İki yönlü süreç","a":"çözünme ⇌ çökelme","d":"Doymuş çözeltide iyonlar bir yandan iyon-dipol etkileşimleriyle çözünürken, bir yandan da örgüye geri çökelir."},{"t":"Dinamik denge","a":"hızlar eşit","d":"Çözünme hızı ile çökelme hızı eşitlendiğinde dinamik denge kurulur; çözünen iyon derişimi sabit kalır."},{"t":"Moleküler düzey","a":"sürekli alışveriş","d":"Mikroskobik ölçekte su molekülleri sürekli iyon hidratlayıp bırakır; net derişim değişmese de süreç durmaz."}],"ans":"Doymuş çözeltide çözünme ile çökelme hızları eşitlenir; iyon-dipol etkileşimleriyle iyonlar sürekli hidratlanıp örgüye geri dönerek dinamik denge oluşturur, net derişim sabit kalır."},{"q":"İyon-dipol etkileşimi 'benzer benzeri çözer' kuralını nasıl açıklar?","steps":[{"t":"Polar çözücü-iyonik madde","a":"güçlü iyon-dipol","d":"Polar çözücü, iyonlarla güçlü iyon-dipol çekimi kurabildiğinden iyonik/polar maddeleri çözer."},{"t":"Apolar çözücü","a":"dipol yok","d":"Apolar çözücüde kalıcı dipol bulunmadığından iyonlarla güçlü çekim oluşturamaz, iyonik maddeyi çözemez."},{"t":"Kural","a":"benzer benzeri çözer","d":"Bu yüzden iyonik/polar maddeler polar çözücülerde, apolar maddeler apolar çözücülerde çözünür; yani 'benzer benzeri çözer'."}],"ans":"Polar çözücüler iyonlarla güçlü iyon-dipol çekimi kurup iyonik maddeleri çözebilir; apolar çözücülerde dipol bulunmadığından bu çekim oluşmaz, bu da 'benzer benzeri çözer' kuralını açıklar."}]}},"iyonikBag":{"ilkokul":{"kolay":[{"q":"Bir atom elektronunu başka bir atoma verdiğinde ne tür bir bağ oluşur?","steps":[{"t":"Verme-alma","a":"elektron aktarımı","d":"Bir atom elektronunu verir, diğer atom bu elektronu alır."},{"t":"Bağ","a":"iyonik bağ","d":"Bu elektron aktarımıyla oluşan bağa iyonik bağ denir."}],"ans":"Bir atomun elektronunu başka bir atoma vermesiyle iyonik bağ oluşur."},{"q":"Yemek tuzu (NaCl) hangi iki atomdan oluşur?","fig":"<svg viewBox='0 0 320 160'><circle cx='110' cy='80' r='28' fill='#cfd8e8' stroke='#1a2b45'/><text x='110' y='85' font-size='13' text-anchor='middle' fill='#1a2b45'>Na</text><circle cx='210' cy='80' r='28' fill='#9ed9a8' stroke='#1a2b45'/><text x='210' y='85' font-size='13' text-anchor='middle' fill='#1a2b45'>Cl</text><text x='160' y='145' font-size='12' text-anchor='middle' fill='#1a2b45'>NaCl</text></svg>","steps":[{"t":"Birinci atom","a":"sodyum (Na)","d":"Tuzda sodyum atomu bulunur."},{"t":"İkinci atom","a":"klor (Cl)","d":"Sodyum, klor atomuyla birleşerek tuzu (NaCl) oluşturur."}],"ans":"Yemek tuzu (NaCl) sodyum (Na) ve klor (Cl) atomlarından oluşur."},{"q":"Bir atom elektron verince artı mı eksi mi yüklenir?","steps":[{"t":"Elektron eksi yüklü","a":"verince azalır","d":"Elektronlar eksi yüklüdür; atom elektron verince eksi yükü azalır."},{"t":"Sonuç","a":"artı yüklenir","d":"Eksi yükü azalan atom artı (+) yüklü hale gelir."}],"ans":"Bir atom elektron verdiğinde artı (+) yüklenir."},{"q":"Artı ve eksi yüklü iki atom birbirine ne yapar?","steps":[{"t":"Zıt yükler","a":"çekim","d":"Artı (+) ve eksi (−) yükler birbirini çeker."},{"t":"Tutunma","a":"birleşir","d":"Bu çekim sayesinde iki atom birbirine tutunur."}],"ans":"Artı ve eksi yüklü atomlar birbirini çeker ve böylece birbirine tutunur."},{"q":"İyonik bağda atomlar elektronlarını paylaşır mı, yoksa birbirine verir mi?","steps":[{"t":"Paylaşmaz","a":"verir-alır","d":"İyonik bağda atomlar elektron paylaşmaz."},{"t":"Aktarım","a":"biri verir biri alır","d":"Bir atom elektronu verir, diğeri alır; buna elektron aktarımı denir."}],"ans":"İyonik bağda atomlar elektronu paylaşmaz; bir atom verir, diğeri alır (elektron aktarımı)."}],"zor":[{"q":"Sodyum klora bir elektron verince hangi yüklü tanecikler oluşur?","fig":"<svg viewBox='0 0 320 165'><circle cx='95' cy='80' r='26' fill='#cfd8e8' stroke='#1a2b45'/><text x='95' y='85' font-size='12' text-anchor='middle' fill='#1a2b45'>Na⁺</text><circle cx='225' cy='80' r='28' fill='#9ed9a8' stroke='#1a2b45'/><text x='225' y='85' font-size='12' text-anchor='middle' fill='#1a2b45'>Cl⁻</text><line x1='123' y1='80' x2='195' y2='80' stroke='#2b6be0' stroke-width='2'/><polygon points='195,80 185,75 185,85' fill='#2b6be0'/><text x='159' y='65' font-size='10' text-anchor='middle' fill='#1a2b45'>e⁻</text><text x='160' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>Na⁺ ve Cl⁻</text></svg>","steps":[{"t":"Sodyum verir","a":"Na⁺","d":"Sodyum bir elektron verince artı yüklü Na⁺ olur."},{"t":"Klor alır","a":"Cl⁻","d":"Klor bu elektronu alınca eksi yüklü Cl⁻ olur."}],"ans":"Sodyum klora bir elektron verince artı yüklü Na⁺ ile eksi yüklü Cl⁻ oluşur."},{"q":"İyonik bağlı tuzun erimesi neden zordur, çok ısı gerekir?","steps":[{"t":"Güçlü çekim","a":"zıt yükler sıkı","d":"Tuzdaki artı ve eksi iyonlar birbirini güçlü bir şekilde çeker ve sıkıca tutar."},{"t":"Eritmek","a":"çok ısı","d":"Bu güçlü çekimi kırıp eritmek için çok yüksek sıcaklık (çok ısı) gerekir."}],"ans":"Tuzda zıt iyonların çekimi çok güçlü olduğundan eritmek için çok yüksek sıcaklık (çok ısı) gerekir."},{"q":"Neden iyonik bağ metal ile ametal arasında oluşur?","steps":[{"t":"Metal","a":"elektron verir","d":"Metaller dış elektronlarını kolayca verir, artı iyon olur."},{"t":"Ametal","a":"elektron alır","d":"Ametaller elektron almaya yatkındır, eksi iyon olur; veren ve alan birleşip iyonik bağ kurar."}],"ans":"İyonik bağ, elektron veren metal ile elektron alan ametal arasında oluşur."},{"q":"Tuz suda çözündüğünde içindeki iyonlara ne olur?","steps":[{"t":"Çözünme","a":"iyonlar ayrılır","d":"Su tuzu çözerken Na⁺ ve Cl⁻ iyonları birbirinden ayrılır."},{"t":"Dağılma","a":"su içinde","d":"Bu iyonlar su içinde serbestçe dağılır."}],"ans":"Tuz suda çözününce Na⁺ ve Cl⁻ iyonları birbirinden ayrılıp su içinde serbestçe dağılır."},{"q":"Magnezyum iki elektron verirse hangi yükü kazanır?","steps":[{"t":"İki elektron","a":"verir","d":"Magnezyum dış katmanındaki iki elektronu verir."},{"t":"Yük","a":"Mg²⁺","d":"İki eksi yük kaybettiği için iki artı yük kazanır, Mg²⁺ olur."}],"ans":"Magnezyum iki elektron verirse iki artı yük kazanır ve Mg²⁺ iyonu olur."}]},"ortaokul":{"kolay":[{"q":"İyonik bağ nasıl oluşur?","steps":[{"t":"Taraflar","a":"metal + ametal","d":"İyonik bağ metal ile ametal atom arasında oluşur."},{"t":"Elektron aktarımı","a":"ver-al","d":"Metal elektron verip artı iyon (katyon), ametal elektron alıp eksi iyon (anyon) olur; zıt yükler çekilir."}],"ans":"İyonik bağ, metalin ametale elektron aktarmasıyla oluşan katyon ve anyonun elektrostatik çekimiyle kurulur."},{"q":"Katyon ve anyon ne demektir?","steps":[{"t":"Katyon","a":"artı iyon","d":"Elektron vererek artı yüklü hale gelen taneciğe katyon denir (örneğin Na⁺)."},{"t":"Anyon","a":"eksi iyon","d":"Elektron alarak eksi yüklü hale gelen taneciğe anyon denir (örneğin Cl⁻)."}],"ans":"Katyon artı yüklü iyon (Na⁺), anyon ise eksi yüklü iyondur (Cl⁻)."},{"q":"NaCl bileşiğinde sodyum ve klorun yükleri nedir?","fig":"<svg viewBox='0 0 320 160'><circle cx='100' cy='80' r='28' fill='#cfd8e8' stroke='#1a2b45'/><text x='100' y='85' font-size='13' text-anchor='middle' fill='#1a2b45'>Na⁺</text><circle cx='220' cy='80' r='28' fill='#9ed9a8' stroke='#1a2b45'/><text x='220' y='85' font-size='13' text-anchor='middle' fill='#1a2b45'>Cl⁻</text><text x='160' y='145' font-size='11' text-anchor='middle' fill='#1a2b45'>NaCl</text></svg>","steps":[{"t":"Sodyum","a":"Na⁺","d":"Sodyum 1 elektron verir, +1 yüklü Na⁺ olur."},{"t":"Klor","a":"Cl⁻","d":"Klor 1 elektron alır, −1 yüklü Cl⁻ olur."}],"ans":"NaCl'de sodyum Na⁺ (+1), klor ise Cl⁻ (−1) yüküne sahiptir."},{"q":"Atomların elektron alıp vermesinin amacı (oktet) nedir?","steps":[{"t":"Hedef","a":"dolu son katman","d":"Atomlar son katmanlarını 8 elektronla (oktet) doldurmak ister."},{"t":"Yol","a":"al ya da ver","d":"Bunun için gereken kadar elektronu alır veya verir, böylece kararlı olur."}],"ans":"Atomlar son katmanlarını 8 elektrona (oktete) tamamlayıp kararlı olmak için elektron alır ya da verir."},{"q":"MgCl₂ bileşiğinde neden iki tane klor vardır?","fig":"<svg viewBox='0 0 320 165'><circle cx='160' cy='75' r='26' fill='#cfd8e8' stroke='#1a2b45'/><text x='160' y='80' font-size='12' text-anchor='middle' fill='#1a2b45'>Mg²⁺</text><circle cx='75' cy='75' r='24' fill='#9ed9a8' stroke='#1a2b45'/><text x='75' y='80' font-size='11' text-anchor='middle' fill='#1a2b45'>Cl⁻</text><circle cx='245' cy='75' r='24' fill='#9ed9a8' stroke='#1a2b45'/><text x='245' y='80' font-size='11' text-anchor='middle' fill='#1a2b45'>Cl⁻</text><text x='160' y='145' font-size='11' text-anchor='middle' fill='#1a2b45'>MgCl₂</text></svg>","steps":[{"t":"Magnezyum","a":"Mg²⁺ (+2)","d":"Magnezyum 2 elektron verip Mg²⁺ olur."},{"t":"Klor sayısı","a":"2 × Cl⁻","d":"Her klor 1 elektron alır (Cl⁻); +2 yükü dengelemek için 2 klor gerekir."}],"ans":"Mg²⁺ +2 yüklüdür; her Cl⁻ −1 olduğundan yükü dengelemek için 2 klor gerekir, bileşik MgCl₂ olur."},{"q":"CaO bileşiğinde kalsiyum ve oksijenin yükleri nedir?","steps":[{"t":"Kalsiyum","a":"Ca²⁺","d":"Kalsiyum 2 elektron verip Ca²⁺ olur."},{"t":"Oksijen","a":"O²⁻","d":"Oksijen 2 elektron alıp O²⁻ olur; +2 ve −2 birbirini dengeler."}],"ans":"CaO'da kalsiyum Ca²⁺ (+2), oksijen O²⁻ (−2) yüklüdür; yükler eşit olduğu için birebir (CaO) birleşir."}],"zor":[{"q":"Al₂O₃ bileşiğinin formülündeki 2 ve 3 sayıları nereden gelir?","fig":"<svg viewBox='0 0 320 165'><circle cx='90' cy='60' r='22' fill='#cfd8e8' stroke='#1a2b45'/><text x='90' y='65' font-size='11' text-anchor='middle' fill='#1a2b45'>Al³⁺</text><circle cx='90' cy='115' r='22' fill='#cfd8e8' stroke='#1a2b45'/><text x='90' y='120' font-size='11' text-anchor='middle' fill='#1a2b45'>Al³⁺</text><circle cx='220' cy='45' r='20' fill='#e0552b' stroke='#1a2b45'/><text x='220' y='50' font-size='10' text-anchor='middle' fill='#fff'>O²⁻</text><circle cx='220' cy='90' r='20' fill='#e0552b' stroke='#1a2b45'/><text x='220' y='95' font-size='10' text-anchor='middle' fill='#fff'>O²⁻</text><circle cx='220' cy='135' r='20' fill='#e0552b' stroke='#1a2b45'/><text x='220' y='140' font-size='10' text-anchor='middle' fill='#fff'>O²⁻</text></svg>","steps":[{"t":"Yükler","a":"Al³⁺ ve O²⁻","d":"Alüminyum Al³⁺ (+3), oksijen O²⁻ (−2) yüklüdür."},{"t":"Yük denkliği","a":"2×(+3)=3×(−2)","d":"Toplam yük sıfır olmalı; 2 alüminyum +6, 3 oksijen −6 verir, dengelenir."}],"ans":"Al³⁺ ve O²⁻ iyonlarında yük denkliği için 2 alüminyum (+6) ve 3 oksijen (−6) gerekir; bu yüzden formül Al₂O₃ olur."},{"q":"İyonik bileşikler katı halde elektriği iletmezken eriyik/çözeltide neden iletir?","steps":[{"t":"Katı hal","a":"iyonlar sabit","d":"Katı iyonik bileşikte iyonlar örgü içinde sabittir, serbestçe hareket edemez, akım taşıyamaz."},{"t":"Eriyik/çözelti","a":"iyonlar serbest","d":"Eridiğinde ya da suda çözündüğünde iyonlar serbest hale gelir ve yükü taşıyarak elektriği iletir."}],"ans":"Katı halde iyonlar sabit olduğundan iletmez; eriyik ya da çözeltide serbest hale gelen iyonlar yükü taşıdığından iyonik bileşikler elektriği iletir."},{"q":"K₂O bileşiğinde potasyumun ve oksijenin yükleri ve sayıları nasıl belirlenir?","steps":[{"t":"Yükler","a":"K⁺ ve O²⁻","d":"Potasyum K⁺ (+1), oksijen O²⁻ (−2) yüklüdür."},{"t":"Denkleme","a":"2×(+1)=1×(−2)","d":"Net yük sıfır olmalı; bir O²⁻'yi dengelemek için iki K⁺ gerekir."}],"ans":"K⁺ (+1) ve O²⁻ (−2) yükleri için iki potasyum bir oksijeni dengeler; bileşik K₂O olur."},{"q":"İyonik bağ ile kovalent bağ arasındaki temel fark nedir?","steps":[{"t":"İyonik","a":"elektron aktarımı","d":"İyonik bağ metal-ametal arasında elektron aktarımıyla (iyon oluşumuyla) kurulur."},{"t":"Kovalent","a":"elektron paylaşımı","d":"Kovalent bağ ametal-ametal arasında elektron paylaşımıyla kurulur, iyon oluşmaz."}],"ans":"İyonik bağda elektron aktarılır ve iyon oluşur (metal-ametal); kovalent bağda ise elektron paylaşılır (ametal-ametal)."},{"q":"Na₂S bileşiğindeki iyonların yüklerini ve formüldeki katsayıları açıklayınız.","steps":[{"t":"Sodyum","a":"Na⁺","d":"Sodyum 1A grubunda olup 1 elektron verir, Na⁺ olur."},{"t":"Kükürt","a":"S²⁻","d":"Kükürt 6A grubunda olup 2 elektron alır, S²⁻ olur."},{"t":"Denklik","a":"2 Na⁺ + 1 S²⁻","d":"Net yük sıfır için iki Na⁺ (+2) bir S²⁻'yi (−2) dengeler."}],"ans":"Na⁺ (+1) ve S²⁻ (−2) yüklerinde denge için iki sodyum bir kükürdü dengeler; bileşik Na₂S olur."}]},"lise":{"kolay":[{"q":"İyonik bağın oluşum mekanizmasını açıklayınız.","steps":[{"t":"Elektron aktarımı","a":"metal → ametal","d":"Düşük iyonlaşma enerjili metal, değerlik elektron(lar)ını yüksek elektron ilgili ametale aktarır."},{"t":"Elektrostatik çekim","a":"katyon-anyon","d":"Oluşan katyon (+) ve anyon (−) arasındaki elektrostatik çekim iyonik bağı meydana getirir."}],"ans":"İyonik bağ, metalin ametale elektron aktarmasıyla oluşan katyon ve anyon arasındaki elektrostatik çekimle meydana gelir."},{"q":"Oktet kuralı iyon oluşumunu nasıl yönlendirir? NaCl üzerinden açıklayınız.","fig":"<svg viewBox='0 0 320 170'><circle cx='95' cy='85' r='28' fill='#cfd8e8' stroke='#1a2b45'/><text x='95' y='90' font-size='12' text-anchor='middle' fill='#1a2b45'>Na</text><circle cx='225' cy='85' r='28' fill='#9ed9a8' stroke='#1a2b45'/><text x='225' y='90' font-size='12' text-anchor='middle' fill='#1a2b45'>Cl</text><line x1='124' y1='85' x2='194' y2='85' stroke='#2b6be0' stroke-width='2'/><polygon points='194,85 184,80 184,90' fill='#2b6be0'/><text x='159' y='72' font-size='9' text-anchor='middle' fill='#1a2b45'>1 e⁻</text><text x='159' y='155' font-size='10' text-anchor='middle' fill='#1a2b45'>Na⁺ + Cl⁻ → NaCl</text></svg>","steps":[{"t":"Sodyum","a":"1 e⁻ verir","d":"Sodyumun son katmanında 1 elektron vardır; bunu verirse Ne düzenine (oktet) ulaşır ve Na⁺ olur."},{"t":"Klor","a":"1 e⁻ alır","d":"Klorun son katmanında 7 elektron vardır; 1 elektron alırsa Ar düzenine (oktet) ulaşır ve Cl⁻ olur."}],"ans":"Sodyum 1 elektron verip oktete ulaşarak Na⁺, klor 1 elektron alıp oktete ulaşarak Cl⁻ olur; zıt iyonlar çekilip NaCl'yi oluşturur."},{"q":"İyonik bir bileşiğin formülü iyon yüklerinden nasıl yazılır? MgCl₂ örneğiyle gösteriniz.","steps":[{"t":"İyon yükleri","a":"Mg²⁺, Cl⁻","d":"Magnezyum Mg²⁺ (+2), klor Cl⁻ (−1) yüklüdür."},{"t":"Yük denkliği","a":"1×(+2)+2×(−1)=0","d":"Net yük sıfır olmalı; bir Mg²⁺ için iki Cl⁻ gerekir."}],"ans":"Mg²⁺ ve Cl⁻ yüklerinin denge için oranı 1:2'dir; bu yüzden bileşiğin formülü MgCl₂ olur."},{"q":"İyonik katıların yüksek erime noktası ve kırılganlığı hangi özellikle açıklanır?","steps":[{"t":"Örgü çekimi","a":"güçlü elektrostatik","d":"İyonik katıda iyonlar düzenli bir örgüde güçlü elektrostatik çekimle tutulur; eritmek yüksek enerji ister."},{"t":"Kırılganlık","a":"yük itmesi","d":"Örgü kaydırılınca aynı yüklü iyonlar yan yana gelir, birbirini iter ve kristal kırılır (kırılgandır)."}],"ans":"İyonik katılar güçlü örgü çekimi nedeniyle yüksek erime noktasına sahiptir; örgü kaydığında aynı yüklü iyonların itmesi nedeniyle de kırılgandırlar."},{"q":"Al₂O₃ bileşiğinin formülünü iyon yükleriyle yük denkliği yaparak açıklayınız.","steps":[{"t":"İyon yükleri","a":"Al³⁺, O²⁻","d":"Alüminyum Al³⁺ (+3), oksijen O²⁻ (−2) yüklüdür."},{"t":"En küçük tam oran","a":"2 Al³⁺, 3 O²⁻","d":"Net yük sıfır için yüklerin EKOK'u (6) alınır: 2×(+3)=+6 ve 3×(−2)=−6."}],"ans":"Al³⁺ ve O²⁻ yüklerinin denge için en küçük tam sayı oranı 2:3'tür (2×(+3) = 3×(−2) = 6); böylece formül Al₂O₃ olur."}],"zor":[{"q":"İyonik bağ enerjisini (örgü enerjisini) iyon yükü ve yarıçapı nasıl etkiler?","steps":[{"t":"Yük etkisi","a":"yük arttıkça artar","d":"İyon yükleri büyüdükçe elektrostatik çekim güçlenir, örgü enerjisi (bağ kuvveti) artar."},{"t":"Yarıçap etkisi","a":"yarıçap küçüldükçe artar","d":"İyon yarıçapı küçüldükçe iyon merkezleri yaklaşır, çekim güçlenir ve örgü enerjisi artar."},{"t":"Sonuç","a":"MgO > NaCl","d":"Bu yüzden çift yüklü, küçük iyonlu MgO'nun örgü enerjisi ve erime noktası NaCl'den çok yüksektir."}],"ans":"Örgü enerjisi iyon yükleri büyüdükçe ve iyon yarıçapları küçüldükçe artar; bu yüzden MgO (Mg²⁺, O²⁻) NaCl'den (Na⁺, Cl⁻) çok daha güçlü iyonik bağa ve yüksek erime noktasına sahiptir."},{"q":"Ca₃(PO₄)₂ bileşiğinin formülündeki katsayıları yük denkliğiyle açıklayınız.","steps":[{"t":"İyonlar","a":"Ca²⁺ ve PO₄³⁻","d":"Kalsiyum Ca²⁺ (+2), fosfat çok atomlu anyon PO₄³⁻ (−3) yüklüdür."},{"t":"EKOK","a":"6","d":"Yüklerin EKOK'u 6'dır; +2 yükten 3 tane (+6), −3 yükten 2 tane (−6) gerekir."},{"t":"Formül","a":"3 Ca²⁺, 2 PO₄³⁻","d":"Üç Ca²⁺ ve iki PO₄³⁻ net yükü sıfırlar; fosfat çok atomlu olduğu için parantez içine alınıp 2 ile çarpılır."}],"ans":"Ca²⁺ (+2) ve PO₄³⁻ (−3) için yük denkliği 3:2 oranını gerektirir (3×(+2) = 2×(−3) = 6); bu yüzden formül Ca₃(PO₄)₂ olur."},{"q":"Bir bileşiğin iyonik mi yoksa kovalent mi olduğunu elektronegatiflik farkıyla nasıl ayırt ederiz?","steps":[{"t":"Ölçüt","a":"elektronegatiflik farkı","d":"Bağ yapan atomların elektronegatiflik farkı ne kadar büyükse bağ o kadar iyonik karakterlidir."},{"t":"Büyük fark","a":"iyonik","d":"Genelde fark yaklaşık 1,7'den büyükse (metal-ametal) bağ iyonik kabul edilir; elektron neredeyse tamamen aktarılır."},{"t":"Küçük fark","a":"kovalent","d":"Fark küçükse (ametal-ametal) elektron paylaşılır, bağ kovalenttir."}],"ans":"Atomlar arası elektronegatiflik farkı büyükse (genelde ~1,7 üstü, metal-ametal) bağ iyonik; küçükse (ametal-ametal) elektronlar paylaşıldığından bağ kovalenttir."},{"q":"NaCl katısının yapısını ve neden katı halde iletken olmadığını açıklayınız.","fig":"<svg viewBox='0 0 320 175'><rect x='80' y='40' width='160' height='110' fill='none' stroke='#1a2b45'/><circle cx='110' cy='70' r='12' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='170' cy='70' r='12' fill='#9ed9a8' stroke='#1a2b45'/><circle cx='110' cy='120' r='12' fill='#9ed9a8' stroke='#1a2b45'/><circle cx='170' cy='120' r='12' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='210' cy='70' r='12' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='210' cy='120' r='12' fill='#9ed9a8' stroke='#1a2b45'/><text x='160' y='168' font-size='10' text-anchor='middle' fill='#1a2b45'>NaCl örgüsü (Na⁺ ve Cl⁻)</text></svg>","steps":[{"t":"Yapı","a":"iyonik örgü","d":"NaCl'de Na⁺ ve Cl⁻ iyonları üç boyutlu, sıkı bir kristal örgü oluşturur; her iyon zıt yüklü komşularla çevrilidir."},{"t":"Katıda iletmez","a":"iyonlar sabit","d":"Katı örgüde iyonlar yerlerinde sabittir, serbestçe hareket edemediğinden yük taşıyamaz."},{"t":"İletkenlik koşulu","a":"eriyik/çözelti","d":"Ancak eridiğinde ya da suda çözündüğünde iyonlar serbest kalır ve elektriği iletir."}],"ans":"NaCl, Na⁺ ve Cl⁻ iyonlarının üç boyutlu kristal örgüsüdür; katıda iyonlar sabit olduğundan iletmez, ancak eriyik ya da sulu çözeltide serbest iyonlarla elektriği iletir."},{"q":"İyon yarıçapı, atom yarıçapından farklı olarak katyon ve anyonda nasıl değişir?","steps":[{"t":"Katyon","a":"küçülür","d":"Atom elektron verip katyon olunca elektron sayısı azalır, kalan elektronları çekirdek daha güçlü çeker; yarıçap küçülür (örneğin Na⁺ < Na)."},{"t":"Anyon","a":"büyür","d":"Atom elektron alıp anyon olunca elektron-elektron itmesi artar ve çekirdeğin elektron başına çekimi azalır; yarıçap büyür (örneğin Cl⁻ > Cl)."}],"ans":"Katyon oluşumunda yarıçap küçülür (Na⁺ < Na), anyon oluşumunda ise elektron itmesi arttığı için yarıçap büyür (Cl⁻ > Cl)."}]}},"iyonikGiris":{"ilkokul":{"kolay":[{"q":"İyonik bağ hangi atomlar arasında kurulur?","steps":[{"t":"Bir metal","a":"sodyum gibi","d":"İyonik bağda bir tarafta metal (örneğin sodyum) bulunur."},{"t":"Bir ametal","a":"klor gibi","d":"Diğer tarafta ametal (örneğin klor) bulunur; bunlar birleşir."}],"ans":"İyonik bağ bir metal ile bir ametal atom arasında kurulur."},{"q":"Metal atom bağ kurarken elektronlarına ne yapar?","steps":[{"t":"Dış elektron","a":"fazla gibi","d":"Metalin dış elektronları kolayca ayrılabilir."},{"t":"Verir","a":"elektron verir","d":"Metal bu dış elektronları başka atoma verir."}],"ans":"Metal atom, dış elektronlarını başka atoma verir."},{"q":"Ametal atom bağ kurarken ne yapar?","steps":[{"t":"Eksik elektron","a":"yer var","d":"Ametalin dış katmanında elektron için boş yer vardır."},{"t":"Alır","a":"elektron alır","d":"Ametal, metalin verdiği elektronu alarak dış katmanını tamamlar."}],"ans":"Ametal atom, başka atomdan elektron alır."},{"q":"Yemek tuzu hangi iki atomdan oluşur?","fig":"<svg viewBox='0 0 320 150'><circle cx='110' cy='75' r='26' fill='#cfd8e8' stroke='#1a2b45'/><text x='110' y='80' font-size='12' text-anchor='middle' fill='#1a2b45'>Na</text><circle cx='210' cy='75' r='26' fill='#9ed9a8' stroke='#1a2b45'/><text x='210' y='80' font-size='12' text-anchor='middle' fill='#1a2b45'>Cl</text><text x='160' y='130' font-size='11' text-anchor='middle' fill='#1a2b45'>tuz (NaCl)</text></svg>","steps":[{"t":"Birinci atom","a":"sodyum","d":"Yemek tuzunda sodyum (Na) atomu bulunur."},{"t":"İkinci atom","a":"klor","d":"Sodyum, klor (Cl) ile birleşerek tuzu (NaCl) oluşturur."}],"ans":"Yemek tuzu sodyum (Na) ve klor (Cl) atomlarından oluşur."},{"q":"Artı ve eksi yüklü iki tanecik karşılaşınca ne olur?","steps":[{"t":"Zıt yükler","a":"+ ve −","d":"Bir tanecik artı, diğeri eksi yüklüdür."},{"t":"Çekim","a":"birbirini çeker","d":"Zıt yükler birbirini çeker, böylece birbirine tutunurlar."}],"ans":"Artı ve eksi yüklü tanecikler birbirini çeker ve birbirine tutunur."}],"zor":[{"q":"Sodyum elektronunu verince ne tür yük kazanır?","steps":[{"t":"Elektron verir","a":"eksi gider","d":"Sodyum bir elektron (eksi yük) verir."},{"t":"Sonuç","a":"artı yük","d":"Eksi yük gidince geriye artı yüklü sodyum (Na⁺) kalır."}],"ans":"Sodyum elektronunu verince artı yüklü (Na⁺) hale gelir."},{"q":"Klor elektron alınca ne tür yük kazanır?","steps":[{"t":"Elektron alır","a":"eksi gelir","d":"Klor bir elektron (eksi yük) alır."},{"t":"Sonuç","a":"eksi yük","d":"Fazladan eksi yük geldiği için klor eksi yüklü (Cl⁻) hale gelir."}],"ans":"Klor elektron alınca eksi yüklü (Cl⁻) hale gelir."},{"q":"Na⁺ ve Cl⁻ neden birbirine tutunur?","fig":"<svg viewBox='0 0 320 150'><circle cx='110' cy='75' r='26' fill='#cfd8e8' stroke='#1a2b45'/><text x='110' y='80' font-size='12' text-anchor='middle' fill='#1a2b45'>Na⁺</text><circle cx='210' cy='75' r='26' fill='#9ed9a8' stroke='#1a2b45'/><text x='210' y='80' font-size='12' text-anchor='middle' fill='#1a2b45'>Cl⁻</text><line x1='136' y1='75' x2='184' y2='75' stroke='#2b6be0' stroke-width='2'/><text x='160' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>zıt yükler çekilir</text></svg>","steps":[{"t":"Yükler","a":"artı ve eksi","d":"Na⁺ artı, Cl⁻ eksi yüklüdür."},{"t":"Çekim","a":"zıt yük","d":"Zıt yükler birbirini çektiği için Na⁺ ve Cl⁻ sıkıca tutunur."}],"ans":"Na⁺ artı, Cl⁻ eksi yüklü olduğu için zıt yükler birbirini çeker ve tutunurlar."},{"q":"İyon nedir, basitçe açıklayın?","steps":[{"t":"Yük kazanma","a":"al ya da ver","d":"Bir atom elektron alıp verince elektriksel yük kazanır."},{"t":"İyon","a":"yüklü atom","d":"Yük kazanmış (artı veya eksi) bu atoma iyon denir."}],"ans":"İyon, elektron alıp vererek artı ya da eksi yük kazanmış atomdur."},{"q":"Metal mi yoksa ametal mi elektron almaya daha yatkındır?","steps":[{"t":"Metal","a":"verir","d":"Metaller dış elektronlarını kolayca verir."},{"t":"Ametal","a":"alır","d":"Ametaller ise elektron almaya yatkındır."}],"ans":"Ametaller elektron almaya, metaller ise vermeye yatkındır."}]},"ortaokul":{"kolay":[{"q":"İyonik bağ nasıl oluşur?","steps":[{"t":"Elektron aktarımı","a":"metal → ametal","d":"Metal, değerlik elektronlarını ametale aktarır."},{"t":"Zıt iyon çekimi","a":"+ ve − çekilir","d":"Oluşan artı ve eksi iyonlar elektriksel çekimle birbirine bağlanır."}],"ans":"İyonik bağ, metalden ametale elektron aktarımı ve oluşan zıt iyonların çekimiyle oluşur."},{"q":"Katyon ve anyon ne demektir?","steps":[{"t":"Katyon","a":"artı iyon","d":"Elektron veren atom artı yüklenir; bu artı iyona katyon denir."},{"t":"Anyon","a":"eksi iyon","d":"Elektron alan atom eksi yüklenir; bu eksi iyona anyon denir."}],"ans":"Katyon elektron vererek artı yüklenmiş, anyon ise elektron alarak eksi yüklenmiş iyondur."},{"q":"NaCl oluşumunda sodyum ve klor hangi iyonlara dönüşür?","fig":"<svg viewBox='0 0 320 160'><circle cx='95' cy='80' r='26' fill='#cfd8e8' stroke='#1a2b45'/><text x='95' y='85' font-size='12' text-anchor='middle' fill='#1a2b45'>Na</text><circle cx='225' cy='80' r='26' fill='#9ed9a8' stroke='#1a2b45'/><text x='225' y='85' font-size='12' text-anchor='middle' fill='#1a2b45'>Cl</text><line x1='123' y1='80' x2='193' y2='80' stroke='#2b6be0' stroke-width='2'/><polygon points='193,80 183,75 183,85' fill='#2b6be0'/><text x='159' y='66' font-size='10' text-anchor='middle' fill='#1a2b45'>e⁻</text><text x='159' y='145' font-size='10' text-anchor='middle' fill='#1a2b45'>Na⁺ + Cl⁻</text></svg>","steps":[{"t":"Sodyum","a":"Na⁺","d":"Sodyum 1 değerlik elektronunu vererek Na⁺ katyonuna dönüşür."},{"t":"Klor","a":"Cl⁻","d":"Klor bu elektronu alarak Cl⁻ anyonuna dönüşür."}],"ans":"NaCl oluşumunda sodyum Na⁺ katyonuna, klor ise Cl⁻ anyonuna dönüşür."},{"q":"Metaller neden kolayca katyon oluşturur?","steps":[{"t":"Az değerlik e⁻","a":"1-2-3 elektron","d":"Metallerin son katmanında az sayıda (genelde 1-3) elektron vardır."},{"t":"Vermek kolay","a":"katyon","d":"Bu az elektronu vermek, oktete ulaşmanın en kolay yoludur; veren atom katyon olur."}],"ans":"Metallerin son katmanında az elektron olduğundan bunları verip katyon oluşturmak kolaydır."},{"q":"İyonik bağda atomların amacı nedir?","steps":[{"t":"Oktet","a":"son katman 8","d":"Her iki atom da son katmanını 8'e (oktete) tamamlamak ister."},{"t":"Aktarımla ulaşma","a":"al-ver","d":"Metal verip, ametal alarak her ikisi de soy gaz düzenine ulaşır ve kararlı olur."}],"ans":"İyonik bağda atomlar, elektron aktarımıyla son katmanlarını oktete tamamlayıp kararlı hale gelmeyi amaçlar."}],"zor":[{"q":"Magnezyum ve oksijen MgO bileşiğini nasıl oluşturur?","fig":"<svg viewBox='0 0 320 160'><circle cx='95' cy='80' r='26' fill='#cfd8e8' stroke='#1a2b45'/><text x='95' y='85' font-size='11' text-anchor='middle' fill='#1a2b45'>Mg</text><circle cx='225' cy='80' r='26' fill='#e0552b' stroke='#1a2b45'/><text x='225' y='85' font-size='11' text-anchor='middle' fill='#fff'>O</text><line x1='123' y1='73' x2='193' y2='73' stroke='#2b6be0' stroke-width='2'/><line x1='123' y1='87' x2='193' y2='87' stroke='#2b6be0' stroke-width='2'/><text x='159' y='145' font-size='10' text-anchor='middle' fill='#1a2b45'>Mg²⁺ + O²⁻</text></svg>","steps":[{"t":"Elektron aktarımı","a":"2 elektron","d":"Magnezyum 2 değerlik elektronunu, 2 elektrona ihtiyacı olan oksijene aktarır."},{"t":"İyonlar","a":"Mg²⁺ ve O²⁻","d":"Mg²⁺ ve O²⁻ iyonları oluşur; zıt yükler çekilerek MgO bileşiğini kurar."}],"ans":"Magnezyum 2 elektronunu oksijene verir; oluşan Mg²⁺ ve O²⁻ iyonları çekimle MgO'yu oluşturur."},{"q":"İyonik bileşiklerin erime noktaları neden yüksektir?","steps":[{"t":"İyon örgüsü","a":"düzenli ağ","d":"İyonik katıda artı ve eksi iyonlar üç boyutlu düzenli bir örgüde güçlü çekimle dizilir."},{"t":"Çok enerji","a":"erimesi zor","d":"Bu güçlü iyonik çekimleri kırıp eritmek için çok yüksek sıcaklık (enerji) gerekir."}],"ans":"İyonik bileşiklerde zıt iyonlar arası çekim çok güçlü ve örgü düzenli olduğundan erime noktaları yüksektir."},{"q":"Neden Na 1 elektron verirken O 2 elektron alır, ama yine de Na₂O dengeli oluşur?","steps":[{"t":"Yük gereksinimi","a":"Na⁺ ve O²⁻","d":"Sodyum 1 elektron verip Na⁺ olur; oksijen 2 elektron alıp O²⁻ olur."},{"t":"Yük dengesi","a":"2 Na : 1 O","d":"Toplam yük sıfır olmalı; iki Na⁺ (toplam +2) bir O²⁻ (−2) ile dengelenir, bileşik Na₂O olur."}],"ans":"Oksijen 2 elektron istediği için iki sodyum birer elektron verir; yük dengesi 2 Na⁺ + 1 O²⁻ olur ve bileşik Na₂O biçiminde oluşur."},{"q":"İyonik bileşikler katı halde elektriği iletmezken eriyik veya çözeltide neden iletir?","steps":[{"t":"Katı hal","a":"iyonlar sabit","d":"Katıda iyonlar örgüde sıkıca sabittir, hareket edemediğinden yük taşıyamaz."},{"t":"Eriyik/çözelti","a":"serbest iyon","d":"Eridiğinde ya da suda çözündüğünde iyonlar serbest hareket eder ve elektrik yükünü taşıyabilir."}],"ans":"Katıda iyonlar sabit olduğundan iletmez; eriyik/çözeltide serbest kalan iyonlar yük taşıyabildiği için elektriği iletir."},{"q":"Bir atomun katyon mu anyon mu olacağını nasıl tahmin ederiz?","steps":[{"t":"Tür","a":"metal/ametal","d":"Atomun metal mi ametal mi olduğuna bakarız; metaller verir, ametaller alır."},{"t":"Değerlik sayısı","a":"oktete uzaklık","d":"Son katmanı yarıdan az dolu (1-3 e⁻) ise verir → katyon; yarıdan fazla (5-7 e⁻) ise alır → anyon."}],"ans":"Metal ve az değerlik elektronlu atomlar verip katyon, ametal ve çok değerlik elektronlu atomlar alıp anyon olur."}]},"lise":{"kolay":[{"q":"İyonik bağın oluşum mekanizmasını açıklayınız.","steps":[{"t":"Elektron aktarımı","a":"metal → ametal","d":"Düşük iyonlaşma enerjili metal, değerlik elektron(lar)ını yüksek elektronegatiflikli ametale aktarır."},{"t":"Elektrostatik çekim","a":"zıt iyonlar","d":"Oluşan katyon ve anyon arasındaki güçlü elektrostatik (Coulomb) çekimi iyonik bağı meydana getirir."}],"ans":"İyonik bağ, metalden ametale elektron aktarımıyla oluşan zıt iyonlar arasındaki elektrostatik çekimle meydana gelir."},{"q":"Katyon ve anyon kavramlarını oluşum yönüyle tanımlayınız.","steps":[{"t":"Katyon","a":"e verir, + yük","d":"Bir veya daha çok elektron veren atom proton fazlalığıyla artı yüklenir; bu pozitif iyona katyon denir (Na⁺, Mg²⁺)."},{"t":"Anyon","a":"e alır, − yük","d":"Elektron alan atom elektron fazlalığıyla eksi yüklenir; bu negatif iyona anyon denir (Cl⁻, O²⁻)."}],"ans":"Katyon elektron vererek artı yüklenmiş, anyon ise elektron alarak eksi yüklenmiş iyondur."},{"q":"NaCl oluşumunu değerlik elektronu ve oktet açısından açıklayınız.","fig":"<svg viewBox='0 0 320 175'><circle cx='95' cy='85' r='28' fill='#cfd8e8' stroke='#1a2b45'/><text x='95' y='90' font-size='12' text-anchor='middle' fill='#1a2b45'>Na</text><circle cx='225' cy='85' r='28' fill='#9ed9a8' stroke='#1a2b45'/><text x='225' y='90' font-size='12' text-anchor='middle' fill='#1a2b45'>Cl</text><line x1='124' y1='85' x2='194' y2='85' stroke='#2b6be0' stroke-width='2'/><polygon points='194,85 184,80 184,90' fill='#2b6be0'/><text x='159' y='72' font-size='10' text-anchor='middle' fill='#1a2b45'>e⁻ aktarımı</text><text x='159' y='160' font-size='11' text-anchor='middle' fill='#1a2b45'>Na⁺ + Cl⁻ → NaCl</text></svg>","steps":[{"t":"Sodyum","a":"1 e⁻ verir","d":"Sodyumun 1 değerlik elektronu vardır; bunu verince bir alttaki dolu katman açığa çıkar, Na⁺ neon düzenine ulaşır."},{"t":"Klor","a":"1 e⁻ alır","d":"Klorun 7 değerlik elektronu vardır; 1 elektron alarak oktete ulaşır, Cl⁻ argon düzenine erişir."}],"ans":"Sodyum 1 değerlik elektronunu verip Na⁺, klor o elektronu alıp Cl⁻ olur; her ikisi de soy gaz oktetine ulaşır ve NaCl oluşur."},{"q":"İyonik bileşiklerin yüksek erime/kaynama noktasını yapısal olarak açıklayınız.","steps":[{"t":"Kristal örgü","a":"iyonik kafes","d":"İyonik bileşikler tek molekül değil, çok sayıda iyondan oluşan üç boyutlu kristal örgü kurar."},{"t":"Kuvvetli çekim","a":"yüksek enerji","d":"Örgüdeki yoğun ve kuvvetli iyon-iyon çekimlerini koparmak yüksek enerji gerektirdiğinden erime/kaynama noktaları yüksektir."}],"ans":"İyonik bileşikler güçlü çekimli üç boyutlu kristal örgü oluşturduğundan, bu çekimleri kırmak yüksek enerji ister; erime/kaynama noktaları yüksektir."},{"q":"Bir iyonik bileşiğin formülünü yük dengesi ile nasıl belirleriz?","steps":[{"t":"İyon yükleri","a":"katyon ve anyon","d":"Önce katyonun ve anyonun yüklerini belirleriz (örneğin Al³⁺ ve O²⁻)."},{"t":"Yük denkleştirme","a":"çapraz katsayı","d":"Toplam yük sıfır olacak şekilde katsayılar bulunur; Al³⁺ ve O²⁻ için 2 Al ve 3 O alınır, formül Al₂O₃ olur."}],"ans":"İyonların yükleri bulunup toplam yük sıfır olacak şekilde denkleştirilir; örneğin Al³⁺ ve O²⁻ için formül Al₂O₃'tür."}],"zor":[{"q":"İyonik bağ oluşumunu enerji basamakları (örgü enerjisi dahil) ile açıklayınız.","steps":[{"t":"İyon oluşturma","a":"enerji gerektirir","d":"Metalin iyonlaşması (Na → Na⁺ + e⁻) enerji ister; ametalin elektron alması (Cl + e⁻ → Cl⁻) bir miktar enerji açığa çıkarır ama tek başına yeterli değildir."},{"t":"Örgü enerjisi","a":"net kararlılık","d":"İyonların kristal örgü kurarken açığa çıkardığı büyük örgü enerjisi, harcanan enerjiyi fazlasıyla karşılar; net sonuç enerji düşüşü ve kararlı bileşiktir."}],"ans":"İyon oluşumu net enerji gerektirse de, kristal örgü kurulurken açığa çıkan büyük örgü enerjisi süreci ekzotermik kılar; bileşik bu yüzden kararlıdır."},{"q":"Örgü enerjisi neye bağlıdır ve NaCl ile MgO karşılaştırması nasıldır?","steps":[{"t":"Bağımlılık","a":"yük ve yarıçap","d":"Örgü enerjisi iyon yüklerinin çarpımıyla doğru, iyonlar arası uzaklıkla (yarıçap toplamı) ters orantılıdır."},{"t":"Karşılaştırma","a":"MgO ≫ NaCl","d":"MgO'da iyon yükleri (2+ ve 2−) NaCl'dekinden (1+ ve 1−) büyük olduğundan MgO'nun örgü enerjisi ve erime noktası çok daha yüksektir."}],"ans":"Örgü enerjisi iyon yüklerinin çarpımıyla artar, uzaklıkla azalır; MgO (2+/2−) yükleri büyük olduğundan NaCl'den (1+/1−) çok daha yüksek örgü enerjisine ve erime noktasına sahiptir."},{"q":"İyonik bağ tamamen 'saf iyonik' midir; polarizasyon (Fajans) etkisini açıklayınız.","steps":[{"t":"İdeal iyonik","a":"tam aktarım","d":"İdeal iyonik bağda elektron tam aktarılır ve iyonlar küresel kabul edilir."},{"t":"Polarizasyon","a":"kısmi kovalent","d":"Küçük ve yüksek yüklü katyon, büyük anyonun elektron bulutunu çarpıtır (polarize eder); bu kovalent karakter katar, yani bağ kısmen kovalentleşir."}],"ans":"Gerçekte saf iyonik bağ idealleştirmedir; küçük/yüksek yüklü katyonun anyonu polarize etmesi (Fajans kuralları) bağa kısmi kovalent karakter kazandırır."},{"q":"İyonik bileşikler neden serttir ama darbeyle (çekiçle) kolayca kırılır?","steps":[{"t":"Sertlik","a":"güçlü örgü","d":"İyonlar arası güçlü ve yönlü çekimler örgüyü sert ve dayanıklı yapar."},{"t":"Kırılganlık","a":"yük itmesi","d":"Darbeyle katmanlar kayınca aynı yüklü iyonlar karşı karşıya gelir; oluşan itme örgüyü iter ve kristal aniden kırılır (kırılganlık)."}],"ans":"Güçlü iyonik örgü bileşiği sert yapar; ancak darbeyle katmanlar kayınca aynı yüklü iyonlar yan yana gelip birbirini ittiğinden kristal kolayca kırılır."},{"q":"Bir bağın iyonik mi kovalent mi olacağını elektronegatiflik farkıyla nasıl değerlendiririz?","steps":[{"t":"Fark ölçütü","a":"ΔEN","d":"İki atom arasındaki elektronegatiflik farkı (ΔEN) büyüdükçe bağ daha iyoniktir; yaklaşık ΔEN > 1,7 belirgin iyonik karakter gösterir."},{"t":"Ara durumlar","a":"polar kovalent","d":"ΔEN küçükse (≈0) apolar kovalent, orta değerlerde (0 < ΔEN < 1,7) polar kovalent bağ oluşur; geçiş süreklidir."}],"ans":"Bağ türü elektronegatiflik farkıyla değerlendirilir: fark büyükse (≈1,7 üzeri) iyonik, çok küçükse apolar kovalent, ara değerlerde polar kovalent karakterdedir."}]}},"iyonikKristal":{"ilkokul":{"kolay":[{"q":"Yemek tuzu tanelerinin köşeli ve düzgün görünmesinin nedeni nedir?","steps":[{"t":"İçindeki tanecikler","a":"düzenli dizilmiş","d":"Tuzun içindeki minik tanecikler gelişigüzel değil, çok düzenli sıralar halinde dizilir."},{"t":"Dış görünüş","a":"köşeli kristal","d":"Bu düzenli diziliş tuza küp gibi köşeli, düzgün bir şekil verir; buna kristal denir."}],"ans":"Tuzun tanecikleri çok düzenli dizildiği için taneleri köşeli ve düzgün (kristal) görünür."},{"q":"Tuz, içinde hangi iki atomdan oluşan düzenli bir yapıdır?","steps":[{"t":"Birinci tanecik","a":"sodyum","d":"Yemek tuzunda sodyum (Na) bulunur."},{"t":"İkinci tanecik","a":"klor","d":"Sodyum, klor (Cl) ile yan yana dizilerek tuzu (NaCl) oluşturur."}],"ans":"Tuz, sodyum ve klor taneciklerinin düzenli dizilmesiyle oluşan bir yapıdır."},{"q":"Bir tuz kristalinde tanecikler nasıl dizilmiştir?","fig":"<svg viewBox='0 0 320 180'><circle cx='110' cy='60' r='16' fill='#cfd8e8' stroke='#1a2b45'/><text x='110' y='65' font-size='10' text-anchor='middle' fill='#1a2b45'>Na</text><circle cx='160' cy='60' r='16' fill='#9ed9a8' stroke='#1a2b45'/><text x='160' y='65' font-size='10' text-anchor='middle' fill='#1a2b45'>Cl</text><circle cx='210' cy='60' r='16' fill='#cfd8e8' stroke='#1a2b45'/><text x='210' y='65' font-size='10' text-anchor='middle' fill='#1a2b45'>Na</text><circle cx='110' cy='110' r='16' fill='#9ed9a8' stroke='#1a2b45'/><text x='110' y='115' font-size='10' text-anchor='middle' fill='#1a2b45'>Cl</text><circle cx='160' cy='110' r='16' fill='#cfd8e8' stroke='#1a2b45'/><text x='160' y='115' font-size='10' text-anchor='middle' fill='#1a2b45'>Na</text><circle cx='210' cy='110' r='16' fill='#9ed9a8' stroke='#1a2b45'/><text x='210' y='115' font-size='10' text-anchor='middle' fill='#1a2b45'>Cl</text><text x='160' y='160' font-size='11' text-anchor='middle' fill='#1a2b45'>düzenli dizilim</text></svg>","steps":[{"t":"Sıralı diziliş","a":"yan yana ve üst üste","d":"Tanecikler birbiriyle nöbetleşe, satır ve sütunlar halinde dizilir."},{"t":"Düzen","a":"hep aynı","d":"Bu düzen tüm kristal boyunca aynı şekilde tekrarlanır."}],"ans":"Tuz kristalinde tanecikler satır ve sütunlar halinde, sürekli tekrar eden düzenli bir dizilimle yerleşir."},{"q":"Tuzu eritmek için neden çok yüksek sıcaklık gerekir?","steps":[{"t":"Sıkı tutunma","a":"birbirini güçlü çeker","d":"Tuzdaki tanecikler birbirine çok güçlü tutunur."},{"t":"Çok ısı","a":"zor erir","d":"Bu güçlü tutunmayı bozmak için çok fazla ısı gerekir, bu yüzden tuz geç erir."}],"ans":"Tuzun tanecikleri birbirine çok güçlü tutunduğu için eritmek yüksek sıcaklık ister."},{"q":"Tuz kristalini sertçe vurursak ne olur?","steps":[{"t":"Kırılma","a":"ufalanır","d":"Tuz esnek değildir; sertçe vurulunca eğilmez, kırılıp ufalanır."},{"t":"Gevreklik","a":"kolay parçalanır","d":"Bu özelliğe gevreklik denir; tuz gibi kristaller kolayca parçalara ayrılır."}],"ans":"Tuz kristali gevrek olduğu için sertçe vurulunca eğilmeyip kırılır ve ufalanır."}],"zor":[{"q":"Bir tuz tanesinin her yöne aynı düzgün şekilde uzanmasının nedeni nedir?","steps":[{"t":"Üç boyutlu düzen","a":"her yöne sıralı","d":"Tanecikler sadece yan yana değil, yukarı-aşağı ve öne-arkaya doğru da düzenli dizilir."},{"t":"Tekrar eden yapı","a":"aynı desen","d":"Aynı düzen her yöne tekrarlandığı için tane düzgün ve simetrik görünür."}],"ans":"Tanecikler üç boyutta her yöne aynı düzenle dizildiği için tuz tanesi düzgün ve simetrik bir şekil alır."},{"q":"Tuz suda çözündüğünde tanecikleri ne yapar?","fig":"<svg viewBox='0 0 320 170'><rect x='40' y='40' width='240' height='100' fill='none' stroke='#1a2b45'/><circle cx='90' cy='80' r='12' fill='#cfd8e8' stroke='#1a2b45'/><text x='90' y='84' font-size='9' text-anchor='middle' fill='#1a2b45'>Na⁺</text><circle cx='170' cy='110' r='12' fill='#9ed9a8' stroke='#1a2b45'/><text x='170' y='114' font-size='9' text-anchor='middle' fill='#1a2b45'>Cl⁻</text><circle cx='230' cy='70' r='12' fill='#cfd8e8' stroke='#1a2b45'/><text x='230' y='74' font-size='9' text-anchor='middle' fill='#1a2b45'>Na⁺</text><circle cx='130' cy='120' r='12' fill='#9ed9a8' stroke='#1a2b45'/><text x='130' y='124' font-size='9' text-anchor='middle' fill='#1a2b45'>Cl⁻</text><text x='160' y='158' font-size='10' text-anchor='middle' fill='#1a2b45'>suda dağılan iyonlar</text></svg>","steps":[{"t":"Düzen bozulur","a":"tanecikler ayrılır","d":"Su, düzenli dizilimi bozar ve tanecikleri birbirinden ayırır."},{"t":"Dağılma","a":"su içinde gezer","d":"Ayrılan yüklü tanecikler (iyonlar) su içinde serbestçe dağılır."}],"ans":"Tuz suda çözününce düzenli dizilim bozulur ve yüklü tanecikler su içinde serbestçe dağılır."},{"q":"Katı tuz elektriği iletmezken tuzlu su neden iletir?","steps":[{"t":"Katıda hareketsiz","a":"yerleri sabit","d":"Katı tuzda yüklü tanecikler sıkıca yerlerine kilitlidir, hareket edemez."},{"t":"Suda serbest","a":"hareketli yükler","d":"Suda çözününce yüklü tanecikler serbest kalıp hareket eder; hareketli yükler elektriği iletir."}],"ans":"Katı tuzda yükler hareketsiz olduğundan iletmez; suda çözününce serbest kalan yüklü tanecikler elektriği iletir."},{"q":"Tuz kristalinde her sodyumun etrafında neden klorlar bulunur?","steps":[{"t":"Zıt çeker","a":"artı-eksi","d":"Sodyum artı, klor eksi yüklüdür; zıt yükler birbirini çeker."},{"t":"Komşuluk","a":"karşılıklı dizilim","d":"Bu yüzden her sodyumun çevresine klorlar, her klorun çevresine sodyumlar dizilir."}],"ans":"Zıt yükler birbirini çektiğinden her sodyumun etrafında klorlar, her klorun etrafında sodyumlar dizilir."},{"q":"Şeker eridiğinde yumuşarken tuz neden katı kalıp birden erir?","steps":[{"t":"Tuzda güçlü çekim","a":"sıkı bağ","d":"Tuzdaki yüklü tanecikler birbirine çok güçlü tutunur, bu yüzden geç ve yüksek sıcaklıkta erir."},{"t":"Şekerde zayıf çekim","a":"daha kolay","d":"Şeker taneciklerinin tutunması daha zayıftır, bu yüzden daha düşük sıcaklıkta yumuşar."}],"ans":"Tuzdaki tanecikler birbirine çok güçlü tutunduğundan yüksek sıcaklıkta erir; şekerin tutunması zayıf olduğu için daha kolay yumuşar."}]},"ortaokul":{"kolay":[{"q":"İyonik kristal nedir?","steps":[{"t":"İyonlar","a":"artı ve eksi yüklüler","d":"İyonik kristalde artı yüklü (katyon) ve eksi yüklü (anyon) iyonlar bulunur."},{"t":"Düzenli dizilim","a":"örgü yapısı","d":"Bu zıt iyonlar üç boyutta düzenli olarak dizilip örgü (kristal) yapısı oluşturur."}],"ans":"İyonik kristal, zıt yüklü iyonların üç boyutta düzenli dizilmesiyle oluşan katı yapıdır."},{"q":"NaCl kristalinde sodyum ve klor iyonları nasıl yerleşir?","fig":"<svg viewBox='0 0 320 185'><circle cx='100' cy='55' r='15' fill='#cfd8e8' stroke='#1a2b45'/><text x='100' y='59' font-size='9' text-anchor='middle' fill='#1a2b45'>Na⁺</text><circle cx='160' cy='55' r='15' fill='#9ed9a8' stroke='#1a2b45'/><text x='160' y='59' font-size='9' text-anchor='middle' fill='#1a2b45'>Cl⁻</text><circle cx='220' cy='55' r='15' fill='#cfd8e8' stroke='#1a2b45'/><text x='220' y='59' font-size='9' text-anchor='middle' fill='#1a2b45'>Na⁺</text><circle cx='100' cy='115' r='15' fill='#9ed9a8' stroke='#1a2b45'/><text x='100' y='119' font-size='9' text-anchor='middle' fill='#1a2b45'>Cl⁻</text><circle cx='160' cy='115' r='15' fill='#cfd8e8' stroke='#1a2b45'/><text x='160' y='119' font-size='9' text-anchor='middle' fill='#1a2b45'>Na⁺</text><circle cx='220' cy='115' r='15' fill='#9ed9a8' stroke='#1a2b45'/><text x='220' y='119' font-size='9' text-anchor='middle' fill='#1a2b45'>Cl⁻</text><text x='160' y='165' font-size='10' text-anchor='middle' fill='#1a2b45'>nöbetleşe dizilim</text></svg>","steps":[{"t":"Nöbetleşe diziliş","a":"karşılıklı","d":"Her Na⁺ iyonunun etrafına Cl⁻, her Cl⁻ iyonunun etrafına Na⁺ iyonları dizilir."},{"t":"Çekim","a":"zıt yük","d":"Bu nöbetleşe dizilim, zıt yüklerin birbirini çekmesiyle en kararlı yapıyı verir."}],"ans":"NaCl kristalinde Na⁺ ve Cl⁻ iyonları zıt yüklerin çekimiyle nöbetleşe (karşılıklı) dizilir."},{"q":"Koordinasyon sayısı ne demektir?","steps":[{"t":"Komşu sayısı","a":"yakın zıt iyon","d":"Bir iyonun çevresinde ona en yakın bulunan zıt yüklü iyon sayısıdır."},{"t":"NaCl örneği","a":"6","d":"NaCl kristalinde her Na⁺ iyonunun çevresinde 6 Cl⁻ bulunur; koordinasyon sayısı 6'dır."}],"ans":"Koordinasyon sayısı, bir iyonun çevresindeki en yakın zıt iyon sayısıdır; NaCl'de bu sayı 6'dır."},{"q":"İyonik kristaller neden serttir ama gevrektir?","steps":[{"t":"Güçlü çekim","a":"sert","d":"İyonlar arası güçlü çekim yapıyı sert ve dayanıklı yapar."},{"t":"Kayan tabakalar","a":"gevrek","d":"Darbe ile tabakalar kayarsa aynı yükler yan yana gelip itişir ve kristal aniden kırılır (gevreklik)."}],"ans":"İyonlar arası güçlü çekim kristali sert yapar; ancak darbede aynı yükler karşılaşıp itişeceğinden kristal gevrek olup kırılır."},{"q":"İyonik bileşikler neden yüksek erime ve kaynama noktasına sahiptir?","steps":[{"t":"Örgü çekimi","a":"çok güçlü","d":"Kristal örgüde zıt iyonlar arasındaki elektrostatik çekim çok güçlüdür."},{"t":"Çok enerji","a":"yüksek sıcaklık","d":"Bu çekimleri yenip iyonları ayırmak için yüksek sıcaklık (çok enerji) gerekir."}],"ans":"İyonik bileşiklerde örgüdeki güçlü iyon çekimini yenmek çok enerji gerektirdiğinden erime ve kaynama noktaları yüksektir."}],"zor":[{"q":"İyonik bir bileşik katı halde iletmezken sıvı (eriyik) halde neden elektriği iletir?","steps":[{"t":"Katıda sabit iyonlar","a":"hareketsiz","d":"Katı halde iyonlar örgüde sabit yerlerine kilitlidir, hareket edemez, bu yüzden yük taşıyamaz."},{"t":"Eriyikte serbest iyonlar","a":"hareketli","d":"Eritildiğinde örgü bozulur, iyonlar serbestçe hareket eder ve yükü taşıyarak elektriği iletir."}],"ans":"Katıda iyonlar sabit olduğundan iletmez; eritildiğinde serbest kalan hareketli iyonlar yük taşıdığı için elektrik iletilir."},{"q":"NaCl kristalinde koordinasyon sayısının 6 olması yapı hakkında ne söyler?","fig":"<svg viewBox='0 0 320 185'><circle cx='160' cy='95' r='16' fill='#cfd8e8' stroke='#1a2b45'/><text x='160' y='99' font-size='9' text-anchor='middle' fill='#1a2b45'>Na⁺</text><circle cx='160' cy='45' r='13' fill='#9ed9a8' stroke='#1a2b45'/><circle cx='160' cy='145' r='13' fill='#9ed9a8' stroke='#1a2b45'/><circle cx='110' cy='95' r='13' fill='#9ed9a8' stroke='#1a2b45'/><circle cx='210' cy='95' r='13' fill='#9ed9a8' stroke='#1a2b45'/><circle cx='125' cy='60' r='13' fill='#9ed9a8' stroke='#1a2b45'/><circle cx='195' cy='130' r='13' fill='#9ed9a8' stroke='#1a2b45'/><line x1='160' y1='95' x2='160' y2='45' stroke='#1a2b45'/><line x1='160' y1='95' x2='160' y2='145' stroke='#1a2b45'/><line x1='160' y1='95' x2='110' y2='95' stroke='#1a2b45'/><line x1='160' y1='95' x2='210' y2='95' stroke='#1a2b45'/><text x='160' y='178' font-size='10' text-anchor='middle' fill='#1a2b45'>6 komşu Cl⁻</text></svg>","steps":[{"t":"Altı komşu","a":"oktahedral","d":"Her iyonun 6 zıt iyonla çevrili olması, iyonların oktahedral (sekiz yüzlü) bir düzende oturduğunu gösterir."},{"t":"Üç boyutlu örgü","a":"sürekli ağ","d":"Bu düzen kristal boyunca tekrarlanarak üç boyutlu, sürekli ve çok güçlü bir iyonik örgü oluşturur."}],"ans":"Koordinasyon sayısının 6 olması, her iyonun 6 zıt iyonla oktahedral düzende çevrildiğini ve üç boyutlu sürekli güçlü bir örgü oluştuğunu gösterir."},{"q":"İyonik bileşiklerin formülü neden molekül değil, en basit oran (NaCl) olarak yazılır?","steps":[{"t":"Ayrı molekül yok","a":"sürekli örgü","d":"İyonik kristalde tek tek 'NaCl molekülü' yoktur; sayısız iyon kesintisiz bir örgü oluşturur."},{"t":"Oran formülü","a":"1:1","d":"Formül, iyonların en basit sayı oranını gösterir; NaCl'de her Na⁺ için bir Cl⁻ olduğundan oran 1:1'dir."}],"ans":"İyonik bileşiklerde ayrı molekül olmadığından formül, iyonların kristaldeki en basit oranını gösterir (NaCl'de 1:1)."},{"q":"İyonik kristaller neden suda çözünebilirken birçok katı çözünmez?","steps":[{"t":"Su çekimi","a":"kutuplu su","d":"Su molekülleri kutupludur; eksi ucu Na⁺'ı, artı ucu Cl⁻'ı çeker."},{"t":"İyonların ayrılması","a":"hidratlanma","d":"Su molekülleri iyonları örgüden çekip sarar (hidratlar); bu çekim örgü enerjisini yenebildiğinde tuz çözünür."}],"ans":"Kutuplu su molekülleri zıt yüklü iyonları çekip sararak örgüden ayırabildiği için iyonik kristaller suda çözünür."},{"q":"Erime noktası MgO'nun NaCl'den çok daha yüksek olmasının nedeni nedir?","steps":[{"t":"İyon yükleri","a":"2+ ve 2−","d":"MgO'da Mg²⁺ ve O²⁻ iyonları varken NaCl'de Na⁺ ve Cl⁻ (tek yük) bulunur."},{"t":"Çekim gücü","a":"yük arttıkça güçlü","d":"İyon yükü büyüdükçe örgü çekim enerjisi artar; daha yüksek yüklü MgO'yu eritmek çok daha fazla enerji ister."}],"ans":"MgO'da iyon yükleri (2+ ve 2−) daha büyük olduğundan örgü çekimi NaCl'den çok güçlüdür; bu nedenle erime noktası çok daha yüksektir."}]},"lise":{"kolay":[{"q":"İyonik örgü (kristal kafes) nedir ve nasıl oluşur?","steps":[{"t":"İyon oluşumu","a":"e⁻ aktarımı","d":"Metal değerlik elektronunu ametale aktarır; katyon (+) ve anyon (−) oluşur."},{"t":"Üç boyutlu düzen","a":"elektrostatik örgü","d":"Zıt yüklü iyonlar elektrostatik çekimle üç boyutta düzenli ve tekrarlı bir kafes (örgü) oluşturur."}],"ans":"İyonik örgü, elektron aktarımıyla oluşan zıt yüklü iyonların elektrostatik çekimle üç boyutta düzenli dizildiği kristal kafestir."},{"q":"NaCl kristalinin koordinasyon yapısını açıklayınız.","fig":"<svg viewBox='0 0 320 185'><circle cx='160' cy='95' r='15' fill='#cfd8e8' stroke='#1a2b45'/><text x='160' y='99' font-size='9' text-anchor='middle' fill='#1a2b45'>Na⁺</text><circle cx='160' cy='45' r='12' fill='#9ed9a8' stroke='#1a2b45'/><circle cx='160' cy='145' r='12' fill='#9ed9a8' stroke='#1a2b45'/><circle cx='110' cy='95' r='12' fill='#9ed9a8' stroke='#1a2b45'/><circle cx='210' cy='95' r='12' fill='#9ed9a8' stroke='#1a2b45'/><circle cx='128' cy='62' r='12' fill='#9ed9a8' stroke='#1a2b45'/><circle cx='192' cy='128' r='12' fill='#9ed9a8' stroke='#1a2b45'/><line x1='160' y1='95' x2='160' y2='45' stroke='#1a2b45'/><line x1='160' y1='95' x2='160' y2='145' stroke='#1a2b45'/><line x1='160' y1='95' x2='110' y2='95' stroke='#1a2b45'/><line x1='160' y1='95' x2='210' y2='95' stroke='#1a2b45'/><text x='160' y='178' font-size='10' text-anchor='middle' fill='#1a2b45'>6:6 koordinasyon</text></svg>","steps":[{"t":"Koordinasyon sayısı","a":"6:6","d":"NaCl'de her Na⁺ iyonu 6 Cl⁻, her Cl⁻ iyonu 6 Na⁺ ile çevrilidir (6:6 koordinasyon)."},{"t":"Geometri","a":"oktahedral","d":"Bu altı komşulu düzen oktahedral boşluk geometrisidir ve yüzey merkezli kübik bir örgü oluşturur."}],"ans":"NaCl'de her iyon zıt iyonla 6:6 koordinasyon yapar; her iyon 6 komşuyla oktahedral düzende, yüzey merkezli kübik örgü oluşturur."},{"q":"İyonik bileşiklerin gevrek olmasının nedenini örgü açısından açıklayınız.","steps":[{"t":"Tabaka kayması","a":"darbe","d":"Kristale darbe uygulanınca bir iyon tabakası diğerine göre kayar."},{"t":"Yük itmesi","a":"aynı yükler karşılaşır","d":"Kayma sonucu aynı yüklü iyonlar karşı karşıya gelir, güçlü itme oluşur ve kristal o düzlemden aniden kırılır."}],"ans":"Darbe ile tabakalar kayınca aynı yüklü iyonlar karşılaşıp itiştiğinden iyonik kristal aniden kırılır; bu yüzden gevrektir."},{"q":"Örgü enerjisi nedir ve iyonik bileşiklerin erime noktasını nasıl etkiler?","steps":[{"t":"Tanım","a":"örgü kuruluş enerjisi","d":"Örgü enerjisi, gaz halindeki iyonlardan iyonik katı oluşurken açığa çıkan enerjidir; iyonları ayırmak için gereken enerjiye eşittir."},{"t":"Erime ilişkisi","a":"büyükse yüksek","d":"Örgü enerjisi büyüdükçe iyonları ayırmak zorlaşır; bu da daha yüksek erime noktası demektir."}],"ans":"Örgü enerjisi iyonları bir arada tutan elektrostatik enerjidir; büyüdükçe iyonları ayırmak zorlaşır ve erime noktası yükselir."},{"q":"İyonik bileşiklerin katı, sıvı ve sulu hallerdeki elektrik iletkenliğini karşılaştırınız.","steps":[{"t":"Katı hal","a":"iletmez","d":"Katıda iyonlar örgüde sabittir; serbest yük taşıyıcı bulunmadığından elektriği iletmez."},{"t":"Sıvı/çözelti","a":"iletir","d":"Eriyik veya sulu çözeltide iyonlar serbestçe hareket ettiğinden yük taşır ve elektriği iletir."}],"ans":"İyonik bileşik katı halde iletmez; eriyik ve sulu çözeltide ise serbest iyonlar yük taşıdığından elektriği iletir."}],"zor":[{"q":"NaCl örgüsünde örgü enerjisini etkileyen faktörleri (Coulomb yasası ile) açıklayınız.","fig":"<svg viewBox='0 0 320 175'><circle cx='100' cy='90' r='24' fill='#cfd8e8' stroke='#1a2b45'/><text x='100' y='95' font-size='12' text-anchor='middle' fill='#1a2b45'>Na⁺</text><circle cx='220' cy='90' r='24' fill='#9ed9a8' stroke='#1a2b45'/><text x='220' y='95' font-size='12' text-anchor='middle' fill='#1a2b45'>Cl⁻</text><line x1='124' y1='90' x2='196' y2='90' stroke='#2b6be0' stroke-width='2' stroke-dasharray='5 3'/><text x='160' y='80' font-size='10' text-anchor='middle' fill='#1a2b45'>r (uzaklık)</text><text x='160' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>E ∝ (q₁·q₂)/r</text></svg>","steps":[{"t":"Yüklerin etkisi","a":"q₁·q₂ artarsa güçlü","d":"Coulomb yasasına göre çekim, iyon yüklerinin çarpımıyla doğru orantılıdır; yük büyüdükçe örgü enerjisi artar."},{"t":"Uzaklığın etkisi","a":"r küçükse güçlü","d":"Çekim, iyonlar arası uzaklıkla ters orantılıdır; iyon yarıçapı küçük olup iyonlar yakınlaştıkça örgü enerjisi büyür."}],"ans":"Örgü enerjisi, iyon yüklerinin çarpımıyla doğru, iyonlar arası uzaklıkla ters orantılıdır; büyük yük ve küçük yarıçap örgü enerjisini artırır."},{"q":"İyon yarıçapları oranının kristal yapıyı (koordinasyon sayısını) nasıl belirlediğini açıklayınız.","steps":[{"t":"Yarıçap oranı","a":"katyon/anyon","d":"Katyonun anyona oranı, katyonun çevresine kaç anyonun temas ederek sığabileceğini belirler."},{"t":"Yapı seçimi","a":"oran-koordinasyon","d":"Oran küçükse az komşu (örneğin 4, çinko sülfür tipi), orta ise 6 (NaCl tipi), büyükse 8 (sezyum klorür tipi) koordinasyon oluşur."}],"ans":"Katyon/anyon yarıçap oranı kararlı geometriyi belirler; oran büyüdükçe koordinasyon sayısı 4 → 6 → 8 şeklinde artar (ZnS, NaCl, CsCl tipleri)."},{"q":"Born–Haber çevrimi iyonik bileşik oluşumunu hangi enerji basamaklarıyla açıklar?","steps":[{"t":"İyon hazırlama","a":"süblimleşme, iyonlaşma, elektron ilgisi","d":"Metal katıdan gaza geçer (süblimleşme), elektron koparır (iyonlaşma enerjisi); ametal atomlaşır ve elektron alır (elektron ilgisi)."},{"t":"Örgü oluşumu","a":"örgü enerjisi","d":"Gaz iyonlar bir araya gelip örgü kurarken büyük örgü enerjisi açığa çıkar; tüm basamakların toplamı oluşum entalpisini verir (Hess yasası)."}],"ans":"Born–Haber çevrimi; süblimleşme, iyonlaşma enerjisi, bağ ayrışması, elektron ilgisi ve örgü enerjisi basamaklarını Hess yasasıyla toplayarak iyonik oluşum entalpisini açıklar."},{"q":"İyonik bağda kovalent karakter ne zaman ortaya çıkar (Fajans kuralları)?","steps":[{"t":"Polarlaşma","a":"katyon anyonu çeker","d":"Küçük ve yüksek yüklü katyon, büyük ve yüksek yüklü anyonun elektron bulutunu kendine doğru çeker (polarlaştırır)."},{"t":"Kovalent katkı","a":"elektron yoğunluğu kayar","d":"Bu polarlaşma elektron yoğunluğunu iyonlar arasında paylaştırır; böylece iyonik bağ kısmen kovalent karakter kazanır."}],"ans":"Küçük/yüksek yüklü katyonun büyük/yüksek yüklü anyonu polarlaştırması (Fajans kuralları) iyonik bağa kısmi kovalent karakter kazandırır."},{"q":"İyonik bileşiklerin sertlik ve gevrekliğini örgü ve yük dağılımıyla ilişkilendirerek açıklayınız.","steps":[{"t":"Sertlik kaynağı","a":"yönsüz güçlü çekim","d":"Örgüdeki her iyon çok sayıda zıt iyonla güçlü ve yönsüz elektrostatik çekim kurar; bu yapıyı sert ve dirençli yapar."},{"t":"Gevreklik kaynağı","a":"tabaka kayması","d":"Kayan tabakalarda aynı yüklü iyonlar hizalanıp şiddetle itişir; bağlar metalik gibi yeniden kurulamadığından kristal aniden kırılır."}],"ans":"Yönsüz ve güçlü iyon çekimleri kristali sert yapar; ancak tabaka kayınca aynı yükler itişip bağlar yeniden kurulamadığından kristal gevrek olup kırılır."}]}},"iyonIndukDipol":{"ilkokul":{"kolay":[{"q":"Yüklü bir tanecik, yüksüz (tarafsız) bir tanecikten geçici olarak hafif bir yapışkanlık oluşturabilir mi?","steps":[{"t":"Yüklü tanecik","a":"çeker","d":"Artı ya da eksi yüklü bir tanecik, yanına gelen tarafsız taneciği etkiler."},{"t":"Geçici çekim","a":"hafif tutunma","d":"Bu etki çok zayıftır ve sadece yan yanayken sürer; tanecikler uzaklaşınca biter."}],"ans":"Evet; yüklü bir tanecik, tarafsız bir taneciğe geçici ve çok zayıf bir çekim uygulayabilir."},{"q":"Mıknatıs, demir tozunu yanına gelince çeker; bu, yüklü tanecik ile tarafsız tanecik arasındaki çekime nasıl benzer?","steps":[{"t":"Mıknatıs benzetmesi","a":"yaklaşınca etkiler","d":"Mıknatıs, yanına gelen demir tozunu yaklaşınca hareketlendirip çeker."},{"t":"Tanecikte de öyle","a":"yaklaşınca çekim","d":"Yüklü bir tanecik de tarafsız taneciği yaklaşınca etkileyip hafifçe çeker."}],"ans":"Mıknatısın demir tozunu yaklaşınca çekmesi gibi, yüklü tanecik de yanındaki tarafsız taneciği hafifçe çeker."},{"q":"Bu çekim güçlü müdür yoksa çok zayıf mıdır?","steps":[{"t":"Güç","a":"çok zayıf","d":"Bu tür çekim, atomları birbirine sıkıca bağlayan kuvvetlerden çok daha zayıftır."},{"t":"Geçici","a":"kısa sürer","d":"Yalnızca tanecikler yan yanayken ortaya çıkar, sonra kaybolur."}],"ans":"Bu çekim çok zayıftır ve yalnızca tanecikler yan yanayken görülür."},{"q":"Tarafsız bir tanecik, yanına yüklü tanecik gelince geçici olarak nasıl değişir?","fig":"<svg viewBox='0 0 320 150'><circle cx='90' cy='75' r='22' fill='#2b6be0' stroke='#1a2b45'/><text x='90' y='80' font-size='14' text-anchor='middle' fill='#fff'>−</text><circle cx='210' cy='75' r='30' fill='#cfd8e8' stroke='#1a2b45'/><text x='190' y='80' font-size='12' fill='#1a2b45'>+</text><text x='228' y='80' font-size='12' fill='#1a2b45'>−</text><text x='160' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>tarafsız tanecik geçici uçlanır</text></svg>","steps":[{"t":"Önce dengeli","a":"yüksüz","d":"Tarafsız tanecikte artı ve eksi eşit dağılmıştır, dışarıdan yüksüz görünür."},{"t":"Yanına yük gelince","a":"hafif uçlanır","d":"Yüklü tanecik yaklaşınca, tarafsız taneciğin içindeki eksi ve artı az da olsa bir tarafa kayar."}],"ans":"Tarafsız tanecik, yanına yüklü tanecik gelince içindeki yükler hafifçe kayarak geçici olarak uçlanır."},{"q":"Gazların suda çok az çözünmesi, bu zayıf geçici çekimle ilgili olabilir mi?","steps":[{"t":"Gaz tanecikleri","a":"yüksüz","d":"Havadaki bazı gaz tanecikleri tarafsızdır, kolay tutunmaz."},{"t":"Zayıf çekim","a":"az çözünür","d":"Sudaki yüklü tanecikler bu gazları ancak çok zayıf çekebildiği için gaz suda az çözünür."}],"ans":"Evet; gazların suda az çözünmesinin bir nedeni, sudaki yüklü taneciklerle gaz tanecikleri arasındaki çekimin çok zayıf olmasıdır."}],"zor":[{"q":"Bir balon saça sürtülünce küçük kâğıt parçalarını çeker; bu olay yüklü tanecik ile tarafsız tanecik çekimine nasıl benzetilir?","steps":[{"t":"Balon yüklenir","a":"yük kazanır","d":"Saça sürtülen balon yük kazanır, tıpkı yüklü bir tanecik gibi olur."},{"t":"Kâğıdı etkiler","a":"uçlanma","d":"Yüklü balon, yüksüz kâğıttaki yükleri hafif kaydırıp onu çeker; aynı şekilde yüklü tanecik de tarafsız taneciği uçlandırıp çeker."}],"ans":"Yüklenmiş balonun yüksüz kâğıdı çekmesi gibi, yüklü tanecik de tarafsız taneciği geçici uçlandırarak çeker."},{"q":"Neden bu çekim, iki yüklü tanecik arasındaki çekimden daha zayıftır?","steps":[{"t":"İki yük varsa","a":"güçlü çeker","d":"Artı ve eksi iki kalıcı yük her zaman birbirini güçlü çeker."},{"t":"Tek yük + tarafsız","a":"geçici, zayıf","d":"Burada tarafsız taneciğin yükü kalıcı değil, sonradan ve az miktarda oluşur; bu yüzden çekim zayıftır."}],"ans":"Tarafsız taneciğin yükü kalıcı değil, geçici ve küçük olduğundan bu çekim iki kalıcı yük arasındaki çekimden daha zayıftır."},{"q":"Tarafsız tanecik büyük ve yumuşak ise mi, küçük ve sıkı ise mi daha kolay uçlanır?","steps":[{"t":"Büyük tanecik","a":"yükler oynak","d":"Büyük bir tanecikte dış elektronlar daha gevşek tutulduğu için kolayca kayabilir."},{"t":"Kolay uçlanma","a":"daha güçlü çekim","d":"Yükleri kolay kayan tanecik daha çok uçlanır, böylece çekim biraz daha belirgin olur."}],"ans":"Büyük ve yükleri gevşek tutulan tanecik daha kolay uçlanır, bu yüzden çekim ondan daha güçlü olur."},{"q":"Bu geçici çekim kalktıktan sonra tarafsız tanecik eski haline döner mi?","steps":[{"t":"Yük uzaklaşınca","a":"etki biter","d":"Yüklü tanecik uzaklaştığında onu uçlandıran etki ortadan kalkar."},{"t":"Geri döner","a":"yeniden dengeli","d":"Tanecik içindeki yükler tekrar eşit dağılır ve tanecik yine tarafsız hale gelir."}],"ans":"Evet; yüklü tanecik uzaklaşınca tarafsız tanecik tekrar dengeli (yüksüz) haline döner."},{"q":"Tuzlu su gibi yüklü tanecik dolu bir sıvıda, havadaki tarafsız gaz neden zor barınır?","fig":"<svg viewBox='0 0 320 155'><rect x='30' y='30' width='260' height='100' fill='#dceaff' stroke='#1a2b45'/><circle cx='80' cy='70' r='10' fill='#2b6be0'/><text x='80' y='74' font-size='9' text-anchor='middle' fill='#fff'>+</text><circle cx='140' cy='95' r='10' fill='#e0552b'/><text x='140' y='99' font-size='9' text-anchor='middle' fill='#fff'>−</text><circle cx='225' cy='65' r='14' fill='#cfd8e8' stroke='#1a2b45'/><text x='225' y='69' font-size='9' text-anchor='middle' fill='#1a2b45'>gaz</text><text x='160' y='145' font-size='10' text-anchor='middle' fill='#1a2b45'>yüklü tanecikler arası çekim güçlü</text></svg>","steps":[{"t":"Yüklü tanecikler","a":"birbirini güçlü tutar","d":"Sudaki yüklü tanecikler birbirini güçlü çeker ve sıkıca bir arada durur."},{"t":"Gaza zayıf çekim","a":"yer açılmaz","d":"Tarafsız gaz taneciğine ancak zayıf bir çekim uygulanır, bu yüzden gaz sıvının içine kolay giremez."}],"ans":"Sudaki yüklü tanecikler birbirini güçlü tuttuğu, tarafsız gaza ise yalnızca zayıf çekim uygulayabildiği için gaz suda zor barınır (az çözünür)."}]},"ortaokul":{"kolay":[{"q":"İyon-indüklenmiş dipol etkileşimi nedir?","steps":[{"t":"İyon","a":"yüklü tanecik","d":"İyon, artı veya eksi yüklü bir atom ya da atom grubudur."},{"t":"İndükleme","a":"geçici dipol oluşturur","d":"İyon, yanındaki apolar taneciğin yüklerini kaydırarak onda geçici bir dipol (uçlanma) oluşturur; bu zayıf çekime iyon-indüklenmiş dipol denir."}],"ans":"İyon-indüklenmiş dipol, bir iyonun apolar taneciği uçlandırarak (geçici dipol oluşturarak) onu zayıfça çekmesidir."},{"q":"Apolar molekül ne demektir?","steps":[{"t":"Yük dağılımı","a":"dengeli","d":"Apolar molekülde artı ve eksi yük dengeli dağılmıştır, kalıcı bir kutbu yoktur."},{"t":"Örnek","a":"O₂, N₂","d":"Oksijen (O₂) ve azot (N₂) gibi gazlar apolardır."}],"ans":"Apolar molekül, yük dağılımı dengeli olan ve kalıcı kutbu bulunmayan moleküldür (örneğin O₂, N₂)."},{"q":"İyon, apolar moleküle yaklaştığında ne olur?","fig":"<svg viewBox='0 0 320 150'><circle cx='85' cy='75' r='22' fill='#e0552b' stroke='#1a2b45'/><text x='85' y='80' font-size='15' text-anchor='middle' fill='#fff'>+</text><circle cx='210' cy='75' r='30' fill='#cfd8e8' stroke='#1a2b45'/><text x='192' y='80' font-size='12' fill='#1a2b45'>−</text><text x='226' y='80' font-size='12' fill='#1a2b45'>+</text><text x='160' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>apolar molekülde geçici dipol</text></svg>","steps":[{"t":"İyonun alanı","a":"yükü iter/çeker","d":"İyonun yükü, apolar moleküldeki elektronları bir tarafa doğru iter ya da çeker."},{"t":"Geçici dipol","a":"uçlar oluşur","d":"Böylece apolar molekülde bir uç hafif eksi, diğer uç hafif artı olur; bu geçici dipoldür."}],"ans":"İyon yaklaştığında apolar molekülün elektronları kayar ve molekülde geçici bir dipol (uçlanma) oluşur."},{"q":"Bu etkileşim güçlü bir bağ mıdır?","steps":[{"t":"Karşılaştırma","a":"zayıf","d":"İyon-indüklenmiş dipol etkileşimi, iyonik ya da kovalent bağlardan çok daha zayıftır."},{"t":"Tür","a":"zayıf etkileşim","d":"Bu, atomları molekülde tutan güçlü bağlardan değil, moleküller arası zayıf çekim türündendir."}],"ans":"Hayır; iyon-indüklenmiş dipol, iyonik ve kovalent bağlara göre çok zayıf bir moleküller arası etkileşimdir."},{"q":"Apolar gazların iyonlu (örneğin tuzlu) suda az çözünmesini ne açıklar?","steps":[{"t":"Zayıf çekim","a":"iyon–apolar","d":"Sudaki iyonlar apolar gaz moleküllerini ancak zayıf bir iyon-indüklenmiş dipol etkileşimiyle çekebilir."},{"t":"Az çözünme","a":"tutunamaz","d":"Bu çekim zayıf olduğundan apolar gaz iyonlu çözeltide kolay tutunamaz ve az çözünür."}],"ans":"İyonlar apolar gazları yalnızca zayıf iyon-indüklenmiş dipol etkileşimiyle çekebildiğinden, apolar gazlar iyonlu çözeltide az çözünür."}],"zor":[{"q":"İyon-indüklenmiş dipol etkileşiminin gücü neye bağlıdır?","steps":[{"t":"İyonun yükü","a":"büyük yük = güçlü","d":"İyonun yükü büyüdükçe apolar molekülü daha çok uçlandırır, etkileşim güçlenir."},{"t":"Polarlanabilirlik","a":"büyük molekül = güçlü","d":"Apolar molekül büyük ve elektronları gevşek (kolay kayar) ise daha çok uçlanır, etkileşim artar."}],"ans":"Etkileşim, iyonun yükü büyüdükçe ve apolar molekül kolay polarlanabildikçe (büyük, gevşek elektronlu) güçlenir."},{"q":"İyon-dipol ile iyon-indüklenmiş dipol etkileşimi arasındaki fark nedir?","steps":[{"t":"İyon-dipol","a":"kalıcı dipol","d":"İyon-dipolde iyon, kalıcı dipolü olan polar molekülü çeker (örneğin Na⁺ ile su)."},{"t":"İyon-indüklenmiş dipol","a":"geçici dipol","d":"Burada apolar moleküldeki dipol kalıcı değildir; iyon onu geçici olarak oluşturur, bu yüzden daha zayıftır."}],"ans":"İyon-dipolde polar molekülün kalıcı dipolü çekilir; iyon-indüklenmiş dipolde apolar molekülde geçici dipol oluşturulur ve etkileşim daha zayıftır."},{"q":"Neden büyük apolar moleküller iyon tarafından daha kolay uçlandırılır?","steps":[{"t":"Büyük elektron bulutu","a":"gevşek tutulur","d":"Büyük moleküllerde elektronlar çekirdeklerden uzakta ve gevşek tutulduğundan kolayca yer değiştirir."},{"t":"Yüksek polarlanabilirlik","a":"daha çok dipol","d":"Bu moleküller daha çok uçlanır (yüksek polarlanabilirlik), iyon onları daha güçlü çeker."}],"ans":"Büyük apolar moleküllerin elektronları gevşek tutulduğundan kolay kayar; polarlanabilirlikleri yüksek olduğu için iyon tarafından daha kolay uçlandırılırlar."},{"q":"İyonlu çözeltiye apolar gaz eklendiğinde çözünürlük neden saf sudakinden de düşük olabilir?","fig":"<svg viewBox='0 0 320 160'><rect x='25' y='28' width='270' height='105' fill='#dceaff' stroke='#1a2b45'/><circle cx='70' cy='65' r='11' fill='#e0552b'/><text x='70' y='69' font-size='9' text-anchor='middle' fill='#fff'>+</text><circle cx='120' cy='100' r='11' fill='#2b6be0'/><text x='120' y='104' font-size='9' text-anchor='middle' fill='#fff'>−</text><circle cx='235' cy='70' r='15' fill='#cfd8e8' stroke='#1a2b45'/><text x='235' y='74' font-size='9' text-anchor='middle' fill='#1a2b45'>apolar</text><text x='160' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>iyonlar suyu kendine bağlar</text></svg>","steps":[{"t":"İyonlar suyu bağlar","a":"hidrasyon","d":"İyonlar su moleküllerini güçlü iyon-dipol çekimiyle çevresine bağlar (hidrasyon)."},{"t":"Apolara yer kalmaz","a":"tuz etkisi","d":"Su iyonlarla meşgul olduğundan apolar gazı barındıracak yer azalır; bu yüzden çözünürlük saf sudakinden de düşebilir."}],"ans":"İyonlar su moleküllerini güçlü iyon-dipol çekimiyle kendine bağlar, apolar gaza yer kalmaz; bu nedenle çözünürlük saf sudakinden de düşük olabilir (tuzla çöktürme etkisi)."},{"q":"İyon-indüklenmiş dipol etkileşimi neden moleküller arası kuvvetler arasında sayılır?","steps":[{"t":"Bağ değil","a":"e ortaklığı/aktarımı yok","d":"Bu etkileşimde elektron alışverişi ya da ortak elektron çifti yoktur; gerçek kimyasal bağ kurulmaz."},{"t":"Tanecikler arası çekim","a":"zayıf kuvvet","d":"Sadece iyon ile apolar tanecik arasında zayıf bir çekim vardır; bu yüzden moleküller arası kuvvetler sınıfına girer."}],"ans":"Elektron aktarımı/ortaklığı içermeyip yalnızca iyon ile apolar tanecik arasında zayıf çekim sağladığından, iyon-indüklenmiş dipol moleküller arası kuvvetler arasında sayılır."}]},"lise":{"kolay":[{"q":"İyon-indüklenmiş dipol etkileşimi nasıl oluşur?","steps":[{"t":"İyonun elektrik alanı","a":"apoları etkiler","d":"İyonun çevresindeki elektrik alanı, yakınındaki apolar moleküle etki eder."},{"t":"İndüklenmiş dipol","a":"geçici uçlanma","d":"Bu alan apolar molekülün elektron bulutunu kaydırarak onda anlık (indüklenmiş) bir dipol oluşturur; iyon ile bu dipol birbirini çeker."}],"ans":"İyonun elektrik alanı apolar molekülün elektron bulutunu kaydırıp geçici (indüklenmiş) dipol oluşturur; iyon ile bu dipol arasındaki çekim iyon-indüklenmiş dipol etkileşimidir."},{"q":"Bu etkileşimin gücünü belirleyen iki temel etken nedir?","steps":[{"t":"İyon yükü ve büyüklüğü","a":"yük yoğunluğu","d":"İyonun yükü büyük, yarıçapı küçük (yük yoğunluğu yüksek) ise apolar molekülü daha çok uçlandırır."},{"t":"Polarlanabilirlik","a":"apolar molekülün","d":"Apolar molekülün polarlanabilirliği (elektron bulutunun kolay kayması) arttıkça etkileşim güçlenir."}],"ans":"Etkileşimin gücü, iyonun yük yoğunluğuna ve apolar molekülün polarlanabilirliğine bağlıdır; ikisi de arttıkça etkileşim güçlenir."},{"q":"İyon-indüklenmiş dipol, etkileşim gücü bakımından diğer moleküller arası kuvvetlere göre nerededir?","steps":[{"t":"Sıralama","a":"London'dan güçlü","d":"İyonun kalıcı yükü bulunduğundan bu etkileşim, yalnız apolar moleküller arası London kuvvetlerinden genelde daha güçlüdür."},{"t":"Bağlardan zayıf","a":"iyonik/kovalentten zayıf","d":"Yine de kalıcı dipol olmadığından iyon-dipolden ve gerçek kimyasal bağlardan (iyonik, kovalent) çok daha zayıftır."}],"ans":"İyon-indüklenmiş dipol, London kuvvetlerinden genelde güçlü; iyon-dipolden, iyonik ve kovalent bağlardan ise çok daha zayıftır."},{"q":"Apolar gazların iyonlu çözeltide az çözünmesini iyon-indüklenmiş dipol ile açıklayınız.","fig":"<svg viewBox='0 0 320 165'><rect x='25' y='28' width='270' height='110' fill='#dceaff' stroke='#1a2b45'/><circle cx='75' cy='65' r='12' fill='#e0552b'/><text x='75' y='69' font-size='10' text-anchor='middle' fill='#fff'>+</text><circle cx='130' cy='105' r='12' fill='#2b6be0'/><text x='130' y='109' font-size='10' text-anchor='middle' fill='#fff'>−</text><circle cx='235' cy='70' r='16' fill='#cfd8e8' stroke='#1a2b45'/><text x='220' y='74' font-size='9' fill='#1a2b45'>−</text><text x='247' y='74' font-size='9' fill='#1a2b45'>+</text><text x='160' y='155' font-size='10' text-anchor='middle' fill='#1a2b45'>zayıf iyon-ind. dipol çekimi</text></svg>","steps":[{"t":"Zayıf çekim","a":"apolar tutunamaz","d":"Apolar gaz molekülü ile çözeltideki iyonlar yalnızca zayıf iyon-indüklenmiş dipol etkileşimi kurabilir."},{"t":"İyon-dipol baskın","a":"su iyonu sarar","d":"Suyun iyonlarla yaptığı güçlü iyon-dipol çekimi baskın olduğundan apolar gaza yer kalmaz; çözünürlük düşer."}],"ans":"Apolar gaz iyonlarla yalnızca zayıf iyon-indüklenmiş dipol kurabilir; güçlü iyon-dipol çekimi suyu iyonlara bağladığından apolar gaz az çözünür."},{"q":"İndüklenmiş dipolün 'geçici' olmasının anlamı nedir?","steps":[{"t":"Alan varken","a":"dipol oluşur","d":"İndüklenmiş dipol yalnızca iyonun elektrik alanı apolar moleküle etki ederken vardır."},{"t":"Alan kalkınca","a":"dipol kaybolur","d":"İyon uzaklaşıp alan ortadan kalktığında elektron bulutu eski simetrik dağılımına döner, dipol kaybolur."}],"ans":"İndüklenmiş dipol kalıcı değildir; yalnızca iyonun alanı etki ederken vardır, alan kalkınca apolar molekül yine simetrik (dipolsüz) hale döner."}],"zor":[{"q":"İyon-indüklenmiş dipol etkileşim enerjisinin iyon yükü, polarlanabilirlik ve uzaklıkla ilişkisini açıklayınız.","steps":[{"t":"Yük ve polarlanabilirlik","a":"doğru orantı","d":"Etkileşim enerjisi, iyonun yükünün karesi (q²) ve apolar molekülün polarlanabilirliği (α) ile doğru orantılı artar."},{"t":"Uzaklık etkisi","a":"r⁴ ile düşer","d":"Etkileşim enerjisi, iyon ile molekül arası uzaklığın dördüncü kuvvetiyle (1/r⁴) hızla azalır; bu nedenle çok kısa menzillidir."}],"ans":"İyon-indüklenmiş dipol enerjisi, iyon yükünün karesi ve molekülün polarlanabilirliğiyle artar; uzaklığın dördüncü kuvvetiyle (1/r⁴) azaldığından çok kısa menzillidir."},{"q":"Aynı yüke sahip Li⁺ ve K⁺ iyonlarından hangisi apolar bir molekülü daha güçlü uçlandırır, neden?","steps":[{"t":"Yarıçap farkı","a":"Li⁺ küçük","d":"Li⁺ iyon yarıçapı K⁺'dan küçüktür; yükleri aynı (+1) olsa da Li⁺'nin yük yoğunluğu daha yüksektir."},{"t":"Daha güçlü alan","a":"Li⁺ uçlandırır","d":"Yüksek yük yoğunluğu daha güçlü elektrik alanı demektir; bu yüzden Li⁺ apolar molekülü K⁺'dan daha çok uçlandırır."}],"ans":"Li⁺; yarıçapı küçük olduğundan yük yoğunluğu ve elektrik alanı daha güçlüdür, bu nedenle apolar molekülü K⁺'dan daha güçlü uçlandırır."},{"q":"Çözeltide tuz derişimi arttıkça apolar gazın çözünürlüğünün azalması (salting-out) iyon-indüklenmiş dipol ile nasıl ilişkilendirilir?","fig":"<svg viewBox='0 0 320 170'><rect x='25' y='25' width='270' height='118' fill='#dceaff' stroke='#1a2b45'/><circle cx='65' cy='58' r='10' fill='#e0552b'/><text x='65' y='62' font-size='8' text-anchor='middle' fill='#fff'>+</text><circle cx='110' cy='95' r='10' fill='#2b6be0'/><text x='110' y='99' font-size='8' text-anchor='middle' fill='#fff'>−</text><circle cx='160' cy='55' r='10' fill='#e0552b'/><text x='160' y='59' font-size='8' text-anchor='middle' fill='#fff'>+</text><circle cx='200' cy='100' r='10' fill='#2b6be0'/><text x='200' y='104' font-size='8' text-anchor='middle' fill='#fff'>−</text><circle cx='258' cy='65' r='15' fill='#cfd8e8' stroke='#1a2b45'/><text x='258' y='69' font-size='8' text-anchor='middle' fill='#1a2b45'>gaz↑</text><text x='160' y='160' font-size='10' text-anchor='middle' fill='#1a2b45'>iyonlar suyu tutar, gaz dışarı itilir</text></svg>","steps":[{"t":"İyon-dipol baskınlığı","a":"su iyonlara çekilir","d":"İyon derişimi arttıkça su molekülleri güçlü iyon-dipol etkileşimiyle iyonların etrafına daha çok çekilir (hidrasyon kabuğu büyür)."},{"t":"Apolara enerji yetmez","a":"çözünürlük düşer","d":"Apolar gaz yalnızca zayıf iyon-indüklenmiş dipol kurabildiğinden, su ile yarışı kaybeder ve çözeltiden dışarı itilir."}],"ans":"Artan iyon derişiminde su, güçlü iyon-dipol etkileşimiyle iyonlara bağlanır; apolar gaz yalnızca zayıf iyon-indüklenmiş dipol kurabildiği için yarışı kaybeder ve çözünürlüğü azalır (salting-out)."},{"q":"İyon-indüklenmiş dipol etkileşiminde çekimin neden her zaman çekici (itici değil) olduğunu açıklayınız.","steps":[{"t":"İndüklenen kutup","a":"zıt uç döner","d":"İyon, apolar molekülde kendisine en yakın tarafta her zaman kendi yüküne zıt kutbu indükler (örneğin + iyon yanında − uç oluşur)."},{"t":"Daima çekme","a":"net çekici","d":"En yakın uç her zaman zıt yüklü olduğundan iyon ile indüklenmiş dipol arasındaki net kuvvet daima çekicidir."}],"ans":"İyon, apolar moleküle yakın tarafta kendi yüküne zıt kutbu indüklediğinden, oluşan dipolün yakın ucu daima zıt yüklüdür; bu nedenle etkileşim her zaman çekicidir."},{"q":"İyon-indüklenmiş dipol ve London (dağılma) kuvvetleri her ikisi de indüklenmiş dipole dayanır; aralarındaki temel fark nedir?","steps":[{"t":"İndükleyen kaynak","a":"kalıcı yük vs anlık dipol","d":"İyon-indüklenmiş dipolde dipolü indükleyen iyonun kalıcı yüküdür; London'da ise indükleyen, komşu apolar moleküldeki anlık (geçici) dipoldür."},{"t":"Güç ve süreklilik","a":"iyon daha güçlü","d":"Kalıcı bir yükün alanı sürekli ve güçlü olduğundan iyon-indüklenmiş dipol, anlık dipollere dayanan London kuvvetlerinden genelde daha güçlüdür."}],"ans":"İyon-indüklenmiş dipolde dipolü iyonun kalıcı yükü indükler ve etkileşim daha güçlüdür; London kuvvetlerinde ise dipolü komşu molekülün anlık (geçici) dipolü indükler ve etkileşim daha zayıftır."}]}},"kimyasalTur":{"ilkokul":{"kolay":[{"q":"Maddeyi oluşturan en küçük yapı taşına ne denir?","steps":[{"t":"Çok küçük yapı","a":"gözle görülmez","d":"Maddeler gözle göremeyeceğimiz kadar küçük yapı taşlarından oluşur."},{"t":"Adı","a":"atom","d":"Bu en küçük yapı taşına atom denir."}],"ans":"Maddeyi oluşturan en küçük yapı taşına atom denir."},{"q":"İki ya da daha çok atomun birbirine bağlanmasıyla oluşan tanecik nedir?","fig":"<svg viewBox='0 0 320 150'><circle cx='120' cy='75' r='22' fill='#cfd8e8' stroke='#1a2b45'/><text x='120' y='80' font-size='12' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='200' cy='75' r='22' fill='#cfd8e8' stroke='#1a2b45'/><text x='200' y='80' font-size='12' text-anchor='middle' fill='#1a2b45'>H</text><line x1='142' y1='75' x2='178' y2='75' stroke='#1a2b45' stroke-width='3'/><text x='160' y='125' font-size='11' text-anchor='middle' fill='#1a2b45'>molekül (H₂)</text></svg>","steps":[{"t":"Atomlar bağlanır","a":"yan yana","d":"İki ya da daha çok atom birbirine tutunur."},{"t":"Adı","a":"molekül","d":"Birbirine bağlı bu atom topluluğuna molekül denir."}],"ans":"İki ya da daha çok atomun bağlanmasıyla oluşan taneciğe molekül denir."},{"q":"Soluduğumuz oksijen gazı (O₂) kaç oksijen atomundan oluşur?","steps":[{"t":"İçeriği","a":"iki oksijen","d":"Oksijen gazı, iki oksijen atomunun birleşmesiyle oluşur."},{"t":"Yazılışı","a":"O₂","d":"Bu yüzden oksijen molekülü O₂ olarak gösterilir."}],"ans":"Oksijen gazı (O₂) iki oksijen atomundan oluşur."},{"q":"Su molekülü (H₂O) hangi atomlardan oluşur?","fig":"<svg viewBox='0 0 320 165'><circle cx='160' cy='85' r='25' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='90' font-size='13' text-anchor='middle' fill='#fff'>O</text><circle cx='112' cy='58' r='15' fill='#cfd8e8' stroke='#1a2b45'/><text x='112' y='62' font-size='10' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='208' cy='58' r='15' fill='#cfd8e8' stroke='#1a2b45'/><text x='208' y='62' font-size='10' text-anchor='middle' fill='#1a2b45'>H</text><line x1='139' y1='73' x2='124' y2='64' stroke='#1a2b45' stroke-width='2'/><line x1='181' y1='73' x2='196' y2='64' stroke='#1a2b45' stroke-width='2'/><text x='160' y='145' font-size='11' text-anchor='middle' fill='#1a2b45'>2 H + 1 O</text></svg>","steps":[{"t":"Atomlar","a":"2 H, 1 O","d":"Su molekülünde iki hidrojen (H) ve bir oksijen (O) atomu vardır."},{"t":"Birleşme","a":"molekül","d":"Bu atomlar birbirine bağlanarak su molekülünü oluşturur."}],"ans":"Su molekülü iki hidrojen ve bir oksijen atomundan oluşur (H₂O)."},{"q":"Atomlar her zaman yüksüz mü olur, yoksa bazen yük kazanabilir mi?","steps":[{"t":"Yüklü tanecik","a":"elektron alıp verir","d":"Bir atom elektron alır ya da verirse artı veya eksi yük kazanabilir."},{"t":"Adı","a":"iyon","d":"Yük kazanmış bu taneciğe iyon denir."}],"ans":"Atomlar bazen elektron alıp vererek yük kazanır; yük kazanmış taneciğe iyon denir."}],"zor":[{"q":"Atom, molekül ve iyon arasındaki temel fark nedir?","steps":[{"t":"Atom ve molekül","a":"tekli ve bağlı","d":"Atom tek bir yapı taşıdır; molekül ise birden çok atomun birbirine bağlanmış halidir."},{"t":"İyon","a":"yüklü tanecik","d":"İyon ise elektron alıp vererek artı ya da eksi yük kazanmış bir atom ya da atom grubudur."}],"ans":"Atom tek yapı taşı, molekül bağlı atomlar topluluğu, iyon ise yük kazanmış bir tanecik (atom ya da grup)dur."},{"q":"Bir atom elektron verirse hangi yüke sahip iyon olur?","fig":"<svg viewBox='0 0 320 150'><circle cx='100' cy='75' r='24' fill='#cfd8e8' stroke='#1a2b45'/><text x='100' y='80' font-size='11' text-anchor='middle' fill='#1a2b45'>Na</text><text x='150' y='80' font-size='16' fill='#1a2b45'>→</text><circle cx='220' cy='75' r='24' fill='#cfd8e8' stroke='#1a2b45'/><text x='220' y='80' font-size='11' text-anchor='middle' fill='#1a2b45'>Na⁺</text><circle cx='185' cy='50' r='6' fill='#2b6be0'/><text x='185' y='40' font-size='9' text-anchor='middle' fill='#1a2b45'>e⁻ verildi</text></svg>","steps":[{"t":"Elektron verme","a":"eksi azalır","d":"Atom eksi yüklü elektronlardan birini verirse, geriye artı yükü fazla bir tanecik kalır."},{"t":"Sonuç","a":"artı iyon","d":"Bu yüzden elektron veren atom artı (+) yüklü iyon olur; örneğin sodyum Na⁺."}],"ans":"Elektron veren atom artı (+) yüklü iyon olur; örneğin sodyum elektron verince Na⁺ olur."},{"q":"Bir atom elektron alırsa hangi yüke sahip iyon olur?","steps":[{"t":"Elektron alma","a":"eksi artar","d":"Atom dışarıdan eksi yüklü bir elektron alırsa, eksi yükü fazlalaşır."},{"t":"Sonuç","a":"eksi iyon","d":"Bu yüzden elektron alan atom eksi (−) yüklü iyon olur; örneğin klor Cl⁻."}],"ans":"Elektron alan atom eksi (−) yüklü iyon olur; örneğin klor elektron alınca Cl⁻ olur."},{"q":"Aynı atomlardan oluşan molekül ile farklı atomlardan oluşan moleküle birer örnek verir misiniz?","steps":[{"t":"Aynı atomlar","a":"O₂","d":"İki oksijen atomu birleşip oksijen molekülünü (O₂) oluşturur; bu aynı atomlardan bir moleküldür."},{"t":"Farklı atomlar","a":"H₂O","d":"Hidrojen ve oksijen birleşip su molekülünü (H₂O) oluşturur; bu farklı atomlardan bir moleküldür."}],"ans":"Aynı atomlardan örnek O₂ (oksijen), farklı atomlardan örnek H₂O (su) molekülüdür."},{"q":"Bir maddenin içinde hangi çeşit tanecikler bulunabilir?","steps":[{"t":"Tanecik çeşitleri","a":"atom, molekül, iyon","d":"Maddeler atom, molekül ya da iyon gibi farklı tanecik çeşitlerinden oluşabilir."},{"t":"Örnekler","a":"demir, su, tuz","d":"Demir atomlardan, su moleküllerden, yemek tuzu ise iyonlardan oluşur."}],"ans":"Bir maddenin içinde atom, molekül ya da iyon bulunabilir; demir atomlardan, su moleküllerden, tuz iyonlardan oluşur."}]},"ortaokul":{"kolay":[{"q":"Kimyasal tür ne demektir, başlıca çeşitleri nelerdir?","steps":[{"t":"Tanım","a":"madde taneciği","d":"Maddeyi oluşturan tanecikler kimyasal tür olarak adlandırılır."},{"t":"Çeşitleri","a":"atom, molekül, iyon","d":"Başlıca kimyasal türler atom, molekül ve iyondur."}],"ans":"Kimyasal tür, maddeyi oluşturan taneciktir; başlıcaları atom, molekül ve iyondur."},{"q":"Element molekülü ile bileşik molekülünü örnekle ayırınız.","fig":"<svg viewBox='0 0 320 150'><circle cx='70' cy='75' r='20' fill='#5b6b85' stroke='#1a2b45'/><text x='70' y='80' font-size='10' text-anchor='middle' fill='#fff'>N</text><circle cx='115' cy='75' r='20' fill='#5b6b85' stroke='#1a2b45'/><text x='115' y='80' font-size='10' text-anchor='middle' fill='#fff'>N</text><line x1='90' y1='75' x2='95' y2='75' stroke='#1a2b45' stroke-width='3'/><text x='92' y='115' font-size='10' text-anchor='middle' fill='#1a2b45'>N₂ element molekülü</text><circle cx='225' cy='75' r='18' fill='#33415588' stroke='#1a2b45'/><text x='225' y='80' font-size='10' text-anchor='middle' fill='#fff'>C</text><circle cx='190' cy='75' r='14' fill='#e0552b' stroke='#1a2b45'/><text x='190' y='80' font-size='9' text-anchor='middle' fill='#fff'>O</text><circle cx='260' cy='75' r='14' fill='#e0552b' stroke='#1a2b45'/><text x='260' y='80' font-size='9' text-anchor='middle' fill='#fff'>O</text><text x='225' y='115' font-size='10' text-anchor='middle' fill='#1a2b45'>CO₂ bileşik molekülü</text></svg>","steps":[{"t":"Element molekülü","a":"aynı atomlar","d":"Aynı tür atomlardan oluşan moleküllerdir; örneğin O₂, N₂, H₂."},{"t":"Bileşik molekülü","a":"farklı atomlar","d":"Farklı tür atomların bağlanmasıyla oluşur; örneğin H₂O, CO₂."}],"ans":"Element molekülü aynı tür atomlardan (O₂, N₂) oluşur; bileşik molekülü farklı tür atomlardan (H₂O, CO₂) oluşur."},{"q":"İyon nedir, kaça ayrılır?","steps":[{"t":"Tanım","a":"yüklü tanecik","d":"İyon, elektron alıp vererek yük kazanmış atom ya da atom grubudur."},{"t":"İkiye ayrılır","a":"katyon ve anyon","d":"Artı yüklü iyona katyon, eksi yüklü iyona anyon denir."}],"ans":"İyon, yük kazanmış bir taneciktir; artı yüklü olana katyon, eksi yüklü olana anyon denir."},{"q":"Sodyumun katyon, klorun anyon olmasını yük açısından açıklayınız.","fig":"<svg viewBox='0 0 320 150'><circle cx='90' cy='75' r='24' fill='#cfd8e8' stroke='#1a2b45'/><text x='90' y='80' font-size='11' text-anchor='middle' fill='#1a2b45'>Na⁺</text><text x='160' y='80' font-size='10' text-anchor='middle' fill='#1a2b45'>katyon</text><circle cx='240' cy='75' r='24' fill='#9ed9a8' stroke='#1a2b45'/><text x='240' y='80' font-size='11' text-anchor='middle' fill='#1a2b45'>Cl⁻</text><text x='240' y='120' font-size='10' text-anchor='middle' fill='#1a2b45'>anyon</text></svg>","steps":[{"t":"Sodyum","a":"e⁻ verir → +","d":"Sodyum bir elektron verince artı yüklenir, Na⁺ olur; artı iyon olduğu için katyondur."},{"t":"Klor","a":"e⁻ alır → −","d":"Klor bir elektron alınca eksi yüklenir, Cl⁻ olur; eksi iyon olduğu için anyondur."}],"ans":"Sodyum elektron verip artı yüklendiği için katyon (Na⁺), klor elektron alıp eksi yüklendiği için anyondur (Cl⁻)."},{"q":"Asal (soy) gazlar neden çoğunlukla tek atom halinde bulunur?","steps":[{"t":"Dolu katman","a":"kararlı","d":"Helyum, neon, argon gibi soy gazların son katmanı zaten doludur."},{"t":"Molekül kurmaz","a":"tek atomlu","d":"Kararlı oldukları için başka atomla bağ kurmaya gerek duymaz, tek atom (atomik) halde bulunurlar."}],"ans":"Soy gazların son katmanı dolu ve kararlı olduğundan bağ kurmaya gerek duymaz; bu yüzden çoğunlukla tek atom halinde bulunurlar."}],"zor":[{"q":"NaCl katısında molekül yoktur denmesinin nedeni nedir?","steps":[{"t":"İyon örgüsü","a":"Na⁺ ve Cl⁻ ağı","d":"Yemek tuzu, sayısız Na⁺ ve Cl⁻ iyonunun düzenli bir ağ (örgü) içinde dizilmesiyle oluşur."},{"t":"Ayrı molekül yok","a":"sürekli yapı","d":"Belirli iki atomdan oluşan ayrı bir 'NaCl molekülü' yoktur; yapı uçsuz bucaksız bir iyon örgüsüdür."}],"ans":"NaCl, ayrı moleküller yerine düzenli bir Na⁺–Cl⁻ iyon örgüsünden oluşur; bu yüzden tuzda molekül değil, iyonlar bulunur."},{"q":"Çok atomlu (kök) iyon nedir, bir örnekle açıklayınız.","steps":[{"t":"Tanım","a":"yüklü atom grubu","d":"Birden çok atomun bağlanıp bir bütün olarak yük taşıdığı iyona çok atomlu (kök) iyon denir."},{"t":"Örnek","a":"SO₄²⁻","d":"Sülfat iyonu (SO₄²⁻) bir kükürt ve dört oksijenden oluşur, toplam 2− yük taşır ve tek bir iyon gibi davranır."}],"ans":"Çok atomlu iyon, birden çok atomun bağlanıp tek bir yük taşıyan grubudur; örneğin sülfat iyonu SO₄²⁻ (toplam 2− yük)."},{"q":"O₂ bir molekül, O₂⁻ bir iyon olabilir mi; aralarındaki fark nedir?","steps":[{"t":"O₂ molekülü","a":"yüksüz","d":"O₂, iki oksijenin bağlanmasıyla oluşan nötr (yüksüz) bir element molekülüdür."},{"t":"Yük kazanma","a":"elektron alırsa iyon","d":"Bir yapı elektron alıp veya verip yük kazanırsa iyon olur; yani molekül de iyon da olabilir, ayırt edici özellik yük taşıyıp taşımamasıdır."}],"ans":"O₂ yüksüz olduğu için moleküldür; bir tanecik elektron alıp/verip yük kazanırsa iyon olur. Temel fark, taneciğin net yük taşıyıp taşımamasıdır."},{"q":"Hem element molekülü hem de tek atomlu element bulunabilen kimyasal türlere örnek veriniz.","steps":[{"t":"Tek atomlu element","a":"soy gazlar, metaller","d":"Helyum (He), neon (Ne) gibi soy gazlar ve birçok metal tane olarak tek atom halinde değerlendirilir."},{"t":"Element molekülü","a":"O₂, N₂, H₂","d":"Bazı ametaller ise atomik halde değil, iki atomlu moleküller halinde bulunur; örneğin oksijen O₂, azot N₂."}],"ans":"Soy gazlar (He, Ne) tek atomlu element olarak; oksijen (O₂), azot (N₂), hidrojen (H₂) ise element molekülü olarak bulunur. İkisi de elementtir, fark tane yapısındadır."},{"q":"Bir maddedeki tane çeşidi, o maddenin element, bileşik ya da iyonik yapı oluşunu nasıl gösterir?","steps":[{"t":"Atom/element molekülü","a":"element","d":"Madde yalnız tek tür atom ya da aynı tür atomlu moleküllerden oluşuyorsa elementtir (Fe, O₂)."},{"t":"Bileşik molekülü/iyon örgüsü","a":"bileşik","d":"Farklı atomlu moleküllerden (H₂O, CO₂) ya da farklı iyonların örgüsünden (NaCl) oluşuyorsa bileşiktir."}],"ans":"Maddedeki tane çeşidi yapısını gösterir: tek tür atom veya element molekülü = element; farklı atomlu molekül ya da farklı iyon örgüsü = bileşik."}]},"lise":{"kolay":[{"q":"Kimyasal tür kavramını tanımlayıp temel türleri sıralayınız.","steps":[{"t":"Tanım","a":"madde taneciği","d":"Bir maddeyi oluşturan ve onun kimyasal kimliğini taşıyan en küçük tanecikler kimyasal tür olarak adlandırılır."},{"t":"Türler","a":"atom, molekül, iyon","d":"Başlıca kimyasal türler atom (tek yapı taşı), molekül (kovalent bağlı atom grubu) ve iyon (yüklü tür)dur."}],"ans":"Kimyasal tür, maddeyi oluşturan tanecik birimidir; başlıca türleri atom, molekül ve iyondur."},{"q":"Element molekülü ve bileşik molekülünü tanımlayıp örneklerle ayırınız.","steps":[{"t":"Element molekülü","a":"tek tür atom","d":"Aynı cins atomların kovalent bağ ile birleşmesiyle oluşur; örneğin O₂, N₂, H₂, Cl₂, O₃."},{"t":"Bileşik molekülü","a":"farklı atom","d":"Farklı elementlerin atomlarının belirli oranda kovalent bağlanmasıyla oluşur; örneğin H₂O, CO₂, NH₃, CH₄."}],"ans":"Element molekülü aynı tür atomlardan (O₂, N₂) oluşur ve elementtir; bileşik molekülü farklı tür atomlardan (H₂O, CO₂) oluşur ve bileşiktir."},{"q":"Katyon ve anyon oluşumunu elektron alışverişi ve yük açısından açıklayınız.","fig":"<svg viewBox='0 0 320 160'><circle cx='80' cy='80' r='26' fill='#cfd8e8' stroke='#1a2b45'/><text x='80' y='85' font-size='11' text-anchor='middle' fill='#1a2b45'>Mg²⁺</text><text x='80' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>2 e⁻ verdi</text><text x='160' y='85' font-size='14' fill='#1a2b45'>+</text><circle cx='245' cy='80' r='26' fill='#9ed9a8' stroke='#1a2b45'/><text x='245' y='85' font-size='11' text-anchor='middle' fill='#1a2b45'>O²⁻</text><text x='245' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>2 e⁻ aldı</text></svg>","steps":[{"t":"Katyon","a":"e⁻ verir → artı","d":"Atom değerlik elektronlarını verince proton sayısı baskın gelir ve artı yüklü katyon oluşur (örneğin Mg²⁺)."},{"t":"Anyon","a":"e⁻ alır → eksi","d":"Atom elektron alınca elektron sayısı baskın gelir ve eksi yüklü anyon oluşur (örneğin O²⁻)."}],"ans":"Atom elektron verirse proton fazlalığından artı yüklü katyon (Mg²⁺), elektron alırsa elektron fazlalığından eksi yüklü anyon (O²⁻) oluşur."},{"q":"Atom, molekül ve iyon türlerini yük ve yapı bakımından karşılaştırınız.","steps":[{"t":"Atom","a":"nötr, tekli","d":"Atom proton ve elektron sayısı eşit, yüksüz ve tek yapı taşıdır."},{"t":"Molekül ve iyon","a":"bağlı / yüklü","d":"Molekül kovalent bağlı atom grubudur ve genelde nötrdür; iyon ise yük kazanmış (artı/eksi) tek atom ya da atom grubudur."}],"ans":"Atom nötr tek yapı taşı, molekül kovalent bağlı (genelde nötr) atom grubu, iyon ise net yük taşıyan tek atom ya da atom grubudur."},{"q":"Tek atomlu ve çok atomlu (kök) iyonları örneklerle açıklayınız.","steps":[{"t":"Tek atomlu iyon","a":"Na⁺, Cl⁻, Mg²⁺","d":"Tek bir atomun elektron alıp vermesiyle oluşan iyonlardır; örneğin Na⁺, Cl⁻, Mg²⁺, O²⁻."},{"t":"Çok atomlu iyon","a":"SO₄²⁻, NH₄⁺, NO₃⁻","d":"Birden çok atomun bağlanıp birlikte net yük taşıdığı iyonlardır; örneğin sülfat SO₄²⁻, amonyum NH₄⁺, nitrat NO₃⁻."}],"ans":"Tek atomlu iyonlar tek atomun yük kazanmasıyla oluşur (Na⁺, Cl⁻); çok atomlu (kök) iyonlar atom gruplarının birlikte yük taşımasıyla oluşur (SO₄²⁻, NH₄⁺, NO₃⁻)."}],"zor":[{"q":"NaCl ve şeker (C₆H₁₂O₆) katılarındaki tane çeşitlerini karşılaştırınız.","steps":[{"t":"NaCl","a":"iyonik örgü","d":"Sodyum klorür, Na⁺ ve Cl⁻ iyonlarının düzenli bir kristal örgüde dizilmesiyle oluşur; tane çeşidi iyondur, molekül yoktur."},{"t":"Şeker","a":"moleküller","d":"Glikoz katısı ise C₆H₁₂O₆ molekülleri içerir; tane çeşidi nötr moleküldür."}],"ans":"NaCl'de tane çeşidi Na⁺ ve Cl⁻ iyonlarıdır (iyonik örgü, molekül yok); şekerde ise C₆H₁₂O₆ molekülleridir. Bu fark sulu çözeltide tuzun iletken, şekerin iletken olmamasını da açıklar."},{"q":"Bir taneciğin atom, molekül mü yoksa iyon mu olduğuna formülüne bakarak nasıl karar verilir?","steps":[{"t":"Yük işareti","a":"varsa iyon","d":"Formülde üst simge yük (örneğin ⁺, ²⁻) varsa tanecik iyondur (Na⁺, SO₄²⁻)."},{"t":"Atom sayısı","a":"tek/birden çok","d":"Yük yoksa ve tek sembol varsa atom (Fe, He); birden çok atom bağlıysa moleküldür (O₂, H₂O)."}],"ans":"Formülde net yük varsa iyon (Na⁺, SO₄²⁻); yük yoksa tek atomluysa atom (Fe, He), birden çok atom bağlıysa moleküldür (O₂, H₂O)."},{"q":"İyonların nötr atomlardan yarıçap bakımından farkını nedeniyle açıklayınız.","steps":[{"t":"Katyon küçülür","a":"e⁻ kaybı","d":"Atom elektron verince çoğu zaman bir katman boşalır ve kalan elektronlar daha güçlü çekilir; bu yüzden katyon nötr atomdan küçüktür (Na > Na⁺)."},{"t":"Anyon büyür","a":"e⁻ kazanımı","d":"Atom elektron alınca elektronlar arası itme artar ve elektron bulutu genişler; bu yüzden anyon nötr atomdan büyüktür (Cl < Cl⁻)."}],"ans":"Katyon, elektron kaybıyla çekirdek çekiminin artması (ve çoğu kez katman boşalması) sonucu nötr atomdan küçülür; anyon ise elektron kazanımıyla itme artıp bulut genişlediği için nötr atomdan büyür."},{"q":"Allotrop element molekülleri (O₂ ve O₃) kimyasal tür açısından nasıl değerlendirilir?","steps":[{"t":"İki element molekülü","a":"aynı atom","d":"Hem O₂ hem O₃ yalnızca oksijen atomlarından oluşan element molekülleridir; ikisi de elementtir."},{"t":"Farklı tür","a":"farklı yapı/özellik","d":"Atom sayıları ve dizilişleri farklı olduğundan O₂ ile O₃ ayrı kimyasal türlerdir ve farklı kimyasal-fiziksel özellik gösterir."}],"ans":"O₂ ve O₃ aynı elementin (oksijen) farklı element molekülleridir; ikisi de elementtir ama atom sayısı ve dizilişleri farklı olduğundan ayrı kimyasal türlerdir."},{"q":"İyonik bir bileşikte 'formül birimi' kavramı, molekül kavramından nasıl ayrılır?","steps":[{"t":"Molekül","a":"gerçek bağımsız tanecik","d":"Molekül, kovalent bağlarla birbirine bağlı, bağımsız ve sayısı belli bir atom grubudur (örneğin H₂O)."},{"t":"Formül birimi","a":"en basit iyon oranı","d":"İyonik katıda bağımsız molekül yoktur; formül birimi (örneğin NaCl), örgüdeki katyon-anyon oranını gösteren en basit gösterimdir."}],"ans":"Molekül, kovalent bağlı bağımsız bir tanecik (H₂O) iken; formül birimi (NaCl) iyonik örgüde gerçek bir molekülü değil, yalnızca iyonların en basit oranını gösterir."}]}},"koordineKovalent":{"ilkokul":{"kolay":[{"q":"İki arkadaş bir oyuncağı birlikte tutuyor; bazen ikisi de elini koyar, bazen sadece biri tutar. Atomlarda da bazen elektronu tek atom verir mi?","steps":[{"t":"Paylaşma","a":"birlikte tutma","d":"Atomlar bağ kurarken küçük tanecikleri (elektron) çoğu zaman ikisi birlikte ortaya koyar."},{"t":"Tek atom verir","a":"evet, olur","d":"Bazen ortak tanecik çiftini tek bir atom sağlar, diğeri sadece ona yer açar."}],"ans":"Evet; bazen ortak elektron çiftini tek bir atom sağlar, buna özel (koordine) bağ denir."},{"q":"Bir bağda ortak tanecik çiftini iki atom da değil de yalnız bir atom verirse buna ne denir?","steps":[{"t":"Normal bağ","a":"ikisi verir","d":"Sıradan ortak bağda her iki atom da birer tanecik koyar."},{"t":"Özel bağ","a":"tek atom verir","d":"Çifti tek atom verirse buna koordine (datif) bağ denir."}],"ans":"Ortak çifti yalnız bir atomun verdiği bağa koordine (datif) kovalent bağ denir."},{"q":"Amonyak (NH₃) bir H⁺ taneciğini yanına alınca ne oluşur?","fig":"<svg viewBox='0 0 320 175'><circle cx='150' cy='80' r='24' fill='#5b6b85' stroke='#1a2b45'/><text x='150' y='85' font-size='13' text-anchor='middle' fill='#fff'>N</text><circle cx='100' cy='120' r='13' fill='#cfd8e8' stroke='#1a2b45'/><text x='100' y='124' font-size='9' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='150' cy='135' r='13' fill='#cfd8e8' stroke='#1a2b45'/><text x='150' y='139' font-size='9' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='200' cy='120' r='13' fill='#cfd8e8' stroke='#1a2b45'/><text x='200' y='124' font-size='9' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='220' cy='55' r='13' fill='#9ed9a8' stroke='#1a2b45'/><text x='220' y='59' font-size='9' text-anchor='middle' fill='#1a2b45'>H</text><text x='160' y='162' font-size='10' text-anchor='middle' fill='#1a2b45'>NH₄⁺ oluşur</text></svg>","steps":[{"t":"Yeni tanecik gelir","a":"H⁺ katılır","d":"Amonyağa artı yüklü bir hidrojen (H⁺) tutunur."},{"t":"Sonuç","a":"NH₄⁺","d":"Böylece amonyum (NH₄⁺) denen artı yüklü yeni tanecik oluşur."}],"ans":"Amonyak bir H⁺ alınca amonyum (NH₄⁺) iyonu oluşur."},{"q":"Koordine bağda ortak çifti veren atom için hangisi doğrudur: 'elini geri çeker' mi 'çifti tek başına koyar' mı?","steps":[{"t":"Veren atom","a":"çifti koyar","d":"Bu bağda bir atom ortak tanecik çiftinin tamamını kendisi koyar."},{"t":"Diğer atom","a":"hiç koymaz","d":"Karşı atom bu bağa kendi taneciğini katmaz, sadece yer verir."}],"ans":"Koordine bağda ortak çifti tek atom koyar; diğeri kendi taneciğini katmaz."},{"q":"Bir su molekülü (H₂O) bir H⁺ alırsa ne oluşur?","steps":[{"t":"Su + H⁺","a":"tutunma","d":"Su molekülüne artı yüklü bir hidrojen (H⁺) tutunur."},{"t":"Sonuç","a":"H₃O⁺","d":"Üç hidrojenli, artı yüklü bu yeni taneciğe hidronyum (H₃O⁺) denir."}],"ans":"Su bir H⁺ alınca hidronyum (H₃O⁺) iyonu oluşur."}],"zor":[{"q":"Koordine bağ oluştuktan sonra onu diğer ortak bağlardan ayırt edebilir miyiz?","steps":[{"t":"Kuruluşu farklı","a":"çifti tek atom verdi","d":"Bağ kurulurken ortak çifti yalnız bir atom sağlamıştı."},{"t":"Sonradan aynı","a":"ayırt edilemez","d":"Bağ kurulduktan sonra diğer ortak bağlarla tamamen aynı görünür, ayırt edilemez."}],"ans":"Hayır; oluştuktan sonra koordine bağ diğer ortak (kovalent) bağlardan ayırt edilemez."},{"q":"NH₄⁺ taneciğindeki dört N–H bağı birbirinden farklı mıdır?","fig":"<svg viewBox='0 0 320 180'><circle cx='160' cy='90' r='26' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='95' font-size='13' text-anchor='middle' fill='#fff'>N</text><circle cx='100' cy='55' r='14' fill='#cfd8e8' stroke='#1a2b45'/><text x='100' y='59' font-size='9' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='220' cy='55' r='14' fill='#cfd8e8' stroke='#1a2b45'/><text x='220' y='59' font-size='9' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='100' cy='130' r='14' fill='#cfd8e8' stroke='#1a2b45'/><text x='100' y='134' font-size='9' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='220' cy='130' r='14' fill='#cfd8e8' stroke='#1a2b45'/><text x='220' y='134' font-size='9' text-anchor='middle' fill='#1a2b45'>H</text><line x1='140' y1='75' x2='112' y2='63' stroke='#1a2b45' stroke-width='2'/><line x1='180' y1='75' x2='208' y2='63' stroke='#1a2b45' stroke-width='2'/><line x1='140' y1='105' x2='112' y2='122' stroke='#1a2b45' stroke-width='2'/><line x1='180' y1='105' x2='208' y2='122' stroke='#1a2b45' stroke-width='2'/><text x='160' y='168' font-size='10' text-anchor='middle' fill='#1a2b45'>NH₄⁺: dört bağ aynı</text></svg>","steps":[{"t":"Üçü normal, biri koordine","a":"farklı kuruldu","d":"Üç bağ normal kovalent, dördüncüsü koordine (çifti azot verdi) olarak kurulur."},{"t":"Sonuçta eşit","a":"dördü özdeş","d":"Oluştuktan sonra dört N–H bağı tamamen özdeş hale gelir, hangisinin koordine olduğu anlaşılamaz."}],"ans":"Hayır; NH₄⁺'in dört N–H bağı oluştuktan sonra özdeştir, koordine olan ayırt edilemez."},{"q":"H₃O⁺ oluşurken çifti hangi atom sağlar?","steps":[{"t":"Suyun oksijeni","a":"yalnız çift var","d":"Su molekülündeki oksijende kullanılmamış (ortaklanmamış) bir elektron çifti bulunur."},{"t":"H⁺'a verir","a":"oksijen sağlar","d":"Oksijen bu çifti gelen H⁺ ile paylaşarak koordine bağı kurar; H⁺'ın getirdiği elektron yoktur."}],"ans":"H₃O⁺'ta ortak çifti suyun oksijen atomu sağlar; gelen H⁺ elektron getirmez."},{"q":"Koordine bağı kurabilmek için bir atomda ne bulunması gerekir?","steps":[{"t":"Hazır çift","a":"ortaklanmamış çift","d":"Çifti verecek atomda kullanılmamış (ortaklanmamış) bir elektron çifti olmalıdır."},{"t":"Boş yer","a":"alacak atomda boşluk","d":"Karşı atomun ise bu çifti alacak boş bir yeri (elektronu eksik kısmı) olmalıdır."}],"ans":"Koordine bağ için bir atomda ortaklanmamış elektron çifti, diğerinde bu çifti alacak boş yer bulunmalıdır."},{"q":"H⁺ taneciğinin kendi elektronu olmadığı halde NH₃ ile bağ kurabilmesinin sebebi nedir?","steps":[{"t":"H⁺ elektronsuz","a":"boş yeri var","d":"H⁺'ın elektronu yoktur, yani bağa katacak taneciği yoktur ama bağ alacak boş yeri vardır."},{"t":"Azot çifti verir","a":"koordine bağ","d":"Azotun ortaklanmamış çifti tek başına paylaşılarak koordine bağ kurulur ve NH₄⁺ oluşur."}],"ans":"H⁺'ın elektronu olmasa da azot ortaklanmamış çiftini tek başına vererek koordine bağ kurar (NH₄⁺)."}]},"ortaokul":{"kolay":[{"q":"Koordine (datif) kovalent bağ ile normal kovalent bağ arasındaki temel fark nedir?","steps":[{"t":"Normal kovalent","a":"her iki atom birer e⁻","d":"Normal kovalent bağda ortak çifti oluşturmak için her iki atom da birer elektron verir."},{"t":"Koordine","a":"çifti tek atom","d":"Koordine bağda ortak elektron çiftinin tamamını tek bir atom sağlar."}],"ans":"Koordine bağda ortak elektron çiftini tek atom verir; normal kovalent bağda iki atom birer elektronla katkı yapar."},{"q":"NH₄⁺ iyonu nasıl oluşur?","fig":"<svg viewBox='0 0 320 175'><circle cx='120' cy='85' r='22' fill='#5b6b85' stroke='#1a2b45'/><text x='120' y='90' font-size='12' text-anchor='middle' fill='#fff'>N</text><text x='120' y='120' font-size='10' text-anchor='middle' fill='#1a2b45'>NH₃</text><text x='160' y='80' font-size='14' text-anchor='middle' fill='#1a2b45'>+</text><circle cx='205' cy='85' r='14' fill='#9ed9a8' stroke='#1a2b45'/><text x='205' y='90' font-size='10' text-anchor='middle' fill='#1a2b45'>H⁺</text><text x='245' y='80' font-size='14' text-anchor='middle' fill='#1a2b45'>→</text><text x='285' y='90' font-size='11' text-anchor='middle' fill='#1a2b45'>NH₄⁺</text></svg>","steps":[{"t":"NH₃ + H⁺","a":"azot çifti hazır","d":"Amonyaktaki (NH₃) azotun ortaklanmamış elektron çifti bulunur."},{"t":"Koordine bağ","a":"çift paylaşılır","d":"Azot bu çifti gelen H⁺ ile paylaşır; koordine bağ kurularak NH₄⁺ oluşur."}],"ans":"NH₄⁺, amonyaktaki azotun ortaklanmamış çiftini H⁺ ile paylaşmasıyla (koordine bağla) oluşur."},{"q":"Hidronyum iyonu (H₃O⁺) hangi iki tanecikten oluşur?","steps":[{"t":"Su molekülü","a":"H₂O","d":"Suda oksijenin ortaklanmamış elektron çifti bulunur."},{"t":"H⁺ katılır","a":"koordine bağ","d":"Su bir H⁺ alır; oksijen çiftini paylaşarak H₃O⁺ oluşur."}],"ans":"H₃O⁺, su molekülü (H₂O) ile bir H⁺ iyonunun koordine bağ yapmasıyla oluşur."},{"q":"Koordine bağda 'çifti veren' ve 'çifti alan' atomlar nasıl ayrılır?","steps":[{"t":"Veren (verici)","a":"ortaklanmamış çift","d":"Çifti veren atomda kullanılmamış elektron çifti bulunur (örneğin NH₃'teki azot)."},{"t":"Alan (alıcı)","a":"boş yer","d":"Çifti alan atomun ise elektron eksiği, yani boş bir yeri vardır (örneğin H⁺)."}],"ans":"Çifti ortaklanmamış elektron çifti olan atom verir; boş yeri olan atom alır."},{"q":"Koordine bağ kurulduktan sonra normal kovalent bağdan ayırt edilebilir mi?","steps":[{"t":"Kuruluş farkı","a":"çifti tek atom verdi","d":"Bağ kurulurken çifti tek atomun verdiği bilinir."},{"t":"Bağ özdeşliği","a":"ayırt edilemez","d":"Kurulduktan sonra koordine bağ, normal kovalent bağla aynı uzunluk ve güçte olur; ayırt edilemez."}],"ans":"Hayır; oluştuktan sonra koordine bağ normal kovalent bağdan ayırt edilemez."}],"zor":[{"q":"NH₄⁺ iyonundaki dört N–H bağının özdeş olması ne anlama gelir?","steps":[{"t":"Üç + bir","a":"kuruluşları farklı","d":"Üç bağ normal kovalent, dördüncüsü koordine olarak (çifti azot verir) kurulur."},{"t":"Özdeşlik","a":"deneysel olarak eşit","d":"Bağ uzunlukları ve enerjileri ölçüldüğünde dördü de aynıdır; hangisinin koordine olduğu anlaşılamaz."}],"ans":"Dört N–H bağının özdeş olması, koordine bağın oluştuktan sonra diğerlerinden hiçbir farkı kalmadığını gösterir."},{"q":"Bir atomun koordine bağda 'verici' olabilmesi için hangi koşul gerekir?","steps":[{"t":"Ortaklanmamış çift","a":"zorunlu","d":"Verici atomda paylaşıma sokulabilecek ortaklanmamış (yalnız) bir elektron çifti bulunmalıdır."},{"t":"Örnekler","a":"N, O","d":"Azot (NH₃) ve oksijen (H₂O) bu çifte sahip olduğundan H⁺'a verici olabilir."}],"ans":"Verici atomda ortaklanmamış elektron çifti bulunmalıdır; N ve O bu nedenle koordine bağ yapabilir."},{"q":"H⁺ iyonu koordine bağda neden yalnızca 'alıcı' olabilir?","steps":[{"t":"Elektronu yok","a":"verecek çift yok","d":"H⁺'ın elektronu olmadığından paylaşıma sokacak bir çifti yoktur, verici olamaz."},{"t":"Boş yeri var","a":"çifti alır","d":"Boş 1s yörüngesi olduğundan karşı atomun verdiği çifti alabilir, yani alıcıdır."}],"ans":"H⁺'ın paylaşacak elektronu olmadığı, yalnızca boş yeri olduğu için koordine bağda sadece alıcı olur."},{"q":"NH₃ + H⁺ → NH₄⁺ tepkimesinde yük korunumunu açıklayınız.","steps":[{"t":"Başlangıç yükleri","a":"0 + (+1)","d":"NH₃ nötr (yük 0), H⁺ ise +1 yüklüdür; toplam yük +1'dir."},{"t":"Ürün yükü","a":"NH₄⁺ = +1","d":"Oluşan amonyum iyonu +1 yüklüdür; tepkimenin iki tarafında toplam yük +1 olarak korunur."}],"ans":"NH₃ (0) + H⁺ (+1) toplamı +1'dir; ürün NH₄⁺ de +1 yüklü olduğundan yük korunur."},{"q":"Koordine bağ kavramı, asit-baz tepkimelerini anlamada nasıl işe yarar?","steps":[{"t":"Çift veren = baz","a":"elektron çifti sağlar","d":"Ortaklanmamış çiftini veren tanecik (NH₃, H₂O) elektron çifti vericisi olarak davranır."},{"t":"Çift alan = asit","a":"boş yere alır","d":"Çifti alan tanecik (H⁺) elektron çifti alıcısı olarak davranır; bu, asit-baz davranışının temelidir."}],"ans":"Koordine bağda çift veren tanecik baz, çift alan tanecik asit gibi davranır; bu, asit-baz tepkimelerinin temelini açıklar."}]},"lise":{"kolay":[{"q":"Koordine (datif) kovalent bağı, normal kovalent bağdan ayıran tek özellik nedir?","steps":[{"t":"Ortak çiftin kaynağı","a":"tek atom","d":"Koordine bağda ortaklaşılan elektron çiftinin her ikisi de tek bir atomdan (verici) gelir."},{"t":"Sonraki özdeşlik","a":"fark kalmaz","d":"Bağ kurulduktan sonra koordine bağ ile normal kovalent bağ arasında uzunluk, enerji veya nitelik farkı kalmaz."}],"ans":"Tek fark oluşum aşamasındadır: koordine bağda çifti tek atom sağlar; oluştuktan sonra normal kovalent bağdan ayırt edilemez."},{"q":"NH₄⁺ iyonunun oluşumunu Lewis (elektron) gösterimiyle açıklayınız.","fig":"<svg viewBox='0 0 320 180'><text x='80' y='60' font-size='12' text-anchor='middle' fill='#1a2b45'>H–N–H</text><text x='80' y='80' font-size='12' text-anchor='middle' fill='#1a2b45'>|</text><text x='80' y='98' font-size='12' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='112' cy='44' r='3' fill='#2b6be0'/><circle cx='124' cy='44' r='3' fill='#2b6be0'/><text x='128' y='48' font-size='9' fill='#1a2b45'>yalnız çift</text><text x='175' y='75' font-size='16' text-anchor='middle' fill='#1a2b45'>+ H⁺ →</text><text x='270' y='75' font-size='13' text-anchor='middle' fill='#1a2b45'>[NH₄]⁺</text><text x='160' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>azotun yalnız çifti H⁺ ile paylaşılır</text></svg>","steps":[{"t":"Verici azot","a":"yalnız çift","d":"NH₃'teki azotun üç N–H bağı dışında bir ortaklanmamış (yalnız) elektron çifti vardır."},{"t":"Koordine bağ","a":"çift H⁺ ile paylaşılır","d":"Azot bu yalnız çifti, elektronu olmayan H⁺ ile paylaşır; dördüncü N–H bağı koordine bağ olarak kurulur ve NH₄⁺ oluşur."}],"ans":"NH₃'teki azotun yalnız elektron çifti, boş yörüngeli H⁺ ile paylaşılarak koordine bağ kurulur ve NH₄⁺ iyonu oluşur."},{"q":"H₃O⁺ (hidronyum) iyonunda koordine bağı hangi atom sağlar ve neden?","steps":[{"t":"Oksijenin çifti","a":"iki yalnız çift","d":"Su molekülünde oksijenin iki ortaklanmamış elektron çifti bulunur."},{"t":"H⁺'a verir","a":"koordine bağ","d":"Oksijen bu çiftlerden birini, elektronsuz H⁺ ile paylaşarak koordine bağ kurar; H₃O⁺ oluşur."}],"ans":"H₃O⁺'ta koordine bağı su oksijeninin ortaklanmamış çifti sağlar; H⁺ elektron getirmediği için çifti oksijen verir."},{"q":"Koordine bağ oluşumu için verici ve alıcı atomlarda hangi özellikler aranır?","steps":[{"t":"Verici","a":"ortaklanmamış çift","d":"Verici atomda paylaşıma sokulabilecek en az bir ortaklanmamış elektron çifti olmalıdır (örneğin N, O)."},{"t":"Alıcı","a":"boş orbital","d":"Alıcı atom/iyonun bu çifti alabileceği boş bir orbitali (elektron eksiği) olmalıdır (örneğin H⁺)."}],"ans":"Verici atomda ortaklanmamış elektron çifti, alıcı atomda ise bu çifti alacak boş orbital bulunmalıdır."},{"q":"Koordine bağ neden Lewis asit-baz tanımıyla doğrudan ilişkilidir?","steps":[{"t":"Lewis bazı","a":"çift verici","d":"Lewis bazı elektron çifti vericisidir; koordine bağda çifti veren atom Lewis bazı gibi davranır."},{"t":"Lewis asidi","a":"çift alıcı","d":"Lewis asidi elektron çifti alıcısıdır; çifti alan tanecik (örneğin H⁺) Lewis asidi gibi davranır."}],"ans":"Koordine bağda çift veren Lewis bazı, çift alan Lewis asidi gibi davranır; bu yüzden koordine bağ Lewis asit-baz tanımının temelidir."}],"zor":[{"q":"NH₄⁺ iyonundaki dört N–H bağının deneysel olarak özdeş bulunması, koordine bağ hakkında ne söyler?","fig":"<svg viewBox='0 0 320 185'><circle cx='160' cy='90' r='24' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='95' font-size='12' text-anchor='middle' fill='#fff'>N</text><circle cx='160' cy='40' r='12' fill='#cfd8e8' stroke='#1a2b45'/><text x='160' y='44' font-size='9' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='110' cy='120' r='12' fill='#cfd8e8' stroke='#1a2b45'/><text x='110' y='124' font-size='9' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='210' cy='120' r='12' fill='#cfd8e8' stroke='#1a2b45'/><text x='210' y='124' font-size='9' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='160' cy='150' r='12' fill='#9ed9a8' stroke='#1a2b45'/><text x='160' y='154' font-size='9' text-anchor='middle' fill='#1a2b45'>H</text><line x1='160' y1='66' x2='160' y2='52' stroke='#1a2b45' stroke-width='2'/><line x1='143' y1='105' x2='120' y2='114' stroke='#1a2b45' stroke-width='2'/><line x1='177' y1='105' x2='200' y2='114' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='114' x2='160' y2='138' stroke='#1a2b45' stroke-width='2'/><text x='160' y='178' font-size='9' text-anchor='middle' fill='#1a2b45'>dört bağ: özdeş uzunluk/enerji</text></svg>","steps":[{"t":"Oluşum kaynağı farklı","a":"3 normal + 1 koordine","d":"Üç bağ normal kovalent, biri koordine olarak (çifti azot verir) oluşur; oluşum kökenleri farklıdır."},{"t":"Elektronların ayırt edilemezliği","a":"özdeşleşme","d":"Elektronlar ayırt edilemez olduğundan bağ kurulduktan sonra dördü de eşit uzunluk, açı ve enerjiye sahip olur."}],"ans":"Dört N–H bağının özdeş bulunması, koordine bağın yalnızca oluşum kökeninin farklı olduğunu; kurulduktan sonra normal kovalent bağdan hiçbir biçimde ayırt edilemediğini kanıtlar."},{"q":"NH₃'in hem H⁺ hem de BF₃ ile koordine bağ kurabilmesini elektron yapısı üzerinden açıklayınız.","steps":[{"t":"Ortak verici","a":"azotun yalnız çifti","d":"Her iki tepkimede de NH₃'teki azotun ortaklanmamış elektron çifti verici olarak işlev görür."},{"t":"Farklı alıcılar","a":"H⁺ ve BF₃","d":"H⁺'ın boş 1s orbitali, BF₃'teki borun boş orbitali bu çifti alır; ürünler NH₄⁺ ve H₃N→BF₃ olur."}],"ans":"NH₃'teki azotun yalnız çifti vericidir; bu çift, boş orbitalli H⁺ veya BF₃'teki bor tarafından alınarak koordine bağ (NH₄⁺ ya da H₃N→BF₃) kurulur."},{"q":"Koordine bağ ile normal kovalent bağ enerji ve uzunluk açısından neden aynıdır?","steps":[{"t":"Sonuçta aynı orbital örtüşmesi","a":"özdeş bağ","d":"Her iki bağ türünde de sonuçta aynı türde orbital örtüşmesi ve aynı sayıda paylaşılan elektron (bir çift) vardır."},{"t":"Köken etkisizliği","a":"geçmiş silinir","d":"Elektronların hangi atomdan geldiği bağ kurulduktan sonra fiziksel olarak izlenemez; bu yüzden uzunluk ve enerji özdeş olur."}],"ans":"İki bağ da bir paylaşılan çift ve aynı tür orbital örtüşmesi içerdiğinden, elektronların kökeni izlenemez olduğu için enerji ve uzunlukları özdeştir."},{"q":"H₃O⁺ iyonundaki oksijenin elektron çiftlerinin sayısını ve geometriye etkisini açıklayınız.","steps":[{"t":"Çift sayımı","a":"3 bağ + 1 yalnız çift","d":"H₃O⁺'ta oksijen üç hidrojenle 3 bağ yapar (biri koordine) ve üzerinde 1 ortaklanmamış çift kalır."},{"t":"Geometri","a":"üçgen piramit","d":"Toplam 4 elektron grubu (3 bağ + 1 yalnız çift) yaklaşık dörtyüzlü dizilir; molekülün şekli üçgen piramit olur (NH₃'e benzer)."}],"ans":"H₃O⁺'ta oksijende 3 bağ ve 1 yalnız çift (toplam 4 elektron grubu) bulunur; bu nedenle iyon üçgen piramit geometridedir."},{"q":"Koordine bağ, klasik Arrhenius asit-baz tanımının yetersiz kaldığı durumları nasıl açıklar?","steps":[{"t":"Arrhenius sınırı","a":"sadece H⁺/OH⁻","d":"Arrhenius tanımı asidi H⁺ veren, bazı OH⁻ veren madde olarak sınırlar; OH⁻ içermeyen bazları açıklayamaz."},{"t":"Çift aktarımı","a":"verici-alıcı","d":"Koordine bağ ile elektron çifti veren (baz) ve alan (asit) yaklaşımı, NH₃ gibi OH⁻ içermeyen bazları da kapsar (Lewis tanımı)."}],"ans":"Koordine bağdaki elektron çifti verici-alıcı yaklaşımı (Lewis tanımı), NH₃ gibi OH⁻ içermeyen bazları kapsayarak Arrhenius tanımının yetersizliğini giderir."}]}},"kovalentGiris":{"ilkokul":{"kolay":[{"q":"İki tane ametal atomu birleştiğinde elektronlarına ne yapar?","steps":[{"t":"İki ametal","a":"yan yana gelir","d":"İki ametal atom (örneğin iki hidrojen) bir araya gelir."},{"t":"Paylaşma","a":"elektron paylaşır","d":"Bu atomlar elektronlarını birbirine vermek yerine ortak kullanır, yani paylaşır."}],"ans":"İki ametal atom birleşince elektronlarını paylaşarak birbirine tutunur."},{"q":"İki hidrojen atomu birleşip hangi molekülü oluşturur?","fig":"<svg viewBox='0 0 320 160'><circle cx='120' cy='80' r='26' fill='#cfd8e8' stroke='#1a2b45'/><text x='120' y='85' font-size='14' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='200' cy='80' r='26' fill='#cfd8e8' stroke='#1a2b45'/><text x='200' y='85' font-size='14' text-anchor='middle' fill='#1a2b45'>H</text><line x1='146' y1='80' x2='174' y2='80' stroke='#1a2b45' stroke-width='3'/><text x='160' y='140' font-size='12' text-anchor='middle' fill='#1a2b45'>H₂</text></svg>","steps":[{"t":"İki H","a":"birleşir","d":"İki hidrojen atomu bir araya gelir."},{"t":"Yeni yapı","a":"H₂","d":"Elektronlarını paylaşarak hidrojen molekülünü (H₂) oluşturur."}],"ans":"İki hidrojen atomu birleşip hidrojen molekülünü (H₂) oluşturur."},{"q":"Atomlar elektronlarını paylaşırken bunu neye benzetebiliriz?","steps":[{"t":"Paylaşma","a":"oyuncak gibi","d":"İki çocuğun aynı oyuncağı birlikte tutup paylaşması gibi düşünebiliriz."},{"t":"Birlikte tutma","a":"bağ kurar","d":"Atomlar da elektronları birlikte tutarak birbirine bağlanır."}],"ans":"Elektron paylaşmak, iki çocuğun aynı oyuncağı birlikte tutup paylaşmasına benzer."},{"q":"Oksijen gazı (O₂) kaç tane oksijen atomundan oluşur?","steps":[{"t":"Atomlar","a":"iki oksijen","d":"Soluduğumuz oksijen gazı iki oksijen atomundan oluşur."},{"t":"Birleşme","a":"O₂","d":"İki oksijen atomu birleşip O₂ molekülünü yapar."}],"ans":"Oksijen gazı (O₂) iki oksijen atomundan oluşur."},{"q":"Atomları birbirine tutturan elektron paylaşımına ne ad verilir?","steps":[{"t":"Paylaşım","a":"ortak elektron","d":"Atomlar elektronlarını ortak kullanır."},{"t":"Ad","a":"kovalent bağ","d":"Bu paylaşma ile kurulan bağa kovalent bağ denir."}],"ans":"Elektron paylaşımıyla kurulan bu bağa kovalent bağ denir."}],"zor":[{"q":"İki azot atomu birleşip azot gazını (N₂) oluştururken neyi paylaşır?","fig":"<svg viewBox='0 0 320 160'><circle cx='120' cy='80' r='28' fill='#5b6b85' stroke='#1a2b45'/><text x='120' y='85' font-size='14' text-anchor='middle' fill='#fff'>N</text><circle cx='200' cy='80' r='28' fill='#5b6b85' stroke='#1a2b45'/><text x='200' y='85' font-size='14' text-anchor='middle' fill='#fff'>N</text><line x1='148' y1='70' x2='172' y2='70' stroke='#1a2b45' stroke-width='3'/><line x1='148' y1='80' x2='172' y2='80' stroke='#1a2b45' stroke-width='3'/><line x1='148' y1='90' x2='172' y2='90' stroke='#1a2b45' stroke-width='3'/><text x='160' y='140' font-size='12' text-anchor='middle' fill='#1a2b45'>N₂</text></svg>","steps":[{"t":"Paylaşma","a":"elektron","d":"İki azot atomu elektronlarını paylaşır."},{"t":"Sıkı tutunma","a":"çok elektron","d":"Çok sayıda elektron paylaştıkları için birbirlerine çok sıkı tutunur."}],"ans":"İki azot atomu çok sayıda elektron paylaşarak azot gazını (N₂) oluşturur."},{"q":"Neden bir hidrojen atomu tek başına değil de eşli (H₂) dolaşmayı sever?","steps":[{"t":"Yalnız H","a":"rahatsız","d":"Tek hidrojen atomu pek rahat değildir, kendini eksik hisseder."},{"t":"Eş bulma","a":"paylaşır","d":"Başka bir hidrojenle elektron paylaşınca daha rahat ve sağlam olur."}],"ans":"Hidrojen atomu başka bir hidrojenle elektron paylaşınca daha sağlam olduğu için eşli (H₂) dolaşmayı sever."},{"q":"Kovalent bağ, demek olan elektron paylaşımı hangi tür atomlar arasında olur?","steps":[{"t":"Taraflar","a":"ametal-ametal","d":"Elektron paylaşımı (kovalent bağ) iki ametal atom arasında olur."},{"t":"Örnek","a":"H, O, N","d":"Hidrojen, oksijen ve azot bunlara örnektir; hepsi ametaldir."}],"ans":"Elektron paylaşımı (kovalent bağ) iki ametal atom arasında olur."},{"q":"İki atom bazen daha çok, bazen daha az elektron paylaşır; bu neyi değiştirir?","steps":[{"t":"Az paylaşım","a":"zayıf gibi","d":"Az sayıda elektron çifti paylaşan atomlar daha gevşek tutunur."},{"t":"Çok paylaşım","a":"daha sıkı","d":"Daha çok elektron çifti paylaşan atomlar (örneğin N₂) birbirine daha sıkı tutunur."}],"ans":"Atomlar ne kadar çok elektron çifti paylaşırsa birbirine o kadar sıkı tutunur."},{"q":"Su molekülünde (H₂O) oksijen, hidrojenlerle elektronlarını paylaşır mı?","fig":"<svg viewBox='0 0 320 170'><circle cx='160' cy='85' r='26' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='90' font-size='13' text-anchor='middle' fill='#fff'>O</text><circle cx='110' cy='55' r='16' fill='#cfd8e8' stroke='#1a2b45'/><text x='110' y='60' font-size='11' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='210' cy='55' r='16' fill='#cfd8e8' stroke='#1a2b45'/><text x='210' y='60' font-size='11' text-anchor='middle' fill='#1a2b45'>H</text><line x1='140' y1='72' x2='123' y2='62' stroke='#1a2b45' stroke-width='2'/><line x1='180' y1='72' x2='197' y2='62' stroke='#1a2b45' stroke-width='2'/><text x='160' y='150' font-size='11' text-anchor='middle' fill='#1a2b45'>H₂O</text></svg>","steps":[{"t":"Atomlar","a":"O ve H","d":"Suda bir oksijen ve iki hidrojen vardır, hepsi ametaldir."},{"t":"Paylaşım","a":"evet","d":"Oksijen her hidrojenle elektron paylaşır, yani kovalent bağ kurar."}],"ans":"Evet; su molekülünde oksijen, iki hidrojenle elektron paylaşarak (kovalent bağ kurarak) birleşir."}]},"ortaokul":{"kolay":[{"q":"Kovalent bağ hangi tür atomlar arasında ve nasıl oluşur?","steps":[{"t":"Taraflar","a":"ametal + ametal","d":"Kovalent bağ iki ametal atom arasında oluşur."},{"t":"Elektron ortaklığı","a":"paylaşım","d":"Atomlar elektron alıp vermek yerine elektronlarını ortaklaşa kullanır."}],"ans":"Kovalent bağ, iki ametal atomun elektronlarını ortaklaşa kullanmasıyla (paylaşmasıyla) oluşur."},{"q":"İki atomun birlikte kullandığı elektron ikilisine ne ad verilir?","fig":"<svg viewBox='0 0 320 160'><circle cx='120' cy='80' r='26' fill='#cfd8e8' stroke='#1a2b45'/><text x='120' y='85' font-size='13' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='200' cy='80' r='26' fill='#cfd8e8' stroke='#1a2b45'/><text x='200' y='85' font-size='13' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='152' cy='80' r='5' fill='#2b6be0'/><circle cx='168' cy='80' r='5' fill='#2b6be0'/><text x='160' y='140' font-size='11' text-anchor='middle' fill='#1a2b45'>ortak elektron çifti</text></svg>","steps":[{"t":"İki elektron","a":"birlikte","d":"Bağda iki atomun birlikte kullandığı iki elektron bulunur."},{"t":"Ad","a":"ortak çift","d":"Bu ikiliye ortak elektron çifti (bağ çifti) denir."}],"ans":"İki atomun birlikte kullandığı bu elektron ikilisine ortak elektron çifti denir."},{"q":"H₂ molekülünde atomlar arasında kaç ortak elektron çifti vardır?","steps":[{"t":"Her H","a":"1 elektron","d":"Her hidrojen bağa bir elektron katar."},{"t":"Toplam","a":"1 çift","d":"İki elektron bir araya gelip tek bir ortak çift oluşturur."}],"ans":"H₂ molekülünde atomlar arasında bir tane ortak elektron çifti (tek bağ) vardır."},{"q":"Tek bağ, çift bağ ve üçlü bağ ne demektir?","steps":[{"t":"Çift sayısı","a":"1, 2, 3","d":"Tek bağda 1, çift bağda 2, üçlü bağda 3 ortak elektron çifti paylaşılır."},{"t":"Gösterim","a":"−, =, ≡","d":"Bunlar sırasıyla tek çizgi (−), çift çizgi (=) ve üç çizgi (≡) ile gösterilir."}],"ans":"Tek bağ 1, çift bağ 2, üçlü bağ ise 3 ortak elektron çifti paylaşımıdır."},{"q":"O₂ molekülünde oksijen atomları arasında ne tür bir bağ vardır?","fig":"<svg viewBox='0 0 320 160'><circle cx='120' cy='80' r='28' fill='#e0552b' stroke='#1a2b45'/><text x='120' y='85' font-size='13' text-anchor='middle' fill='#fff'>O</text><circle cx='200' cy='80' r='28' fill='#e0552b' stroke='#1a2b45'/><text x='200' y='85' font-size='13' text-anchor='middle' fill='#fff'>O</text><line x1='148' y1='72' x2='172' y2='72' stroke='#1a2b45' stroke-width='3'/><line x1='148' y1='88' x2='172' y2='88' stroke='#1a2b45' stroke-width='3'/><text x='160' y='140' font-size='11' text-anchor='middle' fill='#1a2b45'>O=O</text></svg>","steps":[{"t":"İhtiyaç","a":"2 çift","d":"Her oksijen kararlı olmak için iki elektron çifti paylaşmak ister."},{"t":"Çift bağ","a":"O=O","d":"İki oksijen iki ortak çift paylaşır; bu bir çift bağdır."}],"ans":"O₂ molekülünde oksijenler iki ortak çift paylaşır; aralarında çift bağ (O=O) vardır."},{"q":"N₂ molekülünde azot atomları arasında kaç ortak çift paylaşılır?","steps":[{"t":"İhtiyaç","a":"3 çift","d":"Her azot kararlı olmak için üç elektron çifti paylaşır."},{"t":"Üçlü bağ","a":"N≡N","d":"İki azot üç ortak çift paylaşır; bu bir üçlü bağdır."}],"ans":"N₂ molekülünde azotlar üç ortak çift paylaşır; aralarında üçlü bağ (N≡N) vardır."}],"zor":[{"q":"Atomlar kovalent bağ kurarken hangi kararlı düzene ulaşmaya çalışır?","steps":[{"t":"Hedef","a":"soy gaz düzeni","d":"Atomlar son katmanlarını dolu (soy gaz benzeri) yapmak ister."},{"t":"Paylaşarak","a":"oktet","d":"Elektron paylaşarak son katmanı 8'e (hidrojende 2'ye) tamamlar."}],"ans":"Atomlar kovalent bağda elektron paylaşarak son katmanı 8'e (hidrojende 2'ye) tamamlayan kararlı düzene ulaşmaya çalışır."},{"q":"Neden N₂'nin üçlü bağını koparmak, O₂'nin çift bağını koparmaktan daha zordur?","fig":"<svg viewBox='0 0 320 165'><circle cx='80' cy='70' r='22' fill='#5b6b85' stroke='#1a2b45'/><text x='80' y='75' font-size='12' text-anchor='middle' fill='#fff'>N</text><circle cx='150' cy='70' r='22' fill='#5b6b85' stroke='#1a2b45'/><text x='150' y='75' font-size='12' text-anchor='middle' fill='#fff'>N</text><line x1='102' y1='62' x2='128' y2='62' stroke='#1a2b45' stroke-width='2'/><line x1='102' y1='70' x2='128' y2='70' stroke='#1a2b45' stroke-width='2'/><line x1='102' y1='78' x2='128' y2='78' stroke='#1a2b45' stroke-width='2'/><circle cx='220' cy='70' r='22' fill='#e0552b' stroke='#1a2b45'/><text x='220' y='75' font-size='12' text-anchor='middle' fill='#fff'>O</text><circle cx='285' cy='70' r='22' fill='#e0552b' stroke='#1a2b45'/><text x='285' y='75' font-size='12' text-anchor='middle' fill='#fff'>O</text><line x1='242' y1='64' x2='263' y2='64' stroke='#1a2b45' stroke-width='2'/><line x1='242' y1='76' x2='263' y2='76' stroke='#1a2b45' stroke-width='2'/><text x='115' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>N≡N (üçlü)</text><text x='252' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>O=O (çift)</text></svg>","steps":[{"t":"Çift sayısı","a":"3'e karşı 2","d":"N₂'de üç ortak çift, O₂'de iki ortak çift paylaşılır."},{"t":"Daha güçlü","a":"daha çok bağ","d":"Daha çok elektron çifti paylaşan bağ daha güçlüdür ve koparılması daha çok enerji ister."}],"ans":"N₂ üç ortak çiftle (üçlü bağ) bağlandığından O₂'nin çift bağından daha güçlüdür ve koparmak daha zordur."},{"q":"Aynı çeşit iki ametal atomu elektronu nasıl paylaşır, ne kadar adil olur?","steps":[{"t":"Eşit güç","a":"aynı çekim","d":"Aynı çeşit atomlar (örneğin H–H) elektronu eşit güçle çeker."},{"t":"Adil paylaşım","a":"ortada","d":"Bu yüzden ortak çift tam ortada kalır, paylaşım adildir (apolar bağ)."}],"ans":"Aynı çeşit iki ametal elektronu eşit güçle çektiğinden ortak çift ortada kalır, paylaşım adil (apolar) olur."},{"q":"Kovalent bağ kuran maddeler genelde neden elektriği iletmez?","steps":[{"t":"Yük taşıyıcı","a":"serbest iyon yok","d":"Kovalent (moleküler) maddelerde serbestçe dolaşan iyon ya da elektron bulunmaz."},{"t":"İletmez","a":"akım taşınmaz","d":"Yükü taşıyacak serbest tanecik olmadığından elektrik akımı genelde iletilmez."}],"ans":"Kovalent maddelerde serbest iyon ya da elektron olmadığından elektrik akımını genelde iletmezler."},{"q":"CO₂ molekülünde karbon ile oksijenler arasında ne tür bağlar vardır?","fig":"<svg viewBox='0 0 320 150'><circle cx='160' cy='75' r='26' fill='#33415588' stroke='#1a2b45'/><text x='160' y='80' font-size='13' text-anchor='middle' fill='#fff'>C</text><circle cx='80' cy='75' r='24' fill='#e0552b' stroke='#1a2b45'/><text x='80' y='80' font-size='12' text-anchor='middle' fill='#fff'>O</text><circle cx='240' cy='75' r='24' fill='#e0552b' stroke='#1a2b45'/><text x='240' y='80' font-size='12' text-anchor='middle' fill='#fff'>O</text><line x1='104' y1='69' x2='134' y2='69' stroke='#1a2b45' stroke-width='2'/><line x1='104' y1='81' x2='134' y2='81' stroke='#1a2b45' stroke-width='2'/><line x1='186' y1='69' x2='216' y2='69' stroke='#1a2b45' stroke-width='2'/><line x1='186' y1='81' x2='216' y2='81' stroke='#1a2b45' stroke-width='2'/><text x='160' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>O=C=O</text></svg>","steps":[{"t":"Karbon ihtiyacı","a":"4 elektron","d":"Karbon oktete ulaşmak için dört elektron paylaşmalıdır."},{"t":"İki çift bağ","a":"O=C=O","d":"Karbon her oksijenle iki ortak çift paylaşır; iki tane çift bağ oluşur."}],"ans":"CO₂'de karbon her oksijenle çift bağ kurar; molekülde iki adet çift bağ (O=C=O) bulunur."}]},"lise":{"kolay":[{"q":"Kovalent bağ tanımını ve hangi atomlar arasında oluştuğunu açıklayınız.","steps":[{"t":"Taraflar","a":"ametal-ametal","d":"Kovalent bağ, elektronegatiflikleri yüksek iki ametal atom arasında oluşur."},{"t":"Mekanizma","a":"elektron ortaklığı","d":"Atomlar son katmanlarını oktete tamamlamak için bir ya da daha çok elektron çiftini ortaklaşa kullanır."}],"ans":"Kovalent bağ, iki ametal atomun oktete ulaşmak için elektron çift(ler)ini ortaklaşa kullanmasıyla oluşan bağdır."},{"q":"H₂ molekülünün oluşumunu elektron ortaklığı açısından açıklayınız.","fig":"<svg viewBox='0 0 320 165'><circle cx='115' cy='80' r='28' fill='none' stroke='#1a2b45'/><text x='115' y='50' font-size='12' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='205' cy='80' r='28' fill='none' stroke='#1a2b45'/><text x='205' y='50' font-size='12' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='152' cy='80' r='5' fill='#2b6be0'/><circle cx='168' cy='80' r='5' fill='#2b6be0'/><text x='160' y='145' font-size='10' text-anchor='middle' fill='#1a2b45'>ortak çift (H–H)</text></svg>","steps":[{"t":"Başlangıç","a":"1'er elektron","d":"Her hidrojenin 1 değerlik elektronu vardır; tek başına son katmanı (1s) eksiktir."},{"t":"Ortak çift","a":"H–H tek bağ","d":"İki hidrojen birer elektron katarak bir ortak çift oluşturur; her ikisi de He düzenine (2 elektron) ulaşır."}],"ans":"İki hidrojen birer elektron katıp bir ortak çift oluşturur; böylece her atom helyum düzenine ulaşır ve kararlı H₂ molekülü oluşur."},{"q":"Tek, çift ve üçlü kovalent bağı paylaşılan elektron çifti sayısıyla açıklayınız.","steps":[{"t":"Çift sayısı","a":"1 / 2 / 3","d":"Tek bağda 1, çift bağda 2, üçlü bağda 3 ortak elektron çifti paylaşılır."},{"t":"Örnekler","a":"H₂, O₂, N₂","d":"H₂'de tek bağ (H–H), O₂'de çift bağ (O=O), N₂'de üçlü bağ (N≡N) bulunur."}],"ans":"Tek bağ 1, çift bağ 2, üçlü bağ 3 ortak elektron çifti paylaşımıdır; sırasıyla H₂, O₂ ve N₂ örnektir."},{"q":"N₂ molekülünde üçlü bağ nasıl oluşur ve bu bağın özelliği nedir?","fig":"<svg viewBox='0 0 320 160'><circle cx='120' cy='80' r='28' fill='#5b6b85' stroke='#1a2b45'/><text x='120' y='85' font-size='13' text-anchor='middle' fill='#fff'>N</text><circle cx='200' cy='80' r='28' fill='#5b6b85' stroke='#1a2b45'/><text x='200' y='85' font-size='13' text-anchor='middle' fill='#fff'>N</text><line x1='148' y1='70' x2='172' y2='70' stroke='#1a2b45' stroke-width='3'/><line x1='148' y1='80' x2='172' y2='80' stroke='#1a2b45' stroke-width='3'/><line x1='148' y1='90' x2='172' y2='90' stroke='#1a2b45' stroke-width='3'/><text x='160' y='140' font-size='11' text-anchor='middle' fill='#1a2b45'>N≡N</text></svg>","steps":[{"t":"Değerlik","a":"5'er elektron","d":"Her azotun 5 değerlik elektronu vardır; oktete ulaşmak için 3 elektrona ihtiyacı vardır."},{"t":"Üç ortak çift","a":"N≡N","d":"İki azot üç ortak çift paylaşarak üçlü bağ kurar; bu kısa ve çok güçlü bir bağdır."}],"ans":"N₂'de iki azot üç ortak çift paylaşıp üçlü bağ (N≡N) kurar; bu kovalent bağların en güçlülerinden biridir ve koparılması yüksek enerji ister."},{"q":"Kovalent bağda bağ uzunluğu ile bağ sayısı (tek/çift/üçlü) arasındaki ilişki nedir?","steps":[{"t":"Daha çok çift","a":"daha kısa","d":"Paylaşılan ortak çift sayısı arttıkça atomlar birbirine daha çok çekilir."},{"t":"Sonuç","a":"üçlü < çift < tek","d":"Bu nedenle bağ uzunluğu üçlü bağda en kısa, tek bağda en uzundur."}],"ans":"Ortak çift sayısı arttıkça bağ kısalır ve güçlenir; bu yüzden bağ uzunluğu üçlü < çift < tek bağ sırasındadır."}],"zor":[{"q":"O₂ molekülünde çift bağın oluşumunu Lewis yapısı ve oktet üzerinden açıklayınız.","fig":"<svg viewBox='0 0 320 165'><circle cx='115' cy='80' r='30' fill='none' stroke='#1a2b45'/><text x='115' y='85' font-size='13' text-anchor='middle' fill='#1a2b45'>O</text><circle cx='205' cy='80' r='30' fill='none' stroke='#1a2b45'/><text x='205' y='85' font-size='13' text-anchor='middle' fill='#1a2b45'>O</text><circle cx='152' cy='72' r='4' fill='#2b6be0'/><circle cx='168' cy='72' r='4' fill='#2b6be0'/><circle cx='152' cy='88' r='4' fill='#2b6be0'/><circle cx='168' cy='88' r='4' fill='#2b6be0'/><circle cx='90' cy='55' r='4' fill='#2b6be0'/><circle cx='100' cy='48' r='4' fill='#2b6be0'/><circle cx='230' cy='55' r='4' fill='#2b6be0'/><circle cx='220' cy='48' r='4' fill='#2b6be0'/><text x='160' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>O=O (2 ortak çift)</text></svg>","steps":[{"t":"Değerlik","a":"6'şar elektron","d":"Her oksijenin 6 değerlik elektronu vardır; oktet için 2 elektron eksiktir."},{"t":"İki ortak çift","a":"çift bağ","d":"İki oksijen ikişer elektron katıp iki ortak çift paylaşır; her atom 8 elektrona (oktete) ulaşır."},{"t":"Sonuç","a":"O=O","d":"Böylece atomlar arası çift bağ oluşur; her oksijende ayrıca ortaklanmamış çiftler kalır."}],"ans":"Her oksijen oktet için 2 elektron eksiğini iki ortak çift paylaşarak tamamlar; sonuçta atomlar arasında çift bağ (O=O) oluşur."},{"q":"Kovalent bağda σ (sigma) ve π (pi) bağları nasıl oluşur; çift ve üçlü bağda dağılım nasıldır?","steps":[{"t":"Örtüşme türü","a":"eksenel / yanal","d":"Orbitaller bağ ekseni boyunca uç uca örtüşürse σ, ekseninin yanından (paralel) örtüşürse π bağı oluşur."},{"t":"Çift bağ","a":"1 σ + 1 π","d":"Bir çift bağ daima bir σ ve bir π bağından oluşur."},{"t":"Üçlü bağ","a":"1 σ + 2 π","d":"Bir üçlü bağ ise bir σ ve iki π bağından oluşur; N₂ buna örnektir."}],"ans":"Eksenel örtüşme σ, yanal örtüşme π bağı verir; çift bağ 1 σ + 1 π, üçlü bağ 1 σ + 2 π şeklindedir."},{"q":"H₂, O₂ ve N₂ moleküllerini bağ türü, bağ enerjisi ve tepkimeye yatkınlık açısından karşılaştırınız.","steps":[{"t":"Bağ türleri","a":"tek/çift/üçlü","d":"H₂ tek bağ, O₂ çift bağ, N₂ üçlü bağ içerir."},{"t":"Bağ enerjisi","a":"N₂ > O₂ > H₂ (yaklaşık)","d":"Ortak çift sayısı arttıkça bağ enerjisi artar; üçlü bağlı N₂'nin koparılması en çok enerji ister."},{"t":"Tepkime","a":"N₂ inert","d":"Çok güçlü üçlü bağı yüzünden N₂ oda koşullarında tepkimeye çok isteksiz (inert) iken H₂ ve O₂ daha kolay tepkir."}],"ans":"H₂ (tek), O₂ (çift), N₂ (üçlü) bağ içerir; bağ enerjisi N₂ > O₂ > H₂ yönündedir ve güçlü üçlü bağı nedeniyle N₂ tepkimeye en isteksiz olandır."},{"q":"Kovalent bağ kuran iki atomdan biri elektronu daha güçlü çekerse bağda ne olur?","fig":"<svg viewBox='0 0 320 160'><circle cx='110' cy='80' r='26' fill='#cfd8e8' stroke='#1a2b45'/><text x='110' y='85' font-size='13' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='215' cy='80' r='30' fill='#9ed9a8' stroke='#1a2b45'/><text x='215' y='85' font-size='13' text-anchor='middle' fill='#1a2b45'>Cl</text><line x1='136' y1='80' x2='185' y2='80' stroke='#1a2b45' stroke-width='2'/><circle cx='172' cy='80' r='5' fill='#2b6be0'/><text x='100' y='130' font-size='11' fill='#1a2b45'>δ⁺</text><text x='210' y='130' font-size='11' fill='#1a2b45'>δ⁻</text></svg>","steps":[{"t":"Elektronegatiflik farkı","a":"eşitsiz çekim","d":"Elektronegatifliği yüksek atom ortak çifti kendine doğru daha çok çeker."},{"t":"Kısmi yükler","a":"δ⁺ ve δ⁻","d":"Ortak çiftin kayması atomlarda kısmi yükler (δ⁺ ve δ⁻) oluşturur; bağ polar kovalent olur."}],"ans":"Daha elektronegatif atom ortak çifti kendine çeker; atomlarda kısmi yükler (δ⁺/δ⁻) oluşur ve bağ polar kovalent hale gelir (örneğin H–Cl)."},{"q":"Kovalent karakterli moleküler maddelerin erime/kaynama noktaları neden genelde düşüktür?","steps":[{"t":"İki tür kuvvet","a":"bağ vs molekül arası","d":"Molekül İÇİndeki kovalent bağlar güçlüdür, ancak moleküller ARASINDAki çekim kuvvetleri zayıftır."},{"t":"Hal değiştirme","a":"molekül arası kopar","d":"Erime/kaynamada kovalent bağlar değil, zayıf molekül arası kuvvetler kırılır; bunun için az enerji yeter."}],"ans":"Erime/kaynamada güçlü kovalent bağlar değil, zayıf molekül arası kuvvetler kırıldığından moleküler maddelerin erime/kaynama noktaları genelde düşüktür."}]}},"londonKuvvet":{"ilkokul":{"kolay":[{"q":"Moleküller arasında çok zayıf da olsa bir çekim var mıdır?","steps":[{"t":"Tek tek moleküller","a":"yan yana","d":"Maddeler çok sayıda küçük molekülden oluşur; bunlar yan yana durur."},{"t":"Hafif çekim","a":"birbirini tutar","d":"Aralarında çok zayıf da olsa bir çekim vardır; bu sayede birbirine yapışabilirler."}],"ans":"Evet; moleküller arasında çok zayıf da olsa bir çekim kuvveti vardır."},{"q":"Bütün moleküllerde bulunan en zayıf çekime ne ad verilir?","steps":[{"t":"Her molekülde var","a":"genel çekim","d":"En zayıf bu çekim, istisnasız tüm moleküllerde bulunur."},{"t":"Adı","a":"London kuvveti","d":"Bu çok zayıf çekime London (dağılma) kuvveti denir."}],"ans":"Tüm moleküllerde bulunan en zayıf çekime London (dağılma) kuvveti denir."},{"q":"Bir madde küçük moleküllerden büyük moleküllere doğru gittikçe bu zayıf çekim güçlenir mi?","fig":"<svg viewBox='0 0 320 150'><circle cx='70' cy='75' r='14' fill='#cfd8e8' stroke='#1a2b45'/><text x='70' y='100' font-size='9' text-anchor='middle' fill='#1a2b45'>küçük</text><circle cx='160' cy='75' r='22' fill='#9ed9a8' stroke='#1a2b45'/><text x='160' y='110' font-size='9' text-anchor='middle' fill='#1a2b45'>orta</text><circle cx='255' cy='75' r='30' fill='#e0552b' stroke='#1a2b45'/><text x='255' y='118' font-size='9' text-anchor='middle' fill='#1a2b45'>büyük</text><text x='160' y='25' font-size='10' text-anchor='middle' fill='#1a2b45'>çekim güçlenir →</text></svg>","steps":[{"t":"Büyük molekül","a":"daha çok elektron","d":"Büyük moleküllerde daha çok elektron bulunur."},{"t":"Güçlenme","a":"çekim artar","d":"Elektron sayısı arttıkça London çekimi de güçlenir."}],"ans":"Evet; molekül büyüdükçe ve elektron sayısı arttıkça London çekimi güçlenir."},{"q":"Geko (kertenkele) duvara nasıl tutunur sorusunda olduğu gibi, çok küçük yüzeyler arası zayıf çekimler toplamı işe yarar mı?","steps":[{"t":"Tek tek zayıf","a":"çok küçük","d":"Her bir London çekimi tek başına çok zayıftır."},{"t":"Toplamı güçlü","a":"birikir","d":"Çok sayıda zayıf çekim bir araya gelince toplamı fark edilir bir güç oluşturabilir."}],"ans":"Evet; tek tek zayıf olan London çekimleri çok sayıda olunca toplamları fark edilir güç oluşturabilir."},{"q":"Soğutunca gaz olan maddelerin sıvıya dönüşmesinde bu zayıf çekimlerin rolü var mıdır?","steps":[{"t":"Soğuma","a":"yavaşlar","d":"Soğutulunca moleküller yavaşlar, birbirine daha yakın durur."},{"t":"Çekim baskın olur","a":"sıvılaşır","d":"Yavaşlayan moleküller arasında London çekimi baskın gelir ve madde sıvıya döner."}],"ans":"Evet; soğutulunca moleküller yavaşlar ve London çekimleri onları sıvı halde bir arada tutar."}],"zor":[{"q":"London çekimi neden bir an var bir an yok gibi 'anlık' bir çekimdir?","steps":[{"t":"Elektronlar hareketli","a":"bir yana toplanır","d":"Molekülün elektronları sürekli hareket eder; bir anda bir tarafa daha çok toplanabilir."},{"t":"Anlık çekim","a":"geçici uç","d":"O anda molekülün bir ucu hafif eksi, öbürü hafif artı olur; komşu molekülü çeker, sonra dağılır. Bu yüzden çekim anlıktır."}],"ans":"Elektronlar bir anda bir tarafa toplanıp molekülde geçici artı-eksi uç oluşturduğundan, London çekimi anlık (sürekli değişen) bir çekimdir."},{"q":"İki apolar molekül (örneğin iki oksijen) arasında bile çekim olmasının nedeni nedir?","steps":[{"t":"Apolar molekül","a":"normalde dengeli","d":"Apolar moleküllerin yükü normalde dengeli dağılmıştır, kalıcı uçları yoktur."},{"t":"Anlık dengesizlik","a":"London çekimi","d":"Yine de elektronlar bir an bir tarafa kayınca geçici uçlar doğar ve London çekimi oluşur; bu yüzden apolar moleküller bile birbirini çeker."}],"ans":"Apolar moleküllerde bile elektronlar anlık olarak bir tarafa kayıp geçici uçlar oluşturduğundan London çekimi doğar."},{"q":"Halojenlerde kaynama noktası F₂ < Cl₂ < Br₂ < I₂ şeklinde artar; bunun sebebi nedir?","fig":"<svg viewBox='0 0 320 150'><circle cx='55' cy='90' r='12' fill='#cfd8e8' stroke='#1a2b45'/><text x='55' y='115' font-size='9' text-anchor='middle' fill='#1a2b45'>F₂</text><circle cx='125' cy='90' r='18' fill='#9ed9a8' stroke='#1a2b45'/><text x='125' y='120' font-size='9' text-anchor='middle' fill='#1a2b45'>Cl₂</text><circle cx='200' cy='90' r='24' fill='#e0552b' stroke='#1a2b45'/><text x='200' y='126' font-size='9' text-anchor='middle' fill='#1a2b45'>Br₂</text><circle cx='280' cy='90' r='30' fill='#5b6b85' stroke='#1a2b45'/><text x='280' y='132' font-size='9' text-anchor='middle' fill='#fff'>I₂</text><text x='160' y='25' font-size='10' text-anchor='middle' fill='#1a2b45'>elektron sayısı, kaynama n. artar →</text></svg>","steps":[{"t":"Büyüyen molekül","a":"daha çok elektron","d":"F₂'den I₂'ye gidildikçe molekül büyür ve elektron sayısı artar."},{"t":"Güçlü London","a":"yüksek kaynama","d":"Elektron arttıkça London çekimi güçlenir; molekülleri ayırmak için daha çok enerji gerektiğinden kaynama noktası yükselir."}],"ans":"F₂'den I₂'ye elektron sayısı arttıkça London çekimi güçlenir, bu yüzden kaynama noktaları F₂ < Cl₂ < Br₂ < I₂ sırasıyla artar."},{"q":"Aynı sıcaklıkta F₂ gaz, I₂ katı iken bunun nedeni nedir?","steps":[{"t":"F₂ zayıf çekim","a":"az elektron","d":"F₂ küçük ve az elektronlu olduğundan London çekimi zayıftır; molekülleri bir arada tutamaz, gazdır."},{"t":"I₂ güçlü çekim","a":"çok elektron","d":"I₂ büyük ve çok elektronlu olduğundan London çekimi güçlüdür; molekülleri katı halde bir arada tutar."}],"ans":"F₂'nin London çekimi zayıf olduğundan gaz, I₂'nin London çekimi güçlü olduğundan katı halde bulunur."},{"q":"London kuvvetleri neden 'tüm moleküllerde' bulunur, polar moleküllerde de var mıdır?","steps":[{"t":"Anlık dipol her zaman","a":"elektronlar hareketli","d":"Her molekülde elektronlar hareket ettiğinden anlık dipoller her zaman oluşur."},{"t":"Polarda da var","a":"ek olarak","d":"Polar moleküllerde kalıcı çekime ek olarak London kuvveti de bulunur; yani London her molekülde vardır."}],"ans":"Evet; elektron hareketi her molekülde anlık dipol oluşturduğundan London kuvvetleri polar dahil tüm moleküllerde bulunur."}]},"ortaokul":{"kolay":[{"q":"London (dağılma) kuvvetleri nasıl oluşur?","steps":[{"t":"Anlık dipol","a":"elektron kayması","d":"Bir moleküldeki elektronlar bir an bir tarafa kayınca geçici (anlık) bir dipol, yani artı-eksi uç oluşur."},{"t":"İndüklenmiş dipol","a":"komşuyu etkiler","d":"Bu anlık dipol komşu molekülde de geçici bir dipol oluşturur (indükler); ikisi arasındaki çekim London kuvvetidir."}],"ans":"London kuvvetleri, bir moleküldeki anlık dipolün komşu molekülde dipol oluşturmasıyla (anlık dipol–indüklenmiş dipol) doğan zayıf çekimdir."},{"q":"London kuvvetleri hangi moleküllerde bulunur?","steps":[{"t":"Her molekülde","a":"istisnasız","d":"Elektron hareketi her molekülde anlık dipol yarattığından London kuvveti istisnasız tüm moleküllerde bulunur."},{"t":"Özellikle apolarda","a":"tek kuvvet","d":"Apolar moleküllerde kalıcı dipol olmadığından moleküller arası tek çekim genelde London kuvvetidir."}],"ans":"London kuvvetleri tüm moleküllerde, özellikle de apolar moleküllerde başlıca moleküller arası kuvvet olarak bulunur."},{"q":"Molekül büyüdükçe London kuvveti neden güçlenir?","fig":"<svg viewBox='0 0 320 150'><circle cx='70' cy='80' r='16' fill='#cfd8e8' stroke='#1a2b45'/><text x='70' y='110' font-size='9' text-anchor='middle' fill='#1a2b45'>az e⁻</text><circle cx='220' cy='80' r='32' fill='#e0552b' stroke='#1a2b45'/><text x='220' y='124' font-size='9' text-anchor='middle' fill='#1a2b45'>çok e⁻</text><text x='145' y='80' font-size='14' text-anchor='middle' fill='#1a2b45'>→</text><text x='160' y='25' font-size='10' text-anchor='middle' fill='#1a2b45'>çekim güçlenir</text></svg>","steps":[{"t":"Daha çok elektron","a":"kolay polarlaşma","d":"Büyük moleküllerde elektron sayısı fazladır ve elektron bulutu daha kolay biçim değiştirir (polarlaşır)."},{"t":"Güçlü anlık dipol","a":"daha kuvvetli çekim","d":"Daha kolay polarlaşan bulut daha güçlü anlık dipoller oluşturur; bu da London çekimini güçlendirir."}],"ans":"Molekül büyüyüp elektron sayısı arttıkça elektron bulutu kolay polarlaşır; daha güçlü anlık dipoller oluştuğundan London kuvveti güçlenir."},{"q":"Halojenlerde kaynama noktası F₂ < Cl₂ < Br₂ < I₂ olarak değişir; bunu London kuvveti nasıl açıklar?","steps":[{"t":"Artan elektron","a":"F₂→I₂","d":"F₂'den I₂'ye gidildikçe molekül büyür, elektron sayısı artar."},{"t":"Güçlenen London","a":"kaynama yükselir","d":"London kuvveti güçlendikçe molekülleri ayırmak için daha çok enerji gerekir; kaynama noktası artar."}],"ans":"F₂'den I₂'ye elektron sayısı arttıkça London kuvveti güçlenir; bu nedenle kaynama noktaları F₂ < Cl₂ < Br₂ < I₂ sırasında artar."},{"q":"London kuvveti diğer moleküller arası kuvvetlere göre güçlü müdür zayıf mıdır?","steps":[{"t":"En zayıf tür","a":"genelde zayıf","d":"Tek bir London kuvveti, hidrojen bağı veya dipol-dipol çekimine göre genellikle daha zayıftır."},{"t":"Toplamda etkili","a":"büyük molekülde","d":"Ancak büyük moleküllerde çok sayıda London çekimi toplanınca etkisi önemli hale gelir."}],"ans":"London kuvveti tek başına en zayıf moleküller arası kuvvettir; ancak büyük moleküllerde çok sayıda toplandığında etkisi belirginleşir."}],"zor":[{"q":"İki apolar molekül arasında kalıcı dipol yokken nasıl çekim oluşabilir?","steps":[{"t":"Anlık dipol","a":"geçici dengesizlik","d":"Apolar molekülde yük ortalama olarak dengelidir, fakat elektronlar bir an bir tarafa kayıp geçici (anlık) dipol oluşturur."},{"t":"İndükleme","a":"komşuda dipol","d":"Bu anlık dipol, komşu apolar molekülde de bir dipol indükler; aralarında London çekimi doğar."}],"ans":"Apolar moleküllerde elektronların anlık kayması geçici dipol yaratır ve komşuda dipol indükler; bu anlık dipol–indüklenmiş dipol etkileşimi London çekimini oluşturur."},{"q":"Aynı sayıda atom içeren n-pentan zincir halinde iken neopentan küresel yapıda; n-pentanın kaynama noktası daha yüksektir. Bunun nedeni nedir?","steps":[{"t":"Temas yüzeyi","a":"zincir geniş","d":"Uzun düz zincirli n-pentan moleküllerinin komşu moleküllerle temas yüzeyi geniştir."},{"t":"Daha çok London teması","a":"yüksek kaynama","d":"Geniş temas, daha çok London etkileşimi demektir; bu yüzden n-pentanın kaynama noktası küresel (az temaslı) neopentandan yüksektir."}],"ans":"Uzun zincirli n-pentanın temas yüzeyi geniş olduğundan London etkileşimi daha fazladır; bu nedenle kaynama noktası küresel neopentandan yüksektir."},{"q":"London kuvveti neden 'anlık dipol – indüklenmiş dipol' kuvveti olarak adlandırılır?","steps":[{"t":"Anlık dipol","a":"kendiliğinden","d":"Bir molekülde elektron hareketiyle kendiliğinden geçici (anlık) bir dipol oluşur."},{"t":"İndüklenmiş dipol","a":"komşuda yaratılır","d":"Bu anlık dipol, komşu moleküldeki elektron bulutunu etkileyerek orada da bir dipol oluşturur (indükler); iki adın birleşimi kuvvetin adıdır."}],"ans":"İlk molekülde kendiliğinden 'anlık dipol', komşuda ise onun yarattığı 'indüklenmiş dipol' oluştuğu için bu çekime anlık dipol–indüklenmiş dipol (London) kuvveti denir."},{"q":"Polarlaşabilirlik (elektron bulutunun kolay biçim değiştirmesi) London kuvvetini nasıl etkiler?","steps":[{"t":"Polarlaşabilirlik","a":"bulut esnekliği","d":"Büyük ve çok elektronlu moleküllerde elektron bulutu çekirdeklere daha gevşek bağlıdır, kolay biçim değiştirir (polarlaşabilirlik yüksektir)."},{"t":"Güçlü London","a":"daha büyük çekim","d":"Kolay polarlaşan bulut daha güçlü anlık ve indüklenmiş dipoller oluşturur; bu da London kuvvetini artırır."}],"ans":"Polarlaşabilirlik arttıkça elektron bulutu daha güçlü anlık/indüklenmiş dipoller oluşturur; bu nedenle London kuvveti de artar."},{"q":"Soy gazlardan helyumun kaynama noktası ksenondan çok düşüktür; bu tek atomlu gazlarda hangi kuvvet rol oynar?","steps":[{"t":"Tek kuvvet London","a":"apolar atomlar","d":"Soy gaz atomlarında kalıcı dipol yoktur; aralarındaki tek çekim London kuvvetidir."},{"t":"Elektron sayısı","a":"He az, Xe çok","d":"Helyumun çok az, ksenonun çok fazla elektronu vardır; ksenonda London çekimi çok güçlü olduğundan kaynama noktası helyumdan oldukça yüksektir."}],"ans":"Soy gazlarda tek çekim London kuvvetidir; ksenon çok elektronlu olduğundan London çekimi güçlüdür ve kaynama noktası az elektronlu helyumdan çok yüksektir."}]},"lise":{"kolay":[{"q":"London (dağılma) kuvvetlerinin oluşum mekanizmasını açıklayınız.","fig":"<svg viewBox='0 0 320 160'><ellipse cx='95' cy='80' rx='40' ry='26' fill='#cfd8e8' stroke='#1a2b45'/><text x='75' y='84' font-size='12' fill='#1a2b45'>δ⁺</text><text x='115' y='84' font-size='12' fill='#1a2b45'>δ⁻</text><ellipse cx='225' cy='80' rx='40' ry='26' fill='#9ed9a8' stroke='#1a2b45'/><text x='205' y='84' font-size='12' fill='#1a2b45'>δ⁺</text><text x='245' y='84' font-size='12' fill='#1a2b45'>δ⁻</text><line x1='135' y1='80' x2='185' y2='80' stroke='#2b6be0' stroke-width='1' stroke-dasharray='3 3'/><text x='160' y='135' font-size='9' text-anchor='middle' fill='#1a2b45'>anlık dipol komşuda dipol indükler</text></svg>","steps":[{"t":"Anlık dipol","a":"elektron dalgalanması","d":"Bir moleküldeki elektronların anlık dağılımı dengesizleşince geçici (anlık) bir dipol oluşur."},{"t":"İndüklenmiş dipol","a":"komşuda dipol","d":"Bu anlık dipolün elektrik alanı, komşu molekülün elektron bulutunu kutuplaştırarak orada bir dipol indükler; iki dipol arasındaki çekim London kuvvetidir."}],"ans":"London kuvvetleri, bir moleküldeki elektron dalgalanmasının yarattığı anlık dipolün komşu molekülde dipol indüklemesiyle (anlık dipol–indüklenmiş dipol) oluşan zayıf çekimdir."},{"q":"London kuvvetlerinin tüm moleküllerde bulunmasının nedeni nedir?","steps":[{"t":"Elektron hareketi evrensel","a":"her molekülde","d":"Her molekülde elektronlar sürekli hareket ettiğinden anlık dipoller kaçınılmaz olarak oluşur."},{"t":"Apolarda tek kuvvet","a":"baskın çekim","d":"Polar moleküllerde diğer kuvvetlere eşlik eder; apolar moleküllerde ise moleküller arası başlıca (çoğu zaman tek) çekimdir."}],"ans":"Elektron hareketi her molekülde anlık dipol yarattığından London kuvvetleri istisnasız tüm moleküllerde bulunur; apolar moleküllerde başlıca moleküller arası kuvvettir."},{"q":"London kuvveti molekül kütlesi/elektron sayısı arttıkça neden güçlenir?","steps":[{"t":"Polarlaşabilirlik artar","a":"gevşek elektron bulutu","d":"Elektron sayısı (ve genellikle molekül kütlesi) arttıkça elektron bulutu büyür ve çekirdeklere daha gevşek bağlanır; polarlaşabilirlik artar."},{"t":"Güçlü dipoller","a":"daha büyük çekim","d":"Daha kolay polarlaşan bulut daha büyük anlık ve indüklenmiş dipoller oluşturur; bu nedenle London çekimi güçlenir."}],"ans":"Elektron sayısı/kütle arttıkça polarlaşabilirlik artar ve daha güçlü anlık/indüklenmiş dipoller oluşur; bu yüzden London kuvveti güçlenir."},{"q":"Halojenlerin kaynama noktası F₂ < Cl₂ < Br₂ < I₂ sıralamasını London kuvveti ile açıklayınız.","fig":"<svg viewBox='0 0 320 150'><circle cx='55' cy='95' r='11' fill='#cfd8e8' stroke='#1a2b45'/><text x='55' y='120' font-size='9' text-anchor='middle' fill='#1a2b45'>F₂</text><circle cx='125' cy='95' r='17' fill='#9ed9a8' stroke='#1a2b45'/><text x='125' y='126' font-size='9' text-anchor='middle' fill='#1a2b45'>Cl₂</text><circle cx='200' cy='95' r='23' fill='#e0552b' stroke='#1a2b45'/><text x='200' y='132' font-size='9' text-anchor='middle' fill='#fff'>Br₂</text><circle cx='280' cy='95' r='29' fill='#5b6b85' stroke='#1a2b45'/><text x='280' y='138' font-size='9' text-anchor='middle' fill='#fff'>I₂</text><text x='160' y='25' font-size='10' text-anchor='middle' fill='#1a2b45'>elektron sayısı ve kaynama n. artar →</text></svg>","steps":[{"t":"Artan elektron","a":"F₂'den I₂'ye","d":"Hepsi apolar diatomik moleküldür; F₂'den I₂'ye elektron sayısı ve polarlaşabilirlik artar."},{"t":"Güçlenen London","a":"yüksek kaynama","d":"London kuvveti güçlendikçe molekülleri ayırmak için daha çok enerji gerekir; bu yüzden kaynama noktaları F₂ < Cl₂ < Br₂ < I₂ sırasıyla yükselir (F₂, Cl₂ gaz; Br₂ sıvı; I₂ katı)."}],"ans":"Apolar halojenlerde F₂'den I₂'ye polarlaşabilirlik arttığından London kuvveti güçlenir; bu nedenle kaynama noktaları F₂ < Cl₂ < Br₂ < I₂ olarak artar."},{"q":"London kuvvetlerinin gerçek (ideal olmayan) gazların davranışına etkisi nedir?","steps":[{"t":"Zayıf çekim","a":"moleküller arası","d":"London kuvvetleri gaz moleküllerini birbirine doğru zayıfça çeker."},{"t":"İdeallikten sapma","a":"düşük sıcaklık/yüksek basınç","d":"Özellikle düşük sıcaklık ve yüksek basınçta bu çekim hissedilir hale gelir; gaz idealden sapar ve sonunda yoğuşabilir."}],"ans":"London kuvvetleri gaz moleküllerini zayıfça çekerek özellikle düşük sıcaklık ve yüksek basınçta ideal gaz davranışından sapmaya ve yoğuşmaya yol açar."}],"zor":[{"q":"Aynı elektron sayısına sahip n-bütan ile yapısal izomeri izobütanın (2-metilpropan) kaynama noktaları neden farklıdır?","steps":[{"t":"Molekül şekli","a":"zincir vs dallı","d":"İkisinin de elektron sayısı aynıdır; n-bütan uzun düz zincir, izobütan ise dallı (daha küresel) yapıdadır."},{"t":"Yüzey teması","a":"London farkı","d":"Düz zincirli n-bütanın komşu moleküllerle temas yüzeyi daha geniş olduğundan London etkileşimi daha güçlüdür; bu yüzden n-bütanın kaynama noktası izobütandan biraz yüksektir."}],"ans":"Elektron sayısı aynı olsa da n-bütanın düz zinciri komşu moleküllerle daha geniş temas yüzeyi (daha güçlü London etkileşimi) sağladığından kaynama noktası dallı izobütandan yüksektir."},{"q":"HCl molekülünde hem dipol-dipol hem London kuvvetleri varken, daha büyük HI molekülünün kaynama noktasının HCl'den yüksek olması neyi gösterir?","steps":[{"t":"Beklenti","a":"dipol HCl'de güçlü","d":"HCl, HI'dan daha polardır; yalnız dipol-dipol kuvvetine bakılsa HCl'nin daha yüksek kaynaması beklenirdi."},{"t":"London baskınlığı","a":"HI çok elektronlu","d":"Ancak HI çok daha fazla elektrona (yüksek polarlaşabilirlik) sahip olduğundan London kuvveti baskın gelir; HI'nin kaynama noktası HCl'den yüksektir."}],"ans":"HI'nin HCl'den daha yüksek kaynaması, büyük ve çok elektronlu moleküllerde London kuvvetinin dipol-dipol kuvvetini geçerek baskın hale gelebildiğini gösterir."},{"q":"Polarlaşabilirlik kavramını London kuvvetinin büyüklüğüyle nicel olarak ilişkilendiriniz.","steps":[{"t":"Polarlaşabilirlik (α)","a":"bulut esnekliği","d":"Polarlaşabilirlik, bir elektrik alanı altında molekülün elektron bulutunun ne kadar kolay kutuplaştığının ölçüsüdür; büyük, çok elektronlu ve yayvan moleküllerde yüksektir."},{"t":"London ile orantı","a":"α büyüdükçe artar","d":"London etkileşim enerjisi, etkileşen moleküllerin polarlaşabilirliklerinin çarpımıyla artar; α arttıkça London çekimi belirgin biçimde güçlenir."}],"ans":"London kuvvetinin büyüklüğü moleküllerin polarlaşabilirliği (α) ile orantılıdır; α arttıkça (büyük, çok elektronlu moleküllerde) London çekim enerjisi belirgin biçimde artar."},{"q":"Soy gazlarda He'den Xe'ye kaynama noktasının düzenli artmasını, atomik polarlaşabilirlik üzerinden açıklayınız.","steps":[{"t":"Tek kuvvet London","a":"apolar atomlar","d":"Soy gaz atomlarında kalıcı dipol yoktur; atomlar arası tek çekim London kuvvetidir."},{"t":"Artan polarlaşabilirlik","a":"He < Ne < ... < Xe","d":"He'den Xe'ye atom büyür, elektron sayısı ve polarlaşabilirlik artar; London kuvveti güçlendiğinden kaynama noktaları düzenli olarak yükselir."}],"ans":"Soy gazlarda tek çekim London kuvvetidir; He'den Xe'ye atomik polarlaşabilirlik arttığından London kuvveti güçlenir ve kaynama noktaları düzenli olarak artar."},{"q":"Grafit ve elmas gibi yapılar dışında, katı CO₂ (kuru buz) gibi moleküler katıların düşük süblimleşme/erime noktasına sahip olmasını London kuvvetiyle açıklayınız.","steps":[{"t":"Moleküller arası zayıf","a":"sadece London","d":"CO₂ apolar bir moleküldür; moleküller arası tek çekim London kuvvetidir (molekül içi kovalent bağlar güçlü olsa da bunlar koparılmaz)."},{"t":"Zayıf çekim → düşük geçiş","a":"kolay süblimleşme","d":"Zayıf London kuvvetlerini aşmak az enerji gerektirdiğinden kuru buz oda koşullarında doğrudan süblimleşir; moleküler katılar genelde düşük erime/süblimleşme noktalıdır."}],"ans":"Moleküler katı CO₂'de moleküller arası tek çekim zayıf London kuvveti olduğundan, bu çekimi aşmak az enerji gerektirir ve kuru buz kolayca süblimleşir; moleküler katılar bu nedenle düşük geçiş sıcaklıklıdır."}]}},"metalikBag":{"ilkokul":{"kolay":[{"q":"Demir, bakır, altın gibi metalleri bir arada tutan özel bir bağ var mıdır?","steps":[{"t":"Metal atomları","a":"yan yana dizili","d":"Metallerde çok sayıda metal atomu düzenli biçimde yan yana dizilir."},{"t":"Özel bağ","a":"metalik bağ","d":"Bu atomları bir arada tutan bağa metalik bağ denir."}],"ans":"Evet; metalleri bir arada tutan bağa metalik bağ denir."},{"q":"Metallerde elektronların 'deniz' gibi serbestçe dolaştığı söylenir. Bu ne demektir?","fig":"<svg viewBox='0 0 320 170'><circle cx='90' cy='70' r='16' fill='#e0552b' stroke='#1a2b45'/><text x='90' y='75' font-size='10' text-anchor='middle' fill='#fff'>+</text><circle cx='160' cy='70' r='16' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='75' font-size='10' text-anchor='middle' fill='#fff'>+</text><circle cx='230' cy='70' r='16' fill='#e0552b' stroke='#1a2b45'/><text x='230' y='75' font-size='10' text-anchor='middle' fill='#fff'>+</text><circle cx='90' cy='120' r='16' fill='#e0552b' stroke='#1a2b45'/><text x='90' y='125' font-size='10' text-anchor='middle' fill='#fff'>+</text><circle cx='160' cy='120' r='16' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='125' font-size='10' text-anchor='middle' fill='#fff'>+</text><circle cx='230' cy='120' r='16' fill='#e0552b' stroke='#1a2b45'/><text x='230' y='125' font-size='10' text-anchor='middle' fill='#fff'>+</text><circle cx='125' cy='95' r='4' fill='#2b6be0'/><circle cx='195' cy='95' r='4' fill='#2b6be0'/><circle cx='125' cy='55' r='4' fill='#2b6be0'/><circle cx='195' cy='135' r='4' fill='#2b6be0'/><text x='160' y='160' font-size='10' text-anchor='middle' fill='#1a2b45'>elektron denizi</text></svg>","steps":[{"t":"Serbest elektronlar","a":"bağlı değil","d":"Metallerin dış elektronları tek bir atoma bağlı kalmaz, gevşek durur."},{"t":"Dolaşma","a":"deniz gibi","d":"Bu elektronlar metalin her yerinde serbestçe dolaşır; sanki bir deniz gibidir."}],"ans":"Metallerde dış elektronlar serbestçe dolaşır; bu serbest elektron topluluğuna 'elektron denizi' denir."},{"q":"Metal teli prize taktığımızda elektriği iletmesini sağlayan nedir?","steps":[{"t":"Serbest elektronlar","a":"hareketli","d":"Metalin içinde serbestçe dolaşan elektronlar vardır."},{"t":"Akım","a":"elektron akışı","d":"Bu elektronlar bir uçtan diğerine hareket ederek elektrik akımını taşır."}],"ans":"Metallerdeki serbest elektronlar hareket ederek elektriği iletir."},{"q":"Altın neden parlaktır?","steps":[{"t":"Serbest elektronlar","a":"yüzeyde","d":"Metalin yüzeyindeki serbest elektronlar ışıkla etkileşir."},{"t":"Yansıma","a":"ışığı geri verir","d":"Bu elektronlar ışığı geri yansıttığı için metal parlak görünür."}],"ans":"Metallerdeki serbest elektronlar ışığı yansıttığı için altın gibi metaller parlaktır."},{"q":"Bakır teli neden çekip uzatabiliriz ama camı uzatamayız?","steps":[{"t":"Metal atomları kayar","a":"esnek","d":"Metalde atomlar birbiri üzerinden kayabilir, çünkü elektron denizi onları bir arada tutmaya devam eder."},{"t":"Tel olma","a":"şekillenir","d":"Bu sayede metal kırılmadan tel haline gelebilir; cam ise kayamaz, kırılır."}],"ans":"Metal atomları elektron denizi sayesinde kayabildiğinden, bakır kırılmadan tel haline gelebilir."}],"zor":[{"q":"Metalde atomlar elektronlarını bırakınca geriye ne kalır?","steps":[{"t":"Elektron bırakma","a":"dış e⁻ ayrılır","d":"Metal atomu dış elektronlarını serbest denize bırakır."},{"t":"Geriye kalan","a":"artı iyon","d":"Elektronlarını bırakan atom artı (+) yüklü iyon haline gelir; bunlar düzenli dizilir."}],"ans":"Metalde atomlar dış elektronlarını bırakınca geriye düzenli dizilmiş artı yüklü metal iyonları kalır."},{"q":"Metallerin hem elektriği hem ısıyı iyi iletmesinin ortak nedeni nedir?","fig":"<svg viewBox='0 0 320 150'><rect x='40' y='55' width='240' height='40' fill='none' stroke='#1a2b45'/><circle cx='70' cy='75' r='4' fill='#2b6be0'/><circle cx='110' cy='75' r='4' fill='#2b6be0'/><circle cx='150' cy='75' r='4' fill='#2b6be0'/><circle cx='190' cy='75' r='4' fill='#2b6be0'/><circle cx='230' cy='75' r='4' fill='#2b6be0'/><line x1='60' y1='75' x2='260' y2='75' stroke='#2b6be0' stroke-width='1' stroke-dasharray='3 3'/><polygon points='260,75 250,70 250,80' fill='#2b6be0'/><text x='160' y='120' font-size='10' text-anchor='middle' fill='#1a2b45'>hareketli elektronlar</text></svg>","steps":[{"t":"Hareketli elektronlar","a":"serbest e⁻","d":"Metalde serbestçe dolaşan elektronlar bulunur."},{"t":"Hem akım hem ısı","a":"taşırlar","d":"Bu elektronlar hareket ederek hem elektrik yükünü hem de ısı enerjisini hızla taşır."}],"ans":"Metallerin iyi iletken olmasının ortak nedeni, serbest elektronların hem elektriği hem ısıyı taşımasıdır."},{"q":"Metalik bağda elektronlar belirli iki atom arasında mı durur?","steps":[{"t":"Ortak değil tek çift","a":"yayılmış","d":"Metalde elektronlar iki atom arasına sıkışmaz; tüm yapıya yayılmıştır."},{"t":"Herkesin ortak","a":"elektron denizi","d":"Elektronlar bütün metal iyonlarının ortak kullandığı bir denizdir."}],"ans":"Hayır; metalik bağda elektronlar tüm metale yayılmış ortak bir denizdir, iki atom arasında sabit durmaz."},{"q":"Çekiçle dövülen demir neden kırılmaz da şekil alır?","steps":[{"t":"Katmanlar kayar","a":"yer değiştirir","d":"Çekiç vurunca metal iyon katmanları birbiri üstünden kayar."},{"t":"Deniz bağı korur","a":"kopmaz","d":"Elektron denizi her yerde bulunduğundan kayan katmanlar yeniden tutunur, bağ kopmaz, metal şekil alır."}],"ans":"Demir dövülünce iyon katmanları kayar; elektron denizi bağı koruduğu için kırılmaz, şekil alır."},{"q":"Aynı tür atomlardan oluşan bakır neden metalik bağ yapar, oysa iki ametal kovalent bağ yapar?","steps":[{"t":"Metalin elektronu gevşek","a":"kolay bırakır","d":"Metal atomları dış elektronlarını kolayca bırakır; bu elektronlar ortak denize katılır."},{"t":"Ametal tutar","a":"paylaşır","d":"Ametaller elektronlarını bırakmaz, sıkıca tutup ortak çift olarak paylaşır; bu yüzden kovalent bağ kurarlar."}],"ans":"Metaller dış elektronlarını kolay bırakıp ortak deniz oluşturduğundan metalik bağ; ametaller ise tutup paylaştığından kovalent bağ yapar."}]},"ortaokul":{"kolay":[{"q":"Metalik bağ nasıl tanımlanır?","steps":[{"t":"Metal iyonları","a":"pozitif örgü","d":"Metal atomları değerlik elektronlarını bırakıp pozitif iyon halinde düzenli bir örgü oluşturur."},{"t":"Elektron denizi","a":"serbest e⁻","d":"Bırakılan elektronlar tüm yapıya yayılmış serbest bir 'elektron denizi' oluşturur; bu deniz ile pozitif iyonlar arasındaki çekim bağı sağlar."}],"ans":"Metalik bağ, pozitif metal iyonları ile etrafta serbest dolaşan 'elektron denizi' arasındaki çekim kuvvetidir."},{"q":"Metaller elektriği neden iyi iletir?","fig":"<svg viewBox='0 0 320 165'><circle cx='90' cy='70' r='15' fill='#e0552b' stroke='#1a2b45'/><text x='90' y='75' font-size='10' text-anchor='middle' fill='#fff'>+</text><circle cx='160' cy='70' r='15' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='75' font-size='10' text-anchor='middle' fill='#fff'>+</text><circle cx='230' cy='70' r='15' fill='#e0552b' stroke='#1a2b45'/><text x='230' y='75' font-size='10' text-anchor='middle' fill='#fff'>+</text><circle cx='120' cy='100' r='4' fill='#2b6be0'/><circle cx='200' cy='100' r='4' fill='#2b6be0'/><line x1='60' y1='100' x2='260' y2='100' stroke='#2b6be0' stroke-width='1' stroke-dasharray='3 3'/><polygon points='260,100 250,95 250,105' fill='#2b6be0'/><text x='160' y='145' font-size='10' text-anchor='middle' fill='#1a2b45'>serbest elektronlar akar</text></svg>","steps":[{"t":"Serbest elektronlar","a":"hareketli","d":"Metalik bağdaki elektronlar belirli bir atoma bağlı olmayıp serbestçe hareket eder."},{"t":"Yük taşıma","a":"akım","d":"Gerilim uygulandığında bu serbest elektronlar yönlü hareket ederek elektrik akımını taşır."}],"ans":"Metaller, metalik bağdaki serbest elektronların yük taşıması sayesinde elektriği iyi iletir."},{"q":"Metallerin dövülebilir (levha haline gelebilir) ve tel haline gelebilir olmasının nedeni nedir?","steps":[{"t":"Katmanların kayması","a":"iyonlar kayar","d":"Kuvvet uygulandığında pozitif iyon katmanları birbiri üzerinden kayabilir."},{"t":"Denizin esnekliği","a":"bağ korunur","d":"Elektron denizi her konumda bağı sürdürdüğünden katmanlar kaysa da bağ kopmaz; metal kırılmadan şekil alır."}],"ans":"Metalde iyon katmanları kayabilir ve elektron denizi bağı koruduğu için metaller dövülebilir ve tel haline gelebilir."},{"q":"Metallerin parlak görünmesi neyle açıklanır?","steps":[{"t":"Yüzey elektronları","a":"ışıkla etkileşir","d":"Metal yüzeyindeki serbest elektronlar gelen ışığı soğurup yeniden yayar."},{"t":"Yansıma","a":"parlaklık","d":"Bu yeniden yayılan ışık düzgün yansıdığı için metaller parlak (metalik parıltılı) görünür."}],"ans":"Metallerin yüzeyindeki serbest elektronlar ışığı yansıttığı için metaller parlak görünür."},{"q":"Metalik bağ ile iyonik bağ arasındaki temel fark nedir?","steps":[{"t":"Metalik","a":"ortak elektron denizi","d":"Metalik bağda elektronlar bütün yapıda serbestçe dolaşan ortak bir deniz oluşturur."},{"t":"İyonik","a":"belirli iyonlara bağlı","d":"İyonik bağda elektron tamamen bir atomdan diğerine geçer; zıt yüklü sabit iyonlar arasında çekim olur, serbest elektron yoktur."}],"ans":"Metalik bağda serbest dolaşan ortak elektron denizi varken, iyonik bağda elektronlar sabit iyonlara aittir ve serbest dolaşmaz."}],"zor":[{"q":"Metalik bağ teorisi metallerin neden hem elektrik hem ısı iletkeni olduğunu nasıl açıklar?","steps":[{"t":"Tek nedenli","a":"serbest elektronlar","d":"İki özelliğin de kaynağı aynıdır: yapıda serbestçe hareket eden değerlik elektronları."},{"t":"İki taşıma","a":"yük ve enerji","d":"Bu elektronlar gerilim altında yönlü hareketle yükü (elektrik), sıcak bölgeden soğuğa hareketle ısı enerjisini taşır."}],"ans":"Serbest elektronlar hem elektrik yükünü hem ısı enerjisini taşıdığından metaller her iki bakımdan da iyi iletkendir."},{"q":"İyonik katılar kırılgan iken metaller dövülebilir olmasının nedenini bağ yapısıyla açıklayınız.","fig":"<svg viewBox='0 0 320 175'><text x='80' y='25' font-size='10' text-anchor='middle' fill='#1a2b45'>metal: kayar</text><circle cx='55' cy='55' r='12' fill='#e0552b' stroke='#1a2b45'/><circle cx='90' cy='55' r='12' fill='#e0552b' stroke='#1a2b45'/><circle cx='70' cy='85' r='12' fill='#e0552b' stroke='#1a2b45'/><circle cx='105' cy='85' r='12' fill='#e0552b' stroke='#1a2b45'/><text x='240' y='25' font-size='10' text-anchor='middle' fill='#1a2b45'>iyonik: kırılır</text><circle cx='215' cy='55' r='12' fill='#cfd8e8' stroke='#1a2b45'/><text x='215' y='59' font-size='9' text-anchor='middle' fill='#1a2b45'>+</text><circle cx='250' cy='55' r='12' fill='#9ed9a8' stroke='#1a2b45'/><text x='250' y='59' font-size='9' text-anchor='middle' fill='#1a2b45'>−</text><circle cx='215' cy='85' r='12' fill='#9ed9a8' stroke='#1a2b45'/><text x='215' y='89' font-size='9' text-anchor='middle' fill='#1a2b45'>−</text><circle cx='250' cy='85' r='12' fill='#cfd8e8' stroke='#1a2b45'/><text x='250' y='89' font-size='9' text-anchor='middle' fill='#1a2b45'>+</text><text x='160' y='160' font-size='9' text-anchor='middle' fill='#1a2b45'>kayma: metalde bağ korunur, iyonikte itme doğar</text></svg>","steps":[{"t":"Metalde kayma","a":"deniz esner","d":"Metalde katmanlar kaydığında elektron denizi her yerde bulunduğundan bağ korunur, kopma olmaz."},{"t":"İyonikte kayma","a":"aynı yük çakışır","d":"İyonik katıda katmanlar kayınca aynı yüklü iyonlar yan yana gelir, itme oluşur ve örgü çatlar (kırılır)."}],"ans":"Metalde kayma sonrası elektron denizi bağı korur (dövülebilir); iyonik katıda kayma aynı yüklü iyonları karşılaştırıp itme yarattığı için kırılgandır."},{"q":"Bir metalin değerlik elektron sayısı arttıkça metalik bağ gücü nasıl değişir?","steps":[{"t":"Daha çok elektron","a":"yoğun deniz","d":"Daha fazla değerlik elektronu, elektron denizini yoğunlaştırır ve geriye daha yüksek yüklü iyonlar kalır."},{"t":"Daha güçlü çekim","a":"erime n. artar","d":"Pozitif iyon yükü ve elektron yoğunluğu arttıkça çekim güçlenir; metal genelde daha sert ve yüksek erime noktalı olur."}],"ans":"Değerlik elektronu arttıkça elektron denizi yoğunlaşır ve iyon yükü artar; metalik bağ güçlenir, erime noktası genelde yükselir."},{"q":"Metaller katı halde de eridiğinde de elektriği iletir; iyonik bileşikler ise sadece eriyik/çözeltide iletir. Bu farkın nedeni nedir?","steps":[{"t":"Metalde her zaman serbest e⁻","a":"katıda da iletir","d":"Metalde serbest elektronlar katı halde de bulunduğundan metal her durumda iletkendir."},{"t":"İyonikte iyon serbest olmalı","a":"katıda sabit","d":"İyonik katıda iyonlar örgüde sabittir, hareket edemez; ancak eriyik/çözeltide serbest kalıp yükü taşır."}],"ans":"Metalde serbest elektronlar katı halde de bulunduğundan her zaman iletir; iyonik bileşikte yük taşıyıcı iyonlar yalnız eriyik/çözeltide serbest kaldığından sadece o hallerde iletir."},{"q":"Civanın oda sıcaklığında sıvı, demirin katı olması metalik bağ gücüyle nasıl ilişkilendirilir?","steps":[{"t":"Bağ gücü farkı","a":"zayıf vs güçlü","d":"Metalik bağ gücü her metalde aynı değildir; iyon yükü ve elektron yoğunluğuna bağlı olarak değişir."},{"t":"Erime noktası","a":"civa düşük","d":"Civada metalik bağ zayıf olduğundan erime noktası çok düşüktür (oda sıcaklığında sıvı); demirde bağ güçlü olduğundan erime noktası yüksektir (katı)."}],"ans":"Civanın metalik bağı zayıf olduğundan erime noktası düşüktür ve oda sıcaklığında sıvıdır; demirin bağı güçlü olduğundan katıdır."}]},"lise":{"kolay":[{"q":"Metalik bağı modern 'elektron denizi' modeliyle tanımlayınız.","fig":"<svg viewBox='0 0 320 170'><circle cx='80' cy='60' r='14' fill='#e0552b' stroke='#1a2b45'/><text x='80' y='65' font-size='9' text-anchor='middle' fill='#fff'>M⁺</text><circle cx='160' cy='60' r='14' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='65' font-size='9' text-anchor='middle' fill='#fff'>M⁺</text><circle cx='240' cy='60' r='14' fill='#e0552b' stroke='#1a2b45'/><text x='240' y='65' font-size='9' text-anchor='middle' fill='#fff'>M⁺</text><circle cx='120' cy='110' r='14' fill='#e0552b' stroke='#1a2b45'/><text x='120' y='115' font-size='9' text-anchor='middle' fill='#fff'>M⁺</text><circle cx='200' cy='110' r='14' fill='#e0552b' stroke='#1a2b45'/><text x='200' y='115' font-size='9' text-anchor='middle' fill='#fff'>M⁺</text><circle cx='115' cy='60' r='3' fill='#2b6be0'/><circle cx='200' cy='60' r='3' fill='#2b6be0'/><circle cx='80' cy='105' r='3' fill='#2b6be0'/><circle cx='160' cy='110' r='3' fill='#2b6be0'/><circle cx='240' cy='105' r='3' fill='#2b6be0'/><text x='160' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>M⁺ örgüsü + serbest e⁻ denizi</text></svg>","steps":[{"t":"Pozitif iyon örgüsü","a":"değerlik e⁻ bırakılır","d":"Metal atomları değerlik elektronlarını bırakarak düzenli bir pozitif iyon örgüsü oluşturur."},{"t":"Delokalize elektronlar","a":"elektron denizi","d":"Bırakılan elektronlar belirli bir atoma ait olmayıp tüm kristale yayılır (delokalize); bu elektron denizi ile pozitif iyonlar arasındaki elektrostatik çekim metalik bağı oluşturur."}],"ans":"Metalik bağ, pozitif metal iyonlarından oluşan örgü ile bunların etrafına delokalize olmuş serbest 'elektron denizi' arasındaki elektrostatik çekimdir."},{"q":"Metallerin elektrik iletkenliğini metalik bağ üzerinden açıklayınız.","steps":[{"t":"Delokalize elektronlar","a":"serbest yük","d":"Metalik bağdaki değerlik elektronları belirli bir atoma bağlı olmadığından serbest yük taşıyıcısı gibi davranır."},{"t":"Yönlü hareket","a":"akım","d":"Potansiyel farkı uygulandığında bu elektronlar yönlü hareket ederek elektrik akımını taşır; iletkenlik sıcaklık arttıkça örgü titreşimi nedeniyle bir miktar azalır."}],"ans":"Metalik bağdaki delokalize elektronlar potansiyel farkı altında yönlü hareket ederek elektriği iletir; bu metallerin iyi iletken olmasını sağlar."},{"q":"Metallerin dövülebilirlik ve tel haline gelebilirlik özelliklerini bağ yapısıyla açıklayınız.","steps":[{"t":"Katman kayması","a":"yönsüz bağ","d":"Metalik bağ belirli bir yöne bağlı değildir; kuvvet altında iyon katmanları birbiri üzerinden kayabilir."},{"t":"Denizin sürekliliği","a":"bağ kopmaz","d":"Elektron denizi her konumda yeniden çekim sağladığından, katmanlar kayarken de bağ korunur; metal kırılmadan biçim değiştirir."}],"ans":"Metalik bağ yönsüz olduğundan iyon katmanları kayabilir ve elektron denizi bağı sürdürdüğünden metaller kırılmadan dövülebilir ve tel haline gelebilir."},{"q":"Metalik bağ gücü hangi etkenlere bağlıdır?","steps":[{"t":"Değerlik elektron sayısı","a":"daha çok = güçlü","d":"Atom başına verilen değerlik elektronu arttıkça elektron denizi yoğunlaşır ve bağ güçlenir."},{"t":"İyon yükü ve yarıçapı","a":"yüksek yük, küçük yarıçap","d":"İyon yükü büyük ve yarıçap küçük oldukça çekim artar; bu da erime noktası ve sertliği yükseltir."}],"ans":"Metalik bağ gücü; değerlik elektron sayısı, iyon yükü ve iyon yarıçapına bağlıdır; daha çok elektron, daha yüksek yük ve daha küçük yarıçap bağı güçlendirir."},{"q":"Metaller neden ısıyı verimli iletir?","steps":[{"t":"Serbest elektronlar","a":"hızlı taşıyıcı","d":"Metalik bağdaki delokalize elektronlar yüksek hareketliliğe sahiptir."},{"t":"Enerji aktarımı","a":"sıcaktan soğuğa","d":"Sıcak bölgede yüksek enerji kazanan elektronlar hızla soğuk bölgeye giderek kinetik enerjiyi aktarır; bu, örgü titreşimi yayılmasından çok daha hızlıdır."}],"ans":"Metallerde delokalize elektronlar yüksek hareketlilikle ısı enerjisini hızla sıcaktan soğuğa taşıdığından metaller verimli ısı iletkenidir."}],"zor":[{"q":"Elektron denizi modeli ile band (bant) teorisi, metalik bağı açıklamada nasıl bütünleşir?","steps":[{"t":"Elektron denizi","a":"niteliksel model","d":"Elektron denizi modeli, delokalize elektronları niteliksel olarak açıklar ama enerji düzeylerini ele almaz."},{"t":"Band teorisi","a":"sürekli enerji bandı","d":"Çok sayıda atom orbitali birleşerek neredeyse sürekli enerji bandları oluşturur; değerlik bandı ile iletkenlik bandının örtüşmesi/yakınlığı metallerin iletkenliğini açıklar."}],"ans":"Elektron denizi modeli delokalizasyonu niteliksel anlatır; band teorisi ise atom orbitallerinin sürekli bandlar oluşturup örtüşmesiyle iletkenliği nicel olarak açıklayarak modeli tamamlar."},{"q":"Metalik bağın yönsüz (yönelimsiz) olması metallerin mekanik davranışını nasıl belirler?","fig":"<svg viewBox='0 0 320 165'><circle cx='70' cy='55' r='13' fill='#e0552b' stroke='#1a2b45'/><circle cx='110' cy='55' r='13' fill='#e0552b' stroke='#1a2b45'/><circle cx='150' cy='55' r='13' fill='#e0552b' stroke='#1a2b45'/><circle cx='90' cy='90' r='13' fill='#e0552b' stroke='#1a2b45'/><circle cx='130' cy='90' r='13' fill='#e0552b' stroke='#1a2b45'/><circle cx='170' cy='90' r='13' fill='#e0552b' stroke='#1a2b45'/><line x1='200' y1='72' x2='250' y2='72' stroke='#2b6be0' stroke-width='2'/><polygon points='250,72 240,67 240,77' fill='#2b6be0'/><text x='225' y='62' font-size='9' text-anchor='middle' fill='#1a2b45'>kayma</text><text x='160' y='140' font-size='9' text-anchor='middle' fill='#1a2b45'>yönsüz bağ: plastik şekil değiştirme</text></svg>","steps":[{"t":"Yönsüz çekim","a":"her yönde eşit","d":"Metalik bağ kovalent bağ gibi belirli yönlere kilitli değildir; çekim her yönde benzer olduğundan iyonlar kolayca yeniden konumlanır."},{"t":"Plastik şekil değiştirme","a":"süneklik","d":"Bu nedenle metaller dış kuvvet altında kırılmadan plastik biçimde uzar (sünek) ve dövülür; düzlemler kayar ama bağ sürer."}],"ans":"Metalik bağın yönsüz olması iyonların yeniden konumlanmasına izin verir; bu yüzden metaller kırılgan değil, sünek ve dövülebilir (plastik şekil değiştiren) malzemelerdir."},{"q":"Geçiş metallerinin (örneğin demir, volfram) ana grup metallerine göre genelde daha yüksek erime noktasına sahip olmasının nedeni nedir?","steps":[{"t":"Daha fazla delokalize e⁻","a":"d elektronları katkı","d":"Geçiş metallerinde değerlik s elektronlarına ek olarak d elektronları da elektron denizine katkı sağlayabilir."},{"t":"Güçlü bağ","a":"yüksek erime n.","d":"Daha çok delokalize elektron ve daha yüksek etkin iyon yükü metalik bağı güçlendirir; bu da erime noktasını yükseltir (örneğin volfram çok yüksek)."}],"ans":"Geçiş metallerinde d elektronlarının da denize katkısı daha çok delokalize elektron ve güçlü çekim sağlar; bu nedenle erime noktaları genelde ana grup metallerinden yüksektir."},{"q":"Alaşımların (örneğin çelik, pirinç) saf metallere göre çoğunlukla daha sert olmasını metalik bağ ve yapı üzerinden açıklayınız.","steps":[{"t":"Farklı boyutlu atomlar","a":"örgü bozulur","d":"Alaşımda farklı boyutlardaki yabancı atomlar düzenli iyon örgüsünü bozar."},{"t":"Kaymanın zorlaşması","a":"sertlik artar","d":"Bozulan örgüde katmanların birbiri üzerinden kayması zorlaşır; metalik bağ korunsa da süneklik azalır, malzeme sertleşir (örneğin çelik demirden serttir)."}],"ans":"Alaşımdaki farklı boyutlu atomlar düzenli örgüyü bozarak katman kaymasını güçleştirir; metalik bağ sürse de kayma zorlaştığından alaşımlar genelde saf metalden serttir."},{"q":"Metaller neden geniş bir dalga boyu aralığında ışığı yansıtarak parlak görünür?","steps":[{"t":"Serbest elektron tepkisi","a":"geniş soğurma","d":"Delokalize elektronlar, sürekli enerji bandı sayesinde geniş bir frekans aralığındaki ışığı kolayca soğurabilir."},{"t":"Yeniden yayma","a":"yansıma","d":"Soğurulan enerji, elektronların aynı frekansta yeniden ışıma yapmasıyla geri yansıtılır; geniş aralıkta yansıma metalik parlaklığı oluşturur."}],"ans":"Metalin delokalize elektronları sürekli enerji bandı sayesinde geniş frekans aralığındaki ışığı soğurup aynı frekansta yeniden yaydığından, metaller geniş aralıkta yansıma yaparak parlak görünür."}]}},"molekulModelleri":{"ilkokul":{"kolay":[{"q":"Molekül modeli ne işe yarar?","steps":[{"t":"Küçük tanecik","a":"görmek zor","d":"Molekül o kadar küçüktür ki gözle göremeyiz."},{"t":"Model","a":"büyük gösterim","d":"Model, atomları renkli toplarla büyütüp gösterir, böylece molekülü inceleyebiliriz."}],"ans":"Molekül modeli, gözle göremediğimiz molekülü renkli toplarla büyütüp gösterir."},{"q":"Top-çubuk modelinde toplar ve çubuklar neyi gösterir?","fig":"<svg viewBox='0 0 320 160'><circle cx='160' cy='80' r='24' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='85' font-size='13' text-anchor='middle' fill='#fff'>O</text><circle cx='105' cy='80' r='15' fill='#cfd8e8' stroke='#1a2b45'/><text x='105' y='85' font-size='10' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='215' cy='80' r='15' fill='#cfd8e8' stroke='#1a2b45'/><text x='215' y='85' font-size='10' text-anchor='middle' fill='#1a2b45'>H</text><line x1='120' y1='80' x2='136' y2='80' stroke='#1a2b45' stroke-width='4'/><line x1='184' y1='80' x2='200' y2='80' stroke='#1a2b45' stroke-width='4'/><text x='160' y='140' font-size='11' text-anchor='middle' fill='#1a2b45'>top-çubuk modeli</text></svg>","steps":[{"t":"Toplar","a":"atomlar","d":"Renkli toplar atomları gösterir, her renk bir çeşit atomdur."},{"t":"Çubuklar","a":"bağlar","d":"Topları birbirine bağlayan çubuklar, atomlar arasındaki bağları gösterir."}],"ans":"Top-çubuk modelinde toplar atomları, çubuklar ise atomlar arasındaki bağları gösterir."},{"q":"Uzay-dolgu modelinde atomlar nasıl görünür?","steps":[{"t":"Şişkin toplar","a":"iç içe","d":"Atomlar şişkin toplar gibi birbirine yapışık çizilir, aralarında boşluk görünmez."},{"t":"Gerçek görünüm","a":"dolgun","d":"Bu model molekülün gerçek dolgun şeklini göstermeye çalışır."}],"ans":"Uzay-dolgu modelinde atomlar birbirine yapışık şişkin toplar gibi görünür."},{"q":"Modelde farklı renkler ne anlama gelir?","steps":[{"t":"Renk","a":"atom çeşidi","d":"Her renk farklı bir çeşit atomu gösterir."},{"t":"Örnek","a":"O kırmızı, H açık","d":"Örneğin oksijen kırmızı, hidrojen açık renkle gösterilir."}],"ans":"Modeldeki farklı renkler farklı çeşit atomları gösterir."},{"q":"Su molekülü modelinde kaç top vardır?","fig":"<svg viewBox='0 0 320 160'><circle cx='160' cy='85' r='24' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='90' font-size='13' text-anchor='middle' fill='#fff'>O</text><circle cx='110' cy='120' r='15' fill='#cfd8e8' stroke='#1a2b45'/><text x='110' y='125' font-size='10' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='210' cy='120' r='15' fill='#cfd8e8' stroke='#1a2b45'/><text x='210' y='125' font-size='10' text-anchor='middle' fill='#1a2b45'>H</text><line x1='144' y1='98' x2='122' y2='112' stroke='#1a2b45' stroke-width='3'/><line x1='176' y1='98' x2='198' y2='112' stroke='#1a2b45' stroke-width='3'/></svg>","steps":[{"t":"Toplar","a":"say","d":"Su molekülünde bir oksijen ve iki hidrojen topu vardır."},{"t":"Toplam","a":"3 top","d":"Bir büyük (O) ve iki küçük (H) top olmak üzere toplam 3 top görünür."}],"ans":"Su molekülü modelinde biri oksijen, ikisi hidrojen olmak üzere toplam 3 top vardır."}],"zor":[{"q":"Top-çubuk ile uzay-dolgu modeli arasındaki fark nedir?","steps":[{"t":"Top-çubuk","a":"bağlar görünür","d":"Top-çubuk modelinde atomlar arası çubuklar (bağlar) açıkça görünür."},{"t":"Uzay-dolgu","a":"dolgun şekil","d":"Uzay-dolgu modelinde atomlar yapışık olduğundan bağlar görünmez ama gerçek şekil iyi anlaşılır."}],"ans":"Top-çubuk modelinde bağlar görünür; uzay-dolgu modelinde atomlar yapışık olup molekülün gerçek dolgun şekli gösterilir."},{"q":"Bir modelde 1 büyük ve 2 küçük top, bağlarla bağlıysa hangi molekül olabilir?","fig":"<svg viewBox='0 0 320 160'><circle cx='160' cy='80' r='24' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='85' font-size='13' text-anchor='middle' fill='#fff'>O</text><circle cx='105' cy='80' r='15' fill='#cfd8e8' stroke='#1a2b45'/><text x='105' y='85' font-size='10' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='215' cy='80' r='15' fill='#cfd8e8' stroke='#1a2b45'/><text x='215' y='85' font-size='10' text-anchor='middle' fill='#1a2b45'>H</text><line x1='120' y1='80' x2='136' y2='80' stroke='#1a2b45' stroke-width='3'/><line x1='184' y1='80' x2='200' y2='80' stroke='#1a2b45' stroke-width='3'/></svg>","steps":[{"t":"Büyük top","a":"oksijen","d":"Büyük kırmızı top genellikle oksijeni gösterir."},{"t":"İki küçük top","a":"iki hidrojen","d":"İki küçük açık top iki hidrojendir; bu yapı su (H₂O) molekülüdür."}],"ans":"Bir oksijen ve iki hidrojenden oluşan bu yapı su (H₂O) molekülüdür."},{"q":"Modeldeki atom sayısını ve çeşidini nasıl okuruz?","steps":[{"t":"Çeşit","a":"renk say","d":"Kaç farklı renk varsa o kadar çeşit atom vardır."},{"t":"Sayı","a":"top say","d":"Her renkten kaç top olduğunu sayarsak o atomdan kaç tane olduğunu buluruz."}],"ans":"Renk çeşidi atom türünü, her renkten top sayısı ise o atomdan kaç tane olduğunu gösterir."},{"q":"CO₂ modelinde ortadaki ve yanlardaki toplar hangi atomlardır?","fig":"<svg viewBox='0 0 320 150'><circle cx='160' cy='75' r='22' fill='#334155' stroke='#1a2b45'/><text x='160' y='80' font-size='12' text-anchor='middle' fill='#fff'>C</text><circle cx='95' cy='75' r='20' fill='#e0552b' stroke='#1a2b45'/><text x='95' y='80' font-size='12' text-anchor='middle' fill='#fff'>O</text><circle cx='225' cy='75' r='20' fill='#e0552b' stroke='#1a2b45'/><text x='225' y='80' font-size='12' text-anchor='middle' fill='#fff'>O</text><line x1='117' y1='75' x2='138' y2='75' stroke='#1a2b45' stroke-width='3'/><line x1='182' y1='75' x2='203' y2='75' stroke='#1a2b45' stroke-width='3'/><text x='160' y='130' font-size='11' text-anchor='middle' fill='#1a2b45'>CO₂</text></svg>","steps":[{"t":"Orta top","a":"karbon","d":"Ortadaki koyu top karbon (C) atomudur."},{"t":"Yan toplar","a":"iki oksijen","d":"Yanlardaki iki kırmızı top oksijen (O) atomudur."}],"ans":"CO₂ modelinde ortadaki top karbon, yanlardaki iki top ise oksijen atomlarıdır."},{"q":"Aynı molekül neden hem top-çubuk hem uzay-dolgu olarak çizilebilir?","steps":[{"t":"Aynı molekül","a":"iki bakış","d":"Aynı molekül farklı amaçlarla farklı modellerle gösterilebilir."},{"t":"Amaç","a":"bağ ya da şekil","d":"Bağları göstermek istiyorsak top-çubuk, gerçek dolgun şekli göstermek istiyorsak uzay-dolgu seçilir."}],"ans":"Aynı molekül; bağları vurgulamak için top-çubuk, gerçek şeklini vurgulamak için uzay-dolgu modeliyle çizilebilir."}]},"ortaokul":{"kolay":[{"q":"Top-çubuk modelinin sağladığı temel bilgi nedir?","steps":[{"t":"Atom ve bağ","a":"ikisi de görünür","d":"Top-çubuk modelinde hem atomlar (toplar) hem de aralarındaki bağlar (çubuklar) açıkça görünür."},{"t":"Bağlanış","a":"hangi atom hangisine","d":"Hangi atomun hangisine bağlı olduğunu ve molekülün iskeletini gösterir."}],"ans":"Top-çubuk modeli, hangi atomun hangisine bağlandığını ve molekülün bağ yapısını gösterir."},{"q":"Uzay-dolgu (uzaysal) modelin avantajı nedir?","steps":[{"t":"Gerçek boyut","a":"orantılı","d":"Atomlar gerçek büyüklük oranlarına yakın, birbirine yapışık çizilir."},{"t":"Gerçek şekil","a":"hacim","d":"Molekülün kapladığı gerçek hacmi ve genel şeklini en iyi bu model gösterir."}],"ans":"Uzay-dolgu modeli, atomların gerçek boyut oranlarını ve molekülün kapladığı hacmi (gerçek şeklini) gösterir."},{"q":"Bir molekül modelinde atom türünü nasıl ayırt ederiz?","fig":"<svg viewBox='0 0 320 150'><circle cx='90' cy='75' r='20' fill='#e0552b' stroke='#1a2b45'/><text x='90' y='80' font-size='11' text-anchor='middle' fill='#fff'>O</text><circle cx='160' cy='75' r='16' fill='#cfd8e8' stroke='#1a2b45'/><text x='160' y='80' font-size='10' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='230' cy='75' r='18' fill='#334155' stroke='#1a2b45'/><text x='230' y='80' font-size='11' text-anchor='middle' fill='#fff'>C</text><text x='160' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>renk = atom çeşidi</text></svg>","steps":[{"t":"Renk kodu","a":"her renk bir atom","d":"Modellerde her atom türü belirli bir renkle gösterilir (O kırmızı, H açık, C koyu)."},{"t":"Boyut","a":"atom büyüklüğü","d":"Topun büyüklüğü de atomun göreli boyutu hakkında ipucu verir."}],"ans":"Atom türünü topun rengi (ve boyutu) ile ayırt ederiz; her renk belirli bir atom çeşidini gösterir."},{"q":"CH₄ modelinde kaç atom ve kaç çeşit atom vardır?","fig":"<svg viewBox='0 0 320 170'><circle cx='160' cy='85' r='22' fill='#334155' stroke='#1a2b45'/><text x='160' y='90' font-size='12' text-anchor='middle' fill='#fff'>C</text><circle cx='160' cy='35' r='13' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='110' cy='115' r='13' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='210' cy='115' r='13' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='160' cy='135' r='13' fill='#cfd8e8' stroke='#1a2b45'/><line x1='160' y1='63' x2='160' y2='48' stroke='#1a2b45' stroke-width='2'/><line x1='144' y1='98' x2='120' y2='108' stroke='#1a2b45' stroke-width='2'/><line x1='176' y1='98' x2='200' y2='108' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='107' x2='160' y2='122' stroke='#1a2b45' stroke-width='2'/><text x='160' y='160' font-size='10' text-anchor='middle' fill='#1a2b45'>CH₄</text></svg>","steps":[{"t":"Atom sayısı","a":"5 atom","d":"Bir karbon ve dört hidrojen olmak üzere toplam 5 atom vardır."},{"t":"Çeşit","a":"2 çeşit","d":"Karbon ve hidrojen olmak üzere 2 çeşit atom bulunur."}],"ans":"CH₄ modelinde 1 karbon + 4 hidrojen = 5 atom ve 2 çeşit atom (C ve H) vardır."},{"q":"Formülde alt indis rakamı modelde neyi gösterir?","steps":[{"t":"Alt indis","a":"atom sayısı","d":"Formüldeki küçük rakam (örneğin H₂O'daki 2) o atomdan kaç tane olduğunu söyler."},{"t":"Modelde karşılığı","a":"top sayısı","d":"Bu rakam, modelde o renkten kaç top çizileceğini belirler."}],"ans":"Formüldeki alt indis, o atomdan kaç tane olduğunu yani modelde o renkten kaç top çizileceğini gösterir."}],"zor":[{"q":"Top-çubuk ve uzay-dolgu modellerinin birbirine göre eksik yönü nedir?","steps":[{"t":"Top-çubuk eksiği","a":"boyut yanlış","d":"Top-çubuk modeli bağları gösterir ama atomları gerçeğinden küçük ve aralıklı çizdiğinden gerçek hacmi yanlış verir."},{"t":"Uzay-dolgu eksiği","a":"bağ gizli","d":"Uzay-dolgu modeli gerçek şekli verir ama atomlar yapışık olduğundan bağları ve iç yapıyı göstermez."}],"ans":"Top-çubuk gerçek atom boyutunu/hacmini, uzay-dolgu ise bağ yapısını göstermez; her model bir yönü vurgular."},{"q":"Bir modelde merkez atoma 4 farklı top bağlıysa bu hakkında ne söyleriz?","fig":"<svg viewBox='0 0 320 170'><circle cx='160' cy='85' r='22' fill='#334155' stroke='#1a2b45'/><text x='160' y='90' font-size='12' text-anchor='middle' fill='#fff'>C</text><circle cx='160' cy='35' r='12' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='110' cy='120' r='12' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='210' cy='120' r='12' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='160' cy='140' r='12' fill='#cfd8e8' stroke='#1a2b45'/><line x1='160' y1='63' x2='160' y2='47' stroke='#1a2b45' stroke-width='2'/><line x1='145' y1='99' x2='119' y2='112' stroke='#1a2b45' stroke-width='2'/><line x1='175' y1='99' x2='201' y2='112' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='107' x2='160' y2='128' stroke='#1a2b45' stroke-width='2'/></svg>","steps":[{"t":"Bağ sayısı","a":"4 bağ","d":"Merkez atomun dört topa bağlı olması, dört bağ kurduğunu gösterir."},{"t":"Merkez atom","a":"karbon olabilir","d":"Dört bağ kuran tipik merkez atom karbondur; bu yapı CH₄'e benzer dörtyüzlü bir düzendir."}],"ans":"Merkez atoma 4 top bağlıysa atom 4 bağ kurmuştur; bu çoğunlukla karbondur ve dörtyüzlü bir yapı oluşturur."},{"q":"C₂H₆ formülünden modeli oluştururken kaç top ve kaç çubuk çizilir?","steps":[{"t":"Toplar","a":"8 top","d":"2 karbon ve 6 hidrojen olmak üzere toplam 8 top çizilir."},{"t":"Çubuklar","a":"7 bağ","d":"İki karbon arasında 1 bağ, her karbona 3'er hidrojen bağı: 1 + 3 + 3 = 7 çubuk çizilir."}],"ans":"C₂H₆ modelinde 8 top (2 C + 6 H) ve 7 çubuk (1 C–C + 6 C–H bağı) çizilir."},{"q":"Çift bağ top-çubuk modelinde nasıl gösterilir?","fig":"<svg viewBox='0 0 320 150'><circle cx='115' cy='75' r='22' fill='#e0552b' stroke='#1a2b45'/><text x='115' y='80' font-size='12' text-anchor='middle' fill='#fff'>O</text><circle cx='205' cy='75' r='22' fill='#e0552b' stroke='#1a2b45'/><text x='205' y='80' font-size='12' text-anchor='middle' fill='#fff'>O</text><line x1='137' y1='68' x2='183' y2='68' stroke='#1a2b45' stroke-width='3'/><line x1='137' y1='82' x2='183' y2='82' stroke='#1a2b45' stroke-width='3'/><text x='160' y='130' font-size='11' text-anchor='middle' fill='#1a2b45'>O=O çift bağ</text></svg>","steps":[{"t":"Tek bağ","a":"bir çubuk","d":"Tek bağ atomlar arasında tek bir çubukla gösterilir."},{"t":"Çift bağ","a":"iki çubuk","d":"Çift bağ ise iki paralel çubukla gösterilir (örneğin O=O)."}],"ans":"Top-çubuk modelinde çift bağ, iki atom arasına çizilen iki paralel çubukla gösterilir."},{"q":"Aynı atom sayısına sahip iki model neden farklı şekilde görünebilir?","steps":[{"t":"Bağlanış farkı","a":"farklı dizilim","d":"Atomlar aynı sayıda olsa bile birbirine farklı sırayla bağlanabilir (izomeri)."},{"t":"Şekil farkı","a":"farklı geometri","d":"Farklı bağlanış farklı bir uzaysal şekil oluşturur, bu yüzden modeller farklı görünür."}],"ans":"Atom sayıları aynı olsa da atomların farklı bağlanış (dizilim) biçimi farklı şekiller oluşturur; buna izomeri denir."}]},"lise":{"kolay":[{"q":"Molekül modellerinin (top-çubuk, uzay-dolgu) bilimsel amacı nedir?","steps":[{"t":"Soyutu görselleştirme","a":"3 boyut","d":"Modeller, soyut bağ ve geometriyi üç boyutlu somut bir biçimde temsil ederek anlaşılır kılar."},{"t":"Tahmin gücü","a":"özellik öngörüsü","d":"Geometriyi göstererek molekülün polarite, tepkime davranışı gibi özelliklerinin yorumlanmasını sağlar."}],"ans":"Molekül modelleri soyut bağ ve geometriyi üç boyutlu temsil eder; bu da molekülün özelliklerinin yorumlanmasını sağlar."},{"q":"Top-çubuk modeli ile uzay-dolgu modelini hangi durumda tercih ederiz?","steps":[{"t":"Top-çubuk","a":"bağ ve açı","d":"Bağ türleri, bağ açıları ve molekül iskeletini incelemek için top-çubuk modeli tercih edilir."},{"t":"Uzay-dolgu","a":"hacim ve sterik","d":"Atomların gerçek boyut oranı, kapladığı hacim ve sterik (yer kaplama) etkileri için uzay-dolgu modeli kullanılır."}],"ans":"Bağ/açı incelemesinde top-çubuk; gerçek boyut, hacim ve sterik etki incelemesinde uzay-dolgu modeli tercih edilir."},{"q":"Bir molekül modelinden molekül formülü nasıl çıkarılır?","fig":"<svg viewBox='0 0 320 170'><circle cx='160' cy='85' r='20' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='90' font-size='12' text-anchor='middle' fill='#fff'>N</text><circle cx='110' cy='125' r='12' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='160' cy='140' r='12' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='210' cy='125' r='12' fill='#cfd8e8' stroke='#1a2b45'/><line x1='146' y1='99' x2='120' y2='117' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='105' x2='160' y2='128' stroke='#1a2b45' stroke-width='2'/><line x1='174' y1='99' x2='200' y2='117' stroke='#1a2b45' stroke-width='2'/><text x='160' y='162' font-size='10' text-anchor='middle' fill='#1a2b45'>NH₃</text></svg>","steps":[{"t":"Atomları say","a":"tür ve sayı","d":"Her renkten kaç top olduğunu sayarak her atom türünden kaç tane olduğunu belirleriz."},{"t":"Formülü yaz","a":"indis ekle","d":"Atom sayısını alt indis olarak yazarız; örnekte 1 N ve 3 H → NH₃."}],"ans":"Modeldeki her atom türünden top sayısı alt indis yapılarak formül yazılır; örnekteki yapı NH₃'tür."},{"q":"Bağ açısı bilgisini hangi model daha iyi yansıtır ve neden?","steps":[{"t":"Top-çubuk","a":"açı net","d":"Top-çubuk modelinde atomlar arası çubuklar net olduğundan bağ açıları (örneğin 104,5°, 109,5°) doğrudan ölçülebilir görünür."},{"t":"Uzay-dolgu kısıtı","a":"açı gizli","d":"Uzay-dolgu modelinde atomlar yapışık olduğundan bağ açıları net görünmez."}],"ans":"Bağ açısını top-çubuk modeli daha iyi yansıtır; çünkü bağlar çubukla net gösterildiğinden açılar doğrudan görünür."},{"q":"Modellerde kullanılan standart atom renk kodları neye yarar?","steps":[{"t":"Ortak dil","a":"evrensel kod","d":"Standart renkler (O kırmızı, H açık, C koyu, N mavi) tüm dünyada ortak bir görsel dil oluşturur."},{"t":"Hızlı tanıma","a":"yanlışı önler","d":"Bu sayede farklı kaynaklardaki modeller karışmadan, atom türleri hızlıca ve doğru tanınır."}],"ans":"Standart atom renkleri evrensel ortak bir görsel dil sağlar; böylece modellerdeki atom türleri her yerde aynı şekilde, hızlı ve doğru tanınır."}],"zor":[{"q":"H₂O modelinde uzay-dolgu ve top-çubuk gösterimi molekülün polaritesi hakkında ne söyler?","fig":"<svg viewBox='0 0 320 175'><circle cx='160' cy='75' r='24' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='80' font-size='12' text-anchor='middle' fill='#fff'>O</text><circle cx='112' cy='125' r='15' fill='#cfd8e8' stroke='#1a2b45'/><text x='112' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='208' cy='125' r='15' fill='#cfd8e8' stroke='#1a2b45'/><text x='208' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>H</text><line x1='143' y1='92' x2='123' y2='113' stroke='#1a2b45' stroke-width='2'/><line x1='177' y1='92' x2='197' y2='113' stroke='#1a2b45' stroke-width='2'/><text x='160' y='40' font-size='10' text-anchor='middle' fill='#1a2b45'>δ⁻</text><text x='160' y='165' font-size='9' text-anchor='middle' fill='#1a2b45'>açısal yapı</text></svg>","steps":[{"t":"Açısal geometri","a":"~104,5°","d":"Model H₂O'nun açısal (doğrusal değil) olduğunu gösterir; oksijende iki ortaklanmamış çift bağları aşağı iter."},{"t":"Net dipol","a":"polardır","d":"Açısal yapıda polar O–H bağ dipolleri birbirini götürmez; bu da molekülün net dipole sahip, yani polar olduğunu gösterir."}],"ans":"Model H₂O'nun açısal geometrisini gösterir; bu yapıda polar bağ dipolleri toplandığından molekül polardır."},{"q":"CO₂ ve H₂O modelleri aynı atom sayısına yakınken neden farklı geometriler gösterir?","steps":[{"t":"Merkez atom çiftleri","a":"bağ ve yalnız çift","d":"CO₂'de karbonun ortaklanmamış çifti yokken, H₂O'da oksijende iki ortaklanmamış çift vardır."},{"t":"VSEPR etkisi","a":"doğrusal vs açısal","d":"Ortaklanmamış çiftler bağları iterek H₂O'yu açısal yapar; CO₂'de itme olmadığından geometri doğrusaldır."}],"ans":"CO₂ merkez atomunda yalnız çift olmadığından doğrusal; H₂O'da oksijenin iki yalnız çifti bağları ittiğinden açısaldır (VSEPR)."},{"q":"Bir top-çubuk modelinde üç paralel çubuk gördüğümüzde bu ne anlama gelir, örnekle açıklayınız?","fig":"<svg viewBox='0 0 320 150'><circle cx='115' cy='75' r='22' fill='#5b6b85' stroke='#1a2b45'/><text x='115' y='80' font-size='12' text-anchor='middle' fill='#fff'>N</text><circle cx='205' cy='75' r='22' fill='#5b6b85' stroke='#1a2b45'/><text x='205' y='80' font-size='12' text-anchor='middle' fill='#fff'>N</text><line x1='137' y1='65' x2='183' y2='65' stroke='#1a2b45' stroke-width='3'/><line x1='137' y1='75' x2='183' y2='75' stroke='#1a2b45' stroke-width='3'/><line x1='137' y1='85' x2='183' y2='85' stroke='#1a2b45' stroke-width='3'/><text x='160' y='130' font-size='11' text-anchor='middle' fill='#1a2b45'>N≡N üçlü bağ</text></svg>","steps":[{"t":"Çubuk sayısı","a":"üçlü bağ","d":"İki atom arasındaki üç paralel çubuk, aralarında üçlü bağ (3 ortak elektron çifti) olduğunu gösterir."},{"t":"Örnek","a":"N₂","d":"Azot molekülü N₂'de iki azot üçlü bağ (N≡N) ile bağlıdır; bu bağ çok güçlü ve kararlıdır."}],"ans":"Üç paralel çubuk üçlü bağı (3 ortak elektron çifti) gösterir; örneği N₂'deki çok kararlı N≡N bağıdır."},{"q":"Bir molekül modeli ile gerçek molekül arasındaki sınırlamalar (modelin eksikleri) nelerdir?","steps":[{"t":"Statik gösterim","a":"hareket yok","d":"Model molekülü sabit gösterir; oysa gerçek moleküllerde bağlar titreşir, döner ve elektronlar sürekli hareket eder."},{"t":"Elektron bulutu","a":"belirsizlik","d":"Toplar kesin sınırlı çizilir; oysa gerçekte elektronlar olasılıksal bir bulut halindedir, kesin yüzey yoktur."}],"ans":"Modeller molekülü statik ve keskin sınırlı gösterir; oysa gerçekte bağlar titreşir, döner ve elektronlar olasılıksal bir bulut oluşturur."},{"q":"İzomerlerin modelleri aynı formüle sahipken neden farklı çizilir, örnekle açıklayınız?","steps":[{"t":"Aynı formül","a":"C₂H₆O","d":"Etanol ve dimetil eter aynı kapalı formüle (C₂H₆O) sahiptir; atom sayıları birebir aynıdır."},{"t":"Farklı bağlanış","a":"farklı iskelet","d":"Etanolde C–C–O–H, dimetil eterde C–O–C dizilimi vardır; bu farklı bağlanış modelleri farklı çizdirir ve özellikleri değiştirir."}],"ans":"İzomerler aynı formüle sahip olsa da atomların bağlanış sırası (iskelet) farklıdır; örneğin C₂H₆O için etanol ve dimetil eter farklı çizilir."}]}},"nedenBag":{"ilkokul":{"kolay":[{"q":"Atomlar neden başka atomlarla birleşmek ister?","steps":[{"t":"Yalnızken","a":"kararsız","d":"Çoğu atom tek başına rahat ve sağlam değildir."},{"t":"Birleşince","a":"daha sağlam","d":"Başka atomlarla birleşince daha sağlam, kararlı bir yapıya kavuşur."}],"ans":"Atomlar daha sağlam ve kararlı bir yapıya kavuşmak için başka atomlarla birleşmek ister."},{"q":"Bir atomun en dışındaki elektronlara ne ad verilir?","steps":[{"t":"Dış katman","a":"en dış halka","d":"Atomun en dış katmanındaki elektronlar bağ kurmada en önemlisidir."},{"t":"İsim","a":"değerlik elektronu","d":"Bu en dıştaki elektronlara değerlik elektronu denir."}],"ans":"Atomun en dışındaki elektronlara değerlik elektronu denir."},{"q":"Soy gazlar neden başka atomlarla pek birleşmez?","steps":[{"t":"Dış katman","a":"dolu","d":"Soy gazların en dış katmanı zaten elektronla doludur."},{"t":"İhtiyaç yok","a":"rahat","d":"Dolu olduğu için kararlıdırlar ve birleşmeye ihtiyaç duymazlar."}],"ans":"Soy gazların dış katmanı dolu ve kararlı olduğundan başka atomlarla pek birleşmezler."},{"q":"Atomlar bağ kurunca enerji bakımından ne olur?","steps":[{"t":"Bağ öncesi","a":"yüksek enerji","d":"Ayrı duran kararsız atomların enerjisi yüksektir."},{"t":"Bağ sonrası","a":"düşük enerji","d":"Bağ kurunca enerjileri düşer; düşük enerji daha kararlı, daha rahat demektir."}],"ans":"Atomlar bağ kurunca enerjileri düşer; düşük enerji daha kararlı ve sağlam bir yapı demektir."},{"q":"İki atomun dış elektronlarını tamamlaması neden iyidir?","fig":"<svg viewBox='0 0 320 165'><circle cx='160' cy='85' r='12' fill='#e0552b' stroke='#1a2b45'/><circle cx='160' cy='85' r='36' fill='none' stroke='#1a2b45'/><circle cx='160' cy='49' r='5' fill='#2b6be0'/><circle cx='196' cy='85' r='5' fill='#2b6be0'/><circle cx='160' cy='121' r='5' fill='#2b6be0'/><circle cx='124' cy='85' r='5' fill='#2b6be0'/><text x='160' y='155' font-size='10' text-anchor='middle' fill='#1a2b45'>dolu dış katman</text></svg>","steps":[{"t":"Tam dolu","a":"kararlı","d":"Dış katman tamamlanınca atom soy gazlar gibi kararlı olur."},{"t":"Sonuç","a":"sağlam yapı","d":"Bu sağlam yapı sayesinde atom kolayca dağılmaz, dayanıklı hale gelir."}],"ans":"Dış elektronlar tamamlanınca atom soy gazlar gibi kararlı ve sağlam olur, bu yüzden iyidir."}],"zor":[{"q":"Bir atom dış katmanını neden 'doldurmak' ister?","steps":[{"t":"Yarım dolu","a":"kararsız","d":"Yarım dolu bir dış katman atomu kararsız ve enerjisi yüksek yapar."},{"t":"Doldurunca","a":"soy gaz düzeni","d":"Katmanı doldurunca en yakın soy gaz gibi kararlı düzene ulaşır ve enerjisi düşer."}],"ans":"Atom, soy gaz gibi kararlı düzene ulaşıp enerjisini düşürmek için dış katmanını doldurmak ister."},{"q":"Hidrojen, helyuma benzemek için kaç elektrona ihtiyaç duyar?","steps":[{"t":"Hidrojen","a":"1 elektron","d":"Hidrojenin tek bir elektronu vardır."},{"t":"Hedef","a":"2 elektron","d":"İlk katman 2 elektronla dolar (dublet); helyum gibi olmak için 1 elektron daha ister."}],"ans":"Hidrojen, ilk katmanı 2'ye (helyum gibi) tamamlamak için 1 elektron daha ister."},{"q":"Oktet ne demektir, basitçe açıklayın?","steps":[{"t":"Sekiz elektron","a":"dolu son katman","d":"Birçok atomun son katmanı 8 elektronla dolar."},{"t":"Oktet","a":"sekizli düzen","d":"Son katmanda 8 elektron bulunan bu kararlı düzene oktet denir."}],"ans":"Oktet, bir atomun son katmanında 8 elektron bulunan kararlı düzenidir."},{"q":"Neden bir atom 7 değerlik elektronu varsa 1 elektron almak ister?","steps":[{"t":"Eksik bir","a":"7 elektron","d":"Son katmanında 7 elektronu olan atomun 8'e (oktete) ulaşmak için sadece 1 elektrona ihtiyacı vardır."},{"t":"Kolay yol","a":"1 al","d":"7 verip boşaltmak yerine 1 almak çok daha kolaydır, bu yüzden 1 elektron alır."}],"ans":"7 değerlik elektronu olan atom, 8'e (oktete) ulaşmanın en kolay yolu olduğu için 1 elektron almak ister."},{"q":"Atomların bağ kurması neden 'daha az enerjili' bir duruma geçiştir?","fig":"<svg viewBox='0 0 320 165'><line x1='40' y1='130' x2='280' y2='130' stroke='#1a2b45'/><line x1='40' y1='130' x2='40' y2='30' stroke='#1a2b45'/><circle cx='70' cy='55' r='8' fill='#e0552b'/><text x='70' y='45' font-size='9' text-anchor='middle' fill='#1a2b45'>ayrı</text><circle cx='240' cy='110' r='8' fill='#2b6be0'/><text x='240' y='100' font-size='9' text-anchor='middle' fill='#1a2b45'>bağlı</text><text x='25' y='35' font-size='9' fill='#1a2b45'>E</text></svg>","steps":[{"t":"Ayrı atomlar","a":"yüksek enerji","d":"Birbirinden ayrı, kararsız atomların enerjisi yüksektir."},{"t":"Bağlı yapı","a":"düşük enerji","d":"Bağ oluşunca sistem enerji bırakır ve daha düşük enerjili, daha kararlı bir duruma geçer."}],"ans":"Bağ oluşurken sistem enerji bıraktığından, bağlı yapı ayrı atomlardan daha düşük enerjili ve daha kararlıdır."}]},"ortaokul":{"kolay":[{"q":"Atomların bağ kurmasının temel nedeni nedir?","steps":[{"t":"Kararsızlık","a":"dış katman eksik","d":"Çoğu atomun değerlik (son) katmanı tam dolu olmadığından kararsızdır."},{"t":"Kararlılık arayışı","a":"soy gaz düzeni","d":"Atom, en yakın soy gazın dolu elektron düzenine ulaşıp kararlı olmak için bağ kurar."}],"ans":"Atomlar, en yakın soy gazın kararlı elektron düzenine ulaşıp daha kararlı hale gelmek için bağ kurar."},{"q":"Oktet kuralı neyi ifade eder?","steps":[{"t":"Sekiz elektron","a":"son katman 8","d":"Atomlar son katmanlarında 8 elektron bulundurmaya eğilimlidir."},{"t":"Bağ ile ulaşma","a":"al-ver-paylaş","d":"Bu sekizli düzene elektron alarak, vererek veya paylaşarak ulaşırlar."}],"ans":"Oktet kuralı, atomların son katmanlarını 8 elektrona tamamlama eğilimini ifade eder."},{"q":"Hidrojen ve helyum için oktet yerine hangi kural geçerlidir?","steps":[{"t":"İlk katman","a":"2 elektron","d":"En küçük atomların yalnızca ilk katmanı vardır ve bu katman 2 elektronla dolar."},{"t":"Dublet","a":"ikili düzen","d":"Bu yüzden hidrojen ve helyum için 2 elektronlu (dublet) kural geçerlidir."}],"ans":"Hidrojen ve helyum için oktet yerine, ilk katmanın 2 elektronla dolduğu dublet kuralı geçerlidir."},{"q":"Değerlik elektronu bir atomun davranışını nasıl belirler?","fig":"<svg viewBox='0 0 320 165'><circle cx='160' cy='85' r='12' fill='#e0552b' stroke='#1a2b45'/><circle cx='160' cy='85' r='24' fill='none' stroke='#1a2b45'/><circle cx='160' cy='85' r='42' fill='none' stroke='#1a2b45'/><circle cx='160' cy='43' r='4' fill='#2b6be0'/><circle cx='196' cy='62' r='4' fill='#2b6be0'/><circle cx='124' cy='62' r='4' fill='#2b6be0'/><text x='160' y='158' font-size='10' text-anchor='middle' fill='#1a2b45'>en dış katman = değerlik</text></svg>","steps":[{"t":"Son katman","a":"değerlik sayısı","d":"En dış katmandaki elektron sayısı atomun kimyasal davranışını belirler."},{"t":"Bağ eğilimi","a":"al mı ver mi","d":"Değerlik elektronu az olan vermeye, çok olan (oktete yakın) almaya eğilimlidir."}],"ans":"Değerlik (son katman) elektron sayısı, atomun elektron alıp vereceğini ve nasıl bağ kuracağını belirler."},{"q":"Soy gazların kararlı olmasının nedeni nedir?","steps":[{"t":"Dolu katman","a":"oktet/dublet","d":"Soy gazların son katmanı tam doludur (helyumda 2, diğerlerinde 8)."},{"t":"Düşük enerji","a":"kararlı","d":"Dolu katman en düşük enerjili, en kararlı düzendir; bu yüzden bağ kurmaya gerek duymazlar."}],"ans":"Soy gazların son katmanı dolu (oktet/dublet) ve en düşük enerjili olduğundan kararlıdır."}],"zor":[{"q":"Bir atomun kaç ve nasıl bağ kuracağını ne belirler?","steps":[{"t":"Değerlik elektronu","a":"son katman sayısı","d":"Atomun son katmanındaki elektron sayısı belirleyicidir."},{"t":"Oktete uzaklık","a":"al/ver/paylaş","d":"Atom, oktete (veya dublete) ulaşmak için kaç elektron eksik/fazlaysa o kadar elektron alır, verir veya paylaşır."}],"ans":"Atomun değerlik elektron sayısı ve oktete olan uzaklığı, kaç elektron alıp vereceğini ya da paylaşacağını belirler."},{"q":"Neden elektron alıp vermek ya da paylaşmak atomu daha kararlı yapar?","steps":[{"t":"Hedef düzen","a":"soy gaz dizilimi","d":"Elektron alış-verişi veya paylaşımı, atomu en yakın soy gazın dolu elektron düzenine ulaştırır."},{"t":"Enerji düşüşü","a":"daha kararlı","d":"Bu dolu düzen daha düşük enerjili olduğundan atom (ya da molekül) daha kararlı hale gelir."}],"ans":"Çünkü elektron alıp verme/paylaşma atomu soy gazın dolu, düşük enerjili düzenine ulaştırır; bu da daha kararlı yapı demektir."},{"q":"Mg atomu (2 değerlik elektronu) neden 2 elektron verme eğilimindedir?","fig":"<svg viewBox='0 0 320 165'><circle cx='160' cy='85' r='12' fill='#cfd8e8' stroke='#1a2b45'/><text x='160' y='89' font-size='9' text-anchor='middle' fill='#1a2b45'>Mg</text><circle cx='160' cy='85' r='40' fill='none' stroke='#1a2b45'/><circle cx='128' cy='65' r='5' fill='#2b6be0'/><circle cx='192' cy='105' r='5' fill='#2b6be0'/><text x='160' y='155' font-size='10' text-anchor='middle' fill='#1a2b45'>2 değerlik e⁻ verilir</text></svg>","steps":[{"t":"Az değerlik","a":"2 elektron","d":"Magnezyumun son katmanında yalnızca 2 elektronu vardır."},{"t":"Kolay yol","a":"2 ver","d":"6 elektron alıp oktete ulaşmak çok zordur; bu 2 elektronu vermek çok daha kolaydır ve bir alttaki dolu katmanı açığa çıkarır."}],"ans":"Mg, 6 elektron almak yerine 2 değerlik elektronunu vermek daha kolay olduğundan 2 elektron verip Mg²⁺ olarak kararlı düzene ulaşır."},{"q":"Oktet kuralının her atom için geçerli olmadığını bir örnekle açıklayın.","steps":[{"t":"İstisna H","a":"dublet","d":"Hidrojen ve helyum oktet değil, dublet (2 elektron) düzenine ulaşır."},{"t":"Genelleme","a":"kural değil eğilim","d":"Oktet katı bir kanun değil güçlü bir eğilimdir; bazı atomlar (örneğin B, küçük atomlar) 8'e ulaşmadan da kararlı bileşik yapabilir."}],"ans":"Oktet bir eğilimdir, mutlak kanun değil; örneğin hidrojen 2 elektronla (dublet) kararlı olur, dolayısıyla her atom 8'e ulaşmaz."},{"q":"Bağ oluşumu ile enerji arasındaki ilişkiyi açıklayın.","fig":"<svg viewBox='0 0 320 165'><line x1='45' y1='135' x2='285' y2='135' stroke='#1a2b45'/><line x1='45' y1='135' x2='45' y2='30' stroke='#1a2b45'/><path d='M60 50 Q150 50 175 110 Q185 130 220 122' fill='none' stroke='#2b6be0' stroke-width='2'/><circle cx='185' cy='123' r='4' fill='#e0552b'/><text x='185' y='150' font-size='9' text-anchor='middle' fill='#1a2b45'>en kararlı uzaklık</text><text x='30' y='35' font-size='9' fill='#1a2b45'>E</text></svg>","steps":[{"t":"Yaklaşma","a":"enerji düşer","d":"İki atom uygun uzaklığa yaklaşırken çekim baskın olur ve sistemin enerjisi düşer."},{"t":"Bağ enerjisi","a":"en düşük nokta","d":"Belirli bir uzaklıkta enerji en düşük değere iner; bu kararlı bağ uzaklığıdır. Bağı koparmak için bu kadar enerji geri verilmelidir."}],"ans":"İki atom yaklaşırken enerji düşer ve belirli bir uzaklıkta en düşük (en kararlı) değere iner; bağ bu enerji düşüşü sayesinde oluşur."}]},"lise":{"kolay":[{"q":"Atomların bağ kurmasının temelindeki itici güç nedir?","steps":[{"t":"Kararlılık eğilimi","a":"minimum enerji","d":"Sistemler en düşük potansiyel enerjili, en kararlı duruma yönelir; ayrı atomlar bu duruma göre kararsızdır."},{"t":"Soy gaz düzeni","a":"dolu değerlik","d":"Atomlar, değerlik katmanlarını soy gaz düzenine (oktet/dublet) tamamlayarak bu kararlı, düşük enerjili duruma ulaşır."}],"ans":"Atomları bağ kurmaya iten temel güç, değerlik katmanını soy gaz düzenine tamamlayarak daha düşük enerjili, kararlı duruma ulaşma eğilimidir."},{"q":"Oktet kuralı nedir ve neden geçerlidir?","steps":[{"t":"Tanım","a":"son katman 8","d":"Atomlar değerlik katmanlarını 8 elektrona (s²p⁶ dolu düzen) tamamlama eğilimindedir."},{"t":"Gerekçe","a":"soy gaz kararlılığı","d":"Dolu s ve p alt kabukları en düşük enerjili soy gaz dizilimine karşılık geldiğinden bu düzen kararlıdır."}],"ans":"Oktet kuralı, atomların değerlik katmanını 8 elektrona tamamlama eğilimidir; çünkü bu dolu düzen soy gaz kararlılığına (en düşük enerjiye) karşılık gelir."},{"q":"Değerlik elektronu kavramı ile periyodik grup arasındaki ilişki nedir?","steps":[{"t":"Grup numarası","a":"değerlik sayısı","d":"Baş grup elementlerinde grup numarası, atomun değerlik elektron sayısını verir (örneğin 1A → 1, 7A → 7)."},{"t":"Davranış öngörüsü","a":"bağ eğilimi","d":"Değerlik sayısı bilinince atomun oktete ulaşmak için elektron alıp vereceği ya da paylaşacağı önceden tahmin edilebilir."}],"ans":"Baş gruplarda grup numarası değerlik elektron sayısını verir; bu da atomun oktete ulaşmak için nasıl bağ kuracağını öngörmeyi sağlar."},{"q":"Bağ enerjisi neyi ifade eder ve neden bağ oluşumu enerji açığa çıkarır?","fig":"<svg viewBox='0 0 320 170'><line x1='45' y1='140' x2='290' y2='140' stroke='#1a2b45'/><line x1='45' y1='140' x2='45' y2='30' stroke='#1a2b45'/><path d='M65 45 Q140 45 165 115 Q175 135 235 128' fill='none' stroke='#2b6be0' stroke-width='2'/><circle cx='175' cy='128' r='4' fill='#e0552b'/><text x='175' y='158' font-size='9' text-anchor='middle' fill='#1a2b45'>r₀ kararlı uzaklık</text><text x='30' y='35' font-size='9' fill='#1a2b45'>E</text></svg>","steps":[{"t":"Potansiyel kuyusu","a":"minimum enerji","d":"Atomlar yaklaşırken potansiyel enerji bir minimuma (kuyu dibi) iner; bu, kararlı bağ uzaklığıdır (r₀)."},{"t":"Bağ enerjisi","a":"açığa çıkan enerji","d":"Bu minimuma inerken açığa çıkan enerji bağ enerjisidir; bağı koparmak için aynı enerjinin geri verilmesi gerekir."}],"ans":"Bağ enerjisi, kararlı bağ uzaklığında açığa çıkan (bağı koparmak için gereken) enerjidir; sistem enerji minimumuna indiği için bağ oluşumu enerji açığa çıkarır."},{"q":"Atomların elektron alma/verme eğilimi periyodik tabloda nasıl değişir?","steps":[{"t":"Metaller","a":"e verir","d":"Tablonun solundaki metaller az değerlik elektronuna sahiptir ve düşük iyonlaşma enerjisiyle kolayca elektron verip katyon olur."},{"t":"Ametaller","a":"e alır","d":"Sağ üstteki ametaller yüksek elektronegatiflikle elektron çekip alır ve anyon oluşturarak oktete ulaşır."}],"ans":"Soldaki metaller kolayca elektron verip katyon, sağdaki ametaller elektron alıp anyon olur; bu eğilim oktete ulaşma yönündedir."}],"zor":[{"q":"Bağ oluşumunu potansiyel enerji eğrisi üzerinden ayrıntılı açıklayınız.","fig":"<svg viewBox='0 0 320 175'><line x1='45' y1='140' x2='295' y2='140' stroke='#1a2b45'/><line x1='45' y1='140' x2='45' y2='25' stroke='#1a2b45'/><path d='M60 35 Q120 35 155 120 Q170 150 200 132 Q240 110 285 118' fill='none' stroke='#2b6be0' stroke-width='2'/><circle cx='178' cy='133' r='4' fill='#e0552b'/><line x1='178' y1='133' x2='178' y2='140' stroke='#1a2b45' stroke-dasharray='3 2'/><text x='178' y='160' font-size='9' text-anchor='middle' fill='#1a2b45'>r₀</text><text x='30' y='30' font-size='9' fill='#1a2b45'>E</text><text x='278' y='133' font-size='8' fill='#1a2b45'>r</text></svg>","steps":[{"t":"Uzakta","a":"etkileşim yok","d":"Atomlar çok uzaktayken aralarında belirgin etkileşim yoktur, potansiyel enerji yaklaşık sıfır kabul edilir."},{"t":"Yaklaşma","a":"çekim baskın","d":"Yaklaştıkça çekirdek-elektron çekimleri baskın olur, enerji düşer ve r₀ (denge uzaklığı) noktasında minimuma iner."},{"t":"Çok yakın","a":"itme baskın","d":"r₀'dan daha da yaklaşırlarsa çekirdek-çekirdek ve elektron-elektron itmeleri baskın olur, enerji hızla yükselir."}],"ans":"Atomlar yaklaşırken çekim baskın olup enerji r₀'da minimuma iner (kararlı bağ); daha yakında itme baskın olup enerji yükselir, bu yüzden bağ belirli bir denge uzaklığında oluşur."},{"q":"Oktet kuralının sınırlamalarını (genişlemiş oktet, eksik oktet) örneklerle açıklayınız.","steps":[{"t":"Eksik oktet","a":"BF₃","d":"Bor, BF₃'te yalnızca 6 değerlik elektronuyla çevrilidir; oktete ulaşmadan kararlı bileşik yapar."},{"t":"Genişlemiş oktet","a":"SF₆, PCl₅","d":"3. periyot ve sonrası elementler boş d orbitallerini kullanarak 8'den fazla elektronla çevrilebilir (SF₆'da 12, PCl₅'te 10)."}],"ans":"Oktet bir eğilimdir; bor (BF₃) eksik oktetle, kükürt (SF₆) ve fosfor (PCl₅) ise d orbitalleri sayesinde genişlemiş oktetle kararlı kalabilir."},{"q":"İyonlaşma enerjisi ve elektronegatiflik, bağ türünün belirlenmesinde nasıl rol oynar?","steps":[{"t":"İyonlaşma enerjisi","a":"e verme kolaylığı","d":"Düşük iyonlaşma enerjili atomlar (metaller) elektronu kolay verir; bu, iyonik bağda katyon oluşumuna zemin hazırlar."},{"t":"Elektronegatiflik farkı","a":"bağ türü ölçütü","d":"İki atomun elektronegatiflik farkı büyükse elektron tam aktarılır (iyonik); küçük/sıfırsa paylaşılır (kovalent), orta ise polar kovalent olur."}],"ans":"Düşük iyonlaşma enerjisi elektron vermeyi kolaylaştırır; elektronegatiflik farkı ise büyükse iyonik, küçükse kovalent, ortaysa polar kovalent bağ türünü belirler."},{"q":"Neden 18 değil de çoğu kez 8 elektron 'kararlı oktet' sayılır?","steps":[{"t":"Alt kabuk dolumu","a":"ns² np⁶","d":"Baş grup elementlerinde değerlik katmanı yalnızca s (2) ve p (6) alt kabuklarını içerir; bunlar dolunca 8 elektron olur."},{"t":"d orbitalinin durumu","a":"genelde değerlik dışı","d":"d orbitalleri çoğu baş grup atomunda ya yoktur ya da değerlik katmanına dahil değildir; bu yüzden 18 değil 8 elektron dolu değerlik kabuğu sayılır."}],"ans":"Baş grup atomlarında değerlik katmanı s²p⁶ ile 8 elektronda dolar; d orbitalleri genelde değerlik dışında kaldığından kararlı düzen 18 değil 8 elektrondur."},{"q":"Kararlı bir molekülün, onu oluşturan ayrı atomlardan neden daha düşük enerjili olduğunu termodinamik açıdan açıklayınız.","steps":[{"t":"Bağ oluşumu","a":"ekzotermik","d":"Bağ oluşurken enerji açığa çıkar (ekzotermik); sistemin potansiyel enerjisi ayrı atomlara göre düşer."},{"t":"Kararlılık ölçütü","a":"düşük enerji","d":"Daha düşük enerjili durum termodinamik olarak daha kararlıdır; molekülü tekrar atomlara ayırmak için açığa çıkan enerjinin geri verilmesi (enerji harcanması) gerekir."}],"ans":"Bağ oluşumu ekzotermiktir; molekülün potansiyel enerjisi ayrı atomlardan düşük olduğundan termodinamik olarak daha kararlıdır ve ayrışması için enerji gerekir."}]}},"polarKovalent":{"ilkokul":{"kolay":[{"q":"İki farklı atom birleştiğinde elektronlar hangi atoma daha yakın durur?","steps":[{"t":"Farklı güç","a":"biri daha güçlü","d":"Farklı atomların çekme gücü aynı değildir, biri elektronu daha güçlü çeker."},{"t":"Yakınlık","a":"güçlü olana","d":"Bu yüzden ortak elektronlar, daha güçlü çeken atoma biraz daha yakın durur."}],"ans":"İki farklı atomda elektronlar, daha güçlü çeken atoma daha yakın durur."},{"q":"Su molekülünde elektronlar hangi atoma daha yakındır?","fig":"<svg viewBox='0 0 320 175'><circle cx='160' cy='80' r='26' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='85' font-size='13' text-anchor='middle' fill='#fff'>O</text><circle cx='110' cy='130' r='16' fill='#cfd8e8' stroke='#1a2b45'/><text x='110' y='135' font-size='10' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='210' cy='130' r='16' fill='#cfd8e8' stroke='#1a2b45'/><text x='210' y='135' font-size='10' text-anchor='middle' fill='#1a2b45'>H</text><line x1='142' y1='98' x2='120' y2='118' stroke='#1a2b45' stroke-width='2'/><line x1='178' y1='98' x2='200' y2='118' stroke='#1a2b45' stroke-width='2'/><text x='160' y='165' font-size='10' text-anchor='middle' fill='#1a2b45'>elektronlar O tarafına yakın</text></svg>","steps":[{"t":"Oksijen güçlü","a":"daha çok çeker","d":"Suda oksijen, hidrojenden daha güçlü çeker."},{"t":"Yakınlık","a":"oksijene","d":"Bu yüzden ortak elektronlar oksijene daha yakın durur."}],"ans":"Su molekülünde elektronlar, daha güçlü çeken oksijen atomuna daha yakın durur."},{"q":"Elektronlar bir atoma daha yakın olunca o atomda nasıl bir yük oluşur?","steps":[{"t":"Eksi toplanır","a":"hafif eksi","d":"Elektronlar eksi yüklüdür; bir atoma yakınlaşınca o atom hafifçe eksi olur."},{"t":"Diğer taraf","a":"hafif artı","d":"Elektronu az çeken atom ise hafifçe artı kalır."}],"ans":"Elektronların yakın olduğu atom hafif eksi, uzak olan atom hafif artı yük kazanır."},{"q":"Tuz ruhunun içindeki HCl hangi iki atomdan oluşur?","steps":[{"t":"Hidrojen","a":"bir H","d":"HCl molekülünde bir hidrojen (H) atomu bulunur."},{"t":"Klor","a":"bir Cl","d":"Hidrojen, klor (Cl) ile birleşerek hidrojen klorürü (HCl) oluşturur."}],"ans":"HCl, bir hidrojen ve bir klor atomundan oluşur."},{"q":"Bir mıknatısın bir ucu kuzey diğeri güney olur; suyun da bir ucu hafif artı diğeri hafif eksidir, buna ne benzer?","steps":[{"t":"İki uç","a":"farklı yük","d":"Suyun bir ucu hafif artı, diğer ucu hafif eksidir."},{"t":"Benzetme","a":"mıknatıs gibi","d":"Tıpkı mıknatısın iki farklı ucu gibi, suyun da iki farklı uçlu (kutuplu) bir yapısı vardır."}],"ans":"Suyun bir ucu hafif artı, diğeri hafif eksi olduğundan iki kutuplu mıknatısa benzer; buna kutuplu (polar) yapı denir."}],"zor":[{"q":"Neden iki farklı atom arasında elektronlar eşit paylaşılmaz?","steps":[{"t":"Farklı çekim","a":"eşit değil","d":"Farklı atomların elektronu çekme gücü farklıdır, biri daha güçlüdür."},{"t":"Kayma","a":"güçlüye doğru","d":"Bu yüzden ortak elektronlar güçlü çeken atoma doğru kayar, paylaşım eşit olmaz."}],"ans":"Farklı atomların çekme gücü eşit olmadığından elektronlar güçlü olana kayar; paylaşım eşit olmaz."},{"q":"HCl molekülünde hangi atom hafif eksi, hangisi hafif artı olur?","fig":"<svg viewBox='0 0 320 160'><circle cx='110' cy='80' r='22' fill='#cfd8e8' stroke='#1a2b45'/><text x='110' y='85' font-size='12' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='210' cy='80' r='30' fill='#9ed9a8' stroke='#1a2b45'/><text x='210' y='85' font-size='12' text-anchor='middle' fill='#1a2b45'>Cl</text><line x1='132' y1='80' x2='180' y2='80' stroke='#1a2b45' stroke-width='3'/><text x='100' y='45' font-size='12' fill='#1a2b45'>δ⁺</text><text x='215' y='45' font-size='12' fill='#1a2b45'>δ⁻</text></svg>","steps":[{"t":"Klor güçlü","a":"hafif eksi","d":"Klor elektronu daha güçlü çektiği için hafif eksi (δ⁻) olur."},{"t":"Hidrojen","a":"hafif artı","d":"Hidrojen elektronu az çektiği için hafif artı (δ⁺) kalır."}],"ans":"HCl'de klor hafif eksi (δ⁻), hidrojen hafif artı (δ⁺) olur."},{"q":"Suyun damlalarının bir tarağa veya balona yapışmasının yapısıyla ilgisi nedir?","steps":[{"t":"Kutuplu su","a":"iki uçlu","d":"Su molekülünün bir ucu hafif artı, diğeri hafif eksidir; yani kutupludur."},{"t":"Çekim","a":"yüklü cisme","d":"Yüklü tarak/balon, suyun zıt yüklü ucunu çeker; bu yüzden su akışı saparak yaklaşır."}],"ans":"Su molekülü kutuplu (iki uçlu) olduğundan, yüklü bir cisim suyun zıt yüklü ucunu çeker ve su ona doğru sapar."},{"q":"Amonyak (NH₃) molekülünde elektronlar hangi atoma daha yakındır?","steps":[{"t":"Azot güçlü","a":"daha çok çeker","d":"Amonyakta azot, hidrojenden daha güçlü çeker."},{"t":"Yakınlık","a":"azota","d":"Bu yüzden ortak elektronlar azota daha yakın olur; azot hafif eksi, hidrojenler hafif artı kalır."}],"ans":"NH₃'te elektronlar, daha güçlü çeken azot atomuna daha yakın durur."},{"q":"İki kişi ipi çekiyor ama biri daha güçlü; ip ne yapar, bu hangi bağa benzer?","steps":[{"t":"Güçlü taraf","a":"ip kayar","d":"Daha güçlü çeken kişiye doğru ip kayar, tam ortada kalmaz."},{"t":"Benzetme","a":"polar bağ","d":"Elektronlar da güçlü çeken atoma kayar; bu, eşit olmayan paylaşımlı polar bağa benzer."}],"ans":"İp güçlü çekene doğru kayar; bu, elektronların güçlü atoma kaydığı polar bağa benzer."}]},"ortaokul":{"kolay":[{"q":"Polar kovalent bağ nedir?","steps":[{"t":"Eşit olmayan paylaşım","a":"farklı çekim","d":"Polar kovalent bağda iki atom ortak elektronları eşit olmayan biçimde paylaşır."},{"t":"Kısmi yükler","a":"δ⁺ ve δ⁻","d":"Elektronu güçlü çeken atom kısmi eksi (δ⁻), diğeri kısmi artı (δ⁺) yük kazanır."}],"ans":"Polar kovalent bağ, ortak elektronların eşit olmayan paylaşıldığı ve atomlarda kısmi yükler (δ⁺, δ⁻) oluştuğu bağdır."},{"q":"Bir kovalent bağ ne zaman polar olur?","steps":[{"t":"Farklı atomlar","a":"elektronegatiflik farkı","d":"İki atomun elektron çekme gücü (elektronegatiflik) farklı olduğunda bağ polar olur."},{"t":"Fark aralığı","a":"0,4 - 1,7","d":"Elektronegatiflik farkı yaklaşık 0,4 ile 1,7 arasındaysa bağ polar kovalent kabul edilir."}],"ans":"Elektronegatiflik farkı olan (yaklaşık 0,4 - 1,7) iki farklı atom arasında oluşan kovalent bağ polardır."},{"q":"HCl molekülünde kısmi yükler nasıl oluşur?","fig":"<svg viewBox='0 0 320 160'><circle cx='110' cy='80' r='22' fill='#cfd8e8' stroke='#1a2b45'/><text x='110' y='85' font-size='12' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='210' cy='80' r='30' fill='#9ed9a8' stroke='#1a2b45'/><text x='210' y='85' font-size='12' text-anchor='middle' fill='#1a2b45'>Cl</text><line x1='132' y1='80' x2='180' y2='80' stroke='#1a2b45' stroke-width='3'/><text x='98' y='42' font-size='12' fill='#1a2b45'>δ⁺</text><text x='216' y='42' font-size='12' fill='#1a2b45'>δ⁻</text><text x='160' y='140' font-size='10' text-anchor='middle' fill='#1a2b45'>ortak çift Cl'a kayar</text></svg>","steps":[{"t":"Klor güçlü","a":"elektronu çeker","d":"Klorun elektronegatifliği daha yüksektir, ortak elektron çiftini kendine doğru çeker."},{"t":"Kısmi yük","a":"δ⁻ ve δ⁺","d":"Elektron klora kaydığından klor δ⁻, hidrojen δ⁺ olur."}],"ans":"HCl'de klor ortak çifti daha güçlü çektiğinden klor kısmi eksi (δ⁻), hidrojen kısmi artı (δ⁺) yük kazanır."},{"q":"Dipol momenti ne anlatır?","steps":[{"t":"Yük ayrılması","a":"artı-eksi mesafe","d":"Dipol momenti, bir moleküldeki kısmi artı ve kısmi eksi yüklerin ayrılma miktarını gösterir."},{"t":"Polarlık ölçüsü","a":"büyükse polar","d":"Dipol momenti sıfırdan büyükse molekül polardır; büyüdükçe molekül daha polardır."}],"ans":"Dipol momenti, moleküldeki kısmi yüklerin ayrılma derecesini gösterir; sıfırdan büyükse molekül polardır."},{"q":"Su molekülünün polar olmasının nedeni nedir?","steps":[{"t":"Polar bağlar","a":"O–H","d":"Suda oksijen hidrojenden güçlü çektiği için her O–H bağı polardır."},{"t":"Açısal yapı","a":"dipoller toplanır","d":"Molekül açısal (V) biçimli olduğundan bağların kısmi yükleri birbirini götürmez; net kutup oluşur."}],"ans":"Suda polar O–H bağları açısal yapıda birbirini götürmediğinden molekülün net bir kutbu vardır; bu yüzden su polardır."}],"zor":[{"q":"Elektronegatiflik farkı bağ türünü nasıl belirler?","steps":[{"t":"Fark küçükse","a":"apolar/polar","d":"Fark sıfıra yakınsa (≈ 0) bağ apolar; 0,4 - 1,7 arasındaysa polar kovalenttir."},{"t":"Fark büyükse","a":"iyonik","d":"Fark yaklaşık 1,7'den büyükse elektron neredeyse tümüyle bir atoma geçer ve bağ iyonik karakter kazanır."}],"ans":"Elektronegatiflik farkı arttıkça bağ apolar → polar kovalent → iyonik yönünde değişir; 0,4 - 1,7 aralığı polar kovalenti gösterir."},{"q":"NH₃ molekülünün polarlığını açıklayınız.","fig":"<svg viewBox='0 0 320 180'><circle cx='160' cy='80' r='24' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='85' font-size='13' text-anchor='middle' fill='#fff'>N</text><circle cx='105' cy='130' r='15' fill='#cfd8e8' stroke='#1a2b45'/><text x='105' y='135' font-size='9' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='160' cy='148' r='15' fill='#cfd8e8' stroke='#1a2b45'/><text x='160' y='153' font-size='9' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='215' cy='130' r='15' fill='#cfd8e8' stroke='#1a2b45'/><text x='215' y='135' font-size='9' text-anchor='middle' fill='#1a2b45'>H</text><line x1='145' y1='96' x2='115' y2='118' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='104' x2='160' y2='133' stroke='#1a2b45' stroke-width='2'/><line x1='175' y1='96' x2='205' y2='118' stroke='#1a2b45' stroke-width='2'/><text x='160' y='44' font-size='11' text-anchor='middle' fill='#1a2b45'>δ⁻</text></svg>","steps":[{"t":"Polar bağlar","a":"N–H","d":"Azot hidrojenden daha elektronegatif olduğundan üç N–H bağı polardır; azot δ⁻ olur."},{"t":"Üçgen piramit","a":"dipoller toplanır","d":"Molekül üçgen piramit biçimli ve ortaklanmamış çift taşır; bağ dipolleri birbirini götürmez ve net dipol oluşur."}],"ans":"NH₃'te polar N–H bağları üçgen piramit yapıda birbirini götürmediğinden net dipol oluşur; molekül polardır."},{"q":"Polar moleküller arasında hangi çekim kuvvetleri etkilidir?","steps":[{"t":"Dipol-dipol","a":"kutuplar çekişir","d":"Polar moleküllerin kısmi artı ucu, komşu molekülün kısmi eksi ucunu çeker (dipol-dipol çekimi)."},{"t":"Hidrojen bağı","a":"H ile O/N/F","d":"H atomu O, N veya F'ye bağlıysa çok daha güçlü bir özel dipol çekimi olan hidrojen bağı oluşur."}],"ans":"Polar moleküller arasında dipol-dipol çekimleri; H, O/N/F'ye bağlıysa ek olarak güçlü hidrojen bağları etkilidir."},{"q":"Su (H₂O) polar, karbondioksit (CO₂) apolar; ikisinin de polar bağları olduğu halde bu farkın nedeni nedir?","steps":[{"t":"Geometri farkı","a":"açısal vs doğrusal","d":"Su açısal (V), CO₂ ise doğrusaldır; geometri kısmi yüklerin toplamını belirler."},{"t":"Dipol sonucu","a":"toplanır vs götürür","d":"Suda bağ dipolleri açı nedeniyle toplanıp net dipol verir; CO₂'de doğrusal yapıda zıt dipoller birbirini götürür."}],"ans":"Su açısal olduğundan bağ dipolleri toplanıp net dipol verir (polar); CO₂ doğrusal olduğundan dipoller birbirini götürür (apolar)."},{"q":"Polar maddeler neden suda kolay çözünür?","steps":[{"t":"Benzer benzeri çözer","a":"polar-polar","d":"Polar çözücü su, polar maddelerle uyumludur; \"benzer benzeri çözer\" ilkesi geçerlidir."},{"t":"Kutup çekimi","a":"sarılma","d":"Su moleküllerinin kutupları, çözünen polar molekülün zıt kutuplarını çekip sararak onu çözeltiye dağıtır."}],"ans":"Polar su molekülleri, polar çözünenin zıt kutuplarını çekip sararak çözer; \"benzer benzeri çözer\" ilkesiyle polar maddeler suda kolay çözünür."}]},"lise":{"kolay":[{"q":"Polar kovalent bağ nasıl oluşur?","steps":[{"t":"Elektronegatiflik farkı","a":"0,4 - 1,7","d":"İki atomun elektronegatiflik farkı yaklaşık 0,4 ile 1,7 arasında olduğunda bağ polar kovalenttir."},{"t":"Eşitsiz paylaşım","a":"kısmi yükler","d":"Ortak elektron çifti daha elektronegatif atoma kayar; o atom δ⁻, diğeri δ⁺ kısmi yük kazanır."}],"ans":"Elektronegatiflik farkı yaklaşık 0,4 - 1,7 olan atomlar arasında ortak elektronlar eşitsiz paylaşılır; kısmi yükler (δ⁺, δ⁻) oluşur ve bağ polar kovalent olur."},{"q":"HCl molekülünde bağ polaritesini ve dipol yönünü açıklayınız.","fig":"<svg viewBox='0 0 320 160'><circle cx='105' cy='80' r='20' fill='#cfd8e8' stroke='#1a2b45'/><text x='105' y='85' font-size='12' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='215' cy='80' r='30' fill='#9ed9a8' stroke='#1a2b45'/><text x='215' y='85' font-size='12' text-anchor='middle' fill='#1a2b45'>Cl</text><line x1='125' y1='80' x2='185' y2='80' stroke='#1a2b45' stroke-width='3'/><text x='92' y='44' font-size='12' fill='#1a2b45'>δ⁺</text><text x='220' y='44' font-size='12' fill='#1a2b45'>δ⁻</text><line x1='130' y1='110' x2='195' y2='110' stroke='#2b6be0' stroke-width='2'/><polygon points='195,110 185,105 185,115' fill='#2b6be0'/><text x='160' y='135' font-size='9' text-anchor='middle' fill='#1a2b45'>dipol H'ten Cl'a</text></svg>","steps":[{"t":"Elektronegatiflik","a":"Cl > H","d":"Klorun elektronegatifliği hidrojeninkinden büyüktür; ortak çift klora kayar, klor δ⁻, hidrojen δ⁺ olur."},{"t":"Dipol yönü","a":"δ⁺ → δ⁻","d":"Bağ dipolü kısmi artı uçtan (H) kısmi eksi uca (Cl) doğrudur; molekül net dipole sahip, polardır."}],"ans":"HCl'de klor daha elektronegatif olduğundan ortak çift klora kayar; klor δ⁻, hidrojen δ⁺ olur ve dipol H'ten Cl'a doğrudur, molekül polardır."},{"q":"Dipol momenti kavramını ve birimini açıklayınız.","steps":[{"t":"Tanım","a":"yük × uzaklık","d":"Dipol momenti, kısmi yükün büyüklüğü ile artı-eksi merkezler arası uzaklığın çarpımıdır; yönü olan bir vektördür."},{"t":"Anlamı","a":"polarlık ölçüsü","d":"Dipol momenti sıfırsa molekül apolar, sıfırdan büyükse polardır; arttıkça molekül daha polardır (birim: debye, D)."}],"ans":"Dipol momenti, kısmi yük ile yükler arası uzaklığın çarpımı olan bir vektördür (birim debye); sıfırdan büyük olması molekülün polar olduğunu gösterir."},{"q":"H₂O molekülünün net dipol momentini geometri ile açıklayınız.","fig":"<svg viewBox='0 0 320 180'><circle cx='160' cy='75' r='24' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='80' font-size='13' text-anchor='middle' fill='#fff'>O</text><circle cx='108' cy='128' r='15' fill='#cfd8e8' stroke='#1a2b45'/><text x='108' y='133' font-size='9' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='212' cy='128' r='15' fill='#cfd8e8' stroke='#1a2b45'/><text x='212' y='133' font-size='9' text-anchor='middle' fill='#1a2b45'>H</text><line x1='143' y1='91' x2='119' y2='116' stroke='#1a2b45' stroke-width='2'/><line x1='177' y1='91' x2='201' y2='116' stroke='#1a2b45' stroke-width='2'/><text x='160' y='40' font-size='11' text-anchor='middle' fill='#1a2b45'>δ⁻</text><line x1='160' y1='100' x2='160' y2='55' stroke='#2b6be0' stroke-width='2'/><polygon points='160,55 155,65 165,65' fill='#2b6be0'/><text x='195' y='160' font-size='9' fill='#1a2b45'>~104,5°</text></svg>","steps":[{"t":"Bağ dipolleri","a":"iki polar O–H","d":"Oksijen daha elektronegatif olduğundan iki O–H bağı polardır; oksijen δ⁻, hidrojenler δ⁺ olur."},{"t":"Açısal toplam","a":"net dipol yukarı","d":"Molekül ~104,5° açısaldır; iki bağ dipolü vektörel toplandığında oksijen ucuna doğru sıfırdan farklı net bir dipol verir."}],"ans":"H₂O'da iki polar O–H bağ dipolü açısal (~104,5°) geometride vektörel toplanır ve oksijen ucuna doğru net bir dipol oluşturur; bu yüzden su polardır."},{"q":"Polar moleküllerin kaynama noktaları benzer kütleli apolar moleküllerden neden yüksektir?","steps":[{"t":"Güçlü çekim","a":"dipol-dipol/H bağı","d":"Polar moleküller arasında apolarlardan farklı olarak dipol-dipol ve gerekirse hidrojen bağı gibi güçlü çekimler bulunur."},{"t":"Daha çok enerji","a":"yüksek kaynama","d":"Bu daha güçlü çekimleri yenip molekülleri ayırmak daha çok enerji gerektirdiğinden kaynama noktası yükselir."}],"ans":"Polar moleküller arasındaki dipol-dipol ve hidrojen bağı çekimleri apolarlara göre daha güçlü olduğundan, onları ayırmak daha çok enerji ister ve kaynama noktaları yüksek olur."}],"zor":[{"q":"Bir bağ polar olduğu halde molekülün net dipol momentinin sıfır olabileceği durumları açıklayınız.","steps":[{"t":"Bağ dipolleri","a":"vektör toplamı","d":"Net dipol momenti, tek tek bağ dipol vektörlerinin toplamıdır; her bağ polar olsa bile toplam sıfır olabilir."},{"t":"Simetri etkisi","a":"götürme","d":"CO₂ (doğrusal), BF₃ (düzlem üçgen), CCl₄ (dörtyüzlü) gibi simetrik moleküllerde zıt yönlü bağ dipolleri birbirini götürür; net dipol sıfır olur."}],"ans":"Net dipol momenti bağ dipollerinin vektörel toplamıdır; simetrik geometrilerde (CO₂, BF₃, CCl₄) polar bağların dipolleri birbirini götürdüğünden molekül apolar olabilir."},{"q":"NH₃ ve NF₃ moleküllerinin ikisi de üçgen piramit olduğu halde dipol momentlerinin çok farklı olmasının nedenini açıklayınız.","steps":[{"t":"NH₃ dipolü","a":"aynı yönde toplanır","d":"NH₃'te azotun ortaklanmamış çiftinin dipolü ile N–H bağlarının dipolleri aynı yöne eklenir; net dipol büyüktür."},{"t":"NF₃ dipolü","a":"zıt yönde azalır","d":"NF₃'te flor azottan daha elektronegatif olup bağ dipolleri ortaklanmamış çiftin dipoline ters yöndedir; büyük ölçüde götürülür, net dipol küçüktür."}],"ans":"NH₃'te ortaklanmamış çift ve N–H dipolleri aynı yönde toplanıp büyük dipol verir; NF₃'te N–F bağ dipolleri ortaklanmamış çiftin dipoline ters yönde olup büyük ölçüde sönümlendiğinden dipol momenti çok daha küçüktür."},{"q":"Yüzde iyonik karakter kavramını elektronegatiflik farkıyla ilişkilendirerek açıklayınız.","steps":[{"t":"Süreklilik","a":"saf yok","d":"Bağlar tam apolar ile tam iyonik arasında bir süreklilik üzerindedir; çoğu polar kovalent bağ kısmen iyonik karakter taşır."},{"t":"Fark ilişkisi","a":"fark arttıkça artar","d":"Elektronegatiflik farkı büyüdükçe elektron yoğunluğu bir atomda daha çok toplanır ve bağın yüzde iyonik karakteri artar."}],"ans":"Polar kovalent bağlar kısmi iyonik karakter taşır; elektronegatiflik farkı arttıkça elektron yoğunluğunun bir atomda toplanması artar ve bağın yüzde iyonik karakteri yükselir."},{"q":"Hidrojen bağının özel bir dipol-dipol etkileşimi olduğunu ve HF, H₂O, NH₃'te neden güçlü olduğunu açıklayınız.","fig":"<svg viewBox='0 0 320 175'><circle cx='90' cy='70' r='18' fill='#e0552b' stroke='#1a2b45'/><text x='90' y='75' font-size='10' text-anchor='middle' fill='#fff'>O</text><circle cx='128' cy='98' r='11' fill='#cfd8e8' stroke='#1a2b45'/><text x='128' y='102' font-size='8' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='222' cy='120' r='18' fill='#e0552b' stroke='#1a2b45'/><text x='222' y='125' font-size='10' text-anchor='middle' fill='#fff'>O</text><line x1='138' y1='103' x2='206' y2='117' stroke='#2b6be0' stroke-width='2' stroke-dasharray='4 3'/><text x='95' y='50' font-size='10' fill='#1a2b45'>δ⁻</text><text x='133' y='80' font-size='9' fill='#1a2b45'>δ⁺</text><text x='172' y='100' font-size='9' text-anchor='middle' fill='#1a2b45'>hidrojen bağı</text></svg>","steps":[{"t":"Aşırı polar bağ","a":"H–F/O/N","d":"F, O ve N çok elektronegatiftir; H'ye bağlandığında çok büyük kısmi yük ayrılması (yüksek δ⁺ H, yüksek δ⁻) oluşur."},{"t":"Yoğun çekim","a":"küçük H çekirdeği","d":"Küçük ve neredeyse çıplak H çekirdeği, komşu molekülün yoğun δ⁻ atomuna çok yakın yaklaşabildiğinden alışılmış dipol-dipolden çok daha güçlü çekim oluşur."}],"ans":"Hidrojen bağı, H'nin çok elektronegatif F/O/N'ye bağlı olduğu aşırı polar bağlarda oluşan özel ve güçlü bir dipol-dipol etkileşimidir; HF, H₂O, NH₃'te büyük kısmi yükler ve küçük H çekirdeği nedeniyle bu çekim çok güçlüdür."},{"q":"Bağ dipol momenti ile molekül dipol momenti arasındaki ayrımı, bir molekülün çözücü davranışına etkisiyle açıklayınız.","steps":[{"t":"Bağ vs molekül dipolü","a":"yerel vs toplam","d":"Bağ dipol momenti tek bir bağdaki yerel yük ayrılmasıdır; molekül dipol momenti ise tüm bağ dipollerinin geometriye göre vektörel toplamıdır."},{"t":"Çözücü etkisi","a":"net dipol belirler","d":"Çözücüyle etkileşimi ve polar çözücüde çözünürlüğü molekülün net (toplam) dipol momenti belirler; bağlar polar olsa da net dipol sıfırsa molekül apolar gibi davranır."}],"ans":"Bağ dipol momenti tek bağdaki yerel yük ayrılması, molekül dipol momenti ise bunların geometriye göre vektörel toplamıdır; bir maddenin polar çözücüdeki davranışını bağ dipolleri değil, net molekül dipol momenti belirler."}]}},"suYapisi":{"ilkokul":{"kolay":[{"q":"Su molekülü hangi atomlardan oluşur?","fig":"<svg viewBox='0 0 320 165'><circle cx='160' cy='70' r='26' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='75' font-size='13' text-anchor='middle' fill='#fff'>O</text><circle cx='112' cy='115' r='16' fill='#cfd8e8' stroke='#1a2b45'/><text x='112' y='120' font-size='10' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='208' cy='115' r='16' fill='#cfd8e8' stroke='#1a2b45'/><text x='208' y='120' font-size='10' text-anchor='middle' fill='#1a2b45'>H</text><line x1='142' y1='88' x2='122' y2='104' stroke='#1a2b45' stroke-width='2'/><line x1='178' y1='88' x2='198' y2='104' stroke='#1a2b45' stroke-width='2'/><text x='160' y='152' font-size='11' text-anchor='middle' fill='#1a2b45'>su (H₂O)</text></svg>","steps":[{"t":"Atomlar","a":"hidrojen ve oksijen","d":"Su molekülünde hidrojen (H) ve oksijen (O) atomları bulunur."},{"t":"Sayı","a":"2 H + 1 O","d":"Bir su molekülünde iki hidrojen ve bir oksijen atomu vardır, bu yüzden H₂O yazılır."}],"ans":"Su molekülü iki hidrojen (H) ve bir oksijen (O) atomundan oluşur; formülü H₂O'dur."},{"q":"Su molekülünün şekli düz bir çizgi mi, yoksa hafif kıvrık (açılı) mı?","steps":[{"t":"İki H'nin yeri","a":"yana açık","d":"İki hidrojen, oksijenin aynı tarafına doğru hafif açıyla durur."},{"t":"Şekil","a":"açılı (V gibi)","d":"Bu yüzden su molekülü düz değil, V harfi gibi hafif kıvrık (açılı) bir yapıdadır."}],"ans":"Su molekülü düz değil, V harfi gibi hafif açılı (kıvrık) bir şekildedir."},{"q":"Su neden 'her şeyi eriten' (birçok şeyi içinde çözen) bir sıvı sayılır?","steps":[{"t":"Yüklü uçlar","a":"tutunur","d":"Su molekülünün hafif artı ve eksi uçları, şeker ya da tuz taneciklerine tutunur."},{"t":"Çözer","a":"sarıp dağıtır","d":"Su bu tanecikleri sarıp birbirinden ayırarak içinde eritir."}],"ans":"Su, yüklü uçlarıyla birçok taneciğe tutunup onları sarıp dağıttığından birçok maddeyi içinde eritebilir."},{"q":"Yağmur damlasının yuvarlak kalmasını sağlayan, su moleküllerinin hangi özelliğidir?","fig":"<svg viewBox='0 0 320 160'><path d='M160 35 C120 95 120 130 160 130 C200 130 200 95 160 35 Z' fill='#9ccaff' stroke='#1a2b45'/><text x='160' y='108' font-size='11' text-anchor='middle' fill='#1a2b45'>damla</text></svg>","steps":[{"t":"Birbirine tutunma","a":"çekim","d":"Su molekülleri birbirine tutunarak bir arada durur."},{"t":"Toparlanma","a":"yuvarlak","d":"Bu tutunma damlayı içe doğru toplar, böylece damla yuvarlak kalır."}],"ans":"Su moleküllerinin birbirine tutunma (çekim) özelliği, yağmur damlasını yuvarlak tutar."},{"q":"Su ısıtılınca neden kolayca buz gibi soğumaz; ısıyı bir süre tutar mı?","steps":[{"t":"Isı depolama","a":"ısıyı tutar","d":"Su, aldığı ısıyı bir süre içinde tutabilen bir sıvıdır."},{"t":"Yavaş değişim","a":"sıcaklığı geç değişir","d":"Bu yüzden suyun sıcaklığı yavaş yükselir ve yavaş düşer."}],"ans":"Evet; su ısıyı içinde tutabildiğinden sıcaklığı yavaş yükselir ve yavaş soğur."}],"zor":[{"q":"Su molekülünün bir ucu neden hafif eksi, diğer ucu hafif artı gibi davranır?","fig":"<svg viewBox='0 0 320 165'><circle cx='160' cy='68' r='24' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='73' font-size='12' text-anchor='middle' fill='#fff'>O</text><circle cx='116' cy='112' r='14' fill='#cfd8e8' stroke='#1a2b45'/><text x='116' y='116' font-size='9' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='204' cy='112' r='14' fill='#cfd8e8' stroke='#1a2b45'/><text x='204' y='116' font-size='9' text-anchor='middle' fill='#1a2b45'>H</text><text x='160' y='36' font-size='11' text-anchor='middle' fill='#1a2b45'>− uç</text><text x='100' y='148' font-size='10' fill='#1a2b45'>+ uç</text><text x='195' y='148' font-size='10' fill='#1a2b45'>+ uç</text></svg>","steps":[{"t":"Oksijen güçlü çeker","a":"elektronları çeker","d":"Oksijen, ortak elektronları kendine doğru daha güçlü çeker."},{"t":"Uçlar oluşur","a":"O eksi, H artı","d":"Bu yüzden oksijen tarafı hafif eksi, hidrojen tarafı hafif artı gibi davranır."}],"ans":"Oksijen ortak elektronları kendine güçlü çektiğinden, oksijen ucu hafif eksi, hidrojen ucu hafif artı gibi davranır."},{"q":"Su sineği gibi hafif bir böcek neden su yüzeyinde batmadan durabilir?","steps":[{"t":"Yüzey zarı","a":"tutunan moleküller","d":"Yüzeydeki su molekülleri birbirine güçlü tutunarak gergin bir zar gibi davranır."},{"t":"Hafif yük","a":"batmaz","d":"Böcek çok hafif olduğundan bu gergin yüzeyi yırtamaz ve üstünde kalır."}],"ans":"Su yüzeyindeki moleküller birbirine güçlü tutunup gergin bir zar oluşturur; hafif böcek bu zarı yırtamadığı için batmaz."},{"q":"Bir bardak suya kâğıt mendil değdirildiğinde su neden mendilin yukarısına doğru tırmanır?","steps":[{"t":"Mendile tutunma","a":"adezyon","d":"Su molekülleri mendilin liflerine tutunur (adezyon)."},{"t":"Birbirini çekme","a":"yukarı taşır","d":"Tutunan su, arkasındaki diğer su moleküllerini de çekerek yukarı doğru taşır; böylece su mendile tırmanır."}],"ans":"Su molekülleri hem mendilin liflerine tutunur hem birbirini çeker; bu sayede su mendilin yukarısına doğru tırmanır."},{"q":"Göl üstü kışın buz tutsa da balıkların altta yaşayabilmesini su nasıl sağlar?","steps":[{"t":"Buz yüzer","a":"üstte kalır","d":"Su donunca buz, sudan daha hafif olduğu için yüzeyde kalır."},{"t":"Alt sıvı kalır","a":"balıklar yaşar","d":"Üstteki buz tabakası altındaki suyu soğuktan korur, su sıvı kalır ve balıklar yaşamını sürdürebilir."}],"ans":"Buz sudan hafif olup yüzeyde kaldığından alttaki su sıvı kalır; bu sayede balıklar buzun altında yaşayabilir."},{"q":"İki cam yüzey arasına bir damla su konunca cam yüzeyleri neden birbirine yapışmış gibi tutar?","steps":[{"t":"Cama tutunma","a":"adezyon","d":"Su molekülleri her iki cam yüzeye de tutunur."},{"t":"Birbirine tutunma","a":"kohezyon","d":"Aynı zamanda su molekülleri birbirine de tutunduğundan, aradaki su iki camı birbirine doğru çeker."}],"ans":"Aradaki su hem camlara tutunur (adezyon) hem birbirine tutunur (kohezyon); bu çekimler iki camı birbirine yapıştırır gibi tutar."}]},"ortaokul":{"kolay":[{"q":"Su molekülünün geometrisi nasıldır ve bağ açısı yaklaşık kaç derecedir?","fig":"<svg viewBox='0 0 320 170'><circle cx='160' cy='65' r='24' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='70' font-size='12' text-anchor='middle' fill='#fff'>O</text><circle cx='112' cy='120' r='15' fill='#cfd8e8' stroke='#1a2b45'/><text x='112' y='125' font-size='9' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='208' cy='120' r='15' fill='#cfd8e8' stroke='#1a2b45'/><text x='208' y='125' font-size='9' text-anchor='middle' fill='#1a2b45'>H</text><line x1='142' y1='82' x2='123' y2='108' stroke='#1a2b45' stroke-width='2'/><line x1='178' y1='82' x2='197' y2='108' stroke='#1a2b45' stroke-width='2'/><text x='160' y='95' font-size='10' text-anchor='middle' fill='#1a2b45'>≈104,5°</text></svg>","steps":[{"t":"Şekil","a":"açısal","d":"Su molekülü düz değil, açısal (V harfi gibi) bir geometriye sahiptir."},{"t":"Bağ açısı","a":"≈104,5°","d":"İki O–H bağı arasındaki açı yaklaşık 104,5°'dir."}],"ans":"Su molekülü açısal yapıdadır ve H–O–H bağ açısı yaklaşık 104,5°'dir."},{"q":"Su molekülü neden polar (kutuplu) bir moleküldür?","steps":[{"t":"O daha elektronegatif","a":"elektronları çeker","d":"Oksijen, ortak elektronları hidrojenden daha güçlü çektiği için oksijen kısmi eksi, hidrojenler kısmi artı olur."},{"t":"Açısal yapı","a":"uçlar ayrı","d":"Molekül açısal olduğundan eksi ve artı uçlar üst üste gelip birbirini götürmez; molekülün net bir kutbu olur."}],"ans":"Oksijen elektronları daha güçlü çeker ve molekül açısal olduğundan su, eksi ve artı uçları olan polar bir moleküldür."},{"q":"Su moleküllerini birbirine bağlayan etkileşimin adı nedir?","fig":"<svg viewBox='0 0 320 160'><circle cx='90' cy='62' r='17' fill='#e0552b' stroke='#1a2b45'/><text x='90' y='67' font-size='9' text-anchor='middle' fill='#fff'>O</text><circle cx='126' cy='88' r='10' fill='#cfd8e8' stroke='#1a2b45'/><text x='126' y='92' font-size='7' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='220' cy='106' r='17' fill='#e0552b' stroke='#1a2b45'/><text x='220' y='111' font-size='9' text-anchor='middle' fill='#fff'>O</text><line x1='135' y1='90' x2='205' y2='104' stroke='#2b6be0' stroke-width='2' stroke-dasharray='4 3'/><text x='172' y='86' font-size='9' text-anchor='middle' fill='#1a2b45'>hidrojen bağı</text></svg>","steps":[{"t":"Polar molekül","a":"uçlar çeker","d":"Bir su molekülünün artı (H) ucu, komşu molekülün eksi (O) ucunu çeker."},{"t":"Bağ adı","a":"hidrojen bağı","d":"H'nin oksijene bağlı olduğu bu güçlü çekime hidrojen bağı denir."}],"ans":"Su moleküllerini birbirine bağlayan etkileşime hidrojen bağı denir."},{"q":"Su neden 'evrensel çözücü' olarak adlandırılır?","steps":[{"t":"Polar yapı","a":"yüklü uçlar","d":"Su polar olduğundan artı ve eksi uçlarıyla birçok maddeye tutunabilir."},{"t":"Çok şey çözer","a":"iyon/polar","d":"Tuz gibi iyonik ve şeker gibi polar maddeleri çözebildiğinden suya evrensel çözücü denir."}],"ans":"Su polar yapısı sayesinde çok sayıda iyonik ve polar maddeyi çözebildiğinden 'evrensel çözücü' olarak adlandırılır."},{"q":"Suyun yüzey gerilimi ne demektir?","steps":[{"t":"Yüzey molekülleri","a":"içe çekilir","d":"Yüzeydeki su molekülleri yalnızca alttaki ve yanındaki moleküllerce çekildiğinden içe doğru çekilir."},{"t":"Gergin yüzey","a":"yüzey gerilimi","d":"Bu içe çekim yüzeyi gergin bir zar gibi yapar; buna yüzey gerilimi denir."}],"ans":"Yüzey gerilimi, yüzeydeki su moleküllerinin içe çekilerek yüzeyi gergin bir zar gibi davrandırması olayıdır."}],"zor":[{"q":"Su molekülünün bağ açısının (≈104,5°) düzgün dörtyüzlü açısından (109,5°) küçük olmasının nedeni nedir?","steps":[{"t":"Yalın çiftler","a":"oksijende 2 çift","d":"Oksijenin üzerinde iki ortaklanmamış (yalın) elektron çifti bulunur."},{"t":"İtme etkisi","a":"açıyı daraltır","d":"Yalın çiftler bağ çiftlerinden daha güçlü ittiğinden O–H bağlarını biraz birbirine doğru bastırır ve açı 109,5°'den 104,5°'ye düşer."}],"ans":"Oksijendeki iki yalın elektron çiftinin güçlü itmesi O–H bağlarını sıkıştırdığından, su molekülünün açısı 109,5° yerine yaklaşık 104,5° olur."},{"q":"Suyun yüksek kaynama noktasını molekül yapısıyla açıklayınız.","steps":[{"t":"Hidrojen bağı ağı","a":"moleküller arası","d":"Polar su molekülleri birbirine çok sayıda hidrojen bağıyla bağlıdır."},{"t":"Kopma enerjisi","a":"yüksek kaynama","d":"Kaynamak için bu hidrojen bağlarının kopması gerekir; bu fazladan enerji gerektirdiğinden suyun kaynama noktası yüksektir."}],"ans":"Su molekülleri arasındaki çok sayıda hidrojen bağı, kaynama sırasında kopması için fazla enerji gerektirdiğinden suyun kaynama noktası yüksektir."},{"q":"Suyun donunca genleşip buzun yüzmesini molekül dizilimiyle açıklayınız.","fig":"<svg viewBox='0 0 320 160'><circle cx='100' cy='58' r='13' fill='#9ccaff' stroke='#1a2b45'/><circle cx='160' cy='48' r='13' fill='#9ccaff' stroke='#1a2b45'/><circle cx='220' cy='58' r='13' fill='#9ccaff' stroke='#1a2b45'/><circle cx='130' cy='104' r='13' fill='#9ccaff' stroke='#1a2b45'/><circle cx='190' cy='104' r='13' fill='#9ccaff' stroke='#1a2b45'/><line x1='112' y1='60' x2='148' y2='51' stroke='#2b6be0' stroke-dasharray='3 3'/><line x1='172' y1='51' x2='208' y2='59' stroke='#2b6be0' stroke-dasharray='3 3'/><text x='160' y='145' font-size='10' text-anchor='middle' fill='#1a2b45'>açık (boşluklu) örgü</text></svg>","steps":[{"t":"Donunca dizilim","a":"açık örgü","d":"Su donarken hidrojen bağları molekülleri düzenli, boşluklu bir altıgen örgüye yerleştirir."},{"t":"Daha az yoğun","a":"buz yüzer","d":"Boşluklu örgü buzun hacmini artırır, yoğunluğunu düşürür; bu yüzden buz suyun üstünde yüzer."}],"ans":"Donarken hidrojen bağları molekülleri boşluklu (açık) örgüye dizdiğinden buz genleşir, yoğunluğu düşer ve suyun üstünde yüzer."},{"q":"Kohezyon ile adezyon arasındaki fark nedir; suda hangi olaylarda görülür?","steps":[{"t":"Kohezyon","a":"su–su çekimi","d":"Kohezyon, su moleküllerinin birbirine tutunmasıdır; yüzey gerilimi ve damla oluşumunda görülür."},{"t":"Adezyon","a":"su–yüzey çekimi","d":"Adezyon, su moleküllerinin başka bir yüzeye tutunmasıdır; suyun cam ya da bitki borularında yukarı tırmanmasında (kılcallık) görülür."}],"ans":"Kohezyon su moleküllerinin birbirine tutunmasıdır (yüzey gerilimi, damla); adezyon ise suyun başka yüzeye tutunmasıdır (kılcal yükselme). Her ikisi de su moleküllerinin polarlığından kaynaklanır."},{"q":"Suyun yüksek özısısının iklimi yumuşatmadaki rolünü açıklayınız.","steps":[{"t":"Yavaş ısınıp soğuma","a":"H bağına ısı gider","d":"Suya verilen ısının çoğu önce hidrojen bağlarını zorlar, bu yüzden deniz ve göller yavaş ısınır, yavaş soğur."},{"t":"İklim etkisi","a":"sıcaklık dengesi","d":"Bu nedenle büyük su kütlelerinin yanındaki bölgelerde gece-gündüz ve mevsim sıcaklık farkları daha az, iklim daha ılımandır."}],"ans":"Suyun yüksek özısısı, büyük su kütlelerinin yavaş ısınıp soğumasını sağlar; bu da çevresindeki sıcaklık farklarını azaltarak iklimi yumuşatır."}]},"lise":{"kolay":[{"q":"Su molekülünün VSEPR'ye göre geometrisini ve bağ açısını açıklayınız.","fig":"<svg viewBox='0 0 320 170'><circle cx='160' cy='62' r='24' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='67' font-size='12' text-anchor='middle' fill='#fff'>O</text><circle cx='110' cy='118' r='15' fill='#cfd8e8' stroke='#1a2b45'/><text x='110' y='123' font-size='9' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='210' cy='118' r='15' fill='#cfd8e8' stroke='#1a2b45'/><text x='210' y='123' font-size='9' text-anchor='middle' fill='#1a2b45'>H</text><line x1='141' y1='80' x2='121' y2='106' stroke='#1a2b45' stroke-width='2'/><line x1='179' y1='80' x2='199' y2='106' stroke='#1a2b45' stroke-width='2'/><circle cx='150' cy='40' r='3' fill='#2b6be0'/><circle cx='170' cy='40' r='3' fill='#2b6be0'/><text x='160' y='100' font-size='10' text-anchor='middle' fill='#1a2b45'>≈104,5°</text></svg>","steps":[{"t":"Elektron çiftleri","a":"2 bağ + 2 yalın","d":"Merkez oksijende 2 bağ çifti ve 2 ortaklanmamış (yalın) çift, toplam 4 elektron grubu vardır."},{"t":"Geometri","a":"açısal, ≈104,5°","d":"Elektron geometrisi dörtyüzlüye yakındır; yalın çiftlerin itmesiyle molekül geometrisi açısal ve bağ açısı ≈104,5° olur."}],"ans":"Suda merkez oksijende 2 bağ + 2 yalın çift bulunur; molekül açısal geometrilidir ve H–O–H bağ açısı yaklaşık 104,5°'dir."},{"q":"Suyun polarlığının kaynağını elektronegatiflik ve geometri ile açıklayınız.","steps":[{"t":"Polar bağlar","a":"O–H polar","d":"Oksijen hidrojenden çok daha elektronegatif olduğundan her O–H bağı polardır; oksijen δ⁻, hidrojenler δ⁺ yüklenir."},{"t":"Geometri etkisi","a":"dipoller toplanır","d":"Molekül açısal olduğundan iki bağ dipolü birbirini götürmez, bileşkeleri net bir molekül dipolü oluşturur."}],"ans":"Oksijen-hidrojen elektronegatiflik farkı O–H bağlarını polar yapar; açısal geometride bu bağ dipolleri toplandığından su net dipole sahip, yani polar bir moleküldür."},{"q":"Su moleküllerinin oluşturduğu hidrojen bağı ağını ve özelliklere etkisini açıklayınız.","fig":"<svg viewBox='0 0 320 170'><circle cx='90' cy='55' r='15' fill='#e0552b' stroke='#1a2b45'/><text x='90' y='60' font-size='9' text-anchor='middle' fill='#fff'>O</text><circle cx='210' cy='55' r='15' fill='#e0552b' stroke='#1a2b45'/><text x='210' y='60' font-size='9' text-anchor='middle' fill='#fff'>O</text><circle cx='150' cy='120' r='15' fill='#e0552b' stroke='#1a2b45'/><text x='150' y='125' font-size='9' text-anchor='middle' fill='#fff'>O</text><line x1='104' y1='62' x2='196' y2='62' stroke='#2b6be0' stroke-dasharray='4 3'/><line x1='98' y1='68' x2='142' y2='108' stroke='#2b6be0' stroke-dasharray='4 3'/><line x1='202' y1='68' x2='158' y2='108' stroke='#2b6be0' stroke-dasharray='4 3'/><text x='150' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>her molekül ~4 komşuya H bağı</text></svg>","steps":[{"t":"Ağ yapısı","a":"4 komşu bağı","d":"Her su molekülü 2 H'si ve 2 yalın çiftiyle çevresindeki yaklaşık 4 komşu molekülle hidrojen bağı kurabilir, geniş bir ağ oluşur."},{"t":"Özelliklere etki","a":"yüksek kaynama vb.","d":"Bu güçlü ağ; yüksek kaynama noktası, yüksek özısı, yüksek yüzey gerilimi gibi olağandışı özellikleri açıklar."}],"ans":"Her su molekülü yaklaşık 4 komşusuyla hidrojen bağı kurarak geniş bir ağ oluşturur; bu ağ suyun yüksek kaynama noktası, özısısı ve yüzey gerilimi gibi özelliklerini açıklar."},{"q":"Suyun evrensel çözücü olmasını polarlık ve hidrojen bağı ile açıklayınız.","steps":[{"t":"İyonik maddeler","a":"iyon-dipol","d":"Polar su, iyonik maddelerin iyonlarını iyon-dipol etkileşimiyle sarar (hidrasyon) ve çözer."},{"t":"Polar maddeler","a":"hidrojen bağı","d":"Şeker, alkol gibi polar maddelerle hidrojen bağı/dipol-dipol kurarak onları da çözer; 'benzer benzeri çözer' ilkesi geçerlidir."}],"ans":"Su, polar yapısı ve hidrojen bağı kurabilmesi sayesinde iyonik maddeleri iyon-dipolle, polar maddeleri hidrojen bağı/dipol-dipolle çözer; bu yüzden çok geniş bir çözücüdür."},{"q":"Suyun yüzey gerilimi ile kohezyon ve adezyon kavramlarını ilişkilendiriniz.","steps":[{"t":"Kohezyon","a":"su–su","d":"Su moleküllerinin hidrojen bağıyla birbirine tutunması kohezyondur; yüzeydeki içe çekim yüzey gerilimini oluşturur."},{"t":"Adezyon","a":"su–yüzey","d":"Suyun cam ya da bitki ksilemi gibi başka yüzeylere tutunması adezyondur; kohezyonla birlikte kılcal yükselmeyi sağlar."}],"ans":"Kohezyon (su–su hidrojen bağı) yüzey gerilimini doğurur; adezyon (su–yüzey çekimi) kohezyonla birlikte kılcal borularda suyun yükselmesini sağlar."}],"zor":[{"q":"Suyun 4 °C'de en yüksek yoğunluğa ulaşmasını (yoğunluk anomalisi) molekül yapısıyla açıklayınız.","steps":[{"t":"Soğurken sıkışma","a":"4 °C'ye dek artar","d":"Su soğutulurken moleküller yavaşlar ve birbirine yaklaşır, yoğunluk 4 °C'ye kadar artar."},{"t":"Açık örgüye geçiş","a":"4 °C'den sonra azalır","d":"4 °C'nin altında hidrojen bağları molekülleri boşluklu altıgen düzene itmeye başlar; hacim büyür, yoğunluk azalır. Bu yüzden en yüksek yoğunluk 4 °C'dedir ve buz sudan hafiftir."}],"ans":"Su soğurken 4 °C'ye dek sıkışıp yoğunluğu artar; bu sıcaklığın altında hidrojen bağları molekülleri boşluklu örgüye itmeye başladığından hacim büyür ve yoğunluk azalır, böylece en yüksek yoğunluk 4 °C'de görülür."},{"q":"H₂O'nun, periyodik tablodaki komşu hidrürlere (H₂S, H₂Se) göre beklenmedik biçimde yüksek kaynama noktasına sahip olmasının nedenini açıklayınız.","fig":"<svg viewBox='0 0 320 170'><line x1='40' y1='140' x2='300' y2='140' stroke='#1a2b45'/><line x1='40' y1='30' x2='40' y2='140' stroke='#1a2b45'/><circle cx='90' cy='50' r='5' fill='#e0552b'/><text x='90' y='42' font-size='9' text-anchor='middle' fill='#1a2b45'>H₂O</text><circle cx='160' cy='118' r='5' fill='#2b6be0'/><text x='160' y='110' font-size='9' text-anchor='middle' fill='#1a2b45'>H₂S</text><circle cx='230' cy='105' r='5' fill='#2b6be0'/><text x='230' y='97' font-size='9' text-anchor='middle' fill='#1a2b45'>H₂Se</text><text x='170' y='158' font-size='9' text-anchor='middle' fill='#1a2b45'>artan molekül kütlesi →</text></svg>","steps":[{"t":"Beklenti","a":"kütleyle artmalı","d":"Yalnız van der Waals kuvvetleri olsaydı kaynama noktası molekül kütlesiyle artar, su (en hafifi) en düşük noktaya sahip olurdu."},{"t":"H bağı sıçraması","a":"O elektronegatif","d":"Oksijen çok elektronegatif olduğundan suda güçlü hidrojen bağı oluşur; bu ek kuvvet kaynama noktasını beklentinin çok üstüne çıkarır. H₂S/H₂Se'de hidrojen bağı yoktur."}],"ans":"Yalnız van der Waals kuvvetleri olsaydı en hafif olan suyun kaynama noktası en düşük olurdu; ancak oksijenin yüksek elektronegatifliği güçlü hidrojen bağı oluşturduğundan su, H₂S ve H₂Se'den çok daha yüksek sıcaklıkta kaynar."},{"q":"Suyun yüksek özısısı ve yüksek buharlaşma ısısının, canlılarda sıcaklık düzenlemesindeki rolünü açıklayınız.","steps":[{"t":"Yüksek özısı","a":"ısı tamponu","d":"Verilen ısının çoğu hidrojen bağlarını zorlamaya gittiğinden vücut/hücre sıvısının sıcaklığı yavaş değişir; bu, ani sıcaklık dalgalanmalarına karşı tampon görevi görür."},{"t":"Yüksek buharlaşma ısısı","a":"terle serinleme","d":"Suyun buharlaşması için molekülleri birbirinden ayırmak (hidrojen bağlarını koparmak) çok enerji ister; bu enerji vücuttan çekildiğinden terleme etkili biçimde serinletir."}],"ans":"Suyun yüksek özısısı sıcaklık değişimlerine karşı tampon oluşturur; yüksek buharlaşma ısısı ise terleme sırasında çok ısı çekerek canlıyı serinletir. Her ikisi de hidrojen bağlarının enerji gerektirmesinden kaynaklanır."},{"q":"Suyun kılcal borularda (örneğin bitki ksileminde) yukarı çıkmasını kohezyon-adezyon-yüzey gerilimi birlikteliğiyle açıklayınız.","steps":[{"t":"Adezyon başlatır","a":"çepere tutunma","d":"Su molekülleri kılcal borunun çeperine (örneğin selüloz) hidrojen bağıyla tutunur (adezyon) ve yukarı doğru yükselmeye başlar."},{"t":"Kohezyon sürdürür","a":"su sütunu çekilir","d":"Yukarı çıkan su, kohezyonla altındaki molekülleri de çeker; yüzey gerilimi su sütununu bütün tutar. Boru ne kadar dar olursa su o kadar yükselir."}],"ans":"Su, adezyonla çepere tutunup yükselir; kohezyon ve yüzey gerilimi su sütununu bütün ve sürekli tutarak alttaki suyu yukarı çeker. Bu birliktelik bitki ksileminde suyun yükselmesini sağlar (boru daraldıkça yükseklik artar)."},{"q":"Suyun donarken hidrojen bağlarıyla oluşturduğu altıgen örgünün, buzun yüzmesi dışında ekolojik bir önemi nedir?","steps":[{"t":"Açık örgü, düşük yoğunluk","a":"buz üstte donar","d":"Hidrojen bağlarının boşluklu altıgen örgüsü buzu sudan hafif yapar; bu yüzden göller yüzeyden aşağı doğru donar."},{"t":"Yalıtım etkisi","a":"alt su sıvı kalır","d":"Yüzeydeki buz tabakası bir yalıtkan gibi davranıp altındaki suyu daha fazla donmaktan korur; böylece su canlıları kış boyunca buzun altında yaşamını sürdürebilir."}],"ans":"Hidrojen bağlarının açık altıgen örgüsü buzu sudan hafif yaptığından göller yüzeyden donar; üstteki buz tabakası altındaki suyu yalıtarak sıvı tutar ve su canlılarının kışın yaşamını sürdürmesini sağlar."}]}}};
